-- Dependencies: 1347
-- Name: FUNCTION grant_pg_net_access(); Type: COMMENT; Schema: extensions; Owner: supabase_admin
--

COMMENT ON FUNCTION extensions.grant_pg_net_access() IS 'Grants access to pg_net';


--
-- TOC entry 483 (class 1255 OID 16607)
-- Name: pgrst_ddl_watch(); Type: FUNCTION; Schema: extensions; Owner: supabase_admin
--

CREATE FUNCTION extensions.pgrst_ddl_watch() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN SELECT * FROM pg_event_trigger_ddl_commands()
  LOOP
    IF cmd.command_tag IN (
      'CREATE SCHEMA', 'ALTER SCHEMA'
    , 'CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO', 'ALTER TABLE'
    , 'CREATE FOREIGN TABLE', 'ALTER FOREIGN TABLE'
    , 'CREATE VIEW', 'ALTER VIEW'
    , 'CREATE MATERIALIZED VIEW', 'ALTER MATERIALIZED VIEW'
    , 'CREATE FUNCTION', 'ALTER FUNCTION'
    , 'CREATE TRIGGER'
    , 'CREATE TYPE', 'ALTER TYPE'
    , 'CREATE RULE'
    , 'COMMENT'
    )
    -- don't notify in case of CREATE TEMP table or other objects created on pg_temp
    AND cmd.schema_name is distinct from 'pg_temp'
    THEN
      NOTIFY pgrst, 'reload schema';
    END IF;
  END LOOP;
END; $$;


ALTER FUNCTION extensions.pgrst_ddl_watch() OWNER TO supabase_admin;

--
-- TOC entry 1292 (class 1255 OID 16608)
-- Name: pgrst_drop_watch(); Type: FUNCTION; Schema: extensions; Owner: supabase_admin
--

CREATE FUNCTION extensions.pgrst_drop_watch() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  obj record;
BEGIN
  FOR obj IN SELECT * FROM pg_event_trigger_dropped_objects()
  LOOP
    IF obj.object_type IN (
      'schema'
    , 'table'
    , 'foreign table'
    , 'view'
    , 'materialized view'
    , 'function'
    , 'trigger'
    , 'type'
    , 'rule'
    )
    AND obj.is_temporary IS false -- no pg_temp objects
    THEN
      NOTIFY pgrst, 'reload schema';
    END IF;
  END LOOP;
END; $$;


ALTER FUNCTION extensions.pgrst_drop_watch() OWNER TO supabase_admin;

--
-- TOC entry 1288 (class 1255 OID 16618)
-- Name: set_graphql_placeholder(); Type: FUNCTION; Schema: extensions; Owner: supabase_admin
--

CREATE FUNCTION extensions.set_graphql_placeholder() RETURNS event_trigger
    LANGUAGE plpgsql
    AS $_$
    DECLARE
    graphql_is_dropped bool;
    BEGIN
    graphql_is_dropped = (
        SELECT ev.schema_name = 'graphql_public'
        FROM pg_event_trigger_dropped_objects() AS ev
        WHERE ev.schema_name = 'graphql_public'
    );

    IF graphql_is_dropped
    THEN
        create or replace function graphql_public.graphql(
            "operationName" text default null,
            query text default null,
            variables jsonb default null,
            extensions jsonb default null
        )
            returns jsonb
            language plpgsql
        as $$
            DECLARE
                server_version float;
            BEGIN
                server_version = (SELECT (SPLIT_PART((select version()), ' ', 2))::float);

                IF server_version >= 14 THEN
                    RETURN jsonb_build_object(
                        'errors', jsonb_build_array(
                            jsonb_build_object(
                                'message', 'pg_graphql extension is not enabled.'
                            )
                        )
                    );
                ELSE
                    RETURN jsonb_build_object(
                        'errors', jsonb_build_array(
                            jsonb_build_object(
                                'message', 'pg_graphql is only available on projects running Postgres 14 onwards.'
                            )
                        )
                    );
                END IF;
            END;
        $$;
    END IF;

    END;
$_$;


ALTER FUNCTION extensions.set_graphql_placeholder() OWNER TO supabase_admin;

--
-- TOC entry 6715 (class 0 OID 0)
-- Dependencies: 1288
-- Name: FUNCTION set_graphql_placeholder(); Type: COMMENT; Schema: extensions; Owner: supabase_admin
--

COMMENT ON FUNCTION extensions.set_graphql_placeholder() IS 'Reintroduces placeholder function for graphql_public.graphql';


--
-- TOC entry 1205 (class 1255 OID 16387)
-- Name: get_auth(text); Type: FUNCTION; Schema: pgbouncer; Owner: supabase_admin
--

CREATE FUNCTION pgbouncer.get_auth(p_usename text) RETURNS TABLE(username text, password text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO ''
    AS $_$
  BEGIN
      RAISE DEBUG 'PgBouncer auth request: %', p_usename;

      RETURN QUERY
      SELECT
          rolname::text,
          CASE WHEN rolvaliduntil < now()
              THEN null
              ELSE rolpassword::text
          END
      FROM pg_authid
      WHERE rolname=$1 and rolcanlogin;
  END;
  $_$;


ALTER FUNCTION pgbouncer.get_auth(p_usename text) OWNER TO supabase_admin;

--
-- TOC entry 549 (class 1255 OID 276763)
-- Name: add_or_update_purchase_item(uuid, uuid, uuid, numeric, numeric, text, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_or_update_purchase_item(p_purchase_id uuid, p_inventory_id uuid, p_user_id uuid, p_quantity numeric, p_purchase_price numeric, p_batch_number text DEFAULT NULL::text, p_expiry_date date DEFAULT NULL::date) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_purchase RECORD;
    v_inventory RECORD;
    v_existing_item RECORD;
    v_item_id UUID;
    v_total_price NUMERIC(12,2);
    v_subtotal NUMERIC(12,2);
    v_total NUMERIC(12,2);
    v_expiry_date DATE;
    v_batch_number TEXT;
    v_is_medicine BOOLEAN;
    v_display_name TEXT;
    v_items_count INT;
BEGIN
    -- AUTHENTICATION
    v_current_user_id := auth.uid();
    IF v_current_user_id IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    -- INPUT VALIDATION
    IF p_purchase_id IS NULL OR p_inventory_id IS NULL OR p_quantity IS NULL OR p_quantity <= 0 THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Required fields missing or invalid quantity');
    END IF;

    -- FETCH & LOCK PURCHASE
    SELECT id, pharmacy_id, purchase_status, discount_amount, paid_amount
    INTO v_purchase
    FROM purchases
    WHERE id = p_purchase_id AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN json_build_object('code', 'PURCHASE_NOT_FOUND', 'message', 'Purchase not found');
    END IF;

    IF v_purchase.purchase_status != 'DRAFT' THEN
        RETURN json_build_object('code', 'INVALID_STATUS', 'message', 'Can only modify draft purchases');
    END IF;

  

    -- FETCH INVENTORY
    SELECT id, type, name, brand, primary_unit
    INTO v_inventory
    FROM inventory
    WHERE id = p_inventory_id AND pharmacy_id = v_purchase.pharmacy_id AND deleted_at IS NULL;

    IF NOT FOUND THEN
        RETURN json_build_object('code', 'INVENTORY_NOT_FOUND', 'message', 'Item not found');
    END IF;

    v_is_medicine := (v_inventory.type = 'MEDICINE');
    v_display_name := COALESCE(v_inventory.brand, v_inventory.name);

    -- NORMALIZE BATCH NUMBER: treat 'DEFAULT' as NULL
    v_batch_number := NULLIF(NULLIF(UPPER(TRIM(p_batch_number)), ''), 'DEFAULT');

    -- NORMALIZE EXPIRY DATE
    IF p_expiry_date IS NOT NULL AND TRIM(p_expiry_date) NOT IN ('', 'N/A') THEN
        BEGIN
            v_expiry_date := TO_DATE(TRIM(p_expiry_date), 'YYYY-MM-DD');
        EXCEPTION WHEN OTHERS THEN
            v_expiry_date := NULL;
        END;
    END IF;

    -- MEDICINE-SPECIFIC VALIDATIONS
    IF v_is_medicine THEN
        IF v_batch_number IS NULL THEN
            RETURN json_build_object('code', 'BATCH_REQUIRED', 'message', 'Batch number is required for medicine');
        END IF;
        IF v_expiry_date IS NULL THEN
            RETURN json_build_object('code', 'EXPIRY_REQUIRED', 'message', 'Valid expiry date (YYYY-MM-DD) is required for medicine');
        END IF;
        IF v_expiry_date <= CURRENT_DATE THEN
            RETURN json_build_object('code', 'EXPIRED_ITEM', 'message', 'Cannot add expired medicine');
        END IF;
    END IF;

    -- CALCULATE TOTALS
    v_total_price := ROUND(p_quantity * p_purchase_price, 2);

    -- UPSERT ITEM (Match by purchase_id + inventory_id + batch_number)
    SELECT id INTO v_existing_item
    FROM purchase_items
    WHERE purchase_id = p_purchase_id
      AND inventory_id = p_inventory_id
      AND (
          (batch_number IS NULL AND v_batch_number IS NULL) OR
          (UPPER(TRIM(batch_number)) = UPPER(v_batch_number))
      )
    LIMIT 1;

    IF v_existing_item.id IS NOT NULL THEN
        UPDATE purchase_items
        SET quantity = p_quantity,
            purchase_price = p_purchase_price,
            selling_price = p_selling_price,
            total_price = v_total_price,
            expiry_date = v_expiry_date,
            batch_number = v_batch_number,
            shelf_location = NULLIF(TRIM(p_shelf_location), ''),
            notes = NULLIF(TRIM(p_notes), ''),
            updated_at = NOW()
        WHERE id = v_existing_item.id
        RETURNING id INTO v_item_id;
    ELSE
        INSERT INTO purchase_items (
            id, purchase_id, inventory_id, batch_number, expiry_date,
            quantity, purchase_price, selling_price, total_price,
            shelf_location, notes, created_at, updated_at
        ) VALUES (
            gen_random_uuid(), p_purchase_id, p_inventory_id, v_batch_number, v_expiry_date,
            p_quantity, p_purchase_price, p_selling_price, v_total_price,
            NULLIF(TRIM(p_shelf_location), ''),
            NULLIF(TRIM(p_notes), ''),
            NOW(), NOW()
        )
        RETURNING id INTO v_item_id;
    END IF;

    -- UPDATE PURCHASE TOTALS
    SELECT COALESCE(SUM(total_price), 0), COUNT(*)
    INTO v_subtotal, v_items_count
    FROM purchase_items
    WHERE purchase_id = p_purchase_id;

    v_total := GREATEST(0, v_subtotal - COALESCE(v_purchase.discount_amount, 0));

    UPDATE purchases
    SET subtotal = v_subtotal,
        total_amount = v_total,
        outstanding_amount = GREATEST(0, v_total - COALESCE(paid_amount, 0)),
        updated_at = NOW()
    WHERE id = p_purchase_id;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Item saved successfully',
        'details', json_build_object(
            'item_id', v_item_id,
            'inventory_id', p_inventory_id,
            'inventory_name', v_display_name,
            'quantity', p_quantity,
            'total_price', v_total_price,
            'purchase_totals', json_build_object(
                'subtotal', v_subtotal,
                'total_amount', v_total
            )
        )
    );
END;
$$;


ALTER FUNCTION public.add_or_update_purchase_item(p_purchase_id uuid, p_inventory_id uuid, p_user_id uuid, p_quantity numeric, p_purchase_price numeric, p_batch_number text, p_expiry_date date) OWNER TO postgres;

--
-- TOC entry 1527 (class 1255 OID 255201)
-- Name: add_or_update_purchase_item(uuid, uuid, integer, numeric, numeric, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_or_update_purchase_item(p_purchase_id uuid, p_inventory_id uuid, p_quantity integer, p_purchase_price numeric, p_selling_price numeric, p_batch_number text DEFAULT NULL::text, p_expiry_date text DEFAULT NULL::text, p_shelf_location text DEFAULT NULL::text, p_notes text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_purchase RECORD;
    v_inventory RECORD;
    v_existing_item RECORD;
    v_item_id UUID;
    v_total_price NUMERIC(12,2);
    v_subtotal NUMERIC(12,2);
    v_total NUMERIC(12,2);
    v_expiry_date DATE;
    v_batch_number TEXT;
    v_is_medicine BOOLEAN;
    v_display_name TEXT;
    v_items_count INT;
BEGIN
    -- AUTHENTICATION
    v_current_user_id := auth.uid();
    IF v_current_user_id IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    -- INPUT VALIDATION
    IF p_purchase_id IS NULL OR p_inventory_id IS NULL OR p_quantity IS NULL OR p_quantity <= 0 THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Required fields missing or invalid quantity');
    END IF;

    -- FETCH & LOCK PURCHASE
    SELECT id, pharmacy_id, purchase_status, discount_amount, paid_amount
    INTO v_purchase
    FROM purchases
    WHERE id = p_purchase_id AND deleted_at IS NULL
    FOR UPDATE;

    IF NOT FOUND THEN
        RETURN json_build_object('code', 'PURCHASE_NOT_FOUND', 'message', 'Purchase not found');
    END IF;

    IF v_purchase.purchase_status != 'DRAFT' THEN
        RETURN json_build_object('code', 'INVALID_STATUS', 'message', 'Can only modify draft purchases');
    END IF;

  

    -- FETCH INVENTORY
    SELECT id, type, name, brand, primary_unit
    INTO v_inventory
    FROM inventory
    WHERE id = p_inventory_id AND pharmacy_id = v_purchase.pharmacy_id AND deleted_at IS NULL;

    IF NOT FOUND THEN
        RETURN json_build_object('code', 'INVENTORY_NOT_FOUND', 'message', 'Item not found');
    END IF;

    v_is_medicine := (v_inventory.type = 'MEDICINE');
    v_display_name := COALESCE(v_inventory.brand, v_inventory.name);

    -- NORMALIZE BATCH NUMBER: treat 'DEFAULT' as NULL
    v_batch_number := NULLIF(NULLIF(UPPER(TRIM(p_batch_number)), ''), 'DEFAULT');

    -- NORMALIZE EXPIRY DATE
    IF p_expiry_date IS NOT NULL AND TRIM(p_expiry_date) NOT IN ('', 'N/A') THEN
        BEGIN
            v_expiry_date := TO_DATE(TRIM(p_expiry_date), 'YYYY-MM-DD');
        EXCEPTION WHEN OTHERS THEN
            v_expiry_date := NULL;
        END;
    END IF;

    -- MEDICINE-SPECIFIC VALIDATIONS
    IF v_is_medicine THEN
        IF v_batch_number IS NULL THEN
            RETURN json_build_object('code', 'BATCH_REQUIRED', 'message', 'Batch number is required for medicine');
        END IF;
        IF v_expiry_date IS NULL THEN
            RETURN json_build_object('code', 'EXPIRY_REQUIRED', 'message', 'Valid expiry date (YYYY-MM-DD) is required for medicine');
        END IF;
        IF v_expiry_date <= CURRENT_DATE THEN
            RETURN json_build_object('code', 'EXPIRED_ITEM', 'message', 'Cannot add expired medicine');
        END IF;
    END IF;

    -- CALCULATE TOTALS
    v_total_price := ROUND(p_quantity * p_purchase_price, 2);

    -- UPSERT ITEM (Match by purchase_id + inventory_id + batch_number)
    SELECT id INTO v_existing_item
    FROM purchase_items
    WHERE purchase_id = p_purchase_id
      AND inventory_id = p_inventory_id
      AND (
          (batch_number IS NULL AND v_batch_number IS NULL) OR
          (UPPER(TRIM(batch_number)) = UPPER(v_batch_number))
      )
    LIMIT 1;

    IF v_existing_item.id IS NOT NULL THEN
        UPDATE purchase_items
        SET quantity = p_quantity,
            purchase_price = p_purchase_price,
            selling_price = p_selling_price,
            total_price = v_total_price,
            expiry_date = v_expiry_date,
            batch_number = v_batch_number,
            shelf_location = NULLIF(TRIM(p_shelf_location), ''),
            notes = NULLIF(TRIM(p_notes), ''),
            updated_at = NOW()
        WHERE id = v_existing_item.id
        RETURNING id INTO v_item_id;
    ELSE
        INSERT INTO purchase_items (
            id, purchase_id, inventory_id, batch_number, expiry_date,
            quantity, purchase_price, selling_price, total_price,
            shelf_location, notes, created_at, updated_at
        ) VALUES (
            gen_random_uuid(), p_purchase_id, p_inventory_id, v_batch_number, v_expiry_date,
            p_quantity, p_purchase_price, p_selling_price, v_total_price,
            NULLIF(TRIM(p_shelf_location), ''),
            NULLIF(TRIM(p_notes), ''),
            NOW(), NOW()
        )
        RETURNING id INTO v_item_id;
    END IF;

    -- UPDATE PURCHASE TOTALS
    SELECT COALESCE(SUM(total_price), 0), COUNT(*)
    INTO v_subtotal, v_items_count
    FROM purchase_items
    WHERE purchase_id = p_purchase_id;

    v_total := GREATEST(0, v_subtotal - COALESCE(v_purchase.discount_amount, 0));

    UPDATE purchases
    SET subtotal = v_subtotal,
        total_amount = v_total,
        outstanding_amount = GREATEST(0, v_total - COALESCE(paid_amount, 0)),
        updated_at = NOW()
    WHERE id = p_purchase_id;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Item saved successfully',
        'details', json_build_object(
            'item_id', v_item_id,
            'inventory_id', p_inventory_id,
            'inventory_name', v_display_name,
            'quantity', p_quantity,
            'total_price', v_total_price,
            'purchase_totals', json_build_object(
                'subtotal', v_subtotal,
                'total_amount', v_total
            )
        )
    );
END;
$$;


