-- Name: FUNCTION add_or_update_purchase_item(p_purchase_id uuid, p_inventory_id uuid, p_quantity integer, p_purchase_price numeric, p_selling_price numeric, p_batch_number text, p_expiry_date text, p_shelf_location text, p_notes text); Type: COMMENT; Schema: public; Owner: postgres
