--
-- TOC entry 699 (class 1255 OID 231621)
-- Name: add_or_update_purchase_return_item(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_or_update_purchase_return_item(p_return_id uuid, p_purchase_item_id uuid, p_quantity integer) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id              UUID;
    v_return               RECORD;
    v_purchase_item        RECORD;
    v_already_returned     INT;
    v_batch_stock          INT;
    v_max_returnable       INT;
    v_existing_item        UUID;
    v_item_total           DECIMAL;
    v_return_subtotal      DECIMAL;
    v_credit_adjustment    DECIMAL;
    v_cash_refund          DECIMAL;
    v_purchase_outstanding DECIMAL;
    v_now                  TIMESTAMP WITH TIME ZONE;
BEGIN
    v_now := NOW() AT TIME ZONE 'Asia/Dhaka';

    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    -- Lock the return record to prevent concurrent modifications
    BEGIN
        SELECT pr.*,
               p.outstanding_amount AS purchase_outstanding,
               p.pharmacy_id        AS purchase_pharmacy_id,
               p.id                 AS linked_purchase_id
        INTO STRICT v_return
        FROM purchase_returns pr
        JOIN purchases p ON pr.purchase_id = p.id
        WHERE pr.id = p_return_id
          AND pr.refund_status = 'PENDING'::payment_status_enum
        FOR UPDATE OF pr NOWAIT;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN jsonb_build_object('code', 'RETURN_NOT_FOUND', 'message', 'Return draft not found');
        WHEN lock_not_available THEN
            RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'Return is being modified, please try again');
    END;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE up.user_id    = v_user_id
          AND up.pharmacy_id = v_return.purchase_pharmacy_id
          AND up.is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied');
    END IF;

    SELECT pi.*, inv.name AS inventory_name
    INTO v_purchase_item
    FROM purchase_items pi
    JOIN inventory inv ON pi.inventory_id = inv.id
    WHERE pi.id = p_purchase_item_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'ITEM_NOT_FOUND', 'message', 'Purchase item not found');
    END IF;

    -- Verify this purchase item belongs to the return's purchase
    IF v_purchase_item.purchase_id != v_return.linked_purchase_id THEN
        RETURN jsonb_build_object('code', 'INVALID_ITEM', 'message', 'Item does not belong to this purchase');
    END IF;

    -- Quantities returned in prior COMPLETED returns for this item
    SELECT COALESCE(SUM(pri.quantity), 0)
    INTO v_already_returned
    FROM purchase_return_items pri
    JOIN purchase_returns pr ON pri.return_id = pr.id
    WHERE pri.purchase_item_id = p_purchase_item_id
      AND pr.refund_status     = 'COMPLETED'::payment_status_enum;

    -- [BUG-AVAIL-2 FIX] Cap max returnable at the current batch stock.
    -- Without this, a pharmacist could return 50 units when only 30 remain in
    -- the batch (because 20 were sold), causing negative stock after finalization.
    SELECT ib.current_quantity
    INTO v_batch_stock
    FROM inventory_batches ib
    WHERE ib.inventory_id = v_purchase_item.inventory_id
      AND ib.purchase_id  = v_return.linked_purchase_id
      AND ib.pharmacy_id  = v_return.purchase_pharmacy_id
      AND ib.batch_number IS NOT DISTINCT FROM NULLIF(NULLIF(v_purchase_item.batch_number, ''), 'DEFAULT')
      AND ib.deleted_at IS NULL;

    IF NOT FOUND THEN
        -- No matching batch (edge case: batch deleted or purchase_id unset).
        -- Fall back to document-based limit (purchased - completed_returns).
        v_batch_stock := GREATEST(0, v_purchase_item.quantity - v_already_returned);
    END IF;

    v_max_returnable := GREATEST(0, LEAST(
        v_purchase_item.quantity - v_already_returned,
        v_batch_stock
    ));

    IF p_quantity <= 0 THEN
        RETURN jsonb_build_object('code', 'INVALID_QUANTITY', 'message', 'Quantity must be greater than 0');
    END IF;

    IF p_quantity > v_max_returnable THEN
        RETURN jsonb_build_object(
            'code',    'EXCEEDS_AVAILABLE',
            'message', 'Cannot return more than ' || v_max_returnable || ' available'
        );
    END IF;

    SELECT id INTO v_existing_item
    FROM purchase_return_items
    WHERE return_id = p_return_id AND purchase_item_id = p_purchase_item_id;

    v_item_total := p_quantity * v_purchase_item.purchase_price;

    IF v_existing_item IS NOT NULL THEN
        UPDATE purchase_return_items
        SET quantity   = p_quantity,
            total_cost = v_item_total,
            unit_cost  = v_purchase_item.purchase_price
        WHERE id = v_existing_item;
    ELSE
        INSERT INTO purchase_return_items (
            id, return_id, purchase_item_id, inventory_id, batch_number,
            quantity, unit_cost, total_cost, created_at
        ) VALUES (
            gen_random_uuid(),
            p_return_id,
            p_purchase_item_id,
            v_purchase_item.inventory_id,
            COALESCE(v_purchase_item.batch_number, ''),
            p_quantity,
            v_purchase_item.purchase_price,
            v_item_total,
            v_now
        );
    END IF;

    SELECT COALESCE(SUM(total_cost), 0)
    INTO v_return_subtotal
    FROM purchase_return_items
    WHERE return_id = p_return_id;

    v_purchase_outstanding := v_return.purchase_outstanding;

    IF v_purchase_outstanding > 0 THEN
        v_credit_adjustment := LEAST(v_return_subtotal, v_purchase_outstanding);
        v_cash_refund       := GREATEST(0, v_return_subtotal - v_credit_adjustment);
    ELSE
        v_credit_adjustment := 0;
        v_cash_refund       := v_return_subtotal;
    END IF;

    UPDATE purchase_returns
    SET subtotal     = v_return_subtotal,
        total_amount = v_return_subtotal,
        updated_at   = v_now
    WHERE id = p_return_id;

    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Item updated',
        'details', jsonb_build_object(
            'return_id',       p_return_id,
            'subtotal',        v_return_subtotal,
            'total_amount',    v_return_subtotal,
            'credit_adjustment', v_credit_adjustment,
            'cash_refund',     v_cash_refund,
            'is_credit_only',  (v_cash_refund = 0 AND v_return_subtotal > 0)
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'ERROR', 'message', SQLERRM);
END;
$$;


ALTER FUNCTION public.add_or_update_purchase_return_item(p_return_id uuid, p_purchase_item_id uuid, p_quantity integer) OWNER TO postgres;

--
-- TOC entry 1153 (class 1255 OID 226277)
-- Name: add_or_update_return_item(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_or_update_return_item(p_return_id uuid, p_sale_item_id uuid, p_return_quantity integer) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id              UUID;
    v_return               RECORD;
    v_sale_item            RECORD;
    v_existing_return_item UUID;
    v_available_qty        INT;
    v_item_total           DECIMAL;
    v_discount_calc        RECORD;
    v_net_refund           DECIMAL;
    v_invoice_discount     DECIMAL;
BEGIN
    -- ── 1. BUG-SR-3 FIX: auth check first ─────────────────────────────────
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    -- ── 2. INPUT VALIDATION ────────────────────────────────────────────────
    IF p_return_quantity IS NULL OR p_return_quantity <= 0 THEN
        RETURN jsonb_build_object('code', 'INVALID_QUANTITY', 'message', 'Return quantity must be a positive integer');
    END IF;

    -- ── 3. LOCK RETURN ─────────────────────────────────────────────────────
    SELECT r.*, s.subtotal AS sale_subtotal, s.discount_amount AS sale_discount, s.pharmacy_id
    INTO v_return
    FROM sale_returns r
    JOIN sales s ON r.sale_id = s.id
    WHERE r.id = p_return_id
    FOR UPDATE OF r NOWAIT;

    -- BUG-SR-4 FIX: explicit NOT FOUND check (was silently returning PERMISSION_DENIED)
    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'RETURN_NOT_FOUND', 'message', 'Return not found');
    END IF;

    -- ── 4. PERMISSION ──────────────────────────────────────────────────────
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies pu
        WHERE pu.pharmacy_id = v_return.pharmacy_id
          AND pu.user_id     = v_user_id
          AND pu.is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied');
    END IF;

    -- ── 5. STATUS CHECK ────────────────────────────────────────────────────
    IF v_return.return_status != 'DRAFT' THEN
        RETURN jsonb_build_object('code', 'INVALID_STATUS', 'message', 'Only draft returns can be modified');
    END IF;

    -- ── 6. FETCH SALE ITEM ─────────────────────────────────────────────────
    SELECT * INTO v_sale_item FROM sale_items WHERE id = p_sale_item_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'ITEM_NOT_FOUND', 'message', 'Sale item not found');
    END IF;

    -- BUG-NEW-4 FIX: ensure the sale item belongs to the same sale as the return.
    -- Without this, a caller could pass a sale_item_id from a different sale,
    -- causing cross-sale discount calculation and stock corruption.
    IF v_sale_item.sale_id != v_return.sale_id THEN
        RETURN jsonb_build_object(
            'code',    'INVALID_INPUT',
            'message', 'Sale item does not belong to this return''s sale'
        );
    END IF;

    -- Available = original qty minus COMPLETED returns only
    -- (DRAFT quantities don't affect returned_quantity until finalized)
    v_available_qty := v_sale_item.quantity - COALESCE(v_sale_item.returned_quantity, 0);

    IF p_return_quantity > v_available_qty THEN
        RETURN jsonb_build_object(
            'code',    'QUANTITY_EXCEEDS_AVAILABLE',
            'message', format('Quantity %s exceeds available %s', p_return_quantity, v_available_qty)
        );
    END IF;

    -- ── 7. DISCOUNT CALCULATION ────────────────────────────────────────────
    v_item_total       := v_sale_item.unit_price * p_return_quantity;
    v_invoice_discount := calculate_sale_invoice_discount(v_return.sale_id, v_return.sale_discount);

    SELECT *
    INTO v_discount_calc
    FROM calculate_total_discount_share(
        p_return_quantity,
        v_sale_item.quantity,
        COALESCE(v_sale_item.discount_amount, 0),
        v_item_total,
        v_return.sale_subtotal,
        v_invoice_discount
    );

    v_net_refund := ROUND(v_item_total - v_discount_calc.total_discount, 2);

    -- ── 8. UPSERT RETURN ITEM ──────────────────────────────────────────────
    SELECT id INTO v_existing_return_item
    FROM sale_return_items
    WHERE return_id = p_return_id AND sale_item_id = p_sale_item_id;

    IF v_existing_return_item IS NOT NULL THEN
        UPDATE sale_return_items
        SET quantity              = p_return_quantity,
            total_price           = ROUND(v_item_total, 2),
            proportional_discount = ROUND(v_discount_calc.proportional_portion, 2),
            item_discount         = ROUND(v_discount_calc.item_portion, 2),
            net_refund            = v_net_refund,
            updated_at            = NOW() AT TIME ZONE 'Asia/Dhaka'
        WHERE id = v_existing_return_item;
    ELSE
        INSERT INTO sale_return_items (
            id, return_id, sale_item_id, inventory_id, batch_id,
            quantity, unit_price, total_price,
            proportional_discount, item_discount, net_refund,
            created_at
        ) VALUES (
            gen_random_uuid(), p_return_id, p_sale_item_id,
            v_sale_item.inventory_id, v_sale_item.batch_id,
            p_return_quantity, v_sale_item.unit_price,
            ROUND(v_item_total, 2),
            ROUND(v_discount_calc.proportional_portion, 2),
            ROUND(v_discount_calc.item_portion, 2),
            v_net_refund,
            NOW() AT TIME ZONE 'Asia/Dhaka'
        );
    END IF;

    PERFORM recalculate_return_totals(p_return_id);

    RETURN jsonb_build_object('code', 'SUCCESS', 'message', 'Item updated successfully');

EXCEPTION
    WHEN SQLSTATE '55P03' THEN
        RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'System is busy, please try again', 'hint', 'Another operation is in progress');
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'INTERNAL_ERROR', 'message', 'Failed to update return item: ' || SQLERRM);
END;
$$;


ALTER FUNCTION public.add_or_update_return_item(p_return_id uuid, p_sale_item_id uuid, p_return_quantity integer) OWNER TO postgres;

--
-- TOC entry 1076 (class 1255 OID 275103)
-- Name: add_or_update_sale_item(uuid, uuid, integer, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_or_update_sale_item(p_sale_id uuid, p_inventory_id uuid, p_quantity integer, p_item_discount numeric DEFAULT 0) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id        uuid;
    v_sale           RECORD;
    v_inventory      RECORD;
    v_batch          RECORD;       -- best FIFO batch for price display
    v_existing_item  RECORD;
    v_item_id        uuid;
    v_discount       numeric(12,2);
    v_unit_price     numeric(12,2);
    v_total_price    numeric(12,2);
    v_available_stk  integer;
    v_new_subtotal   numeric(12,2);
    v_new_item_disc  numeric(12,2);
    v_new_total      numeric(12,2);
    v_is_update      boolean := false;
BEGIN

    -- ── 1. AUTHENTICATION ─────────────────────────────────────────────────────
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED',
            'message', 'Please log in to continue');
    END IF;

    -- ── 2. INPUT VALIDATION ───────────────────────────────────────────────────
    IF p_sale_id IS NULL THEN
        RETURN jsonb_build_object('code', 'INVALID_INPUT',
            'message', 'Sale ID is required');
    END IF;
    IF p_inventory_id IS NULL THEN
        RETURN jsonb_build_object('code', 'INVALID_INPUT',
            'message', 'Inventory ID is required');
    END IF;
    IF p_quantity IS NULL OR p_quantity <= 0 THEN
        RETURN jsonb_build_object('code', 'INVALID_QUANTITY',
            'message', 'Quantity must be greater than zero');
    END IF;

    v_discount := GREATEST(COALESCE(p_item_discount, 0), 0);

    -- ── 3. LOCK SALE ROW ──────────────────────────────────────────────────────
    SELECT s.id, s.pharmacy_id, s.sale_status,
           s.discount_amount AS sale_discount, s.paid_amount
    INTO   v_sale
    FROM   sales s
    WHERE  s.id = p_sale_id AND s.deleted_at IS NULL
    FOR UPDATE NOWAIT;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'SALE_NOT_FOUND',
            'message', 'Sale not found or has been deleted');
    END IF;
    IF v_sale.sale_status != 'DRAFT' THEN
        RETURN jsonb_build_object('code', 'INVALID_STATUS',
            'message', 'Cannot modify a sale that is not in DRAFT status');
    END IF;

    -- ── 4. PERMISSION CHECK ───────────────────────────────────────────────────
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE  up.user_id    = v_user_id
          AND  up.pharmacy_id = v_sale.pharmacy_id
          AND  up.is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED',
            'message', 'You do not have access to this pharmacy');
    END IF;

    -- ── 5. FETCH INVENTORY WITH LIVE BATCH STOCK ──────────────────────────────
    -- Sellable stock = batches that are ACTIVE, LOW_STOCK, or NEAR_EXPIRY.
    -- Excludes: EXPIRED (date check), DAMAGED, RECALLED, QUARANTINE, RETURNED,
    -- DISPOSED, ARCHIVED, SOLD_OUT (manual/system unsafe statuses).
    -- Mirrors the same filter used in update_stock_summary for full consistency.
    SELECT i.id, i.pharmacy_id, i.type, i.name, i.brand,
           g.name AS generic_name, i.strength,
           i.primary_unit, i.secondary_unit, i.conversion_rate,
           COALESCE(s.total_qty, 0)::integer AS total_stock
    INTO   v_inventory
    FROM   inventory i
    LEFT JOIN inventory_generics g ON i.generic_id = g.id
    LEFT JOIN LATERAL (
        SELECT SUM(ib.current_quantity) AS total_qty
        FROM   inventory_batches ib
        WHERE  ib.inventory_id = i.id
          AND  ib.status       IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY')
          AND  ib.current_quantity > 0
          AND  ib.deleted_at IS NULL
          AND  (ib.expiry_date IS NULL OR ib.expiry_date > CURRENT_DATE)
    ) s ON true
    WHERE  i.id          = p_inventory_id
      AND  i.pharmacy_id = v_sale.pharmacy_id
      AND  i.deleted_at  IS NULL;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'ITEM_NOT_FOUND',
            'message', 'Item not found in this pharmacy inventory');
    END IF;

    -- ── 6. CHECK EXISTING CART ITEM ───────────────────────────────────────────
    SELECT si.id, si.quantity, si.batch_id
    INTO   v_existing_item
    FROM   sale_items si
    WHERE  si.sale_id      = p_sale_id
      AND  si.inventory_id = p_inventory_id;

    v_is_update := v_existing_item.id IS NOT NULL;

    -- ── 7. STOCK VALIDATION (INSERT and UPDATE use identical logic) ───────────
    --
    -- IMPORTANT: Batches are NEVER deducted at cart stage. They are deducted
    -- only when finalize_sale is called. Therefore:
    --   available_stock = SUM(batch.current_quantity)   ← always the true value
    --
    -- DO NOT add v_existing_item.quantity back. The cart quantity has never
    -- been subtracted from batches, so adding it back would overcount and
    -- allow selling beyond actual stock (the bug this fixes).
    --
    v_available_stk := v_inventory.total_stock;

    IF p_quantity > v_available_stk THEN
        RETURN jsonb_build_object(
            'code',    'INSUFFICIENT_STOCK',
            'message', 'Not enough stock available',
            'hint',    format('Available: %s, Requested: %s', v_available_stk, p_quantity),
            'details', jsonb_build_object(
                'available', v_available_stk,
                'requested', p_quantity,
                'item_name', COALESCE(v_inventory.brand, v_inventory.name)
            )
        );
    END IF;

    -- ── 8. SELECT BEST BATCH FOR PRICE DISPLAY (FEFO/FIFO ordering) ──────────
    --
    -- FEFO  → expiry_date ASC NULLS LAST   (nearest-expiry batch sold first;
    --                                        no-expiry items sorted last)
    -- FIFO  → created_at  ASC NULLS LAST   (oldest batch within same expiry group)
    --
    -- This batch_id is stored for display/reference only. finalize_sale runs
    -- its own FIFO loop and may deduct from multiple batches.
    --
    SELECT ib.id, ib.selling_price
    INTO   v_batch
    FROM   inventory_batches ib
    WHERE  ib.inventory_id = p_inventory_id
      AND  ib.status       IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY')
      AND  ib.current_quantity > 0
      AND  ib.deleted_at IS NULL
      AND  (ib.expiry_date IS NULL OR ib.expiry_date > CURRENT_DATE)
    ORDER BY
        ib.expiry_date ASC NULLS LAST,
        ib.created_at  ASC NULLS LAST
    LIMIT 1;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'NO_BATCH_AVAILABLE',
            'message', 'No valid batch available for this item');
    END IF;

    -- ── 9. PRICE CALCULATION ──────────────────────────────────────────────────
    v_unit_price  := COALESCE(v_batch.selling_price, 0);
    v_total_price := ROUND((v_unit_price * p_quantity) - v_discount, 2);
    IF v_total_price < 0 THEN v_total_price := 0; END IF;

    -- ── 10. UPSERT CART ITEM ──────────────────────────────────────────────────
    IF v_is_update THEN
        UPDATE sale_items
        SET quantity        = p_quantity,
            unit_price      = v_unit_price,
            total_price     = v_total_price,
            discount_amount = v_discount,
            item_discount   = v_discount,
            batch_id        = v_batch.id,
            updated_at      = NOW()
        WHERE id = v_existing_item.id;
        v_item_id := v_existing_item.id;
    ELSE
        v_item_id := gen_random_uuid();
        INSERT INTO sale_items (
            id, sale_id, inventory_id, batch_id,
            quantity, unit_price, total_price,
            discount_amount, item_discount,
            returned_quantity, created_at, updated_at
        ) VALUES (
            v_item_id, p_sale_id, p_inventory_id, v_batch.id,
            p_quantity, v_unit_price, v_total_price,
            v_discount, v_discount,
            0, NOW(), NOW()
        );
    END IF;

    -- ── 11. RECALCULATE SALE TOTALS ───────────────────────────────────────────
    --
    -- gross_subtotal  = SUM(quantity × unit_price)     ← before any discounts
    -- total_item_disc = SUM(discount_amount per item)
    -- total_amount    = gross_subtotal − total_item_disc − sale_level_discount
    --
    -- This correctly reflects all discounts in the final charge amount.
    --
    SELECT COALESCE(SUM(si.quantity * si.unit_price), 0),
           COALESCE(SUM(si.discount_amount), 0)
    INTO   v_new_subtotal, v_new_item_disc
    FROM   sale_items si
    WHERE  si.sale_id = p_sale_id;

    v_new_total := ROUND(
        v_new_subtotal
        - v_new_item_disc
        - COALESCE(v_sale.sale_discount, 0),
    2);
    IF v_new_total < 0 THEN v_new_total := 0; END IF;

    UPDATE sales
    SET subtotal           = v_new_subtotal,
        total_amount       = v_new_total,
        outstanding_amount = ROUND(GREATEST(v_new_total - COALESCE(paid_amount, 0), 0), 2),
        updated_at         = NOW()
    WHERE id = p_sale_id;

    -- ── 12. RETURN SUCCESS ────────────────────────────────────────────────────
    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', CASE WHEN v_is_update THEN 'Cart item updated' ELSE 'Item added to cart' END,
        'details', jsonb_build_object(
            'item_id',          v_item_id,
            'inventory_id',     p_inventory_id,
            'inventory_name',   COALESCE(v_inventory.brand, v_inventory.name),
            'inventory_type',   v_inventory.type,
            'quantity',         p_quantity,
            'primary_unit',     v_inventory.primary_unit,
            'unit_price',       v_unit_price,
            'total_price',      v_total_price,
            'primary_batch_id', v_batch.id,
            'sale_totals', jsonb_build_object(
                'subtotal',        v_new_subtotal,
                'discount_amount', COALESCE(v_sale.sale_discount, 0),
                'total_amount',    v_new_total
            )
        )
    );

EXCEPTION
    WHEN lock_not_available THEN
        RETURN jsonb_build_object('code', 'SYSTEM_BUSY',
            'message', 'Sale is being modified by another process. Please try again.');
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'INTERNAL_ERROR',
            'message', 'An unexpected error occurred', 'hint', SQLERRM);
END;
$$;


ALTER FUNCTION public.add_or_update_sale_item(p_sale_id uuid, p_inventory_id uuid, p_quantity integer, p_item_discount numeric) OWNER TO postgres;

--
-- TOC entry 702 (class 1255 OID 256884)
-- Name: adjust_inventory_batch(uuid, jsonb, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.adjust_inventory_batch(p_batch_id uuid, p_adjustments jsonb, p_notes text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$DECLARE
    v_batch RECORD;
    v_inventory_id UUID;
    v_batch_pharmacy_id UUID;
    v_current_quantity INTEGER;
    v_initial_quantity INTEGER;
    v_new_quantity INTEGER;
    v_quantity_change INTEGER := 0;
    v_old_status TEXT;
    v_new_status TEXT;
    v_old_selling_price NUMERIC(12, 2);
    v_new_selling_price NUMERIC(12, 2);
    v_old_purchase_price NUMERIC(12, 2);
    v_new_purchase_price NUMERIC(12, 2);
    v_old_expiry_date DATE;
    v_new_expiry_date DATE;
    v_old_shelf_location TEXT;
    v_new_shelf_location TEXT;
    v_has_changes BOOLEAN := FALSE;
    v_changes_made TEXT[] := ARRAY[]::TEXT[];
    v_adjustment_type TEXT := 'ADJUSTMENT';
    v_current_user_id UUID;
    v_unit_price NUMERIC(12, 2);
    v_total_amount NUMERIC(12, 2);
BEGIN
    -- 1. Authentication
    v_current_user_id := auth.uid();
    IF v_current_user_id IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    -- 2. Input Validation
    IF p_batch_id IS NULL THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Batch ID is required');
    END IF;

    IF p_adjustments IS NULL OR p_adjustments = '{}'::jsonb THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Adjustments are required');
    END IF;

    IF p_notes IS NULL OR TRIM(p_notes) = '' THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Adjustment notes are required');
    END IF;

    -- 3. Lock Batch (NOWAIT for deadlock prevention)
    BEGIN
        SET LOCAL lock_timeout = '5s';

        SELECT ib.*, i.pharmacy_id AS inv_pharmacy_id
        INTO v_batch
        FROM inventory_batches ib
        JOIN inventory i ON i.id = ib.inventory_id
        WHERE ib.id = p_batch_id
          AND ib.deleted_at IS NULL
        FOR UPDATE OF ib NOWAIT;

        IF NOT FOUND THEN
            RETURN json_build_object('code', 'BATCH_NOT_FOUND', 'message', 'Batch not found or deleted');
        END IF;
    EXCEPTION
        WHEN lock_not_available THEN
            RETURN json_build_object('code', 'BATCH_LOCKED', 'message', 'Batch is currently being modified by another user. Please try again.');
    END;

    -- 4. Permission Check
    IF NOT user_has_permission(v_current_user_id, v_batch.inv_pharmacy_id, 'stock.adjust') THEN
        RETURN json_build_object('code', 'PERMISSION_DENIED', 'message', 'You do not have permission to adjust stock');
    END IF;

    -- 5. Capture Current State
    v_inventory_id := v_batch.inventory_id;
    v_batch_pharmacy_id := v_batch.pharmacy_id;
    v_current_quantity := v_batch.current_quantity;
    v_initial_quantity := v_batch.initial_quantity;
    v_old_status := v_batch.status::TEXT;
    v_new_status := v_old_status;
    v_old_selling_price := v_batch.selling_price;
    v_new_selling_price := v_batch.selling_price;
    v_old_purchase_price := v_batch.purchase_price;
    v_new_purchase_price := v_batch.purchase_price;
    v_old_expiry_date := v_batch.expiry_date;
    v_new_expiry_date := v_batch.expiry_date;
    v_old_shelf_location := v_batch.shelf_location;
    v_new_shelf_location := v_batch.shelf_location;
    v_new_quantity := v_current_quantity;

    -- 6. Parse adjustment type
    IF p_adjustments ? 'adjustment_type' AND p_adjustments->>'adjustment_type' IS NOT NULL THEN
        v_adjustment_type := UPPER(TRIM(p_adjustments->>'adjustment_type'));
    END IF;

    -- 6A. Quantity adjustment
    IF p_adjustments ? 'quantity_adjustment' THEN
        BEGIN
            v_quantity_change := (p_adjustments->>'quantity_adjustment')::integer;
        EXCEPTION WHEN OTHERS THEN
            RETURN json_build_object('code', 'INVALID_QUANTITY', 'message', 'Invalid quantity adjustment format. Must be an integer.');
        END;

        IF v_quantity_change != 0 THEN
            v_new_quantity := v_current_quantity + v_quantity_change;

            IF v_new_quantity < 0 THEN
                RETURN json_build_object(
                    'code', 'INSUFFICIENT_QUANTITY',
                    'message', 'Cannot reduce quantity below zero',
                    'details', json_build_object(
                        'current_quantity', v_current_quantity,
                        'adjustment', v_quantity_change,
                        'result', v_new_quantity
                    )
                );
            END IF;

            v_has_changes := TRUE;
            v_changes_made := array_append(v_changes_made,
                format('Quantity: %s -> %s (%s%s)',
                    v_current_quantity, v_new_quantity,
                    CASE WHEN v_quantity_change > 0 THEN '+' ELSE '' END,
                    v_quantity_change
                )
            );
        END IF;
    END IF;

    -- 6B. Status change
    IF p_adjustments ? 'status' AND p_adjustments->>'status' IS NOT NULL THEN
        v_new_status := UPPER(TRIM(p_adjustments->>'status'));

        IF v_new_status NOT IN ('ACTIVE', 'LOW_STOCK', 'RESERVED', 'NEAR_EXPIRY', 'EXPIRED',
                                 'DAMAGED', 'RECALLED', 'QUARANTINE', 'SOLD_OUT', 'RETURNED',
                                 'DISPOSED', 'ARCHIVED') THEN
            RETURN json_build_object('code', 'INVALID_STATUS', 'message', format('Invalid status: %s', v_new_status));
        END IF;

        IF v_new_status != v_old_status THEN
            v_has_changes := TRUE;
            v_changes_made := array_append(v_changes_made, format('Status: %s -> %s', v_old_status, v_new_status));

            INSERT INTO batch_audit_log (batch_id, inventory_id, pharmacy_id, user_id, change_type, field_name, old_value, new_value, notes)
            VALUES (p_batch_id, v_inventory_id, v_batch_pharmacy_id, v_current_user_id, 'status_change', 'status', v_old_status, v_new_status, p_notes);

            -- Map status to transaction type
            IF v_new_status = 'EXPIRED' THEN v_adjustment_type := 'EXPIRED';
            ELSIF v_new_status = 'DAMAGED' THEN v_adjustment_type := 'DAMAGE';
            END IF;
        END IF;
    END IF;

    -- 6C. Selling Price
    IF p_adjustments ? 'selling_price' AND p_adjustments->>'selling_price' IS NOT NULL THEN
        BEGIN
            v_new_selling_price := (p_adjustments->>'selling_price')::NUMERIC(12, 2);
            IF v_new_selling_price < 0 THEN
                RETURN json_build_object('code', 'INVALID_PRICE', 'message', 'Selling price cannot be negative');
            END IF;
            IF v_new_selling_price IS DISTINCT FROM v_old_selling_price THEN
                v_has_changes := TRUE;
                v_changes_made := array_append(v_changes_made, format('Selling price: %s -> %s', COALESCE(v_old_selling_price, 0), v_new_selling_price));
                INSERT INTO batch_audit_log (batch_id, inventory_id, pharmacy_id, user_id, change_type, field_name, old_value, new_value, notes)
                VALUES (p_batch_id, v_inventory_id, v_batch_pharmacy_id, v_current_user_id, 'price_update', 'selling_price', v_old_selling_price::text, v_new_selling_price::text, p_notes);
            END IF;
        EXCEPTION WHEN OTHERS THEN
            RETURN json_build_object('code', 'INVALID_PRICE', 'message', 'Invalid selling price format');
        END;
    END IF;

    -- 6D. Purchase Price
    IF p_adjustments ? 'purchase_price' AND p_adjustments->>'purchase_price' IS NOT NULL THEN
        BEGIN
            v_new_purchase_price := (p_adjustments->>'purchase_price')::NUMERIC(12, 2);
            IF v_new_purchase_price < 0 THEN
                RETURN json_build_object('code', 'INVALID_PRICE', 'message', 'Purchase price cannot be negative');
            END IF;
            IF v_new_purchase_price IS DISTINCT FROM v_old_purchase_price THEN
                v_has_changes := TRUE;
                v_changes_made := array_append(v_changes_made, format('Purchase price: %s -> %s', COALESCE(v_old_purchase_price, 0), v_new_purchase_price));
                INSERT INTO batch_audit_log (batch_id, inventory_id, pharmacy_id, user_id, change_type, field_name, old_value, new_value, notes)
                VALUES (p_batch_id, v_inventory_id, v_batch_pharmacy_id, v_current_user_id, 'price_update', 'purchase_price', v_old_purchase_price::text, v_new_purchase_price::text, p_notes);
            END IF;
        EXCEPTION WHEN OTHERS THEN
            RETURN json_build_object('code', 'INVALID_PRICE', 'message', 'Invalid purchase price format');
        END;
    END IF;

    -- 6E. Expiry Date
    IF p_adjustments ? 'expiry_date' AND p_adjustments->>'expiry_date' IS NOT NULL THEN
        BEGIN
            v_new_expiry_date := (p_adjustments->>'expiry_date')::DATE;
            IF v_new_expiry_date IS DISTINCT FROM v_old_expiry_date THEN
                v_has_changes := TRUE;
                v_changes_made := array_append(v_changes_made, format('Expiry: %s -> %s', COALESCE(v_old_expiry_date::text, 'N/A'), v_new_expiry_date::text));
                INSERT INTO batch_audit_log (batch_id, inventory_id, pharmacy_id, user_id, change_type, field_name, old_value, new_value, notes)
                VALUES (p_batch_id, v_inventory_id, v_batch_pharmacy_id, v_current_user_id, 'expiry_update', 'expiry_date', v_old_expiry_date::text, v_new_expiry_date::text, p_notes);
            END IF;
        EXCEPTION WHEN OTHERS THEN
            RETURN json_build_object('code', 'INVALID_DATE', 'message', 'Invalid expiry date format. Use YYYY-MM-DD.');
        END;
    END IF;

    -- 6F. Shelf Location
    IF p_adjustments ? 'shelf_location' THEN
        v_new_shelf_location := NULLIF(TRIM(p_adjustments->>'shelf_location'), '');
        IF v_new_shelf_location IS DISTINCT FROM v_old_shelf_location THEN
            v_has_changes := TRUE;
            v_changes_made := array_append(v_changes_made, format('Shelf: %s -> %s', COALESCE(v_old_shelf_location, 'N/A'), COALESCE(v_new_shelf_location, 'N/A')));
            INSERT INTO batch_audit_log (batch_id, inventory_id, pharmacy_id, user_id, change_type, field_name, old_value, new_value, notes)
            VALUES (p_batch_id, v_inventory_id, v_batch_pharmacy_id, v_current_user_id, 'location_change', 'shelf_location', v_old_shelf_location, v_new_shelf_location, p_notes);
        END IF;
    END IF;

    -- 7. No changes bail-out
    IF NOT v_has_changes THEN
        RETURN json_build_object('code', 'NO_CHANGES', 'message', 'No changes were made');
    END IF;

    -- 8. Apply batch update (SINGLE unified UPDATE)
    -- initial_quantity increases only on positive quantity adjustments
    UPDATE inventory_batches
    SET current_quantity = v_new_quantity,
        initial_quantity = CASE WHEN v_quantity_change > 0 THEN v_initial_quantity + v_quantity_change ELSE initial_quantity END,
        selling_price = v_new_selling_price,
        purchase_price = v_new_purchase_price,
        expiry_date = v_new_expiry_date,
        shelf_location = v_new_shelf_location,
        status = v_new_status::batch_status_enum,
        updated_at = NOW() AT TIME ZONE 'Asia/Dhaka'
    WHERE id = p_batch_id;

    -- 9. Log stock transaction (if quantity changed)
    IF v_quantity_change != 0 THEN
        v_unit_price := COALESCE(v_new_purchase_price, 0);
        v_total_amount := ABS(v_quantity_change) * v_unit_price;

        INSERT INTO stock_transactions (
            id, pharmacy_id, inventory_id, batch_id,
            transaction_type, quantity_change, quantity_before, quantity_after,
            unit_price, total_amount,
            reference_id, reference_number, user_id, notes, created_at
        ) VALUES (
            gen_random_uuid(),
            v_batch_pharmacy_id, v_inventory_id, p_batch_id,
            v_adjustment_type::transaction_type_enum,
            v_quantity_change, v_current_quantity, v_new_quantity,
            v_unit_price, v_total_amount,
            NULL, NULL, v_current_user_id,
            COALESCE(p_notes, format('Batch adjustment: %s', array_to_string(v_changes_made, ', '))),
            NOW() AT TIME ZONE 'Asia/Dhaka'
        );
    END IF;

    -- NOTE: update_stock_summary() is NOT called here because
    -- the trigger on inventory_batches already handles it.
    -- This eliminates the redundant triple-computation that was happening before.

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Batch adjusted successfully',
        'details', json_build_object(
            'batch_id', p_batch_id,
            'changes_made', v_changes_made,
            'quantity_change', v_quantity_change,
            'new_quantity', v_new_quantity,
            'initial_quantity_updated', v_quantity_change > 0
        )
    );

EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object(
        'code', 'INTERNAL_ERROR',
        'message', SQLERRM,
        'hint', 'Contact system administrator',
        'details', json_build_object('sqlstate', SQLSTATE)
    );
END;$$;


ALTER FUNCTION public.adjust_inventory_batch(p_batch_id uuid, p_adjustments jsonb, p_notes text) OWNER TO postgres;

--
-- TOC entry 7173 (class 0 OID 0)
-- Dependencies: 702
-- Name: FUNCTION adjust_inventory_batch(p_batch_id uuid, p_adjustments jsonb, p_notes text); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.adjust_inventory_batch(p_batch_id uuid, p_adjustments jsonb, p_notes text) IS 'Production-grade batch adjustment: validates inputs, uses NOWAIT locking,
logs to stock_transactions and batch_audit_log. Single UPDATE statement.
Relies on trigger for stock_summary refresh (no redundant explicit call).';


--
-- TOC entry 997 (class 1255 OID 229097)
-- Name: apply_sale_discount(uuid, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.apply_sale_discount(p_sale_id uuid, p_discount_amount numeric) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id            UUID;
    v_sale               RECORD;
    v_item_discounts     NUMERIC(12,2);
    v_new_total          NUMERIC(12,2);
BEGIN
    v_user_id := auth.uid();

    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated'
        );
    END IF;

    -- Lock the sale to prevent concurrent edits
    SELECT *
    INTO   v_sale
    FROM   sales
    WHERE  id         = p_sale_id
    AND    deleted_at IS NULL
    FOR UPDATE NOWAIT;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'code', 'SALE_NOT_FOUND',
            'message', 'Sale not found'
        );
    END IF;

    IF v_sale.sale_status::text != 'DRAFT' THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_STATUS',
            'message', 'Cannot modify a sale that is not in DRAFT status'
        );
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies pu
        WHERE  pu.user_id    = v_user_id
        AND    pu.pharmacy_id = v_sale.pharmacy_id
        AND    pu.is_active   = true
    ) THEN
        RETURN jsonb_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'Permission denied'
        );
    END IF;

    IF COALESCE(p_discount_amount, 0) < 0 THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_DISCOUNT',
            'message', 'Discount cannot be negative'
        );
    END IF;

    IF COALESCE(p_discount_amount, 0) > v_sale.subtotal THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_DISCOUNT',
            'message', 'Sale-level discount cannot exceed the gross subtotal'
        );
    END IF;

    -- ── BUG-7 FIX: account for per-item discounts already stored in sale_items ─
    --   total_amount = gross_subtotal − SUM(item_discounts) − sale_discount
    --   v_sale.subtotal is the gross (SUM qty × unit_price), unchanged by BUG-4.
    SELECT COALESCE(SUM(discount_amount), 0)
    INTO   v_item_discounts
    FROM   sale_items
    WHERE  sale_id = p_sale_id;

    v_new_total := ROUND(
        v_sale.subtotal
        - v_item_discounts
        - COALESCE(p_discount_amount, 0),
    2);

    -- Guard: total must not go negative
    v_new_total := GREATEST(v_new_total, 0);

    UPDATE sales
    SET discount_amount    = COALESCE(p_discount_amount, 0),
        total_amount       = v_new_total,
        outstanding_amount = ROUND(v_new_total - COALESCE(paid_amount, 0), 2),
        updated_at         = NOW()
    WHERE id = p_sale_id;

    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Discount applied',
        'details', jsonb_build_object(
            'subtotal',          v_sale.subtotal,
            'item_discounts',    v_item_discounts,
            'discount_amount',   COALESCE(p_discount_amount, 0),
            'total_amount',      v_new_total,
            'discount_percentage', CASE
                WHEN v_sale.subtotal > 0
                THEN ROUND((COALESCE(p_discount_amount, 0) / v_sale.subtotal) * 100, 2)
                ELSE 0
            END
        )
    );

EXCEPTION
    WHEN SQLSTATE '55P03' THEN
        RETURN jsonb_build_object(
            'code',    'SYSTEM_BUSY',
            'message', 'System is busy, please try again',
            'hint',    'Another operation is in progress'
        );
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'code',    'INTERNAL_ERROR',
            'message', SQLERRM
        );
END;
$$;


ALTER FUNCTION public.apply_sale_discount(p_sale_id uuid, p_discount_amount numeric) OWNER TO postgres;

--
-- TOC entry 1040 (class 1255 OID 267433)
-- Name: archive_old_records(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.archive_old_records(p_retention_days integer DEFAULT 90) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_cutoff_date TIMESTAMPTZ;
    v_st_count INTEGER := 0;
    v_al_count INTEGER := 0;
BEGIN
    -- Validate retention period (minimum 30 days)
    IF p_retention_days < 30 THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Retention period must be at least 30 days'
        );
    END IF;

    v_cutoff_date := (NOW() AT TIME ZONE 'Asia/Dhaka') - (p_retention_days || ' days')::INTERVAL;

    -- Archive stock_transactions older than cutoff
    WITH moved AS (
        DELETE FROM public.stock_transactions
        WHERE created_at < v_cutoff_date
          AND deleted_at IS NULL
        RETURNING *
    )
    INSERT INTO public.stock_transactions_archive (
        id, pharmacy_id, inventory_id, batch_id, transaction_type,
        quantity_change, quantity_before, quantity_after, unit_price,
        total_amount, reference_id, reference_number, user_id,
        notes, created_at, deleted_at
    )
    SELECT
        id, pharmacy_id, inventory_id, batch_id, transaction_type,
        quantity_change, quantity_before, quantity_after, unit_price,
        total_amount, reference_id, reference_number, user_id,
        notes, created_at, deleted_at
    FROM moved;

    GET DIAGNOSTICS v_st_count = ROW_COUNT;

    -- Archive activity_logs older than cutoff
    WITH moved AS (
        DELETE FROM public.activity_logs
        WHERE created_at < v_cutoff_date
        RETURNING *
    )
    INSERT INTO public.activity_logs_archive (
        id, pharmacy_id, entity_id, activity_type, message, metadata, created_at
    )
    SELECT
        id, pharmacy_id, entity_id, activity_type, message, metadata, created_at
    FROM moved;

    GET DIAGNOSTICS v_al_count = ROW_COUNT;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', format('Archived %s stock transactions and %s activity logs', v_st_count, v_al_count),
        'details', json_build_object(
            'stock_transactions_archived', v_st_count,
            'activity_logs_archived', v_al_count,
            'cutoff_date', v_cutoff_date::text,
            'retention_days', p_retention_days
        )
    );

EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object(
        'code', 'ARCHIVE_ERROR',
        'message', 'Failed to archive old records',
        'details', json_build_object(
            'error', SQLERRM,
            'sqlstate', SQLSTATE
        )
    );
END;
$$;


ALTER FUNCTION public.archive_old_records(p_retention_days integer) OWNER TO postgres;

