--
-- TOC entry 1321 (class 1255 OID 194606)
-- Name: auto_update_batch_status(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.auto_update_batch_status() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_today DATE;
BEGIN
    -- 1. Preserve manual statuses (never auto-override these)
    -- Added EXPIRED, SOLD_OUT, LOW_STOCK, and NEAR_EXPIRY to this list 
    -- to allow manual overrides from the adjustment RPC.
    IF NEW.status IN (
        'DAMAGED', 'RECALLED', 'QUARANTINE', 'RETURNED', 
        'DISPOSED', 'ARCHIVED', 'EXPIRED', 'SOLD_OUT', 
        'LOW_STOCK', 'NEAR_EXPIRY'
    ) THEN
        RETURN NEW;
    END IF;

    -- 2. Zero or NULL quantity = SOLD_OUT (takes priority over expiry)
    IF COALESCE(NEW.current_quantity, 0) = 0 THEN
        NEW.status := 'SOLD_OUT';
        RETURN NEW;
    END IF;

    -- 3. Expiry-based status for items with expiry dates
    IF NEW.expiry_date IS NOT NULL THEN
        v_today := (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE;

        IF NEW.expiry_date <= v_today THEN
            NEW.status := 'EXPIRED';
        ELSIF NEW.expiry_date <= v_today + INTERVAL '30 days' THEN
            NEW.status := 'NEAR_EXPIRY';
        ELSE
            NEW.status := 'ACTIVE';
        END IF;
    ELSE
        -- 4. Non-expiry items: ACTIVE if quantity > 0
        NEW.status := 'ACTIVE';
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.auto_update_batch_status() OWNER TO postgres;

