-- Name: FUNCTION auto_update_batch_status(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.auto_update_batch_status() IS 'BEFORE trigger: Auto-sets batch status based on quantity and expiry date.
Manual statuses (DAMAGED, RECALLED, etc.) are never overridden.
Zero quantity always becomes SOLD_OUT regardless of expiry.';


--
-- TOC entry 743 (class 1255 OID 88169)
-- Name: bulk_global_inventory_add_data_from_python(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.bulk_global_inventory_add_data_from_python() RETURNS TABLE(inserted_count integer, duplicate_count integer, error_count integer, total_processed integer, details json)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_record record;
  v_result json;
  v_success_count integer := 0;
  v_duplicate_count integer := 0;
  v_error_count integer := 0;
  v_details json := '[]'::json;
  v_temp_result json;
BEGIN
  FOR v_record IN 
    SELECT category, name, brand, generic_name, strength, base_unit, manufacturer, item_code,
           CASE WHEN unit_per_strip = 'N/A' OR unit_per_strip = '' OR unit_per_strip IS NULL 
                THEN 1 
                ELSE unit_per_strip::smallint END as unit_per_strip_int
    FROM temp_scraped_medicines
    WHERE category != 'N/A' AND name != 'N/A' AND strength != 'N/A' AND item_code != 'N/A'
  LOOP
    SELECT global_inventory_add_data_from_python(
      v_record.category,
      v_record.name,
      v_record.brand,
      v_record.generic_name,
      v_record.strength,
      v_record.base_unit,
      v_record.manufacturer,
      v_record.item_code,
      v_record.unit_per_strip_int
    ) INTO v_result;

    v_temp_result := json_build_object(
      'name', v_record.name,
      'brand', v_record.brand,
      'item_code', v_record.item_code,
      'status', CASE 
        WHEN (v_result->>'success')::boolean = true THEN 'SUCCESS'
        WHEN (v_result->>'duplicate')::boolean = true THEN 'DUPLICATE'
        ELSE 'ERROR'
      END,
      'message', v_result->>'message'
    );

    v_details := v_details || v_temp_result::json;

    IF (v_result->>'success')::boolean = true THEN
      v_success_count := v_success_count + 1;
    ELSIF (v_result->>'duplicate')::boolean = true THEN
      v_duplicate_count := v_duplicate_count + 1;
    ELSE
      v_error_count := v_error_count + 1;
    END IF;
  END LOOP;

  RETURN QUERY SELECT 
    v_success_count,
    v_duplicate_count,
    v_error_count,
    v_success_count + v_duplicate_count + v_error_count,
    v_details;
END;
$$;


ALTER FUNCTION public.bulk_global_inventory_add_data_from_python() OWNER TO postgres;

--
-- TOC entry 1119 (class 1255 OID 226302)
-- Name: calculate_refund_breakdown(numeric, numeric, numeric, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.calculate_refund_breakdown(p_sale_total numeric, p_sale_paid numeric, p_sale_outstanding numeric, p_return_value numeric, p_previous_cash_refunded numeric DEFAULT 0, p_previous_credit_adjusted numeric DEFAULT 0) RETURNS TABLE(credit_adjustment numeric, cash_refund numeric, is_credit_only boolean)
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_remaining_outstanding DECIMAL;
    v_remaining_refundable DECIMAL;
    v_credit_adj DECIMAL;
    v_cash_ref DECIMAL;
BEGIN
    -- AUDIT FIX: Use passed outstanding directly as it represents current debt state
    v_remaining_outstanding := GREATEST(0, p_sale_outstanding);
    
    -- Refundable cash is total paid minus what we already gave back
    v_remaining_refundable := GREATEST(0, p_sale_paid - p_previous_cash_refunded);

    -- Step 1: Return value first reduces outstanding due (credit adjustment)
    v_credit_adj := LEAST(p_return_value, v_remaining_outstanding);

    -- Step 2: Remaining return value after credit adjustment = potential cash refund
    -- Step 3: Cash refund cannot exceed what customer has paid (minus previous refunds)
    v_cash_ref := LEAST(p_return_value - v_credit_adj, v_remaining_refundable);

    RETURN QUERY SELECT
        ROUND(v_credit_adj, 2),
        ROUND(v_cash_ref, 2),
        (v_cash_ref = 0 AND v_credit_adj > 0);
END;
$$;


ALTER FUNCTION public.calculate_refund_breakdown(p_sale_total numeric, p_sale_paid numeric, p_sale_outstanding numeric, p_return_value numeric, p_previous_cash_refunded numeric, p_previous_credit_adjusted numeric) OWNER TO postgres;

--
-- TOC entry 1475 (class 1255 OID 226782)
-- Name: calculate_sale_invoice_discount(uuid, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.calculate_sale_invoice_discount(p_sale_id uuid, p_total_sale_discount numeric) RETURNS numeric
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_item_discounts DECIMAL;
BEGIN
    SELECT COALESCE(SUM(discount_amount), 0) INTO v_item_discounts
    FROM sale_items 
    WHERE sale_id = p_sale_id;
    
    RETURN GREATEST(0, p_total_sale_discount - v_item_discounts);
END;
$$;


ALTER FUNCTION public.calculate_sale_invoice_discount(p_sale_id uuid, p_total_sale_discount numeric) OWNER TO postgres;

--
-- TOC entry 1149 (class 1255 OID 226761)
-- Name: calculate_total_discount_share(integer, integer, numeric, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.calculate_total_discount_share(p_item_return_qty integer, p_item_total_qty integer, p_item_total_discount numeric, p_item_return_price numeric, p_sale_subtotal numeric, p_sale_invoice_discount numeric) RETURNS TABLE(total_discount numeric, item_portion numeric, proportional_portion numeric)
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_item_portion DECIMAL := 0;
    v_proportional_portion DECIMAL := 0;
BEGIN
    -- 1. Calculate Item-Specific Discount Portion
    IF p_item_total_qty > 0 AND p_item_total_discount > 0 THEN
        v_item_portion := ROUND((p_item_return_qty::DECIMAL / p_item_total_qty::DECIMAL) * p_item_total_discount, 2);
    END IF;

    -- 2. Calculate Proportional Invoice Discount
    -- Base logic: (Item Total Return Value / Sale Subtotal) * Invoice Discount
    IF p_sale_subtotal > 0 AND p_sale_invoice_discount > 0 THEN
        v_proportional_portion := ROUND((p_item_return_price / p_sale_subtotal) * p_sale_invoice_discount, 2);
    END IF;

    RETURN QUERY SELECT
        (v_item_portion + v_proportional_portion),
        v_item_portion,
        v_proportional_portion;
END;
$$;


ALTER FUNCTION public.calculate_total_discount_share(p_item_return_qty integer, p_item_total_qty integer, p_item_total_discount numeric, p_item_return_price numeric, p_sale_subtotal numeric, p_sale_invoice_discount numeric) OWNER TO postgres;

--
-- TOC entry 1199 (class 1255 OID 276770)
-- Name: cancel_purchase(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.cancel_purchase(p_purchase_id uuid, p_notes text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id UUID;
    v_pharmacy_id UUID;
    v_status purchase_status_enum;
    v_item RECORD;
BEGIN
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated'); END IF;

    SELECT pharmacy_id, purchase_status INTO v_pharmacy_id, v_status
    FROM public.purchases WHERE id = p_purchase_id;

    IF NOT FOUND THEN RETURN json_build_object('code', 'NOT_FOUND', 'message', 'Purchase not found'); END IF;

    -- (Permission check removed as requested)

    IF v_status IN ('RETURNED', 'PARTIALLY_RETURNED') THEN
        RETURN json_build_object('code', 'INVALID_STATE', 'message', 'Cannot cancel a purchase that has active returns. Please continue using the Return flow.');
    END IF;
    IF v_status = 'CANCELLED' THEN
        RETURN json_build_object('code', 'INVALID_STATE', 'message', 'Purchase is already cancelled.');
    END IF;

    -- Pre-flight verify that all items are perfectly intact (no outbound sales/adjustments/returns made yet!)
    FOR v_item IN (
        SELECT b.id AS batch_id, b.current_quantity, b.initial_quantity, i.name as item_name 
        FROM public.inventory_batches b
        JOIN public.inventory i ON b.inventory_id = i.id
        WHERE b.purchase_id = p_purchase_id
          AND b.deleted_at IS NULL
    ) LOOP
        -- 1. Check if any stock has been physically depleted
        IF v_item.current_quantity < v_item.initial_quantity THEN
            RETURN json_build_object('code', 'INVALID_STATE', 'message', 'Cannot cancel purchase: Stock for ' || v_item.item_name || ' has already been sold or moved.');
        END IF;

        -- 2. Check stock_transactions for ANY activity other than the initial PURCHASE
        -- This ensures we don't cancel if there were adjustments or logic tied to these batches.
        IF EXISTS (
            SELECT 1 FROM public.stock_transactions 
            WHERE batch_id = v_item.batch_id 
              AND transaction_type != 'PURCHASE'
              AND deleted_at IS NULL
        ) THEN
            RETURN json_build_object('code', 'INVALID_STATE', 'message', 'Cannot cancel purchase: ' || v_item.item_name || ' has existing sales or adjustments linked to this purchase batch.');
        END IF;
    END LOOP;

    -- Apply inventory revocation
    FOR v_item IN (
        SELECT b.id AS batch_id, b.inventory_id, b.initial_quantity, b.current_quantity
        FROM public.inventory_batches b
        WHERE b.purchase_id = p_purchase_id
          AND b.deleted_at IS NULL
    ) LOOP
        -- Subtract stock
        UPDATE public.inventory_batches
        SET current_quantity = current_quantity - v_item.initial_quantity,
            updated_at = NOW()
        WHERE id = v_item.batch_id;

        -- (Activity logging is handled automatically via the trigger on stock_transactions insert below)

        -- Record Transaction for history
        INSERT INTO public.stock_transactions (
            id, pharmacy_id, inventory_id, batch_id,
            transaction_type, quantity_change, quantity_before, quantity_after,
            reference_id, reference_number, user_id, notes, created_at
        )
        SELECT 
            gen_random_uuid(), v_pharmacy_id, v_item.inventory_id, v_item.batch_id,
            'ADJUSTMENT', -v_item.initial_quantity, v_item.current_quantity, v_item.current_quantity - v_item.initial_quantity,
            p_purchase_id, (SELECT purchase_number FROM public.purchases WHERE id = p_purchase_id), v_user_id,
            'Purchase cancellation reversal', NOW();
            
        -- Update stock summary
        PERFORM public.update_stock_summary(v_item.inventory_id);
    END LOOP;
    
    -- Soft delete the batches linked to this purchase so they don't show up in search anymore
    UPDATE public.inventory_batches
    SET deleted_at = NOW(),
        status = 'ARCHIVED'
    WHERE purchase_id = p_purchase_id;

    -- Delete payments and credits associated with this purchase
    DELETE FROM public.purchase_payments WHERE purchase_id = p_purchase_id;
    
    -- Cleanup supplier credits and their payments
    DELETE FROM public.supplier_credit_payments WHERE supplier_credit_id IN (
        SELECT id FROM public.supplier_credits WHERE purchase_id = p_purchase_id
    );
    DELETE FROM public.supplier_credits WHERE purchase_id = p_purchase_id;

    -- Update purchase record
    UPDATE public.purchases
    SET purchase_status = 'CANCELLED',
        payment_status = 'UNPAID',
        notes = CASE WHEN p_notes IS NOT NULL THEN COALESCE(notes || CHR(10), '') || 'Cancelled: ' || p_notes ELSE COALESCE(notes || CHR(10), '') || 'Cancelled on ' || NOW() END,
        updated_at = NOW()
    WHERE id = p_purchase_id;

    RETURN json_build_object('code', 'SUCCESS', 'message', 'Purchase cancelled successfully');
END;
$$;


ALTER FUNCTION public.cancel_purchase(p_purchase_id uuid, p_notes text) OWNER TO postgres;

--
-- TOC entry 636 (class 1255 OID 144357)
-- Name: cancel_purchase(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.cancel_purchase(p_purchase_id uuid, p_user_id uuid, p_reason text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_purchase        RECORD;
    v_items_deleted   INT;
    v_current_user_id UUID;
BEGIN
    v_current_user_id := auth.uid();
    IF v_current_user_id IS NULL THEN
        RETURN json_build_object(
            'code',    'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint',    'Please sign in to cancel purchase',
            'details', NULL
        );
    END IF;

    SELECT * INTO v_purchase
    FROM purchases
    WHERE id = p_purchase_id
      AND deleted_at IS NULL
    FOR UPDATE NOWAIT;

    IF NOT FOUND THEN
        RETURN json_build_object(
            'code',    'PURCHASE_NOT_FOUND',
            'message', 'Purchase not found',
            'hint',    NULL,
            'details', NULL
        );
    END IF;

    -- [BUG-PR-3] Verify caller belongs to the pharmacy that owns this purchase.
    IF NOT EXISTS (
        SELECT 1
        FROM user_pharmacies
        WHERE user_id    = v_current_user_id
          AND pharmacy_id = v_purchase.pharmacy_id
          AND is_active   = true
    ) THEN
        RETURN json_build_object(
            'code',    'PERMISSION_DENIED',
            'message', 'You do not have permission to cancel this purchase',
            'hint',    NULL,
            'details', NULL
        );
    END IF;

    IF v_purchase.purchase_status = 'CANCELLED' THEN
        RETURN json_build_object(
            'code',    'ALREADY_CANCELLED',
            'message', 'Purchase already cancelled',
            'hint',    NULL,
            'details', NULL
        );
    END IF;

    IF v_purchase.purchase_status != 'DRAFT' THEN
        RETURN json_build_object(
            'code',    'INVALID_STATUS',
            'message', 'Only draft purchases can be cancelled',
            'hint',    'Use return process for completed purchases',
            'details', json_build_object('current_status', v_purchase.purchase_status)
        );
    END IF;

    DELETE FROM purchase_items WHERE purchase_id = p_purchase_id;
    GET DIAGNOSTICS v_items_deleted = ROW_COUNT;

    UPDATE purchases
    SET purchase_status    = 'CANCELLED',
        notes              = CASE
                                 WHEN p_reason IS NOT NULL AND p_reason <> '' THEN
                                     COALESCE(notes || ' | ', '') || 'Cancelled: ' || p_reason
                                 ELSE notes
                             END,
        subtotal           = 0,
        total_amount       = 0,
        outstanding_amount = 0,
        updated_at         = NOW() AT TIME ZONE 'Asia/Dhaka'
    WHERE id = p_purchase_id;

    INSERT INTO activity_logs (
        pharmacy_id, entity_id, activity_type, message, metadata, created_at
    ) VALUES (
        v_purchase.pharmacy_id,
        p_purchase_id,
        'PURCHASE',
        'Purchase #' || COALESCE(v_purchase.purchase_number, 'N/A') ||
            ' cancelled' ||
            CASE WHEN p_reason IS NOT NULL AND p_reason <> '' THEN ': ' || p_reason ELSE '' END,
        jsonb_build_object(
            'action',          'CANCELLED',
            'purchase_number', COALESCE(v_purchase.purchase_number, ''),
            'amount',          COALESCE(v_purchase.total_amount, 0),
            'items_removed',   v_items_deleted,
            'cancelled_by',    COALESCE(p_user_id, v_current_user_id),
            'reason',          COALESCE(p_reason, '')
        ),
        NOW() AT TIME ZONE 'Asia/Dhaka'
    );

    RETURN json_build_object(
        'code',    'SUCCESS',
        'message', 'Purchase cancelled successfully',
        'hint',    NULL,
        'details', json_build_object(
            'purchase_id',     p_purchase_id,
            'purchase_number', v_purchase.purchase_number,
            'items_removed',   v_items_deleted
        )
    );

EXCEPTION
    WHEN lock_not_available THEN
        RETURN json_build_object(
            'code',    'SYSTEM_BUSY',
            'message', 'Purchase is being modified by another request',
            'hint',    'Please try again in a moment',
            'details', NULL
        );
    WHEN OTHERS THEN
        RETURN json_build_object(
            'code',    'INTERNAL_ERROR',
            'message', SQLERRM,
            'hint',    NULL,
            'details', NULL
        );
END;
$$;


ALTER FUNCTION public.cancel_purchase(p_purchase_id uuid, p_user_id uuid, p_reason text) OWNER TO postgres;

--
-- TOC entry 683 (class 1255 OID 276769)
