--

CREATE FUNCTION public.cancel_sale(p_sale_id uuid, p_notes text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id UUID;
    v_pharmacy_id UUID;
    v_status sale_status_enum;
    v_item RECORD;
BEGIN
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated'); END IF;

    SELECT pharmacy_id, sale_status INTO v_pharmacy_id, v_status
    FROM public.sales WHERE id = p_sale_id;

    IF NOT FOUND THEN RETURN json_build_object('code', 'NOT_FOUND', 'message', 'Sale not found'); END IF;
    
    -- (Permission check removed as requested)

    IF v_status IN ('RETURNED', 'PARTIALLY_RETURNED') THEN
        RETURN json_build_object('code', 'INVALID_STATE', 'message', 'Cannot cancel a sale that has return records. Please continue using the Return flow.');
    END IF;
    IF v_status = 'CANCELLED' THEN
        RETURN json_build_object('code', 'INVALID_STATE', 'message', 'Sale is already cancelled.');
    END IF;

    -- Update inventory batches and log activity
    FOR v_item IN (SELECT * FROM public.sale_items WHERE sale_id = p_sale_id) LOOP
        -- Revert stock
        UPDATE public.inventory_batches
        SET current_quantity = current_quantity + v_item.quantity,
            updated_at = NOW()
        WHERE id = v_item.batch_id;

        -- Record Transaction for history (this automatically triggers activity logging via log_stock_activity)
        INSERT INTO public.stock_transactions (
            id, pharmacy_id, inventory_id, batch_id,
            transaction_type, quantity_change, quantity_before, quantity_after,
            reference_id, reference_number, user_id, notes, created_at
        )
        SELECT 
            gen_random_uuid(), v_pharmacy_id, v_item.inventory_id, v_item.batch_id,
            'ADJUSTMENT', v_item.quantity, current_quantity - v_item.quantity, current_quantity, 
            p_sale_id, (SELECT sale_number FROM public.sales WHERE id = p_sale_id), v_user_id,
            'Sale cancellation reversal' || CASE WHEN p_notes IS NOT NULL THEN ': ' || p_notes ELSE '' END, NOW();
    END LOOP;

    -- Delete payments tied to this sale
    DELETE FROM public.sale_payments WHERE sale_id = p_sale_id;

    -- Update the sale record
    UPDATE public.sales
    SET sale_status = 'CANCELLED',
        payment_status = 'UNPAID',
        notes = CASE WHEN p_notes IS NOT NULL THEN COALESCE(notes || CHR(10), '') || 'Cancelled: ' || p_notes ELSE COALESCE(notes || CHR(10), '') || 'Cancelled on ' || NOW() END,
        updated_at = NOW()
    WHERE id = p_sale_id;

    RETURN json_build_object('code', 'SUCCESS', 'message', 'Sale cancelled successfully');
END;
$$;


ALTER FUNCTION public.cancel_sale(p_sale_id uuid, p_notes text) OWNER TO postgres;

--
-- TOC entry 1503 (class 1255 OID 274528)
-- Name: create_generic(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_generic(p_name text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_trimmed TEXT;
    v_id UUID;
    v_existing_name TEXT;
BEGIN
    IF auth.uid() IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'Authentication required');
    END IF;

    v_trimmed := TRIM(COALESCE(p_name, ''));
    IF v_trimmed = '' THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Name is required');
    END IF;

    -- Concurrency-safe upsert: INSERT ... ON CONFLICT returns existing
    INSERT INTO public.inventory_generics (name)
    VALUES (v_trimmed)
    ON CONFLICT (lower(btrim(name))) DO UPDATE SET name = inventory_generics.name
    RETURNING id, name INTO v_id, v_existing_name;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Generic created',
        'details', json_build_object('id', v_id, 'name', v_existing_name)
    );
EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object('code', 'ERROR', 'message', SQLERRM);
END;
$$;


ALTER FUNCTION public.create_generic(p_name text) OWNER TO postgres;

