--
-- TOC entry 1248 (class 1255 OID 97209)
-- Name: delete_customer(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_customer(p_customer_id uuid, p_pharmacy_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$BEGIN
    IF p_customer_id IS NULL THEN
        RAISE EXCEPTION 'customer_id cannot be null';
    END IF;
    
    IF p_pharmacy_id IS NULL THEN
        RAISE EXCEPTION 'pharmacy_id cannot be null';
    END IF;

    UPDATE customers 
    SET 
        is_deleted = true,
        deleted_at = NOW(),
        updated_at = NOW()
    WHERE id = p_customer_id 
    AND pharmacy_id = p_pharmacy_id 
    AND is_deleted = false;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Customer not found or already deleted';
    END IF;
    
    RETURN true;
END;$$;


ALTER FUNCTION public.delete_customer(p_customer_id uuid, p_pharmacy_id uuid) OWNER TO postgres;

--
-- TOC entry 555 (class 1255 OID 242085)
-- Name: delete_inventory_item(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_inventory_item(p_pharmacy_id uuid, p_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$DECLARE
    v_current_user_id UUID;
BEGIN
    v_current_user_id := auth.uid();
    
    IF v_current_user_id IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    IF NOT user_has_permission(v_current_user_id, p_pharmacy_id, 'inventory.delete') THEN
        RETURN json_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied');
    END IF;

    UPDATE public.inventory
    SET deleted_at = (now() AT TIME ZONE 'Asia/Dhaka')
    WHERE id = p_id AND pharmacy_id = p_pharmacy_id;

    IF FOUND THEN
        RETURN json_build_object(
            'code', 'SUCCESS', 
            'message', 'Inventory deleted',
            'hint', 'The item has been marked as deleted',
            'details', json_build_object('id', p_id)
        );
    ELSE
         RETURN json_build_object(
             'code', 'NOT_FOUND', 
             'message', 'Inventory item not found',
             'hint', 'Verify the item ID and pharmacy ID',
             'details', NULL
         );
    END IF;
END;$$;


ALTER FUNCTION public.delete_inventory_item(p_pharmacy_id uuid, p_id uuid) OWNER TO postgres;

