--
-- TOC entry 712 (class 1255 OID 231623)
-- Name: discard_purchase_return(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.discard_purchase_return(p_return_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_locked_id UUID;
BEGIN
    IF auth.uid() IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    -- [BUG-PR-7] Lock with NOWAIT so concurrent callers get SYSTEM_BUSY instead
    --   of silently blocking. The SELECT also doubles as the existence check.
    BEGIN
        SELECT id INTO v_locked_id
        FROM purchase_returns
        WHERE id = p_return_id
          AND refund_status = 'PENDING'::payment_status_enum
        FOR UPDATE NOWAIT;
    EXCEPTION
        WHEN lock_not_available THEN
            RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'Return is being modified, please try again');
    END;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'NOT_FOUND', 'message', 'Draft not found');
    END IF;

    DELETE FROM purchase_return_items WHERE return_id = p_return_id;
    DELETE FROM purchase_returns       WHERE id       = p_return_id;

    RETURN jsonb_build_object('code', 'SUCCESS', 'message', 'Draft discarded');

EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'ERROR', 'message', SQLERRM);
END;
$$;


ALTER FUNCTION public.discard_purchase_return(p_return_id uuid) OWNER TO postgres;

--
-- TOC entry 844 (class 1255 OID 226284)
-- Name: discard_sale_return(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.discard_sale_return(p_sale_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$DECLARE
    v_user_id UUID;
    v_return RECORD;
BEGIN
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint', NULL
        );
    END IF;

    -- FIX: FOR UPDATE NOWAIT on sale_returns row
    SELECT r.*, s.pharmacy_id
    INTO v_return
    FROM sale_returns r
    JOIN sales s ON r.sale_id = s.id
    WHERE r.sale_id = p_sale_id AND r.return_status = 'DRAFT'
    FOR UPDATE OF r NOWAIT;

    IF v_return IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'RETURN_NOT_FOUND',
            'message', 'No draft return found for this sale',
            'hint', 'There is no draft return to discard'
        );
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies pu
        WHERE pu.user_id = v_user_id
        AND pu.pharmacy_id = v_return.pharmacy_id
        AND pu.is_active = true
    ) THEN
        RETURN jsonb_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'You do not have permission for this pharmacy',
            'hint', NULL
        );
    END IF;

    DELETE FROM sale_return_items WHERE return_id = v_return.id;
    DELETE FROM sale_returns WHERE id = v_return.id;

    RETURN jsonb_build_object(
        'code', 'SUCCESS',
        'message', 'Draft return discarded successfully',
        'hint', NULL
    );
EXCEPTION
    WHEN SQLSTATE '55P03' THEN
        RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'System is busy, please try again', 'hint', 'Another operation is in progress');
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'INTERNAL_ERROR', 'message', SQLERRM, 'hint', NULL);
END;$$;


ALTER FUNCTION public.discard_sale_return(p_sale_id uuid) OWNER TO postgres;

--
-- TOC entry 1306 (class 1255 OID 255668)
-- Name: finalize_purchase(uuid, uuid, jsonb, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.finalize_purchase(p_purchase_id uuid, p_supplier_id uuid, p_payments jsonb, p_idempotency_key text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_purchase RECORD;
    v_supplier RECORD;
    v_supplier_name TEXT := 'Cash Purchase';
    v_item RECORD;
    v_payment JSONB;
    v_total_payment NUMERIC(12,2) := 0.00;
    v_payment_amount NUMERIC(12,2);
    v_outstanding NUMERIC(12,2);
    v_payment_status payment_status_enum;
    v_is_credit_purchase BOOLEAN := FALSE;
    v_batch_id UUID;
    v_credit_id UUID;
    v_inventory_updated UUID[] := ARRAY[]::UUID[];
    v_items_count INTEGER := 0;
    v_batches_created INTEGER := 0;
    v_has_payments BOOLEAN := FALSE;
    v_now TIMESTAMP WITH TIME ZONE;
BEGIN
    -- 1. AUTHENTICATION
    v_current_user_id := auth.uid();

    IF v_current_user_id IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint', 'Please log in to continue',
            'details', NULL
        );
    END IF;

    -- 2. INPUT VALIDATION
    IF p_purchase_id IS NULL THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Purchase ID is required',
            'hint', 'Provide a valid purchase ID',
            'details', NULL
        );
    END IF;

    IF p_payments IS NULL THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Payments parameter is required',
            'hint', 'Provide empty array [] for full credit purchase',
            'details', NULL
        );
    END IF;

    -- 3. IDEMPOTENCY CHECK
    IF p_idempotency_key IS NOT NULL THEN
        SELECT id, purchase_number, total_amount, paid_amount, outstanding_amount, purchase_status
        INTO v_purchase
        FROM purchases
        WHERE idempotency_key = p_idempotency_key
        AND deleted_at IS NULL;

        IF FOUND AND v_purchase.purchase_status = 'COMPLETED' THEN
            RETURN json_build_object(
                'code', 'SUCCESS',
                'message', 'Purchase already completed',
                'hint', 'This request was already processed',
                'details', json_build_object(
                    'purchase_id', v_purchase.id,
                    'purchase_number', v_purchase.purchase_number,
                    'total_amount', v_purchase.total_amount,
                    'paid_amount', v_purchase.paid_amount,
                    'outstanding_amount', v_purchase.outstanding_amount,
                    'is_duplicate', TRUE
                )
            );
        END IF;
    END IF;

    -- 4. LOCK AND VERIFY PURCHASE
    BEGIN
        SELECT * INTO STRICT v_purchase
        FROM purchases
        WHERE id = p_purchase_id
        AND purchase_status = 'DRAFT'
        AND deleted_at IS NULL
        FOR UPDATE NOWAIT;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN json_build_object(
                'code', 'PURCHASE_NOT_FOUND',
                'message', 'Purchase not found or already completed',
                'hint', 'Verify purchase ID and status',
                'details', NULL
            );
        WHEN lock_not_available THEN
            RETURN json_build_object(
                'code', 'SYSTEM_BUSY',
                'message', 'Purchase is being processed by another user',
                'hint', 'Please wait a moment and try again',
                'details', NULL
            );
    END;

    -- Set idempotency key immediately to prevent race conditions
    IF p_idempotency_key IS NOT NULL THEN
        UPDATE purchases
        SET idempotency_key = p_idempotency_key
        WHERE id = p_purchase_id;
    END IF;

    -- Check permission
    IF NOT user_has_permission(v_current_user_id, v_purchase.pharmacy_id, 'purchase.create') THEN
        RETURN json_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'You do not have permission to complete purchases',
            'hint', 'Contact your administrator for access',
            'details', NULL
        );
    END IF;

    -- 5. VERIFY SUPPLIER (Only if ID provided)
    IF p_supplier_id IS NOT NULL THEN
        SELECT
            s.id,
            s.name,
            s.pharmacy_id,
            s.is_active
        INTO v_supplier
        FROM suppliers s
        WHERE s.id = p_supplier_id
        AND s.deleted_at IS NULL;

        IF NOT FOUND THEN
            RETURN json_build_object(
                'code', 'SUPPLIER_NOT_FOUND',
                'message', 'Supplier not found',
                'hint', 'Verify supplier ID is correct',
                'details', NULL
            );
        END IF;

        IF v_supplier.pharmacy_id != v_purchase.pharmacy_id THEN
            RETURN json_build_object(
                'code', 'INVALID_SUPPLIER',
                'message', 'Supplier does not belong to this pharmacy',
                'hint', 'Select a supplier from your pharmacy',
                'details', NULL
            );
        END IF;

        IF NOT v_supplier.is_active THEN
            RETURN json_build_object(
                'code', 'SUPPLIER_INACTIVE',
                'message', 'Supplier is inactive',
                'hint', 'Please activate supplier before completing purchase',
                'details', json_build_object('supplier_name', v_supplier.name)
            );
        END IF;

        v_supplier_name := v_supplier.name;
    END IF;

    -- 6. VERIFY PURCHASE ITEMS
    SELECT count(*)
    INTO v_items_count
    FROM purchase_items
    WHERE purchase_id = p_purchase_id;

    IF v_items_count = 0 THEN
        RETURN json_build_object(
            'code', 'NO_ITEMS',
            'message', 'Cannot complete purchase without items',
            'hint', 'Add at least one item to the purchase',
            'details', NULL
        );
    END IF;

    IF v_purchase.total_amount <= 0 THEN
        RETURN json_build_object(
            'code', 'INVALID_TOTAL',
            'message', 'Purchase total must be greater than zero',
            'hint', 'Verify item prices and quantities',
            'details', json_build_object('total', v_purchase.total_amount)
        );
    END IF;

    -- 7. VALIDATE MEDICINE ITEMS (Batch/Expiry)
    FOR v_item IN
        SELECT
            pi.id,
            pi.inventory_id,
            pi.batch_number,
            pi.expiry_date,
            i.type,
            i.brand,
            i.name
        FROM purchase_items pi
        JOIN inventory i ON i.id = pi.inventory_id
        WHERE pi.purchase_id = p_purchase_id
    LOOP
        IF v_item.type = 'MEDICINE' THEN
            IF v_item.batch_number IS NULL OR TRIM(v_item.batch_number) = '' THEN
                RETURN json_build_object(
                    'code', 'BATCH_REQUIRED',
                    'message', 'Batch number is required for medicine',
                    'hint', 'Add batch number for: ' || COALESCE(v_item.brand, v_item.name, 'Unknown Item'),
                    'details', json_build_object(
                        'item_id', v_item.id,
                        'item_name', COALESCE(v_item.brand, v_item.name)
                    )
                );
            END IF;

            IF v_item.expiry_date IS NULL THEN
                RETURN json_build_object(
                    'code', 'EXPIRY_REQUIRED',
                    'message', 'Expiry date is required for medicine',
                    'hint', 'Add expiry date for: ' || COALESCE(v_item.brand, v_item.name, 'Unknown Item'),
                    'details', json_build_object(
                        'item_id', v_item.id,
                        'item_name', COALESCE(v_item.brand, v_item.name)
                    )
                );
            END IF;

            IF v_item.expiry_date <= CURRENT_DATE THEN
                RETURN json_build_object(
                    'code', 'EXPIRED_ITEM',
                    'message', 'Cannot complete purchase with expired medicine',
                    'hint', 'Remove or update expiry for: ' || COALESCE(v_item.brand, v_item.name, 'Unknown Item'),
                    'details', json_build_object(
                        'item_id', v_item.id,
                        'item_name', COALESCE(v_item.brand, v_item.name),
                        'expiry_date', v_item.expiry_date
                    )
                );
            END IF;
        END IF;
    END LOOP;

    -- 8. VALIDATE AND TOTAL PAYMENTS
    FOR v_payment IN SELECT * FROM jsonb_array_elements(p_payments)
    LOOP
        IF v_payment->>'method' IS NULL OR TRIM(v_payment->>'method') = '' THEN
            RETURN json_build_object(
                'code', 'INVALID_PAYMENT',
                'message', 'Payment method is required',
                'hint', 'Each payment must have a valid method',
                'details', NULL
            );
        END IF;

        IF UPPER(TRIM(v_payment->>'method')) NOT IN ('CASH', 'BKASH', 'NAGAD', 'ROCKET', 'CARD', 'BANK_TRANSFER') THEN
            RETURN json_build_object(
                'code', 'INVALID_PAYMENT',
                'message', 'Invalid payment method: ' || (v_payment->>'method'),
                'hint', 'Valid methods: CASH, BKASH, NAGAD, ROCKET, CARD, BANK_TRANSFER',
                'details', NULL
            );
        END IF;

        BEGIN
            v_payment_amount := (v_payment->>'amount')::NUMERIC;
        EXCEPTION WHEN OTHERS THEN
            RETURN json_build_object(
                'code', 'INVALID_PAYMENT',
                'message', 'Invalid payment amount',
                'hint', 'Payment amount must be a valid number',
                'details', NULL
            );
        END;

        IF v_payment_amount > 0 THEN
            v_total_payment := v_total_payment + v_payment_amount;
            v_has_payments := TRUE;
        END IF;
    END LOOP;

    -- Cap payment at total amount
    v_total_payment := LEAST(v_total_payment, v_purchase.total_amount);
    v_outstanding := v_purchase.total_amount - v_total_payment;

    IF v_outstanding > 0.005 THEN
        v_is_credit_purchase := TRUE;
    END IF;

    -- 9. VALIDATE SUPPLIER FOR CREDIT
    IF v_is_credit_purchase AND p_supplier_id IS NULL THEN
        RETURN json_build_object(
            'code', 'SUPPLIER_REQUIRED_FOR_CREDIT',
            'message', 'Supplier is required for credit purchase',
            'hint', 'Select a supplier to track the credit balance',
            'details', json_build_object('outstanding_amount', v_outstanding)
        );
    END IF;

    IF v_outstanding <= 0 THEN
        v_payment_status := 'COMPLETED'::payment_status_enum;
    ELSIF v_total_payment > 0 THEN
        v_payment_status := 'PARTIAL'::payment_status_enum;
    ELSE
        v_payment_status := 'PENDING'::payment_status_enum;
    END IF;

    -- 10. CREATE INVENTORY BATCHES + STOCK TRANSACTIONS
    v_now := NOW() AT TIME ZONE 'Asia/Dhaka';

    FOR v_item IN
        SELECT
            pi.id AS purchase_item_id,
            pi.inventory_id,
            pi.batch_number,
            pi.expiry_date,
            pi.quantity,
            pi.purchase_price,
            pi.selling_price,
            pi.total_price,
            pi.shelf_location,
            i.type AS inventory_type,
            i.name,
            i.brand,
            i.pharmacy_id
        FROM purchase_items pi
        JOIN inventory i ON i.id = pi.inventory_id
        WHERE pi.purchase_id = p_purchase_id
        ORDER BY pi.created_at
    LOOP
        INSERT INTO inventory_batches (
            pharmacy_id,
            inventory_id,
            batch_number,
            expiry_date,
            initial_quantity,
            current_quantity,
            reserved_quantity,
            purchase_price,
            selling_price,
            purchase_id,
            status,
            shelf_location,
            created_at,
            updated_at
        ) VALUES (
            v_item.pharmacy_id,
            v_item.inventory_id,
            v_item.batch_number, -- FIXED: Preserve batch_number for all types
            v_item.expiry_date,  -- FIXED: Preserve expiry_date for all types
            v_item.quantity,
            v_item.quantity,
            0,
            v_item.purchase_price,
            v_item.selling_price,
            p_purchase_id,
            'ACTIVE',
            v_item.shelf_location,
            v_now,
            v_now
        )
        RETURNING id INTO v_batch_id;

        v_batches_created := v_batches_created + 1;

        -- FIX: unit_price now uses purchase_price (cost basis), not selling_price
        INSERT INTO stock_transactions (
            id, pharmacy_id, inventory_id, batch_id,
            transaction_type, quantity_change, quantity_before, quantity_after,
            unit_price, total_amount,
            reference_id, reference_number, user_id, notes, created_at
        ) VALUES (
            gen_random_uuid(),
            v_item.pharmacy_id,
            v_item.inventory_id,
            v_batch_id,
            'PURCHASE',
            v_item.quantity,
            0,
            v_item.quantity,
            v_item.purchase_price,
            v_item.total_price,
            p_purchase_id,
            v_purchase.purchase_number,
            v_current_user_id,
            format('Purchase %s completed - %s',
                v_purchase.purchase_number,
                COALESCE(v_item.brand, v_item.name, 'Item')
            ),
            v_now
        );

        IF NOT (v_item.inventory_id = ANY(v_inventory_updated)) THEN
            v_inventory_updated := array_append(v_inventory_updated, v_item.inventory_id);
        END IF;
    END LOOP;

    -- 11. RECORD PAYMENTS
    IF v_has_payments THEN
        FOR v_payment IN SELECT * FROM jsonb_array_elements(p_payments)
        LOOP
            v_payment_amount := (v_payment->>'amount')::NUMERIC;

            IF v_payment_amount > 0 THEN
                INSERT INTO purchase_payments (
                    purchase_id,
                    payment_method,
                    amount,
                    mobile_number,
                    transaction_id,
                    card_number,
                    notes,
                    payment_date,
                    created_at,
                    updated_at
                ) VALUES (
                    p_purchase_id,
                    UPPER(v_payment->>'method')::payment_method_enum,
                    v_payment_amount,
                    NULLIF(TRIM(v_payment->>'mobile_number'), ''),
                    NULLIF(TRIM(v_payment->>'transaction_id'), ''),
                    NULLIF(TRIM(v_payment->>'card_number'), ''),
                    NULLIF(TRIM(v_payment->>'notes'), ''),
                    v_now,
                    v_now,
                    v_now
                );
            END IF;
        END LOOP;
    END IF;

    -- 12. UPDATE PURCHASE STATUS
    UPDATE purchases
    SET
        supplier_id = p_supplier_id,
        purchase_status = 'COMPLETED',
        payment_status = v_payment_status,
        paid_amount = v_total_payment,
        outstanding_amount = v_outstanding,
        purchase_date = v_now,
        updated_at = v_now
    WHERE id = p_purchase_id;

    -- 13. CREATE SUPPLIER CREDIT (Only if we have a supplier AND outstanding amount)
    IF v_is_credit_purchase AND p_supplier_id IS NOT NULL THEN
        INSERT INTO supplier_credits (
            supplier_id,
            pharmacy_id,
            purchase_id,
            credit_amount,
            paid_amount,
            outstanding_amount,
            due_date,
            status,
            created_at,
            updated_at
        ) VALUES (
            p_supplier_id,
            v_purchase.pharmacy_id,
            p_purchase_id,
            v_purchase.total_amount,
            v_total_payment,
            v_outstanding,
            (v_now)::DATE + INTERVAL '30 days',
            'ACTIVE',
            v_now,
            v_now
        ) RETURNING id INTO v_credit_id;

        IF v_total_payment > 0 AND v_has_payments THEN
            FOR v_payment IN SELECT * FROM jsonb_array_elements(p_payments)
            LOOP
                v_payment_amount := (v_payment->>'amount')::NUMERIC;

                IF v_payment_amount > 0 THEN
                    INSERT INTO supplier_credit_payments (
                        supplier_credit_id,
                        payment_method,
                        amount,
                        mobile_number,
                        transaction_id,
                        card_number,
                        notes,
                        user_id,
                        payment_date,
                        created_at,
                        transaction_type
                    ) VALUES (
                        v_credit_id,
                        UPPER(v_payment->>'method')::payment_method_enum,
                        v_payment_amount,
                        NULLIF(TRIM(v_payment->>'mobile_number'), ''),
                        NULLIF(TRIM(v_payment->>'transaction_id'), ''),
                        NULLIF(TRIM(v_payment->>'card_number'), ''),
                        COALESCE(
                            NULLIF(TRIM(v_payment->>'notes'), ''),
                            format('Initial payment for credit purchase %s', v_purchase.purchase_number)
                        ),
                        v_current_user_id,
                        v_now,
                        v_now,
                        'PAYMENT'::supplier_credit_payment_type_enum
                    );
                END IF;
            END LOOP;
        END IF;
    END IF;

    -- 14. UPDATE STOCK SUMMARIES
    IF array_length(v_inventory_updated, 1) > 0 THEN
        DECLARE
            v_inv_id UUID;
        BEGIN
            FOREACH v_inv_id IN ARRAY v_inventory_updated
            LOOP
                PERFORM update_stock_summary(v_inv_id);
            END LOOP;
        END;
    END IF;

    -- 15. RETURN SUCCESS
    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', CASE
            WHEN v_is_credit_purchase AND v_total_payment = 0 THEN 'Credit purchase recorded successfully'
            WHEN v_is_credit_purchase THEN 'Partial payment purchase recorded successfully'
            ELSE 'Purchase completed successfully'
        END,
        'hint', NULL,
        'details', json_build_object(
            'purchase_id', p_purchase_id,
            'purchase_number', v_purchase.purchase_number,
            'supplier_id', p_supplier_id,
            'supplier_name', v_supplier_name,
            'total_amount', v_purchase.total_amount,
            'paid_amount', v_total_payment,
            'outstanding_amount', v_outstanding,
            'payment_status', v_payment_status::TEXT,
            'is_credit_purchase', v_is_credit_purchase,
            'credit_id', v_credit_id,
            'items_count', v_items_count,
            'batches_created', v_batches_created,
            'completed_at', v_now
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        RETURN json_build_object(
            'code', 'INTERNAL_ERROR',
            'message', 'Failed to complete purchase',
            'hint', 'Contact system administrator',
            'details', json_build_object(
                'sqlstate', SQLSTATE,
                'error', SQLERRM,
                'purchase_id', p_purchase_id,
                'supplier_id', p_supplier_id
            )
        );
END;
$$;


ALTER FUNCTION public.finalize_purchase(p_purchase_id uuid, p_supplier_id uuid, p_payments jsonb, p_idempotency_key text) OWNER TO postgres;

--
-- TOC entry 914 (class 1255 OID 255193)
-- Name: finalize_purchase_return(uuid, text, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.finalize_purchase_return(p_return_id uuid, p_reason text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_refund_payments jsonb DEFAULT NULL::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id              UUID;
    v_return               RECORD;
    v_return_item          RECORD;
    v_batch_id             UUID;
    v_current_qty          INT;
    v_new_qty              INT;
    v_available_for_return INT;
    v_total_returned_qty   INT;
    v_total_purchased_qty  INT;
    v_credit_adjustment    DECIMAL := 0;
    v_cash_refund          DECIMAL := 0;
    v_payment              JSONB;
    v_total_refund         DECIMAL := 0;
    v_items_count          INT     := 0;
    v_inventory_ids        UUID[]  := ARRAY[]::UUID[];
    v_now                  TIMESTAMP WITH TIME ZONE;
BEGIN
    v_now := NOW() AT TIME ZONE 'Asia/Dhaka';

    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    BEGIN
        SELECT
            pr.*,
            p.pharmacy_id,
            p.supplier_id,
            p.purchase_number,
            p.outstanding_amount AS purchase_outstanding,
            p.paid_amount        AS purchase_paid,
            p.total_amount       AS purchase_total
        INTO STRICT v_return
        FROM purchase_returns pr
        JOIN purchases p ON pr.purchase_id = p.id
        WHERE pr.id = p_return_id
        FOR UPDATE OF pr NOWAIT;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN jsonb_build_object('code', 'RETURN_NOT_FOUND', 'message', 'Purchase return not found');
        WHEN lock_not_available THEN
            RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'Return is being processed by another user, please wait');
    END;

    IF v_return.refund_status != 'PENDING'::payment_status_enum THEN
        RETURN jsonb_build_object('code', 'INVALID_STATUS', 'message', 'Only pending returns can be completed');
    END IF;

    IF NOT EXISTS (SELECT 1 FROM purchase_return_items WHERE return_id = p_return_id) THEN
        RETURN jsonb_build_object('code', 'NO_ITEMS', 'message', 'No items to return');
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies
        WHERE user_id    = v_user_id
          AND pharmacy_id = v_return.pharmacy_id
          AND is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied');
    END IF;

    IF v_return.purchase_outstanding > 0 THEN
        v_credit_adjustment := LEAST(v_return.total_amount, v_return.purchase_outstanding);
        v_cash_refund       := GREATEST(0, v_return.total_amount - v_credit_adjustment);
    ELSE
        v_credit_adjustment := 0;
        v_cash_refund       := v_return.total_amount;
    END IF;

    IF v_cash_refund > 0 THEN
        IF p_refund_payments IS NULL OR jsonb_array_length(p_refund_payments) = 0 THEN
            RETURN jsonb_build_object(
                'code',    'PAYMENT_REQUIRED',
                'message', 'Payment details are required for cash refund (expected: ' || ROUND(v_cash_refund, 2) || ')',
                'details', NULL
            );
        END IF;
    END IF;

    -- Process each return item and remove from stock.
    FOR v_return_item IN
        SELECT
            pri.*,
            pi.batch_number AS orig_batch,
            i.name          AS inventory_name
        FROM purchase_return_items pri
        JOIN purchase_items pi ON pri.purchase_item_id = pi.id
        LEFT JOIN inventory i  ON pri.inventory_id     = i.id
        WHERE pri.return_id = p_return_id
    LOOP
        v_items_count := v_items_count + 1;

        SELECT pi.quantity - COALESCE(completed.qty, 0)
        INTO v_available_for_return
        FROM purchase_items pi
        LEFT JOIN (
            SELECT pri.purchase_item_id, SUM(pri.quantity) AS qty
            FROM purchase_return_items pri
            JOIN purchase_returns pr ON pri.return_id = pr.id
            WHERE pr.refund_status = 'COMPLETED'::payment_status_enum
              AND pri.purchase_item_id = v_return_item.purchase_item_id
            GROUP BY pri.purchase_item_id
        ) completed ON completed.purchase_item_id = pi.id
        WHERE pi.id = v_return_item.purchase_item_id;

        IF v_return_item.quantity > GREATEST(0, v_available_for_return) THEN
            RAISE EXCEPTION '%', jsonb_build_object(
                'code',    'EXCEEDS_AVAILABLE',
                'message', 'Return qty for ' || COALESCE(v_return_item.inventory_name, 'item')
                           || ' exceeds what can be returned ('
                           || GREATEST(0, v_available_for_return) || ' available)',
                'details', NULL
            )::TEXT;
        END IF;

        SELECT id, current_quantity
        INTO v_batch_id, v_current_qty
        FROM inventory_batches
        WHERE inventory_id = v_return_item.inventory_id
          AND batch_number IS NOT DISTINCT FROM NULLIF(
                NULLIF(
                    COALESCE(
                        NULLIF(v_return_item.batch_number, ''),
                        NULLIF(v_return_item.orig_batch,   '')
                    ),
                    ''
                ),
                'DEFAULT'
              )
          AND pharmacy_id   = v_return.pharmacy_id
          AND purchase_id   = v_return.purchase_id
        FOR UPDATE NOWAIT;

        IF v_batch_id IS NULL THEN
            RAISE EXCEPTION '%', jsonb_build_object(
                'code',    'BATCH_NOT_FOUND',
                'message', 'Batch not found for item: ' || COALESCE(v_return_item.inventory_name, 'Unknown'),
                'details', NULL
            )::TEXT;
        END IF;

        IF v_return_item.quantity > v_current_qty THEN
            RAISE EXCEPTION '%', jsonb_build_object(
                'code',    'INSUFFICIENT_STOCK',
                'message', 'Cannot return ' || v_return_item.quantity || ' units of '
                    || COALESCE(v_return_item.inventory_name, 'Unknown')
                    || ' (only ' || v_current_qty || ' in stock)',
                'details', NULL
            )::TEXT;
        END IF;

        v_new_qty := v_current_qty - v_return_item.quantity;

        UPDATE inventory_batches
        SET current_quantity = v_new_qty,
            updated_at       = v_now
        WHERE id = v_batch_id;

        INSERT INTO stock_transactions (
            id, pharmacy_id, inventory_id, batch_id,
            transaction_type, quantity_change, quantity_before, quantity_after,
            unit_price, total_amount,
            reference_id, reference_number, user_id, notes, created_at
        ) VALUES (
            gen_random_uuid(),
            v_return.pharmacy_id,
            v_return_item.inventory_id,
            v_batch_id,
            'PURCHASE_RETURN',
            -v_return_item.quantity,
            v_current_qty,
            v_new_qty,
            v_return_item.unit_cost,
            v_return_item.total_cost,
            p_return_id,
            v_return.return_number,
            v_user_id,
            'Returned to supplier: ' || COALESCE(v_return.purchase_number, 'Unknown'),
            v_now
        );

        IF NOT (v_return_item.inventory_id = ANY(v_inventory_ids)) THEN
            v_inventory_ids := array_append(v_inventory_ids, v_return_item.inventory_id);
        END IF;
    END LOOP;

    DECLARE
        v_inv_id UUID;
    BEGIN
        FOREACH v_inv_id IN ARRAY v_inventory_ids LOOP
            PERFORM update_stock_summary(v_inv_id);
        END LOOP;
    END;

    IF v_cash_refund > 0 AND p_refund_payments IS NOT NULL AND jsonb_array_length(p_refund_payments) > 0 THEN
        FOR v_payment IN SELECT * FROM jsonb_array_elements(p_refund_payments)
        LOOP
            v_total_refund := v_total_refund + COALESCE((v_payment->>'amount')::DECIMAL, 0);

            INSERT INTO purchase_return_payments (
                id, return_id, payment_method, amount,
                mobile_number, transaction_id, card_number,
                payment_date, user_id, notes, created_at
            ) VALUES (
                gen_random_uuid(),
                p_return_id,
                (v_payment->>'method')::payment_method_enum,
                (v_payment->>'amount')::DECIMAL,
                v_payment->>'mobile_number',
                v_payment->>'transaction_id',
                v_payment->>'card_number',
                v_now, v_user_id,
                'Refund from supplier',
                v_now
            );
        END LOOP;
    END IF;

    IF v_cash_refund > 0 AND ROUND(v_total_refund, 2) != ROUND(v_cash_refund, 2) THEN
        RAISE EXCEPTION '%', jsonb_build_object(
            'code',    'PAYMENT_MISMATCH',
            'message', 'Payment total does not match expected cash refund (expected: '
                       || ROUND(v_cash_refund, 2) || ', received: ' || ROUND(v_total_refund, 2) || ')',
            'details', NULL
        )::TEXT;
    END IF;

    UPDATE purchase_returns
    SET refund_status     = 'COMPLETED'::payment_status_enum,
        refunded_amount   = v_total_refund,
        credit_adjustment = v_credit_adjustment,
        cash_refund       = v_cash_refund,
        return_reason     = COALESCE(NULLIF(TRIM(p_reason), ''), return_reason),
        notes             = COALESCE(NULLIF(TRIM(p_notes), ''), notes),
        updated_at        = v_now
    WHERE id = p_return_id;

    IF v_credit_adjustment > 0 THEN
        UPDATE purchases
        SET outstanding_amount = GREATEST(0, outstanding_amount - v_credit_adjustment),
            updated_at         = v_now
        WHERE id = v_return.purchase_id;

        IF v_return.supplier_id IS NOT NULL THEN
            UPDATE supplier_credits
            SET outstanding_amount = GREATEST(0, outstanding_amount - v_credit_adjustment),
                paid_amount        = paid_amount + v_credit_adjustment,
                updated_at         = v_now
            WHERE purchase_id = v_return.purchase_id
              AND supplier_id = v_return.supplier_id;
        END IF;
    END IF;

    SELECT
        COALESCE(SUM(pri.quantity), 0),
        COALESCE((SELECT SUM(pi.quantity) FROM purchase_items pi WHERE pi.purchase_id = v_return.purchase_id), 0)
    INTO v_total_returned_qty, v_total_purchased_qty
    FROM purchase_return_items pri
    JOIN purchase_returns pr ON pri.return_id = pr.id
    WHERE pr.purchase_id   = v_return.purchase_id
      AND pr.refund_status = 'COMPLETED'::payment_status_enum;

    IF v_total_returned_qty >= v_total_purchased_qty THEN
        UPDATE purchases
        SET purchase_status = 'RETURNED'::purchase_status_enum,
            updated_at      = v_now
        WHERE id = v_return.purchase_id;
    ELSE
        UPDATE purchases
        SET purchase_status = 'PARTIALLY_RETURNED'::purchase_status_enum,
            updated_at      = v_now
        WHERE id = v_return.purchase_id;
    END IF;

    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Purchase return completed successfully',
        'details', jsonb_build_object(
            'return_id',       p_return_id,
            'return_number',   v_return.return_number,
            'items_returned',  v_items_count,
            'total_amount',    v_return.total_amount,
            'credit_adjustment', v_credit_adjustment,
            'cash_refund',     v_cash_refund,
            'refunded_amount', v_total_refund
        )
    );

EXCEPTION
    WHEN lock_not_available THEN
        RETURN jsonb_build_object(
            'code',    'SYSTEM_BUSY',
            'message', 'Some inventory is locked by another process',
            'details', NULL
        );
    WHEN OTHERS THEN
        DECLARE
            v_errmsg TEXT := SQLERRM;
        BEGIN
            RETURN v_errmsg::JSONB;
        EXCEPTION WHEN OTHERS THEN
            RETURN jsonb_build_object('code', 'ERROR', 'message', v_errmsg);
        END;
END;
$$;


ALTER FUNCTION public.finalize_purchase_return(p_return_id uuid, p_reason text, p_notes text, p_refund_payments jsonb) OWNER TO postgres;

--
-- TOC entry 7196 (class 0 OID 0)
-- Dependencies: 914
-- Name: FUNCTION finalize_purchase_return(p_return_id uuid, p_reason text, p_notes text, p_refund_payments jsonb); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.finalize_purchase_return(p_return_id uuid, p_reason text, p_notes text, p_refund_payments jsonb) IS 'Completes a purchase return: reduces batch quantities, records stock transactions, 
updates stock summary, processes refund payments, and adjusts supplier credits. 
CRITICAL FIX: Now explicitly calls update_stock_summary for all affected inventories.';


--
-- TOC entry 1497 (class 1255 OID 269880)
-- Name: finalize_sale(uuid, jsonb, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.finalize_sale(p_sale_id uuid, p_payments jsonb, p_customer_id uuid DEFAULT NULL::uuid, p_idempotency_key text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id          uuid;
    v_sale             RECORD;
    v_sale_item        RECORD;
    v_batch            RECORD;
    v_payment          jsonb;
    v_payment_status   payment_status_enum;

    -- payment
    v_total_paid       numeric(12,2) := 0;
    v_pay_amount       numeric(12,2);
    v_credit_amount    numeric(12,2);
    v_credit_id        uuid;

    -- stock
    v_remaining_qty    integer;
    v_deduct_qty       integer;
    v_stock_before     integer;
    v_avail_stock      integer;

    -- totals
    v_items_count      integer;
    v_recalc_subtotal  numeric(12,2);
    v_recalc_item_disc numeric(12,2);
    v_final_total      numeric(12,2);

    -- misc
    v_customer_name    text;
BEGIN

    -- ── 1. AUTHENTICATION ─────────────────────────────────────────────────────
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED',
            'message', 'User not authenticated');
    END IF;

    -- ── 2. LOCK SALE ROW ──────────────────────────────────────────────────────
    SELECT * INTO v_sale
    FROM   sales
    WHERE  id = p_sale_id
    FOR UPDATE NOWAIT;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'SALE_NOT_FOUND',
            'message', 'Sale not found');
    END IF;

    -- ── 3. IDEMPOTENCY GUARD ──────────────────────────────────────────────────
    IF v_sale.sale_status = 'COMPLETED' THEN
        RETURN jsonb_build_object('code', 'SUCCESS',
            'message', 'Sale already completed');
    END IF;

    -- ── 4. STATUS GUARD ───────────────────────────────────────────────────────
    IF v_sale.sale_status != 'DRAFT' THEN
        RETURN jsonb_build_object('code', 'INVALID_STATUS',
            'message', 'Only DRAFT sales can be finalized',
            'hint',    'Current status: ' || v_sale.sale_status::text);
    END IF;

    -- ── 5. PERMISSION CHECK ───────────────────────────────────────────────────
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE  up.user_id    = v_user_id
          AND  up.pharmacy_id = v_sale.pharmacy_id
          AND  up.is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED',
            'message', 'Permission denied');
    END IF;

    -- ── 6. ITEMS EXIST ────────────────────────────────────────────────────────
    SELECT COUNT(*) INTO v_items_count
    FROM   sale_items
    WHERE  sale_id = p_sale_id;

    IF v_items_count = 0 THEN
        RETURN jsonb_build_object('code', 'NO_ITEMS',
            'message', 'Sale must have at least one item before finalizing');
    END IF;

    -- ── 7. VALIDATE & SUM PAYMENTS ───────────────────────────────────────────
    IF p_payments IS NOT NULL AND jsonb_array_length(p_payments) > 0 THEN
        FOR v_payment IN SELECT * FROM jsonb_array_elements(p_payments) LOOP
            v_pay_amount := COALESCE((v_payment->>'amount')::numeric, 0);
            IF v_pay_amount <= 0 THEN
                RETURN jsonb_build_object('code', 'INVALID_PAYMENT',
                    'message', 'Each payment amount must be greater than zero');
            END IF;
            IF (v_payment->>'method') IS NULL THEN
                RETURN jsonb_build_object('code', 'INVALID_PAYMENT',
                    'message', 'Payment method is required for each entry');
            END IF;
            v_total_paid := v_total_paid + v_pay_amount;
        END LOOP;
    END IF;

    -- Credit/partial sales require a customer
    IF v_total_paid < v_sale.total_amount THEN
        IF p_customer_id IS NULL AND v_sale.customer_id IS NULL THEN
            RETURN jsonb_build_object('code', 'CUSTOMER_REQUIRED',
                'message', 'A customer must be assigned for credit or partial-payment sales');
        END IF;
    END IF;

    -- ── 8. DEFENSIVE TOTAL RECALCULATION ─────────────────────────────────────
    -- Recalculate from sale_items to catch any drift from the stored total.
    -- Uses the same formula as add_or_update_sale_item so results are always
    -- consistent: gross − item_discounts − sale_discount.
    SELECT COALESCE(SUM(si.quantity * si.unit_price), 0),
           COALESCE(SUM(si.discount_amount), 0)
    INTO   v_recalc_subtotal, v_recalc_item_disc
    FROM   sale_items si
    WHERE  si.sale_id = p_sale_id;

    v_final_total := ROUND(
        v_recalc_subtotal
        - v_recalc_item_disc
        - COALESCE(v_sale.discount_amount, 0),
    2);
    IF v_final_total < 0 THEN v_final_total := 0; END IF;

    -- Sync if stale (defensive; should not normally differ)
    IF v_final_total IS DISTINCT FROM v_sale.total_amount THEN
        UPDATE sales
        SET subtotal           = v_recalc_subtotal,
            total_amount       = v_final_total,
            outstanding_amount = GREATEST(v_final_total - COALESCE(v_sale.paid_amount, 0), 0),
            updated_at         = NOW()
        WHERE id = p_sale_id;
        v_sale.total_amount := v_final_total;
    END IF;

    -- ── 9. PASS 1 — PRE-VALIDATION (no batch locks, no deductions) ───────────
    -- Validates that every item can be fully fulfilled BEFORE touching any batch.
    -- Ensures we never partially deduct and then return a friendly error;
    -- a partial deduction with a non-exception return would commit to DB.
    FOR v_sale_item IN
        SELECT si.inventory_id, si.quantity,
               COALESCE(i.brand, i.name) AS display_name
        FROM   sale_items si
        JOIN   inventory  i ON i.id = si.inventory_id
        WHERE  si.sale_id = p_sale_id
    LOOP
        SELECT COALESCE(SUM(ib.current_quantity), 0)::integer
        INTO   v_avail_stock
        FROM   inventory_batches ib
        WHERE  ib.inventory_id = v_sale_item.inventory_id
          AND  ib.status       IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY')
          AND  ib.current_quantity > 0
          AND  ib.deleted_at IS NULL
          AND  (ib.expiry_date IS NULL OR ib.expiry_date > CURRENT_DATE);

        IF v_avail_stock < v_sale_item.quantity THEN
            RETURN jsonb_build_object(
                'code',    'INSUFFICIENT_STOCK',
                'message', 'Insufficient stock for ' || v_sale_item.display_name,
                'details', jsonb_build_object(
                    'item',      v_sale_item.display_name,
                    'available', v_avail_stock,
                    'requested', v_sale_item.quantity
                )
            );
        END IF;
    END LOOP;

    -- ── 10. PASS 2 — FIFO STOCK DEDUCTION (with batch-level locking) ─────────
    --
    -- FIFO strategy (deterministic, consistent with add_or_update_sale_item):
    --   1. expiry_date ASC NULLS LAST   → FEFO for medicines with expiry;
    --                                     items without expiry come last.
    --   2. created_at  ASC NULLS LAST   → FIFO fallback for same-expiry or
    --                                     no-expiry batches (oldest purchase first).
    --
    -- FOR UPDATE NOWAIT: locks each batch row exclusively. If a concurrent
    -- transaction holds the lock, we immediately get lock_not_available → the
    -- EXCEPTION block returns SYSTEM_BUSY (full rollback by PostgreSQL).
    --
    -- If a race between PASS 1 and PASS 2 depletes stock: v_remaining_qty > 0
    -- after all batches are exhausted → RAISE EXCEPTION rolls back atomically.
    --
    FOR v_sale_item IN
        SELECT si.*,
               COALESCE(i.brand, i.name) AS display_name
        FROM   sale_items si
        JOIN   inventory  i ON i.id = si.inventory_id
        WHERE  si.sale_id = p_sale_id
    LOOP
        v_remaining_qty := v_sale_item.quantity;

        FOR v_batch IN
            SELECT ib.*
            FROM   inventory_batches ib
            WHERE  ib.inventory_id = v_sale_item.inventory_id
              AND  ib.status       IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY')
              AND  ib.current_quantity > 0
              AND  ib.deleted_at IS NULL
              AND  (ib.expiry_date IS NULL OR ib.expiry_date > CURRENT_DATE)
            ORDER BY
                ib.expiry_date ASC NULLS LAST,
                ib.created_at  ASC NULLS LAST
            FOR UPDATE NOWAIT
        LOOP
            EXIT WHEN v_remaining_qty <= 0;

            v_deduct_qty   := LEAST(v_remaining_qty, v_batch.current_quantity);
            v_stock_before := v_batch.current_quantity;

            -- Deduct from batch.
            -- The BEFORE trigger auto_update_batch_status sets status (SOLD_OUT etc).
            -- The AFTER trigger trigger_update_stock_summary refreshes stock_summary.
            UPDATE inventory_batches
            SET current_quantity = current_quantity - v_deduct_qty,
                updated_at       = NOW()
            WHERE id = v_batch.id;

            -- Record stock transaction.
            -- quantity_before is captured BEFORE the UPDATE (correct audit pattern).
            INSERT INTO stock_transactions (
                id, pharmacy_id, inventory_id, batch_id,
                transaction_type,
                quantity_change, quantity_before, quantity_after,
                unit_price,              total_amount,
                reference_id,            reference_number,
                user_id, notes,          created_at
            ) VALUES (
                gen_random_uuid(),
                v_sale.pharmacy_id,
                v_sale_item.inventory_id,
                v_batch.id,
                'SALE',
                -v_deduct_qty,
                v_stock_before,
                v_stock_before - v_deduct_qty,
                v_sale_item.unit_price,
                ROUND(v_sale_item.unit_price * v_deduct_qty, 2),
                p_sale_id,
                v_sale.sale_number,
                v_user_id,
                'Sale: ' || v_sale.sale_number,
                NOW()
            );

            v_remaining_qty := v_remaining_qty - v_deduct_qty;
        END LOOP;

        -- If batches were exhausted but qty still remains, a concurrent finalize
        -- raced between PASS 1 and PASS 2. RAISE rolls back all deductions.
        IF v_remaining_qty > 0 THEN
            RAISE EXCEPTION 'INSUFFICIENT_STOCK: % (short by %)',
                v_sale_item.display_name, v_remaining_qty;
        END IF;
    END LOOP;

    -- ── 11. INSERT PAYMENTS ───────────────────────────────────────────────────
    IF p_payments IS NOT NULL AND jsonb_array_length(p_payments) > 0 THEN
        FOR v_payment IN SELECT * FROM jsonb_array_elements(p_payments) LOOP
            INSERT INTO sale_payments (
                id, sale_id,
                payment_method,
                amount,
                mobile_number,    transaction_id,
                card_number,      notes,
                user_id,
                payment_date,     created_at
            ) VALUES (
                gen_random_uuid(),
                p_sale_id,
                (v_payment->>'method')::payment_method_enum,
                (v_payment->>'amount')::numeric,
                v_payment->>'mobile_number',
                v_payment->>'transaction_id',
                v_payment->>'card_number',
                v_payment->>'notes',
                v_user_id,
                NOW() AT TIME ZONE 'Asia/Dhaka',
                NOW() AT TIME ZONE 'Asia/Dhaka'
            );
        END LOOP;
    END IF;

    -- ── 12. PAYMENT STATUS ────────────────────────────────────────────────────
    v_payment_status := CASE
        WHEN v_total_paid >= v_sale.total_amount THEN 'COMPLETED'::payment_status_enum
        ELSE                                          'PARTIAL'::payment_status_enum
    END;

    -- ── 13. CREDIT RECORD (partial/zero payment) ──────────────────────────────
    IF v_payment_status = 'PARTIAL'::payment_status_enum THEN
        v_credit_amount := ROUND(v_sale.total_amount - v_total_paid, 2);

        SELECT id INTO v_credit_id
        FROM   customer_credits
        WHERE  sale_id = p_sale_id;

        IF FOUND THEN
            UPDATE customer_credits
            SET outstanding_amount = v_credit_amount,
                credit_amount      = v_credit_amount,
                updated_at         = NOW()
            WHERE id = v_credit_id;
        ELSE
            INSERT INTO customer_credits (
                id, customer_id, sale_id, pharmacy_id,
                credit_amount, paid_amount, outstanding_amount,
                due_date, status, created_at, updated_at
            ) VALUES (
                gen_random_uuid(),
                COALESCE(p_customer_id, v_sale.customer_id),
                p_sale_id, v_sale.pharmacy_id,
                v_credit_amount, 0, v_credit_amount,
                CURRENT_DATE + INTERVAL '30 days',
                'ACTIVE', NOW(), NOW()
            ) RETURNING id INTO v_credit_id;
        END IF;
    END IF;

    -- ── 14. FETCH CUSTOMER NAME ───────────────────────────────────────────────
    IF p_customer_id IS NOT NULL OR v_sale.customer_id IS NOT NULL THEN
        SELECT name INTO v_customer_name
        FROM   customers
        WHERE  id = COALESCE(p_customer_id, v_sale.customer_id);
    END IF;

    -- ── 15. FINALIZE SALE ROW ─────────────────────────────────────────────────
    UPDATE sales
    SET sale_status        = 'COMPLETED'::sale_status_enum,
        payment_status     = v_payment_status,
        customer_id        = COALESCE(p_customer_id, customer_id),
        paid_amount        = v_total_paid,
        outstanding_amount = ROUND(GREATEST(v_sale.total_amount - v_total_paid, 0), 2),
        is_credit_sale     = (v_payment_status = 'PARTIAL'::payment_status_enum),
        sale_date          = NOW() AT TIME ZONE 'Asia/Dhaka',
        updated_at         = NOW()
    WHERE id = p_sale_id;

    -- ── 16. RETURN SUCCESS ────────────────────────────────────────────────────
    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Sale completed successfully',
        'details', jsonb_build_object(
            'sale_id',            p_sale_id,
            'sale_number',        v_sale.sale_number,
            'customer_id',        COALESCE(p_customer_id, v_sale.customer_id),
            'customer_name',      v_customer_name,
            'total_amount',       v_sale.total_amount,
            'paid_amount',        v_total_paid,
            'outstanding_amount', ROUND(GREATEST(v_sale.total_amount - v_total_paid, 0), 2),
            'payment_status',     v_payment_status::text,
            'is_credit_sale',     (v_payment_status = 'PARTIAL'::payment_status_enum),
            'credit_id',          v_credit_id,
            'items_count',        v_items_count,
            'completed_at',       NOW()
        )
    );

EXCEPTION
    WHEN lock_not_available THEN
        -- A batch or sale row is locked by a concurrent transaction.
        -- PostgreSQL has already rolled back all changes in this call.
        RETURN jsonb_build_object(
            'code',    'SYSTEM_BUSY',
            'message', 'System is busy processing another request. Please try again.',
            'hint',    'Another operation is in progress on this sale or its stock'
        );
    WHEN OTHERS THEN
        -- Our own RAISE EXCEPTION from PASS 2 (concurrent race depleted stock).
        IF SQLERRM LIKE 'INSUFFICIENT_STOCK:%' THEN
            RETURN jsonb_build_object(
                'code',    'INSUFFICIENT_STOCK',
                'message', 'Stock became unavailable during checkout due to a concurrent sale. Please refresh and try again.'
            );
        END IF;
        -- Unexpected error — PostgreSQL has rolled back all changes.
        RETURN jsonb_build_object(
            'code',    'INTERNAL_ERROR',
            'message', SQLERRM
        );
END;
$$;


ALTER FUNCTION public.finalize_sale(p_sale_id uuid, p_payments jsonb, p_customer_id uuid, p_idempotency_key text) OWNER TO postgres;

--
-- TOC entry 664 (class 1255 OID 226813)
-- Name: finalize_sale_return(uuid, text, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.finalize_sale_return(p_return_id uuid, p_reason text, p_notes text DEFAULT NULL::text, p_refund_payments jsonb DEFAULT NULL::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id       UUID;
    v_return        RECORD;
    v_items_count   INT;
    v_payment       JSONB;
    v_payment_total DECIMAL := 0;
    v_return_item   RECORD;
    v_sale_item     RECORD;
    v_current_qty   INT;
BEGIN
    -- ── 1. BUG-SR-5 FIX: auth check FIRST (was after p_reason validation) ─
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    -- ── 2. INPUT VALIDATION ────────────────────────────────────────────────
    IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
        RETURN jsonb_build_object('code', 'INVALID_INPUT', 'message', 'Return reason is required');
    END IF;

    -- ── 3. LOCK RETURN + LOCK SALE ─────────────────────────────────────────
    -- BUG-NEW-6 FIX: lock BOTH rows (FOR UPDATE OF r, s) so two concurrent
    -- finalize calls on different returns of the same sale cannot deadlock.
    -- With NOWAIT the second caller gets SYSTEM_BUSY immediately rather than
    -- hanging until PostgreSQL's deadlock detector fires.
    SELECT r.*, s.pharmacy_id, s.customer_id,
           s.total_amount      AS sale_total,
           s.paid_amount       AS sale_paid,
           s.outstanding_amount AS sale_outstanding,
           s.is_credit_sale, s.sale_number
    INTO v_return
    FROM sale_returns r
    JOIN sales s ON r.sale_id = s.id
    WHERE r.id = p_return_id
    FOR UPDATE OF r, s NOWAIT;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'RETURN_NOT_FOUND', 'message', 'Return not found');
    END IF;

    IF v_return.return_status != 'DRAFT' THEN
        RETURN jsonb_build_object('code', 'INVALID_STATUS', 'message', 'Only draft returns can be completed');
    END IF;

    -- ── 4. PERMISSION ──────────────────────────────────────────────────────
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies pu
        WHERE pu.user_id     = v_user_id
          AND pu.pharmacy_id = v_return.pharmacy_id
          AND pu.is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied');
    END IF;

    -- ── 5. ITEM COUNT CHECK ────────────────────────────────────────────────
    SELECT COUNT(*) INTO v_items_count
    FROM sale_return_items
    WHERE return_id = p_return_id AND deleted_at IS NULL;

    IF v_items_count = 0 THEN
        RETURN jsonb_build_object('code', 'NO_ITEMS', 'message', 'Return must have at least one item to complete');
    END IF;

    -- ── 6. PAYMENT VALIDATION & INSERT ────────────────────────────────────
    IF v_return.cash_refund > 0 THEN
        IF p_refund_payments IS NULL OR jsonb_array_length(p_refund_payments) = 0 THEN
            RETURN jsonb_build_object('code', 'PAYMENT_REQUIRED', 'message', 'Payment details required for cash refund');
        END IF;

        FOR v_payment IN SELECT * FROM jsonb_array_elements(p_refund_payments) LOOP
            v_payment_total := v_payment_total + COALESCE((v_payment->>'amount')::DECIMAL, 0);
        END LOOP;

        IF ABS(v_payment_total - v_return.cash_refund) > 0.01 THEN
            RETURN jsonb_build_object('code', 'PAYMENT_MISMATCH', 'message', 'Payment total does not match refund amount');
        END IF;

        FOR v_payment IN SELECT * FROM jsonb_array_elements(p_refund_payments) LOOP
            INSERT INTO sale_return_payments (
                id, return_id, payment_method, amount,
                mobile_number, transaction_id, card_number, notes,
                processed_by, payment_date, created_at
            ) VALUES (
                gen_random_uuid(), p_return_id,
                v_payment->>'method',
                (v_payment->>'amount')::DECIMAL,
                v_payment->>'mobile_number',
                v_payment->>'transaction_id',
                v_payment->>'card_number',
                v_payment->>'notes',
                v_user_id,
                NOW() AT TIME ZONE 'Asia/Dhaka',
                NOW() AT TIME ZONE 'Asia/Dhaka'
            );
        END LOOP;
    END IF;

    -- ── 7. MARK RETURN COMPLETED ───────────────────────────────────────────
    UPDATE sale_returns
    SET return_status = 'COMPLETED',
        reason        = TRIM(p_reason),
        notes         = NULLIF(TRIM(COALESCE(p_notes, '')), ''),
        processed_by  = v_user_id,
        processed_at  = NOW() AT TIME ZONE 'Asia/Dhaka',
        updated_at    = NOW() AT TIME ZONE 'Asia/Dhaka'
    WHERE id = p_return_id;

    -- ── 8. RESTORE STOCK & LOG TRANSACTIONS ───────────────────────────────
    FOR v_return_item IN
        SELECT ri.*, si.batch_id AS item_batch_id
        FROM sale_return_items ri
        JOIN sale_items si ON ri.sale_item_id = si.id
        WHERE ri.return_id = p_return_id
          AND ri.deleted_at IS NULL
    LOOP
        -- BUG-SR-6 FIX: lock sale_items row to prevent concurrent returned_quantity corruption
        SELECT * INTO v_sale_item
        FROM sale_items
        WHERE id = v_return_item.sale_item_id
        FOR UPDATE NOWAIT;

        -- BUG-NEW-5 FIX: guard against absent row — without this, a missing
        -- sale_item causes a silent 0-row UPDATE while stock IS restored, leaving
        -- returned_quantity permanently out of sync with inventory.
        IF NOT FOUND THEN
            RAISE EXCEPTION 'sale_item % not found during finalization (return %)',
                v_return_item.sale_item_id, p_return_id;
        END IF;

        UPDATE sale_items
        SET returned_quantity = COALESCE(returned_quantity, 0) + v_return_item.quantity
        WHERE id = v_return_item.sale_item_id;

        -- Restore inventory batch (RETURNING gives quantity_after)
        UPDATE inventory_batches
        SET current_quantity = current_quantity + v_return_item.quantity,
            updated_at       = NOW() AT TIME ZONE 'Asia/Dhaka'
        WHERE id = v_return_item.batch_id
        RETURNING current_quantity INTO v_current_qty;

        -- Stock transaction (quantity_before = new_qty − returned_qty)
        INSERT INTO stock_transactions (
            id, pharmacy_id, inventory_id, batch_id, transaction_type,
            quantity_change, quantity_before, quantity_after,
            unit_price, total_amount,
            reference_id, reference_number, user_id, notes, created_at
        ) VALUES (
            gen_random_uuid(), v_return.pharmacy_id,
            v_return_item.inventory_id, v_return_item.batch_id,
            'SALE_RETURN',
            v_return_item.quantity,
            v_current_qty - v_return_item.quantity,
            v_current_qty,
            v_return_item.unit_price,
            ROUND(v_return_item.quantity * v_return_item.unit_price, 2),
            p_return_id, v_return.return_number,
            v_user_id,
            'Returned from sale: ' || v_return.sale_number,
            NOW() AT TIME ZONE 'Asia/Dhaka'
        );
    END LOOP;

    -- ── 9. UPDATE SALE STATUS ──────────────────────────────────────────────
    UPDATE sales
    SET sale_status = CASE
            WHEN (SELECT COALESCE(SUM(si.returned_quantity), 0)
                  FROM sale_items si WHERE si.sale_id = v_return.sale_id)
                 >= (SELECT COALESCE(SUM(si.quantity), 0)
                     FROM sale_items si WHERE si.sale_id = v_return.sale_id)
            THEN 'RETURNED'::sale_status_enum
            ELSE 'PARTIALLY_RETURNED'::sale_status_enum
        END,
        updated_at = NOW() AT TIME ZONE 'Asia/Dhaka'
    WHERE id = v_return.sale_id;

    -- ── 10. FINANCIAL ADJUSTMENTS FOR CREDIT SALES ────────────────────────
    IF v_return.credit_adjustment > 0 THEN
        IF v_return.customer_id IS NOT NULL THEN
            UPDATE customer_credits
            SET outstanding_amount = GREATEST(0, outstanding_amount - v_return.credit_adjustment),
                return_adjustment  = COALESCE(return_adjustment, 0) + v_return.credit_adjustment,
                updated_at         = NOW() AT TIME ZONE 'Asia/Dhaka'
            WHERE sale_id = v_return.sale_id;
        END IF;

        UPDATE sales
        SET outstanding_amount = GREATEST(0, outstanding_amount - v_return.credit_adjustment),
            return_adjustment  = COALESCE(return_adjustment, 0) + v_return.credit_adjustment,
            payment_status     = CASE
                WHEN outstanding_amount - v_return.credit_adjustment <= 0
                THEN 'COMPLETED'::payment_status_enum
                ELSE payment_status
            END,
            updated_at = NOW() AT TIME ZONE 'Asia/Dhaka'
        WHERE id = v_return.sale_id;
    END IF;

    RETURN jsonb_build_object('code', 'SUCCESS', 'message', 'Return completed successfully');

EXCEPTION
    WHEN SQLSTATE '55P03' THEN
        RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'System is busy, please try again', 'hint', 'Another operation is in progress');
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'INTERNAL_ERROR', 'message', SQLERRM);
END;
$$;


ALTER FUNCTION public.finalize_sale_return(p_return_id uuid, p_reason text, p_notes text, p_refund_payments jsonb) OWNER TO postgres;

--
-- TOC entry 689 (class 1255 OID 23484)
-- Name: find_nearby_pharmacies(numeric, numeric, text, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.find_nearby_pharmacies(p_latitude numeric, p_longitude numeric, p_medicine_name text, p_radius numeric) RETURNS TABLE(pharmacy_id uuid, pharmacy_name text, distance_meters numeric)
    LANGUAGE sql STABLE SECURITY DEFINER
    AS $$
    SELECT 
        p.id AS pharmacy_id,
        p.name AS pharmacy_name,
        ST_Distance(
            p.location,
            ST_SetSRID(ST_MakePoint(p_longitude, p_latitude), 4326)
        ) AS distance_meters
    FROM public.pharmacies p
    JOIN public.medicines m ON p.id = m.pharmacy_id
    JOIN public.stocks s ON m.id = s.medicine_id
    WHERE m.name ILIKE '%' || p_medicine_name || '%'
        AND s.quantity_in_strips > 0
        AND s.is_active
        AND s.deleted_at IS NULL
        AND p.is_active
        AND p.deleted_at IS NULL
        AND ST_DWithin(
            p.location,
            ST_SetSRID(ST_MakePoint(p_longitude, p_latitude), 4326),
            p_radius
        )
    ORDER BY distance_meters;
$$;


ALTER FUNCTION public.find_nearby_pharmacies(p_latitude numeric, p_longitude numeric, p_medicine_name text, p_radius numeric) OWNER TO postgres;

--
-- TOC entry 1415 (class 1255 OID 195546)
-- Name: get_active_sale_draft(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_active_sale_draft(p_pharmacy_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$DECLARE
    v_current_user_id UUID;
BEGIN
    v_current_user_id := auth.uid();

    IF v_current_user_id IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated'
        );
    END IF;

    IF p_pharmacy_id IS NULL THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Pharmacy ID is required'
        );
    END IF;

    IF NOT user_has_permission(v_current_user_id, p_pharmacy_id, 'sale.view') THEN
        RETURN json_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'Permission denied'
        );
    END IF;

    RETURN COALESCE(
        (
            SELECT json_build_object(
                'code', 'SUCCESS',
                'message', 'Pending sale retrieved',
                'details', json_build_object(
                    'id', s.id,
                    'sale_number', s.sale_number,
                    'customer_id', s.customer_id,
                    'subtotal', ROUND(COALESCE(s.subtotal, 0.00), 2),
                    'discount_amount', ROUND(COALESCE(s.discount_amount, 0.00), 2),
                    'total_amount', ROUND(COALESCE(s.total_amount, 0.00), 2),
                    'sale_status', s.sale_status,
                    'created_at', s.created_at,
                    'updated_at', s.updated_at
                )
            )
            FROM sales s
            WHERE s.pharmacy_id = p_pharmacy_id
              AND s.user_id = v_current_user_id
              AND s.sale_status = 'DRAFT'
              AND s.deleted_at IS NULL
            ORDER BY s.created_at DESC
            LIMIT 1
        ),
        json_build_object(
            'code', 'NO_PENDING_SALE',
            'message', 'No pending sale found'
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        RETURN json_build_object(
            'code', 'INTERNAL_ERROR',
            'message', 'Failed to retrieve pending sale',
            'details', json_build_object(
                'error', SQLERRM,
                'pharmacy_id', p_pharmacy_id
            )
        );
END;$$;


ALTER FUNCTION public.get_active_sale_draft(p_pharmacy_id uuid) OWNER TO postgres;

--
-- TOC entry 7201 (class 0 OID 0)
-- Dependencies: 1415
-- Name: FUNCTION get_active_sale_draft(p_pharmacy_id uuid); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.get_active_sale_draft(p_pharmacy_id uuid) IS 'Retrieves the current user''s pending (DRAFT) sale with all items. Used to resume an incomplete sale.';


--
-- TOC entry 569 (class 1255 OID 255365)
-- Name: get_activity_log_history(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_activity_log_history(p_pharmacy_id uuid, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0) RETURNS json
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE
    v_result JSON;
BEGIN
    SELECT COALESCE(json_agg(row_to_json(t)), '[]'::json)
    INTO v_result
    FROM (
        SELECT 
            id::TEXT, -- Cast UUID to text for JSON
            activity_type AS type,
            message AS description,
            created_at,
            metadata
        FROM activity_logs
        WHERE pharmacy_id = p_pharmacy_id
        ORDER BY created_at DESC
        LIMIT p_limit
        OFFSET p_offset
    ) t;

    RETURN v_result;
END;
$$;


ALTER FUNCTION public.get_activity_log_history(p_pharmacy_id uuid, p_limit integer, p_offset integer) OWNER TO postgres;

--
-- TOC entry 857 (class 1255 OID 242096)
-- Name: get_all_categories(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_all_categories(p_type text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$DECLARE
    v_categories_json JSON;
BEGIN
    SELECT COALESCE(json_agg(t.*), '[]'::json) INTO v_categories_json
    FROM (
        SELECT 
            id, 
            name, 
            slug, 
            type, 
            description 
        FROM public.categories
        WHERE is_active = true
          AND (p_type IS NULL OR type ILIKE p_type) -- Use ILIKE for case-insensitive matching
        ORDER BY name
    ) t;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Categories retrieved successfully',
        'hint', NULL,
        'details', v_categories_json
    );
END;$$;


ALTER FUNCTION public.get_all_categories(p_type text) OWNER TO postgres;

--
-- TOC entry 652 (class 1255 OID 97207)
-- Name: get_all_customers(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_all_customers(p_pharmacy_id uuid) RETURNS TABLE(id uuid, pharmacy_id uuid, name text, phone text, email text, address text, notes text, created_at timestamp with time zone, updated_at timestamp with time zone, color_label text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$BEGIN
    RETURN QUERY
    SELECT 
        c.id,
        c.pharmacy_id,
        c.name,
        c.phone,
        c.email,
        c.address,
        c.notes,
        c.created_at,
        c.updated_at,
        c.color_label
    FROM customers c
    WHERE c.pharmacy_id = p_pharmacy_id 
    AND c.is_deleted = false
    ORDER BY c.updated_at DESC, c.created_at DESC;
END;$$;


ALTER FUNCTION public.get_all_customers(p_pharmacy_id uuid) OWNER TO postgres;

--
-- TOC entry 973 (class 1255 OID 164158)
-- Name: get_customer_details(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_customer_details(p_customer_id uuid, p_pharmacy_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$DECLARE
    v_current_user_id UUID;
    v_result JSON;
BEGIN
    v_current_user_id := auth.uid();

    IF v_current_user_id IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint', 'Please log in',
            'details', NULL
        );
    END IF;

    IF p_customer_id IS NULL OR p_pharmacy_id IS NULL THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Customer ID and Pharmacy ID are required',
            'hint', NULL,
            'details', NULL
        );
    END IF;

    IF NOT user_has_permission(v_current_user_id, p_pharmacy_id, 'customers.view') THEN
        RETURN json_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'You do not have permission to view customers',
            'hint', 'Contact your administrator for access',
            'details', NULL
        );
    END IF;

    WITH customer_data AS (
        SELECT 
            c.id,
            c.pharmacy_id,
            c.name,
            c.phone,
            c.email,
            c.address,
            c.notes,
            c.color_label,
            c.created_at,
            c.updated_at
        FROM customers c
        WHERE c.id = p_customer_id
          AND c.pharmacy_id = p_pharmacy_id
          AND c.deleted_at IS NULL
    ),
    
    credit_summary AS (
        SELECT
            COUNT(*) AS total_credits,
            COUNT(*) FILTER (
                WHERE outstanding_amount > 0 
                AND status IN ('ACTIVE', 'OVERDUE')
            ) AS active_credits,
            COUNT(*) FILTER (
                WHERE outstanding_amount > 0 
                AND paid_amount = 0
                AND status IN ('ACTIVE', 'OVERDUE')
            ) AS outstanding_count,
            COUNT(*) FILTER (
                WHERE outstanding_amount > 0 
                AND paid_amount > 0 
                AND paid_amount < credit_amount
                AND status IN ('ACTIVE', 'OVERDUE')
            ) AS partial_count,
            COUNT(*) FILTER (
                WHERE status = 'PAID' 
                OR (outstanding_amount = 0 AND paid_amount = credit_amount)
            ) AS paid_count,
            COALESCE(SUM(credit_amount), 0) AS total_credit_amount,
            COALESCE(SUM(paid_amount), 0) AS total_paid_amount,
            COALESCE(SUM(outstanding_amount), 0) AS total_outstanding,
            MIN(due_date) FILTER (
                WHERE outstanding_amount > 0 
                AND due_date IS NOT NULL
                AND status IN ('ACTIVE', 'OVERDUE')
            ) AS earliest_due_date,
            MAX(due_date) FILTER (
                WHERE outstanding_amount > 0 
                AND due_date IS NOT NULL
                AND status IN ('ACTIVE', 'OVERDUE')
            ) AS latest_due_date,
            COALESCE(SUM(outstanding_amount), 0) > 0 AS has_outstanding
        FROM customer_credits
        WHERE customer_id = p_customer_id
          AND pharmacy_id = p_pharmacy_id
          AND status != 'CANCELLED'
    ),
    
    purchase_summary AS (
        SELECT
            COUNT(DISTINCT s.id) AS total_purchases,
            COALESCE(SUM(s.total_amount), 0) AS total_spent,
            COALESCE(AVG(s.total_amount), 0) AS avg_purchase_value,
            MAX(s.sale_date) AS last_purchase_date,
            MIN(s.sale_date) AS first_purchase_date,
            GREATEST(COUNT(DISTINCT DATE_TRUNC('month', s.sale_date)), 1) AS months_active,
            COUNT(DISTINCT s.id) FILTER (WHERE s.sale_date >= CURRENT_DATE - INTERVAL '30 days') AS purchases_last_30_days
        FROM sales s
        WHERE s.customer_id = p_customer_id
          AND s.pharmacy_id = p_pharmacy_id
          AND s.sale_status = 'COMPLETED'
          AND s.deleted_at IS NULL
    ),
    
    purchase_history_monthly AS (
        SELECT
            DATE_TRUNC('month', s.sale_date) AS month,
            TO_CHAR(s.sale_date, 'Mon') AS month_label,
            COUNT(DISTINCT s.id) AS purchase_count,
            COALESCE(SUM(s.total_amount), 0) AS total_amount
        FROM sales s
        WHERE s.customer_id = p_customer_id
          AND s.pharmacy_id = p_pharmacy_id
          AND s.sale_status = 'COMPLETED'
          AND s.deleted_at IS NULL
          AND s.sale_date >= CURRENT_DATE - INTERVAL '6 months'
        GROUP BY DATE_TRUNC('month', s.sale_date), TO_CHAR(s.sale_date, 'Mon')
        ORDER BY month DESC
    ),
    
    loyalty_calculation AS (
        SELECT
            ps.total_purchases,
            ps.total_spent,
            ps.months_active,
            ps.purchases_last_30_days,
            ps.avg_purchase_value,
            cs.total_outstanding,
            cs.has_outstanding,
            CASE 
                WHEN cs.total_credit_amount > 0 
                THEN (cs.total_paid_amount / cs.total_credit_amount) * 100
                ELSE 100
            END AS payment_reliability,
            CASE
                WHEN ps.total_spent >= 100000 AND ps.total_purchases >= 50 AND ps.months_active >= 12 
                    AND (cs.total_outstanding = 0 OR (cs.total_paid_amount / NULLIF(cs.total_credit_amount, 0)) >= 0.95)
                THEN 'ELITE'
                WHEN ps.total_spent >= 50000 AND ps.total_purchases >= 30 AND ps.months_active >= 6
                    AND (cs.total_outstanding = 0 OR (cs.total_paid_amount / NULLIF(cs.total_credit_amount, 0)) >= 0.90)
                THEN 'PLATINUM'
                WHEN ps.total_spent >= 25000 AND ps.total_purchases >= 15 AND ps.months_active >= 3
                    AND (cs.total_outstanding = 0 OR (cs.total_paid_amount / NULLIF(cs.total_credit_amount, 0)) >= 0.85)
                THEN 'GOLD'
                WHEN ps.total_spent >= 10000 AND ps.total_purchases >= 8
                THEN 'SILVER'
                WHEN ps.total_spent >= 2000 AND ps.total_purchases >= 3
                THEN 'BRONZE'
                ELSE 'BASIC'
            END AS loyalty_tier,
            CASE
                WHEN ps.total_spent >= 100000 THEN '#9333EA'
                WHEN ps.total_spent >= 50000 THEN '#3B82F6'
                WHEN ps.total_spent >= 25000 THEN '#F59E0B'
                WHEN ps.total_spent >= 10000 THEN '#6B7280'
                WHEN ps.total_spent >= 2000 THEN '#CD7F32'
                ELSE '#9CA3AF'
            END AS tier_color,
            CASE
                WHEN ps.purchases_last_30_days >= 5 THEN 'Very Active'
                WHEN ps.purchases_last_30_days >= 2 THEN 'Active'
                WHEN ps.purchases_last_30_days >= 1 THEN 'Moderate'
                WHEN ps.total_purchases > 0 THEN 'Low Activity'
                ELSE 'Inactive'
            END AS activity_status
        FROM purchase_summary ps
        CROSS JOIN credit_summary cs
    ),
    
    growth_metrics AS (
        SELECT
            CASE 
                WHEN LAG(monthly_spent) OVER (ORDER BY month) > 0 
                THEN ROUND(
                    ((monthly_spent - LAG(monthly_spent) OVER (ORDER BY month)) / 
                     LAG(monthly_spent) OVER (ORDER BY month)) * 100, 
                    2
                )
                ELSE 0 
            END AS growth_percent
        FROM (
            SELECT 
                DATE_TRUNC('month', s.sale_date) AS month,
                SUM(s.total_amount) AS monthly_spent
            FROM sales s
            WHERE s.customer_id = p_customer_id
              AND s.pharmacy_id = p_pharmacy_id
              AND s.sale_status = 'COMPLETED'
              AND s.deleted_at IS NULL
              AND s.sale_date >= CURRENT_DATE - INTERVAL '2 months'
            GROUP BY DATE_TRUNC('month', s.sale_date)
            ORDER BY month DESC
            LIMIT 2
        ) sub
        ORDER BY month DESC
        LIMIT 1
    )
    
    SELECT json_build_object(
        'code', 'SUCCESS',
        'message', 'Customer fetched successfully',
        'hint', NULL,
        'details', json_build_object(
            
            'customer', (
                SELECT json_build_object(
                    'id', cd.id,
                    'pharmacy_id', cd.pharmacy_id,
                    'name', cd.name,
                    'phone', cd.phone,
                    'email', cd.email,
                    'address', cd.address,
                    'notes', cd.notes,
                    'color_label', cd.color_label,
                    'created_at', cd.created_at,
                    'updated_at', cd.updated_at
                )
                FROM customer_data cd
            ),
            
            'financial_summary', json_build_object(
                'total_credit', ROUND((SELECT total_credit_amount FROM credit_summary), 2),
                'total_paid', ROUND((SELECT total_paid_amount FROM credit_summary), 2),
                'outstanding', ROUND((SELECT total_outstanding FROM credit_summary), 2),
                'has_outstanding', (SELECT has_outstanding FROM credit_summary),
                'payment_percentage', ROUND(
                    CASE 
                        WHEN (SELECT total_credit_amount FROM credit_summary) > 0 
                        THEN ((SELECT total_paid_amount FROM credit_summary) / (SELECT total_credit_amount FROM credit_summary)) * 100
                        ELSE 0
                    END, 2
                ),
                'status_breakdown', json_build_object(
                    'outstanding', (SELECT outstanding_count FROM credit_summary),
                    'partial', (SELECT partial_count FROM credit_summary),
                    'paid', (SELECT paid_count FROM credit_summary)
                ),
                'due_dates', CASE 
                    WHEN (SELECT has_outstanding FROM credit_summary) THEN json_build_object(
                        'earliest', (SELECT earliest_due_date FROM credit_summary),
                        'latest', (SELECT latest_due_date FROM credit_summary)
                    )
                    ELSE NULL
                END
            ),
            
            'purchase_statistics', json_build_object(
                'total_purchases', (SELECT total_purchases FROM purchase_summary),
                'total_spent', ROUND((SELECT total_spent FROM purchase_summary), 2),
                'average_purchase', ROUND((SELECT avg_purchase_value FROM purchase_summary), 2),
                'first_purchase_date', (SELECT first_purchase_date FROM purchase_summary),
                'last_purchase_date', (SELECT last_purchase_date FROM purchase_summary),
                'months_active', (SELECT months_active FROM purchase_summary)
            ),
            
            'loyalty_status', (
                SELECT json_build_object(
                    'tier', lc.loyalty_tier,
                    'tier_color', lc.tier_color,
                    'activity_status', lc.activity_status,
                    'payment_reliability', ROUND(lc.payment_reliability, 2)
                )
                FROM loyalty_calculation lc
            ),
            
            'purchase_history', json_build_object(
                'last_6_months', COALESCE((
                    SELECT json_agg(json_build_object(
                        'month', phm.month,
                        'label', phm.month_label,
                        'purchase_count', phm.purchase_count,
                        'total_amount', ROUND(phm.total_amount, 2)
                    ) ORDER BY phm.month)
                    FROM purchase_history_monthly phm
                ), '[]'::json),
                'growth_trend', COALESCE((SELECT growth_percent FROM growth_metrics), 0)
            ),
            
            'insights', json_build_object(
                'is_high_value', (SELECT total_spent >= 50000 FROM purchase_summary),
                'is_frequent', (SELECT total_purchases >= 20 FROM purchase_summary),
                'is_recent', (SELECT last_purchase_date >= CURRENT_DATE - INTERVAL '30 days' FROM purchase_summary),
                'has_credit_risk', (
                    SELECT has_outstanding AND 
                           (total_outstanding / NULLIF(total_credit_amount, 0)) > 0.5
                    FROM credit_summary
                ),
                'payment_score', ROUND((SELECT payment_reliability FROM loyalty_calculation), 0)
            )
        )
    ) INTO v_result
    FROM customer_data;

    RETURN v_result;
END;$$;


ALTER FUNCTION public.get_customer_details(p_customer_id uuid, p_pharmacy_id uuid) OWNER TO postgres;

