--
-- TOC entry 1435 (class 1255 OID 255306)
-- Name: get_dashboard_summary(uuid, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_dashboard_summary(p_pharmacy_id uuid, p_date date DEFAULT CURRENT_DATE) RETURNS json
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$DECLARE
    v_result JSON;
BEGIN
    IF p_pharmacy_id IS NULL THEN
        RAISE EXCEPTION 'pharmacy_id is required';
    END IF;

    WITH 
    active_banners AS (
        SELECT 
            id, message, type, priority 
        FROM system_banners 
        WHERE is_active = true 
          AND (expires_at IS NULL OR expires_at > now())
        ORDER BY priority DESC, created_at DESC
    ),

    per_item_stock AS (
        SELECT
            i.id AS inventory_id,
            i.reorder_level,
            i.created_at AS item_created_at,
            COALESCE(batch_agg.total_qty, 0) AS total_available_qty,
            COALESCE(batch_agg.has_batches, FALSE) AS has_any_batches,
            COALESCE(batch_agg.has_expiring, FALSE) AS has_expiring_batch,
            COALESCE(batch_agg.has_expired, FALSE) AS has_expired_batch
        FROM inventory i
        LEFT JOIN LATERAL (
            SELECT
                SUM(
                    CASE 
                        WHEN ib.current_quantity > 0
                             AND (ib.expiry_date IS NULL OR ib.expiry_date > p_date)
                        THEN ib.current_quantity 
                        ELSE 0 
                    END
                ) AS total_qty,
                bool_or(TRUE) AS has_batches,
                bool_or(
                    ib.current_quantity > 0
                    AND ib.expiry_date IS NOT NULL
                    AND ib.expiry_date >= p_date
                    AND ib.expiry_date <= (p_date + interval '30 days')
                ) AS has_expiring,
                bool_or(
                    ib.current_quantity > 0
                    AND ib.expiry_date IS NOT NULL
                    AND ib.expiry_date < p_date
                ) AS has_expired
            FROM inventory_batches ib
            WHERE ib.inventory_id = i.id
              AND ib.deleted_at IS NULL
        ) batch_agg ON TRUE
        WHERE i.pharmacy_id = p_pharmacy_id
          AND i.deleted_at IS NULL
          AND i.is_active = true
    ),

    inventory_stats AS (
        SELECT
            COUNT(*) AS total_items,

            COUNT(*) FILTER (
                WHERE total_available_qty > 0
                  AND total_available_qty <= reorder_level
            ) AS low_stock_items,

            COUNT(*) FILTER (
                WHERE has_expiring_batch = TRUE
            ) AS expiring_items,

            COUNT(*) FILTER (
                WHERE has_expired_batch = TRUE
            ) AS expired_items,

            COUNT(*) FILTER (
                WHERE total_available_qty = 0
            ) AS out_of_stock_items

        FROM per_item_stock
    ),

    recent_activity AS (
        SELECT 
            id::TEXT,
            activity_type AS type,
            message AS description,
            created_at,
            metadata
        FROM activity_logs
        WHERE pharmacy_id = p_pharmacy_id
        ORDER BY created_at DESC
        LIMIT 10
    )

    SELECT json_build_object(
        'banners', COALESCE((SELECT json_agg(ab) FROM active_banners ab), '[]'::json),
        'inventory', (
            SELECT json_build_object(
                'total_items', COALESCE(total_items, 0),
                'low_stock_items', COALESCE(low_stock_items, 0),
                'expiring_items', COALESCE(expiring_items, 0),
                'expired_items', COALESCE(expired_items, 0),
                'out_of_stock_items', COALESCE(out_of_stock_items, 0)
            ) FROM inventory_stats
        ),
        'financials', NULL,
        'recent_activity', COALESCE((SELECT json_agg(ra) FROM recent_activity ra), '[]'::json)
    ) INTO v_result;

    RETURN v_result;
END;$$;


ALTER FUNCTION public.get_dashboard_summary(p_pharmacy_id uuid, p_date date) OWNER TO postgres;

--
-- TOC entry 1274 (class 1255 OID 274526)
-- Name: get_generic_suggestions(text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_generic_suggestions(p_search_term text, p_limit integer DEFAULT 50) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_results JSON;
    v_trimmed TEXT;
BEGIN
    IF auth.uid() IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'Authentication required');
    END IF;

    v_trimmed := LOWER(TRIM(COALESCE(p_search_term, '')));

    IF v_trimmed = '' THEN
        -- Return top entries alphabetically when no search term
        SELECT COALESCE(json_agg(t), '[]'::json) INTO v_results
        FROM (
            SELECT id, name
            FROM public.inventory_generics
            ORDER BY name ASC
            LIMIT LEAST(p_limit, 50)
        ) t;
    ELSE
        SELECT COALESCE(json_agg(t), '[]'::json) INTO v_results
        FROM (
            SELECT id, name
            FROM public.inventory_generics
            WHERE name ILIKE '%' || v_trimmed || '%'
            ORDER BY
                CASE WHEN LOWER(name) = v_trimmed THEN 0
                     WHEN LOWER(name) LIKE v_trimmed || '%' THEN 1
                     ELSE 2
                END,
                name ASC
            LIMIT LEAST(p_limit, 50)
        ) t;
    END IF;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Suggestions retrieved',
        'details', v_results
    );
EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object('code', 'ERROR', 'message', SQLERRM);
END;
$$;


ALTER FUNCTION public.get_generic_suggestions(p_search_term text, p_limit integer) OWNER TO postgres;

--
-- TOC entry 890 (class 1255 OID 267503)
-- Name: get_inventory_batch_list(uuid, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_inventory_batch_list(p_inventory_id uuid, p_include_zero_qty boolean DEFAULT false) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_result jsonb;
    v_primary_unit text;
    v_secondary_unit text;
    v_conversion_rate integer;
    v_inventory_name text;
    v_inventory_type text;
    v_pharmacy_id uuid;
    v_user_id uuid := auth.uid();
BEGIN
    -- Get common inventory details once
    SELECT
        i.pharmacy_id,
        i.primary_unit,
        i.secondary_unit,
        i.conversion_rate,
        COALESCE(i.brand, i.name),
        i.type::text
    INTO v_pharmacy_id, v_primary_unit, v_secondary_unit, v_conversion_rate, v_inventory_name, v_inventory_type
    FROM inventory i
    WHERE i.id = p_inventory_id;

    IF v_pharmacy_id IS NULL THEN
        RETURN json_build_object('code', 'INVENTORY_NOT_FOUND', 'message', 'Inventory not found');
    END IF;

    -- Check permissions
    IF NOT user_has_permission(v_user_id, v_pharmacy_id, 'stock.view') THEN
        RETURN json_build_object('code', 'ACCESS_DENIED', 'message', 'You do not have permission to view stock');
    END IF;

    -- Fetch batches with sub-query for sorting
    SELECT COALESCE(jsonb_agg(batch_data ORDER BY sort_order, expiry_order, created_order), '[]'::jsonb)
    INTO v_result
    FROM (
        SELECT
            jsonb_build_object(
                'id', ib.id::text,
                'inventory_id', ib.inventory_id::text,
                'batch_number', ib.batch_number, -- Keep as null if null in DB
                'expiry_date', CASE WHEN ib.expiry_date IS NOT NULL THEN TO_CHAR(ib.expiry_date, 'YYYY-MM-DD') ELSE NULL END,
                'purchase_price', COALESCE(ib.purchase_price, 0),
                'selling_price', COALESCE(ib.selling_price, 0),
                'original_quantity', COALESCE(ib.initial_quantity, 0),
                'current_quantity', COALESCE(ib.current_quantity, 0),
                'allocated_quantity', COALESCE(ib.reserved_quantity, 0),
                'available_quantity', GREATEST(COALESCE(ib.current_quantity, 0) - COALESCE(ib.reserved_quantity, 0), 0),
                'status',
                CASE
                    WHEN ib.current_quantity = 0 THEN 'SOLD_OUT'
                    WHEN ib.expiry_date IS NOT NULL AND ib.expiry_date <= (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE THEN 'EXPIRED'
                    WHEN ib.expiry_date IS NOT NULL AND ib.expiry_date <= (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE + INTERVAL '30 days' THEN 'NEAR_EXPIRY'
                    ELSE ib.status::text
                END,
                'shelf_location', ib.shelf_location,
                'created_at', TO_CHAR(ib.created_at, 'YYYY-MM-DD"T"HH24:MI:SS"Z"'),
                'updated_at', TO_CHAR(ib.updated_at, 'YYYY-MM-DD"T"HH24:MI:SS"Z"'),
                'inventory_name', v_inventory_name,
                'primary_unit', v_primary_unit,
                'secondary_unit', v_secondary_unit,
                'conversion_rate', v_conversion_rate,
                'inventory_type', v_inventory_type,
                'purchase_number', p.purchase_number,
                'purchase_date', TO_CHAR(p.purchase_date, 'YYYY-MM-DD'),
                'supplier_name', s.name
            ) AS batch_data,
            CASE
                WHEN ib.expiry_date IS NOT NULL AND ib.expiry_date <= (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE THEN 5
                WHEN ib.current_quantity > 0 AND (ib.expiry_date IS NULL OR ib.expiry_date > (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE + INTERVAL '30 days') THEN 1
                WHEN ib.expiry_date IS NOT NULL AND ib.expiry_date <= (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE + INTERVAL '30 days' AND ib.expiry_date > (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE THEN 2
                WHEN ib.current_quantity <= 0 THEN 6
                ELSE 5
            END AS sort_order,
            ib.expiry_date AS expiry_order,
            ib.created_at AS created_order
        FROM inventory_batches ib
        LEFT JOIN purchases p ON ib.purchase_id = p.id
        LEFT JOIN suppliers s ON p.supplier_id = s.id
        WHERE ib.inventory_id = p_inventory_id
          AND ib.deleted_at IS NULL
          AND (p_include_zero_qty OR ib.current_quantity > 0)
    ) batches;

    RETURN json_build_object('code', 'SUCCESS', 'message', 'Batches fetched successfully', 'details', v_result);
END;
$$;


ALTER FUNCTION public.get_inventory_batch_list(p_inventory_id uuid, p_include_zero_qty boolean) OWNER TO postgres;

--
-- TOC entry 812 (class 1255 OID 248423)
-- Name: get_inventory_batches(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_inventory_batches(p_inventory_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_result jsonb;
    v_primary_unit text;
    v_secondary_unit text;
    v_conversion_rate integer;
    v_inventory_name text;
    v_inventory_type text;
    v_pharmacy_id uuid;
    v_user_id uuid := auth.uid();
BEGIN
    SELECT 
        i.pharmacy_id, 
        i.primary_unit, 
        i.secondary_unit,
        i.conversion_rate, 
        COALESCE(i.brand, i.name),
        i.type::text
    INTO v_pharmacy_id, v_primary_unit, v_secondary_unit, v_conversion_rate, v_inventory_name, v_inventory_type
    FROM inventory i
    WHERE i.id = p_inventory_id;

    IF v_pharmacy_id IS NULL THEN
        RETURN json_build_object('code', 'INVENTORY_NOT_FOUND', 'message', 'Inventory not found');
    END IF;

    IF NOT user_has_permission(v_user_id, v_pharmacy_id, 'stock.view') THEN
        RETURN json_build_object('code', 'ACCESS_DENIED', 'message', 'You do not have permission to view stock');
    END IF;

    SELECT COALESCE(jsonb_agg(batch_data ORDER BY sort_order, expiry_order, created_order), '[]'::jsonb)
    INTO v_result
    FROM (
        SELECT 
            jsonb_build_object(
                'id', ib.id::text,
                'inventory_id', ib.inventory_id::text,
                'batch_number', COALESCE(ib.batch_number, 'N/A'),
                'expiry_date', CASE WHEN ib.expiry_date IS NOT NULL THEN TO_CHAR(ib.expiry_date, 'YYYY-MM-DD') ELSE NULL END,
                'purchase_price', COALESCE(ib.purchase_price, 0),
                'selling_price', COALESCE(ib.selling_price, 0),
                'original_quantity', COALESCE(ib.initial_quantity, 0),
                'current_quantity', COALESCE(ib.current_quantity, 0),
                'allocated_quantity', COALESCE(ib.reserved_quantity, 0),
                'available_quantity', GREATEST(COALESCE(ib.current_quantity, 0) - COALESCE(ib.reserved_quantity, 0), 0),
                'status', 
                -- Dynamic Status Calculation
                CASE 
                    WHEN ib.current_quantity = 0 THEN 'SOLD_OUT'
                    WHEN ib.expiry_date IS NOT NULL AND ib.expiry_date <= (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE THEN 'EXPIRED'
                    WHEN ib.expiry_date IS NOT NULL AND ib.expiry_date <= (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE + INTERVAL '30 days' THEN 'NEAR_EXPIRY'
                    ELSE ib.status::text 
                END,
                'shelf_location', ib.shelf_location,
                'created_at', TO_CHAR(ib.created_at, 'YYYY-MM-DD"T"HH24:MI:SS"Z"'),
                'updated_at', TO_CHAR(ib.updated_at, 'YYYY-MM-DD"T"HH24:MI:SS"Z"'),
                'inventory_name', v_inventory_name,
                'primary_unit', v_primary_unit,
                'secondary_unit', v_secondary_unit,
                'conversion_rate', v_conversion_rate,
                'inventory_type', v_inventory_type,
                'purchase_number', p.purchase_number,
                'purchase_date', TO_CHAR(p.purchase_date, 'YYYY-MM-DD'),
                'supplier_name', s.name
            ) AS batch_data,
            -- Sort Order based on Dynamic Status
            CASE 
                WHEN ib.expiry_date IS NOT NULL AND ib.expiry_date <= (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE THEN 5 -- EXPIRED (push to bottom if desired? No, user usually wants to see problems. Let's keep logic: Active=1, Near=2, Low=3, Reserved=4, Expired/Other=5)
                -- Actually, usually Expired should be conspicuous. Let's stick to standard priority or what was there.
                -- Original: Active=1, Near=2, Low=3, Reserved=4, Else=5.
                -- Let's make EXPIRED = 5 to keep it at bottom? Or top?
                -- If the user wants to see stock to sell, Active is 1. 
                -- If they want to manage stock, Expired is important. 
                -- Let's keep existing order: Active first.
                WHEN ib.current_quantity > 0 AND (ib.expiry_date IS NULL OR ib.expiry_date > (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE + INTERVAL '30 days') THEN 1 -- ACTIVE
                WHEN ib.expiry_date IS NOT NULL AND ib.expiry_date <= (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE + INTERVAL '30 days' AND ib.expiry_date > (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE THEN 2 -- NEAR_EXPIRY
                WHEN ib.current_quantity <= 0 THEN 6 -- SOLD_OUT
                ELSE 5 -- EXPIRED or others
            END AS sort_order,
            ib.expiry_date AS expiry_order,
            ib.created_at AS created_order
        FROM inventory_batches ib
        LEFT JOIN purchases p ON ib.purchase_id = p.id
        LEFT JOIN suppliers s ON p.supplier_id = s.id
        WHERE ib.inventory_id = p_inventory_id
          AND ib.deleted_at IS NULL
          AND ib.current_quantity > 0
    ) batches;

    RETURN json_build_object('code', 'SUCCESS', 'message', 'Batches fetched successfully', 'details', v_result);
END;
$$;


