--
-- TOC entry 1054 (class 1255 OID 256839)
-- Name: get_inventory_item(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_inventory_item(p_pharmacy_id uuid, p_id uuid DEFAULT NULL::uuid, p_item_code text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_item_json JSON;
BEGIN
    IF auth.uid() IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'Authentication required',
            'hint', 'Please log in to continue',
            'details', NULL
        );
    END IF;

    IF p_id IS NULL AND p_item_code IS NULL THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Either item ID or item code is required',
            'hint', 'Provide p_id or p_item_code',
            'details', NULL
        );
    END IF;

    SELECT to_json(result.*) INTO v_item_json
    FROM (
        SELECT
            i.id,
            i.pharmacy_id,
            i.type,
            i.category_id,
            c.name as category_name,
            i.name,
            i.brand,
            i.generic_id,
            ig.name as generic_name,
            i.strength,
            i.manufacturer_id,
            im.name as manufacturer,
            i.primary_unit,
            i.secondary_unit,
            i.conversion_rate,
            i.reorder_level,
            i.item_code,
            i.description,
            i.is_active,
            i.created_at,
            i.updated_at,

            -- Computed: total stock across all active batches
            COALESCE(
                (SELECT SUM(ib.current_quantity)
                 FROM public.inventory_batches ib
                 WHERE ib.inventory_id = i.id
                   AND ib.deleted_at IS NULL
                   AND ib.status = 'ACTIVE'::public.batch_status_enum),
                0
            )::int as stock_quantity,

            -- Computed: whether item has any batches
            EXISTS(
                SELECT 1 FROM public.inventory_batches ib
                WHERE ib.inventory_id = i.id
                  AND ib.deleted_at IS NULL
            ) as has_batches,

            -- Computed: can edit base unit only if no transactions exist
            NOT EXISTS (
                SELECT 1 FROM public.purchase_items WHERE inventory_id = i.id
                UNION ALL
                SELECT 1 FROM public.sale_items WHERE inventory_id = i.id
                UNION ALL
                SELECT 1 FROM public.purchase_return_items WHERE inventory_id = i.id
                UNION ALL
                SELECT 1 FROM public.sale_return_items WHERE inventory_id = i.id
            ) as can_edit_base_unit,

            -- Computed: latest selling price
            COALESCE(
                (SELECT ib.selling_price::float8
                 FROM public.inventory_batches ib
                 WHERE ib.inventory_id = i.id
                   AND ib.deleted_at IS NULL
                   AND ib.status = 'ACTIVE'::public.batch_status_enum
                 ORDER BY ib.created_at DESC
                 LIMIT 1),
                0.0
            ) as selling_price,

            -- Computed: display name
            CASE
                WHEN i.type = 'MEDICINE'::public.inventory_type_enum
                    THEN COALESCE(i.brand, 'Unknown') || ' ' || COALESCE(i.strength, '')
                ELSE COALESCE(i.name, 'Unknown Product')
            END as display_name,

            0 as priority

        FROM public.inventory i
        LEFT JOIN public.categories c ON i.category_id = c.id
        LEFT JOIN public.inventory_generics ig ON i.generic_id = ig.id
        LEFT JOIN public.inventory_manufacturers im ON i.manufacturer_id = im.id
        WHERE i.pharmacy_id = p_pharmacy_id
          AND (p_id IS NULL OR i.id = p_id)
          AND (p_item_code IS NULL OR i.item_code = p_item_code)
          AND i.deleted_at IS NULL
        LIMIT 1
    ) result;

    IF v_item_json IS NULL THEN
        RETURN json_build_object(
            'code', 'NOT_FOUND',
            'message', 'Item not found',
            'hint', 'Check if the item exists and is active',
            'details', NULL
        );
    END IF;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Item retrieved successfully',
        'hint', NULL,
        'details', v_item_json
    );

EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object(
        'code', 'ERROR',
        'message', 'Failed to fetch inventory item: ' || SQLERRM,
        'hint', 'An unexpected error occurred',
        'details', json_build_object('sql_state', SQLSTATE)
    );
END;
$$;


