--
-- TOC entry 1003 (class 1255 OID 271349)
-- Name: get_inventory_items(uuid, integer, integer, text, text, text, text, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_inventory_items(p_pharmacy_id uuid, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0, p_search text DEFAULT NULL::text, p_category_name text DEFAULT NULL::text, p_type text DEFAULT NULL::text, p_manufacturer text DEFAULT NULL::text, p_export_all boolean DEFAULT false) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_items_json JSON;
    v_total_count INTEGER;
    v_search_term TEXT;
BEGIN
    IF auth.uid() IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'Authentication required');
    END IF;

    v_search_term := NULLIF(TRIM(p_search), '');

    -- Count + fetch with JOINed names
    SELECT
        COALESCE(json_agg(t), '[]'::json),
        (SELECT count(*) FROM inventory i
         LEFT JOIN public.categories c ON i.category_id = c.id
         LEFT JOIN public.inventory_generics ig ON i.generic_id = ig.id
         LEFT JOIN public.inventory_manufacturers im ON i.manufacturer_id = im.id
         WHERE i.pharmacy_id = p_pharmacy_id
           AND i.deleted_at IS NULL
           AND (v_search_term IS NULL OR
                i.name ILIKE '%' || v_search_term || '%' OR
                i.brand ILIKE '%' || v_search_term || '%' OR
                ig.name ILIKE '%' || v_search_term || '%' OR
                i.item_code ILIKE v_search_term || '%')
           AND (p_category_name IS NULL OR c.name = p_category_name)
           AND (p_type IS NULL OR i.type::text ILIKE p_type)
           AND (p_manufacturer IS NULL OR im.name = p_manufacturer)
        )
    INTO v_items_json, v_total_count
    FROM (
        SELECT
            i.id,
            i.pharmacy_id,
            i.type,
            i.category_id,
            c.name as category_name,
            i.name,
            i.brand,
            i.generic_id,
            ig.name as generic_name,
            i.strength,
            i.manufacturer_id,
            im.name as manufacturer,
            i.primary_unit,
            i.secondary_unit,
            i.conversion_rate,
            i.item_code,
            i.reorder_level,
            i.is_active,
            i.created_at
        FROM public.inventory i
        LEFT JOIN public.categories c ON i.category_id = c.id
        LEFT JOIN public.inventory_generics ig ON i.generic_id = ig.id
        LEFT JOIN public.inventory_manufacturers im ON i.manufacturer_id = im.id
        WHERE i.pharmacy_id = p_pharmacy_id
          AND i.deleted_at IS NULL
          AND (v_search_term IS NULL OR
               i.name ILIKE '%' || v_search_term || '%' OR
               i.brand ILIKE '%' || v_search_term || '%' OR
               ig.name ILIKE '%' || v_search_term || '%' OR
               i.item_code ILIKE v_search_term || '%')
          AND (p_category_name IS NULL OR c.name = p_category_name)
          AND (p_type IS NULL OR i.type::text ILIKE p_type)
          AND (p_manufacturer IS NULL OR im.name = p_manufacturer)
        ORDER BY i.created_at DESC
        LIMIT CASE WHEN p_export_all = true THEN NULL ELSE p_limit END
        OFFSET CASE WHEN p_export_all = true THEN 0 ELSE p_offset END
    ) t;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Inventory retrieved successfully',
        'hint', NULL,
        'details', json_build_object(
            'items', v_items_json,
            'pagination', json_build_object(
                'total_count', v_total_count,
                'limit', p_limit,
                'offset', p_offset,
                'has_more', CASE WHEN p_export_all THEN false ELSE (p_offset + p_limit) < v_total_count END
            ),
            'metadata', json_build_object(
                'categories', COALESCE((
                    SELECT json_agg(DISTINCT name ORDER BY name)
                    FROM categories
                    WHERE type = COALESCE(p_type, type)
                      AND is_active = true
                ), '[]'::json),
                'manufacturers', COALESCE((
                    SELECT json_agg(DISTINCT im2.name ORDER BY im2.name)
                    FROM inventory i2
                    JOIN inventory_manufacturers im2 ON i2.manufacturer_id = im2.id
                    WHERE i2.pharmacy_id = p_pharmacy_id
                      AND i2.deleted_at IS NULL
                ), '[]'::json)
            ),
            'filters_applied', json_build_object(
                'search', v_search_term,
                'category', p_category_name,
                'type', p_type,
                'manufacturer', p_manufacturer
            )
        )
    );
EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object(
        'code', 'ERROR',
        'message', 'Failed to fetch inventory list: ' || SQLERRM,
        'hint', NULL,
        'details', NULL
    );
END;
$$;


ALTER FUNCTION public.get_inventory_items(p_pharmacy_id uuid, p_limit integer, p_offset integer, p_search text, p_category_name text, p_type text, p_manufacturer text, p_export_all boolean) OWNER TO postgres;

--
-- TOC entry 1356 (class 1255 OID 274527)
-- Name: get_manufacturer_suggestions(text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_manufacturer_suggestions(p_search_term text, p_limit integer DEFAULT 50) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_results JSON;
    v_trimmed TEXT;
BEGIN
    IF auth.uid() IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'Authentication required');
    END IF;

    v_trimmed := LOWER(TRIM(COALESCE(p_search_term, '')));

    IF v_trimmed = '' THEN
        SELECT COALESCE(json_agg(t), '[]'::json) INTO v_results
        FROM (
            SELECT id, name
            FROM public.inventory_manufacturers
            ORDER BY name ASC
            LIMIT LEAST(p_limit, 50)
        ) t;
    ELSE
        SELECT COALESCE(json_agg(t), '[]'::json) INTO v_results
        FROM (
            SELECT id, name
            FROM public.inventory_manufacturers
            WHERE name ILIKE '%' || v_trimmed || '%'
            ORDER BY
                CASE WHEN LOWER(name) = v_trimmed THEN 0
                     WHEN LOWER(name) LIKE v_trimmed || '%' THEN 1
                     ELSE 2
                END,
                name ASC
            LIMIT LEAST(p_limit, 50)
        ) t;
    END IF;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Suggestions retrieved',
        'details', v_results
    );
EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object('code', 'ERROR', 'message', SQLERRM);
END;
$$;


