--
-- TOC entry 1005 (class 1255 OID 183845)
-- Name: get_period_dates(text, timestamp without time zone, timestamp without time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_period_dates(p_period text, p_start_date timestamp without time zone DEFAULT NULL::timestamp without time zone, p_end_date timestamp without time zone DEFAULT NULL::timestamp without time zone) RETURNS TABLE(start_date timestamp without time zone, end_date timestamp without time zone, previous_start timestamp without time zone, previous_end timestamp without time zone, granularity text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_start timestamp;
    v_end timestamp;
    v_prev_start timestamp;
    v_prev_end timestamp;
    v_granularity text;
BEGIN
    v_end := now() AT TIME ZONE 'Asia/Dhaka';
    
    IF p_period = 'custom' THEN
        v_start := p_start_date;
        v_end := p_end_date;
        v_prev_start := v_start - (v_end - v_start);
        v_prev_end := v_start;
        
        IF (v_end - v_start) <= interval '2 days' THEN
            v_granularity := 'hourly';
        ELSIF (v_end - v_start) <= interval '31 days' THEN
            v_granularity := 'daily';
        ELSE
            v_granularity := 'monthly';
        END IF;
    ELSIF p_period = 'all' THEN
        v_start := '1970-01-01'::timestamp;
        v_end := now() AT TIME ZONE 'Asia/Dhaka';
        v_prev_start := v_start;
        v_prev_end := v_start;
        v_granularity := 'monthly';
    ELSIF p_period = 'today' THEN
        v_start := date_trunc('day', v_end);
        v_prev_start := v_start - interval '1 day';
        v_prev_end := v_start;
        v_granularity := 'hourly';
    ELSIF p_period = 'yesterday' THEN
        v_start := date_trunc('day', v_end) - interval '1 day';
        v_end := date_trunc('day', now() AT TIME ZONE 'Asia/Dhaka');
        v_prev_start := v_start - interval '1 day';
        v_prev_end := v_start;
        v_granularity := 'hourly';
    ELSE
        v_start := date_trunc('day', v_end);
        v_prev_start := v_start - interval '1 day';
        v_prev_end := v_start;
        v_granularity := 'hourly';
    END IF;
    
    RETURN QUERY SELECT v_start, v_end, v_prev_start, v_prev_end, v_granularity;
END;
$$;


ALTER FUNCTION public.get_period_dates(p_period text, p_start_date timestamp without time zone, p_end_date timestamp without time zone) OWNER TO postgres;

--
-- TOC entry 908 (class 1255 OID 271321)
-- Name: get_pharmacy_analytics(uuid, text, timestamp without time zone, timestamp without time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_pharmacy_analytics(p_pharmacy_id uuid, p_period text DEFAULT 'today'::text, p_start_date timestamp without time zone DEFAULT NULL::timestamp without time zone, p_end_date timestamp without time zone DEFAULT NULL::timestamp without time zone) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id uuid;
    v_dates RECORD;
    v_granularity text;
    v_result json;
BEGIN
    -- Authentication check
    v_user_id := auth.uid();
    
    IF v_user_id IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED', 
            'message', 'User not authenticated'
        );
    END IF;
    
    -- Permission check removed
    
    -- Validate custom period dates
    IF p_period = 'custom' AND (p_start_date IS NULL OR p_end_date IS NULL) THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT', 
            'message', 'Start and end dates required for custom period'
        );
    END IF;
    
    -- Get period dates
    SELECT * INTO v_dates FROM get_period_dates(p_period, p_start_date, p_end_date);
    
    -- Determine granularity based on date range
    v_granularity := CASE
        WHEN v_dates.end_date - v_dates.start_date <= INTERVAL '2 days' THEN 'hourly'
        WHEN v_dates.end_date - v_dates.start_date <= INTERVAL '31 days' THEN 'daily'
        ELSE 'monthly'
    END;
    
    -- Build analytics response
    WITH 
    sales_summary AS (
        SELECT
            COALESCE(SUM(CASE WHEN s.sale_date >= v_dates.start_date AND s.sale_date <= v_dates.end_date THEN s.total_amount ELSE 0 END), 0) as current_sales,
            COALESCE(SUM(CASE WHEN s.sale_date >= v_dates.previous_start AND s.sale_date < v_dates.previous_end THEN s.total_amount ELSE 0 END), 0) as previous_sales,
            COALESCE(SUM(CASE WHEN s.sale_date >= v_dates.start_date AND s.sale_date <= v_dates.end_date THEN s.paid_amount ELSE 0 END), 0) as current_collected,
            COALESCE(SUM(CASE WHEN s.sale_date >= v_dates.start_date AND s.sale_date <= v_dates.end_date THEN s.outstanding_amount ELSE 0 END), 0) as current_outstanding
        FROM sales s
        WHERE s.pharmacy_id = p_pharmacy_id
            AND s.sale_status = 'COMPLETED'
            AND s.deleted_at IS NULL
            AND s.sale_date >= v_dates.previous_start
            AND s.sale_date <= v_dates.end_date
    ),
    profit_summary AS (
        SELECT
            COALESCE(SUM(CASE WHEN s.sale_date >= v_dates.start_date AND s.sale_date <= v_dates.end_date THEN (si.unit_price - COALESCE(ib.purchase_price, 0)) * si.quantity ELSE 0 END), 0) as current_profit,
            COALESCE(SUM(CASE WHEN s.sale_date >= v_dates.previous_start AND s.sale_date < v_dates.previous_end THEN (si.unit_price - COALESCE(ib.purchase_price, 0)) * si.quantity ELSE 0 END), 0) as previous_profit
        FROM sales s
        INNER JOIN sale_items si ON si.sale_id = s.id
        LEFT JOIN inventory_batches ib ON ib.id = si.batch_id
        WHERE s.pharmacy_id = p_pharmacy_id
            AND s.sale_status = 'COMPLETED'
            AND s.deleted_at IS NULL
            AND s.sale_date >= v_dates.previous_start
            AND s.sale_date <= v_dates.end_date
    ),
    returns_summary AS (
        SELECT
            COALESCE(SUM(CASE WHEN sr.return_date >= v_dates.start_date AND sr.return_date <= v_dates.end_date THEN sr.refund_amount ELSE 0 END), 0) as current_returns,
            COALESCE(SUM(CASE WHEN sr.return_date >= v_dates.previous_start AND sr.return_date < v_dates.previous_end THEN sr.refund_amount ELSE 0 END), 0) as previous_returns
        FROM sale_returns sr
        WHERE sr.pharmacy_id = p_pharmacy_id
            AND sr.return_status != 'CANCELLED'
            AND sr.return_date >= v_dates.previous_start
            AND sr.return_date <= v_dates.end_date
    ),
    purchases_summary AS (
        SELECT
            COALESCE(SUM(CASE WHEN p.purchase_date >= v_dates.start_date AND p.purchase_date <= v_dates.end_date THEN p.total_amount ELSE 0 END), 0) as current_purchases,
            COALESCE(SUM(CASE WHEN p.purchase_date >= v_dates.previous_start AND p.purchase_date < v_dates.previous_end THEN p.total_amount ELSE 0 END), 0) as previous_purchases
        FROM purchases p
        WHERE p.pharmacy_id = p_pharmacy_id
            AND p.purchase_status = 'COMPLETED'
            AND p.purchase_date >= v_dates.previous_start
            AND p.purchase_date <= v_dates.end_date
    ),
    purchase_returns_summary AS (
        SELECT
            COALESCE(SUM(CASE WHEN pr.return_date >= v_dates.start_date AND pr.return_date <= v_dates.end_date THEN pr.total_amount ELSE 0 END), 0) as current_purchase_returns,
            COALESCE(SUM(CASE WHEN pr.return_date >= v_dates.previous_start AND pr.return_date < v_dates.previous_end THEN pr.total_amount ELSE 0 END), 0) as previous_purchase_returns
        FROM purchase_returns pr
        WHERE pr.pharmacy_id = p_pharmacy_id
            AND pr.return_date >= v_dates.previous_start
            AND pr.return_date <= v_dates.end_date
    ),
    time_series AS (
        SELECT
            CASE
                WHEN v_granularity = 'hourly' THEN date_trunc('hour', s.sale_date)
                WHEN v_granularity = 'daily' THEN date_trunc('day', s.sale_date)
                ELSE date_trunc('month', s.sale_date)
            END as time_bucket,
            CASE
                WHEN v_granularity = 'hourly' THEN to_char(date_trunc('hour', s.sale_date), 'HH24:MI')
                WHEN v_granularity = 'daily' THEN to_char(date_trunc('day', s.sale_date), 'Dy DD')
                ELSE to_char(date_trunc('month', s.sale_date), 'Mon YYYY')
            END as label,
            SUM(s.total_amount) as amount
        FROM sales s
        WHERE s.pharmacy_id = p_pharmacy_id
            AND s.sale_status = 'COMPLETED'
            AND s.deleted_at IS NULL
            AND s.sale_date >= v_dates.start_date
            AND s.sale_date <= v_dates.end_date
        GROUP BY time_bucket, label
        ORDER BY time_bucket
    ),
    category_sales AS (
        SELECT
            COALESCE(c.name, 'Uncategorized') as category,
            SUM(si.total_price) as total_amount,
            COUNT(DISTINCT si.inventory_id) as item_count,
            AVG(si.total_price) as avg_price
        FROM sales s
        INNER JOIN sale_items si ON si.sale_id = s.id
        INNER JOIN inventory i ON i.id = si.inventory_id
        LEFT JOIN inventory_generics g ON i.generic_id = g.id
        LEFT JOIN categories c ON c.id = i.category_id
        WHERE s.pharmacy_id = p_pharmacy_id
            AND s.sale_status = 'COMPLETED'
            AND s.deleted_at IS NULL
            AND s.sale_date >= v_dates.start_date
            AND s.sale_date <= v_dates.end_date
        GROUP BY c.name
        ORDER BY total_amount DESC
    ),
    total_category_sales AS (
        SELECT COALESCE(SUM(total_amount), 0) as total FROM category_sales
    ),
    top_products AS (
        SELECT
            i.id,
            i.name,
            i.brand,
            g.name AS generic_name,
            i.strength,
            COALESCE(c.name, 'Uncategorized') as category,
            i.primary_unit,
            i.secondary_unit,
            i.conversion_rate,
            SUM(si.quantity) as units_sold,
            SUM(si.total_price) as total_revenue,
            CASE WHEN SUM(si.quantity) > 0 THEN SUM(si.total_price) / SUM(si.quantity) ELSE 0 END as average_price
        FROM sales s
        INNER JOIN sale_items si ON si.sale_id = s.id
        INNER JOIN inventory i ON i.id = si.inventory_id
        LEFT JOIN inventory_generics g ON i.generic_id = g.id
        LEFT JOIN categories c ON c.id = i.category_id
        WHERE s.pharmacy_id = p_pharmacy_id
            AND s.sale_status = 'COMPLETED'
            AND s.deleted_at IS NULL
            AND s.sale_date >= v_dates.start_date
            AND s.sale_date <= v_dates.end_date
        GROUP BY i.id, i.name, i.brand, g.name, i.strength, c.name, i.primary_unit, i.secondary_unit, i.conversion_rate
        ORDER BY total_revenue DESC
        LIMIT 10
    ),
    staff_performance AS (
        SELECT
            u.id as user_id,
            u.full_name as name,
            COALESCE(ur.name, 'Staff') as role,
            u.avatar_url,
            SUM(s.total_amount) as total_sales,
            COUNT(DISTINCT s.id) as transaction_count,
            CASE WHEN COUNT(DISTINCT s.id) > 0 THEN SUM(s.total_amount) / COUNT(DISTINCT s.id) ELSE 0 END as average_sale
        FROM sales s
        INNER JOIN users u ON u.id = s.user_id
        LEFT JOIN user_pharmacies up ON up.user_id = u.id AND up.pharmacy_id = p_pharmacy_id
        LEFT JOIN user_roles ur ON ur.id = up.role_id
        WHERE s.pharmacy_id = p_pharmacy_id
            AND s.sale_status = 'COMPLETED'
            AND s.deleted_at IS NULL
            AND u.deleted_at IS NULL
            AND s.sale_date >= v_dates.start_date
            AND s.sale_date <= v_dates.end_date
        GROUP BY u.id, u.full_name, ur.name, u.avatar_url
        ORDER BY total_sales DESC
    )
    SELECT json_build_object(
        'code', 'SUCCESS',
        'message', 'Pharmacy analytics retrieved successfully',
        'hint', NULL,
        'details', json_build_object(
            'period', p_period,
            'start_date', v_dates.start_date,
            'end_date', v_dates.end_date,
            'granularity', v_granularity,
            'dashboard_metrics', json_build_object(
                'total_sales', json_build_object(
                    'amount', ROUND((SELECT current_sales FROM sales_summary)::numeric, 2),
                    'change_percent', ROUND(
                        CASE
                            WHEN (SELECT previous_sales FROM sales_summary) = 0 THEN 
                                CASE WHEN (SELECT current_sales FROM sales_summary) > 0 THEN 100 ELSE 0 END
                            ELSE 
                                (((SELECT current_sales FROM sales_summary) - (SELECT previous_sales FROM sales_summary)) / 
                                 NULLIF((SELECT previous_sales FROM sales_summary), 0)) * 100
                        END::numeric, 2
                    )
                ),
                'total_profit', json_build_object(
                    'amount', ROUND((SELECT current_profit FROM profit_summary)::numeric, 2),
                    'change_percent', ROUND(
                        CASE
                            WHEN (SELECT previous_profit FROM profit_summary) = 0 THEN 
                                CASE WHEN (SELECT current_profit FROM profit_summary) > 0 THEN 100 ELSE 0 END
                            ELSE 
                                (((SELECT current_profit FROM profit_summary) - (SELECT previous_profit FROM profit_summary)) / 
                                 NULLIF((SELECT previous_profit FROM profit_summary), 0)) * 100
                        END::numeric, 2
                    )
                ),
                'sale_returns', json_build_object(
                    'amount', ROUND((SELECT current_returns FROM returns_summary)::numeric, 2),
                    'change_percent', ROUND(
                        CASE
                            WHEN (SELECT previous_returns FROM returns_summary) = 0 THEN 
                                CASE WHEN (SELECT current_returns FROM returns_summary) > 0 THEN 100 ELSE 0 END
                            ELSE 
                                (((SELECT current_returns FROM returns_summary) - (SELECT previous_returns FROM returns_summary)) / 
                                 NULLIF((SELECT previous_returns FROM returns_summary), 0)) * 100
                        END::numeric, 2
                    )
                ),
                'new_purchases', json_build_object(
                    'amount', ROUND((SELECT current_purchases FROM purchases_summary)::numeric, 2),
                    'change_percent', ROUND(
                        CASE
                            WHEN (SELECT previous_purchases FROM purchases_summary) = 0 THEN 
                                CASE WHEN (SELECT current_purchases FROM purchases_summary) > 0 THEN 100 ELSE 0 END
                            ELSE 
                                (((SELECT current_purchases FROM purchases_summary) - (SELECT previous_purchases FROM purchases_summary)) / 
                                 NULLIF((SELECT previous_purchases FROM purchases_summary), 0)) * 100
                        END::numeric, 2
                    )
                ),
                'purchase_returns', json_build_object(
                    'amount', ROUND((SELECT current_purchase_returns FROM purchase_returns_summary)::numeric, 2),
                    'change_percent', ROUND(
                        CASE
                            WHEN (SELECT previous_purchase_returns FROM purchase_returns_summary) = 0 THEN 
                                CASE WHEN (SELECT current_purchase_returns FROM purchase_returns_summary) > 0 THEN 100 ELSE 0 END
                            ELSE 
                                (((SELECT current_purchase_returns FROM purchase_returns_summary) - (SELECT previous_purchase_returns FROM purchase_returns_summary)) / 
                                 NULLIF((SELECT previous_purchase_returns FROM purchase_returns_summary), 0)) * 100
                        END::numeric, 2
                    )
                ),
                'accounts_receivable', json_build_object(
                    'amount', ROUND((SELECT current_outstanding FROM sales_summary)::numeric, 2),
                    'change_percent', ROUND(
                        CASE
                            WHEN (SELECT current_sales FROM sales_summary) > 0 
                            THEN ((SELECT current_outstanding FROM sales_summary) / 
                                  NULLIF((SELECT current_sales FROM sales_summary), 0)) * 100
                            ELSE 0
                        END::numeric, 2
                    )
                )
            ),
            'sales_over_time', json_build_object(
                'total', ROUND((SELECT current_sales FROM sales_summary)::numeric, 2),
                'change_percent', NULL,
                'period', p_period,
                'granularity', v_granularity,
                'data_points', COALESCE((
                    SELECT json_agg(json_build_object(
                        'timestamp', time_bucket,
                        'label', label,
                        'date', time_bucket::date,
                        'amount', ROUND(amount::numeric, 2),
                        'granularity', v_granularity
                    ) ORDER BY time_bucket)
                    FROM time_series
                ), '[]'::json)
            ),
            'sales_by_category', json_build_object(
                'total_sales', ROUND((SELECT current_sales FROM sales_summary)::numeric, 2),
                'period', p_period,
                'categories', COALESCE((
                    SELECT json_agg(json_build_object(
                        'name', cs.category,
                        'amount', ROUND(cs.total_amount::numeric, 2),
                        'percentage', ROUND(
                            (cs.total_amount / NULLIF((SELECT total FROM total_category_sales), 0) * 100)::numeric, 
                            1
                        ),
                        'item_count', cs.item_count,
                        'avg_price', ROUND(cs.avg_price::numeric, 2),
                        'color', CASE 
                            WHEN cs.category ILIKE '%tablet%' OR cs.category ILIKE '%capsule%' THEN '#10B981'
                            WHEN cs.category ILIKE '%syrup%' OR cs.category ILIKE '%suspension%' THEN '#F59E0B'
                            WHEN cs.category ILIKE '%injection%' OR cs.category ILIKE '%iv%' THEN '#EF4444'
                            WHEN cs.category ILIKE '%cream%' OR cs.category ILIKE '%ointment%' THEN '#3B82F6'
                            WHEN cs.category ILIKE '%baby%' OR cs.category ILIKE '%maternal%' THEN '#EC4899'
                            WHEN cs.category ILIKE '%hygiene%' OR cs.category ILIKE '%beauty%' THEN '#8B5CF6'
                            ELSE '#6B7280'
                        END
                    ) ORDER BY cs.total_amount DESC)
                    FROM category_sales cs
                ), '[]'::json)
            ),
            'top_products', json_build_object(
                'period', p_period,
                'products', COALESCE((
                    SELECT json_agg(json_build_object(
                        'id', tp.id,
                        'name', tp.name,
                        'brand', tp.brand,
                        'generic_name', tp.generic_name,
                        'strength', tp.strength,
                        'category', tp.category,
                        'primary_unit', tp.primary_unit,
                        'secondary_unit', tp.secondary_unit,
                        'conversion_rate', tp.conversion_rate,
                        'units_sold', tp.units_sold,
                        'total_revenue', ROUND(tp.total_revenue::numeric, 2),
                        'average_price', ROUND(tp.average_price::numeric, 2)
                    ))
                    FROM top_products tp
                ), '[]'::json)
            ),
            'staff_performance', json_build_object(
                'period', p_period,
                'staff', COALESCE((
                    SELECT json_agg(json_build_object(
                        'user_id', sp.user_id,
                        'name', sp.name,
                        'role', sp.role,
                        'avatar_url', sp.avatar_url,
                        'total_sales', ROUND(sp.total_sales::numeric, 2),
                        'transaction_count', sp.transaction_count,
                        'average_sale', ROUND(sp.average_sale::numeric, 2)
                    ))
                    FROM staff_performance sp
                ), '[]'::json)
            )
        )
    ) INTO v_result;
    
    RETURN v_result;
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN json_build_object(
            'code', 'INTERNAL_ERROR',
            'message', 'Failed to retrieve pharmacy analytics',
            'hint', 'Contact system administrator',
            'details', json_build_object(
                'sqlstate', SQLSTATE,
                'error', SQLERRM
            )
        );
END;
$$;


ALTER FUNCTION public.get_pharmacy_analytics(p_pharmacy_id uuid, p_period text, p_start_date timestamp without time zone, p_end_date timestamp without time zone) OWNER TO postgres;

--
-- TOC entry 960 (class 1255 OID 276757)
-- Name: get_purchase_details(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_purchase_details(p_purchase_id uuid DEFAULT NULL::uuid, p_purchase_number text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id UUID;
    v_pharmacy_id UUID;
    v_purchase_data JSONB;
    v_supplier_data JSONB;
    v_items_data JSONB;
    v_payments_data JSONB;
    v_returns_data JSONB;
    v_batches_data JSONB;
    v_summary_data JSONB;
    v_items_count INTEGER;
    v_payments_count INTEGER;
BEGIN
    -- ===================================
    -- 1) AUTHENTICATION
    -- ===================================
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated'
        );
    END IF;

    -- ===================================
    -- 2) INPUT VALIDATION & RESOLUTION
    -- ===================================

    -- Resolve p_purchase_number → p_purchase_id (scanner lookup)
    IF p_purchase_number IS NOT NULL AND p_purchase_id IS NULL THEN
        SELECT p.id INTO p_purchase_id
        FROM purchases p
        WHERE p.purchase_number = p_purchase_number
          AND p.deleted_at IS NULL
        LIMIT 1;

        IF p_purchase_id IS NULL THEN
            RETURN jsonb_build_object(
                'code', 'PURCHASE_NOT_FOUND',
                'message', 'Purchase not found for number: ' || p_purchase_number
            );
        END IF;
    END IF;

    IF p_purchase_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Either purchase_id or purchase_number must be provided'
        );
    END IF;

    -- ===================================
    -- 3) PHARMACY LOOKUP
    -- ===================================
    SELECT pharmacy_id INTO v_pharmacy_id
    FROM purchases
    WHERE id = p_purchase_id AND deleted_at IS NULL;

    IF v_pharmacy_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'PURCHASE_NOT_FOUND',
            'message', 'Purchase not found'
        );
    END IF;

    -- ===================================
    -- 4) PERMISSION CHECK
    -- ===================================
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE up.user_id = v_user_id
          AND up.pharmacy_id = v_pharmacy_id
          AND up.is_active = true
    ) THEN
        RETURN jsonb_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'You do not have permission for this pharmacy'
        );
    END IF;

    -- ===================================
    -- 5) BUILD PURCHASE DATA (with created_by info)
    -- ===================================
    SELECT jsonb_build_object(
        'id', p.id,
        'pharmacy_id', p.pharmacy_id,
        'supplier_id', p.supplier_id,
        'user_id', p.user_id,
        'purchase_number', p.purchase_number,
        'purchase_date', p.purchase_date,
        'subtotal', COALESCE(p.subtotal, 0),
        'discount_amount', COALESCE(p.discount_amount, 0),
        'total_amount', COALESCE(p.total_amount, 0),
        'paid_amount', COALESCE(p.paid_amount, 0),
        'outstanding_amount', COALESCE(p.outstanding_amount, 0),
        'payment_status', p.payment_status::TEXT,
        'purchase_status', p.purchase_status::TEXT,
        'notes', p.notes,
        'idempotency_key', p.idempotency_key,
        'created_at', p.created_at,
        'updated_at', p.updated_at,
        'created_by', CASE WHEN u.id IS NOT NULL THEN
            jsonb_build_object(
                'id', u.id,
                'full_name', COALESCE(u.full_name, ''),
                'email', COALESCE(u.email, ''),
                'phone', u.phone,
                'role', CASE WHEN ur.id IS NOT NULL THEN
                    jsonb_build_object(
                        'id', ur.id,
                        'name', ur.name,
                        'slug', ur.slug
                    )
                ELSE NULL END
            )
        ELSE NULL END
    ) INTO v_purchase_data
    FROM purchases p
    LEFT JOIN users u ON p.user_id = u.id
    LEFT JOIN user_pharmacies uph ON uph.user_id = u.id AND uph.pharmacy_id = p.pharmacy_id AND uph.is_active = true
    LEFT JOIN user_roles ur ON ur.id = uph.role_id
    WHERE p.id = p_purchase_id;

    -- ===================================
    -- 6) BUILD SUPPLIER DATA
    -- ===================================
    SELECT CASE WHEN s.id IS NOT NULL THEN
        jsonb_build_object(
            'id', s.id,
            'pharmacy_id', s.pharmacy_id,
            'name', s.name,
            'company_name', NULL,
            'contact_person', s.contact_person,
            'phone', s.phone,
            'email', s.email,
            'address', s.address,
            'supplier_type', s.supplier_type::TEXT,
            'is_active', s.is_active,
            'created_at', s.created_at
        )
    ELSE NULL END INTO v_supplier_data
    FROM purchases p
    LEFT JOIN suppliers s ON s.id = p.supplier_id AND s.deleted_at IS NULL
    WHERE p.id = p_purchase_id;

    -- ===================================
    -- 7) BUILD ITEMS DATA (with category + generic_name)
    -- ===================================
    SELECT COUNT(*) INTO v_items_count
    FROM purchase_items
    WHERE purchase_id = p_purchase_id;

    SELECT jsonb_build_object(
        'data', COALESCE((
            SELECT jsonb_agg(
                jsonb_build_object(
                    'item', jsonb_build_object(
                        'id', pi.id,
                        'purchase_id', pi.purchase_id,
                        'inventory_id', pi.inventory_id,
                        'batch_number', pi.batch_number,
                        'quantity', pi.quantity,
                        'purchase_price', pi.purchase_price,
                        'selling_price', pi.selling_price,
                        'total_price', pi.total_price,
                        'expiry_date', pi.expiry_date,
                        'created_at', pi.created_at
                    ),
                    'inventory', jsonb_build_object(
                        'id', i.id,
                        'name', i.name,
                        'type', i.type::TEXT,
                        'brand', i.brand,
                        'generic_name', g.name,
                        'manufacturer', m.name,
                        'strength', i.strength,
                        'primary_unit', i.primary_unit,
                        'conversion_rate', COALESCE(i.conversion_rate, 1),
                        'secondary_unit', COALESCE(i.secondary_unit::text, ''),
                        'category', COALESCE(
                            (SELECT c.name FROM categories c WHERE c.id = i.category_id LIMIT 1),
                            ''
                        )
                    ),
                    'batch', CASE WHEN ib.id IS NOT NULL THEN jsonb_build_object(
                        'id', ib.id,
                        'batch_number', ib.batch_number,
                        'expiry_date', ib.expiry_date,
                        'status', ib.status::TEXT
                    ) ELSE NULL END,
                    'calculations', jsonb_build_object(
                        'unit_cost', pi.purchase_price,
                        'total_cost', pi.total_price
                    )
                ) ORDER BY pi.created_at
            )
            FROM purchase_items pi
            JOIN inventory i ON i.id = pi.inventory_id
            LEFT JOIN inventory_generics g ON i.generic_id = g.id
            LEFT JOIN inventory_manufacturers m ON i.manufacturer_id = m.id
            LEFT JOIN inventory_batches ib ON ib.batch_number = pi.batch_number
                AND ib.inventory_id = pi.inventory_id
                AND ib.purchase_id = pi.purchase_id
                AND ib.deleted_at IS NULL
            WHERE pi.purchase_id = p_purchase_id
        ), '[]'::jsonb)
    ) INTO v_items_data;

    -- ===================================
    -- 8) BUILD PAYMENTS DATA (with processed_by staff info)
    -- ===================================
    SELECT COUNT(*) INTO v_payments_count
    FROM purchase_payments
    WHERE purchase_id = p_purchase_id;

    SELECT COALESCE((
        SELECT jsonb_agg(
            jsonb_build_object(
                'id', pp.id,
                'purchase_id', pp.purchase_id,
                'payment_method', pp.payment_method::TEXT,
                'amount', pp.amount,
                'mobile_number', pp.mobile_number,
                'transaction_id', pp.transaction_id,
                'card_number', pp.card_number,
                'payment_date', pp.payment_date,
                'notes', pp.notes,
                'created_at', pp.created_at,
                'processed_by', NULL
            ) ORDER BY pp.payment_date DESC
        )
        FROM purchase_payments pp
        WHERE pp.purchase_id = p_purchase_id
    ), '[]'::jsonb) INTO v_payments_data;

    -- ===================================
    -- 9) BUILD RETURNS DATA
    -- ===================================
    SELECT COALESCE((
        SELECT jsonb_agg(
            jsonb_build_object(
                'id', pr.id,
                'return_number', pr.return_number,
                'return_date', pr.return_date,
                'total_amount', pr.total_amount,
                'items_count', (SELECT COUNT(*) FROM purchase_return_items pri WHERE pri.return_id = pr.id)
            ) ORDER BY pr.return_date DESC
        )
        FROM purchase_returns pr
        WHERE pr.purchase_id = p_purchase_id
          AND pr.refund_status = 'COMPLETED'::payment_status_enum
    ), '[]'::jsonb) INTO v_returns_data;

    -- ===================================
    -- 10) BUILD BATCHES DATA
    -- ===================================
    SELECT COALESCE((
        SELECT jsonb_agg(
            jsonb_build_object(
                'id', ib.id,
                'inventory_id', ib.inventory_id,
                'batch_number', ib.batch_number,
                'expiry_date', ib.expiry_date,
                'initial_quantity', ib.initial_quantity,
                'current_quantity', ib.current_quantity,
                'reserved_quantity', COALESCE(ib.reserved_quantity, 0),
                'purchase_price', COALESCE(ib.purchase_price, 0),
                'selling_price', COALESCE(ib.selling_price, 0),
                'status', ib.status::TEXT,
                'shelf_location', ib.shelf_location,
                'inventory_name', i.name,
                'inventory_type', i.type::TEXT,
                'primary_unit', i.primary_unit,
                'created_at', ib.created_at
            )
        )
        FROM inventory_batches ib
        JOIN stock_transactions st ON st.batch_id = ib.id
        JOIN inventory i ON i.id = ib.inventory_id
        WHERE st.reference_id = p_purchase_id
          AND st.transaction_type = 'PURCHASE'::public.transaction_type_enum
          AND ib.deleted_at IS NULL
    ), '[]'::jsonb) INTO v_batches_data;

    -- ===================================
    -- 11) BUILD SUMMARY
    -- ===================================
    SELECT jsonb_build_object(
        'total_items', v_items_count,
        'total_payments', v_payments_count,
        'is_completed', (v_purchase_data->>'purchase_status') = 'COMPLETED',
        'is_paid', (v_purchase_data->>'payment_status') = 'COMPLETED',
        'has_credit', (v_purchase_data->>'outstanding_amount')::numeric > 0
    ) INTO v_summary_data;

    -- ===================================
    -- 12) RETURN SUCCESS
    -- ===================================
    RETURN jsonb_build_object(
        'code', 'SUCCESS',
        'message', 'Purchase details retrieved successfully',
        'details', jsonb_build_object(
            'purchase', v_purchase_data,
            'supplier', v_supplier_data,
            'items', v_items_data,
            'payments', COALESCE(v_payments_data, '[]'::jsonb),
            'batches', COALESCE(v_batches_data, '[]'::jsonb),
            'returns', COALESCE(v_returns_data, '[]'::jsonb),
            'summary', v_summary_data
        )
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'code', 'INTERNAL_ERROR',
        'message', SQLERRM
    );
END;
$$;


ALTER FUNCTION public.get_purchase_details(p_purchase_id uuid, p_purchase_number text) OWNER TO postgres;

--
-- TOC entry 731 (class 1255 OID 271355)
-- Name: get_purchase_list(uuid, integer, integer, text, text, text, text, text, text, text, text, text, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_purchase_list(p_pharmacy_id uuid, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0, p_search_query text DEFAULT NULL::text, p_date_filter text DEFAULT 'all'::text, p_start_date text DEFAULT NULL::text, p_end_date text DEFAULT NULL::text, p_purchase_status text DEFAULT NULL::text, p_payment_status text DEFAULT NULL::text, p_payment_method text DEFAULT NULL::text, p_purchase_type text DEFAULT NULL::text, p_supplier_id text DEFAULT NULL::text, p_export_all boolean DEFAULT false) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_total_count INTEGER;
    v_purchases JSON;
    v_summary JSON;
    v_start_date DATE;
    v_end_date DATE;
    v_search_term TEXT;
BEGIN
    v_current_user_id := auth.uid();
    IF v_current_user_id IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    IF p_search_query IS NOT NULL AND TRIM(p_search_query) != '' THEN
        v_search_term := '%' || TRIM(p_search_query) || '%';
    END IF;

    IF p_date_filter = 'today' THEN
        v_start_date := CURRENT_DATE;
        v_end_date := CURRENT_DATE;
    ELSIF p_date_filter = 'yesterday' THEN
        v_start_date := CURRENT_DATE - 1;
        v_end_date := CURRENT_DATE - 1;
    ELSIF p_date_filter = 'this_week' THEN
        v_start_date := date_trunc('week', CURRENT_DATE);
        v_end_date := CURRENT_DATE;
    ELSIF p_date_filter = 'this_month' THEN
        v_start_date := date_trunc('month', CURRENT_DATE);
        v_end_date := CURRENT_DATE;
    ELSIF p_date_filter = 'custom' AND p_start_date IS NOT NULL AND p_end_date IS NOT NULL THEN
        v_start_date := p_start_date::DATE;
        v_end_date := p_end_date::DATE;
    END IF;

    SELECT COUNT(*) INTO v_total_count
    FROM purchases p
    LEFT JOIN suppliers s ON s.id = p.supplier_id
    WHERE p.pharmacy_id = p_pharmacy_id
      AND p.deleted_at IS NULL
      AND p.purchase_status != 'DRAFT'::public.purchase_status_enum
      AND (p_supplier_id IS NULL OR p_supplier_id = '' OR p.supplier_id = p_supplier_id::UUID)
      AND (NULLIF(p_purchase_status, '') IS NULL OR p.purchase_status = p_purchase_status::public.purchase_status_enum)
      AND (NULLIF(p_payment_status, '') IS NULL OR p.payment_status = p_payment_status::public.payment_status_enum)
      AND (NULLIF(p_purchase_type, '') IS NULL
          OR (LOWER(p_purchase_type) = 'credit' AND p.outstanding_amount > 0)
          OR (LOWER(p_purchase_type) = 'cash' AND p.outstanding_amount = 0 AND p.payment_status = 'COMPLETED'::public.payment_status_enum))
      AND (v_start_date IS NULL OR p.purchase_date::DATE >= v_start_date)
      AND (v_end_date IS NULL OR p.purchase_date::DATE <= v_end_date)
      AND (NULLIF(p_payment_method, '') IS NULL OR EXISTS (
          SELECT 1 FROM purchase_payments pp
          WHERE pp.purchase_id = p.id
          AND pp.payment_method = p_payment_method::public.payment_method_enum
      ))
      AND (
          v_search_term IS NULL OR
          p.purchase_number ILIKE v_search_term OR
          s.name ILIKE v_search_term OR
          s.phone ILIKE v_search_term
      );

    WITH purchase_counts AS (
        SELECT purchase_id, COUNT(*) as items_count, COALESCE(SUM(quantity), 0) as total_quantity
        FROM purchase_items GROUP BY purchase_id
    ),
    payment_counts AS (
        SELECT purchase_id, COUNT(*) as payments_count FROM purchase_payments GROUP BY purchase_id
    )
    SELECT COALESCE(json_agg(purchase_row ORDER BY (purchase_row->>'purchase_date') DESC, (purchase_row->>'created_at') DESC), '[]'::json)
    INTO v_purchases
    FROM (
        SELECT json_build_object(
            'id', p.id,
            'pharmacy_id', p.pharmacy_id,
            'supplier_id', p.supplier_id,
            'user_id', p.user_id,
            'purchase_number', p.purchase_number,
            'purchase_date', p.purchase_date,
            'purchase_status', p.purchase_status::TEXT,
            'payment_status', p.payment_status::TEXT,
            'subtotal', COALESCE(p.subtotal, 0),
            'discount_amount', COALESCE(p.discount_amount, 0),
            'total_amount', COALESCE(p.total_amount, 0),
            'paid_amount', COALESCE(p.paid_amount, 0),
            'outstanding_amount', COALESCE(p.outstanding_amount, 0),
            'notes', p.notes,
            'created_at', p.created_at,
            'updated_at', p.updated_at,
            'supplier', CASE WHEN s.id IS NOT NULL THEN
                json_build_object('id', s.id, 'name', s.name, 'contact_person', s.contact_person, 'phone', s.phone, 'email', s.email, 'supplier_type', s.supplier_type::TEXT) ELSE NULL END,
            'created_by', CASE WHEN u.id IS NOT NULL THEN
                json_build_object('id', u.id, 'full_name', u.full_name, 'email', u.email, 'phone', u.phone, 'role', NULL) ELSE NULL END,
            'items_summary', json_build_object(
                'items_count', COALESCE(pc.items_count, 0), 'total_quantity', COALESCE(pc.total_quantity, 0), 'medicine_count', 0, 'product_count', 0
            ),
            'payment_summary', json_build_object(
                'is_paid', p.payment_status = 'COMPLETED'::public.payment_status_enum,
                'is_partial', p.payment_status = 'PARTIAL'::public.payment_status_enum,
                'is_pending', p.payment_status = 'PENDING'::public.payment_status_enum,
                'has_credit', p.outstanding_amount > 0,
                'payments_count', COALESCE(ppc.payments_count, 0)
            ),
            'credit_info', NULL
        ) AS purchase_row
        FROM purchases p
        LEFT JOIN suppliers s ON s.id = p.supplier_id
        LEFT JOIN users u ON u.id = p.user_id
        LEFT JOIN purchase_counts pc ON pc.purchase_id = p.id
        LEFT JOIN payment_counts ppc ON ppc.purchase_id = p.id
        WHERE p.pharmacy_id = p_pharmacy_id
          AND p.deleted_at IS NULL
          AND p.purchase_status != 'DRAFT'::public.purchase_status_enum
          AND (p_supplier_id IS NULL OR p_supplier_id = '' OR p.supplier_id = p_supplier_id::UUID)
          AND (NULLIF(p_purchase_status, '') IS NULL OR p.purchase_status = p_purchase_status::public.purchase_status_enum)
          AND (NULLIF(p_payment_status, '') IS NULL OR p.payment_status = p_payment_status::public.payment_status_enum)
          AND (NULLIF(p_purchase_type, '') IS NULL
              OR (LOWER(p_purchase_type) = 'credit' AND p.outstanding_amount > 0)
              OR (LOWER(p_purchase_type) = 'cash' AND p.outstanding_amount = 0 AND p.payment_status = 'COMPLETED'::public.payment_status_enum))
          AND (v_start_date IS NULL OR p.purchase_date::DATE >= v_start_date)
          AND (v_end_date IS NULL OR p.purchase_date::DATE <= v_end_date)
          AND (NULLIF(p_payment_method, '') IS NULL OR EXISTS (
              SELECT 1 FROM purchase_payments pp
              WHERE pp.purchase_id = p.id
              AND pp.payment_method = p_payment_method::public.payment_method_enum
          ))
          AND (
              v_search_term IS NULL OR
              p.purchase_number ILIKE v_search_term OR
              s.name ILIKE v_search_term OR
              s.phone ILIKE v_search_term
          )
        ORDER BY p.purchase_date DESC, p.created_at DESC
        LIMIT CASE WHEN p_export_all THEN NULL ELSE p_limit END
        OFFSET CASE WHEN p_export_all THEN 0 ELSE p_offset END
    ) subquery;

    SELECT json_build_object(
        'total_purchases', COUNT(*),
        'total_amount', COALESCE(SUM(p.total_amount), 0),
        'total_paid', COALESCE(SUM(p.paid_amount), 0),
        'total_outstanding', COALESCE(SUM(p.outstanding_amount), 0),
        'total_discount', COALESCE(SUM(p.discount_amount), 0),
        'avg_purchase_amount', CASE WHEN COUNT(*) > 0 THEN COALESCE(AVG(p.total_amount), 0) ELSE 0 END,
        'completed_purchases', COUNT(*) FILTER (WHERE p.purchase_status = 'COMPLETED'::public.purchase_status_enum),
        'draft_purchases', 0,
        'cash_purchases', COUNT(*) FILTER (WHERE p.outstanding_amount = 0 AND p.payment_status = 'COMPLETED'::public.payment_status_enum),
        'credit_purchases', COUNT(*) FILTER (WHERE p.outstanding_amount > 0),
        'fully_paid', COUNT(*) FILTER (WHERE p.payment_status = 'COMPLETED'::public.payment_status_enum),
        'partially_paid', COUNT(*) FILTER (WHERE p.payment_status = 'PARTIAL'::public.payment_status_enum),
        'pending_payment', COUNT(*) FILTER (WHERE p.payment_status = 'PENDING'::public.payment_status_enum)
    ) INTO v_summary
    FROM purchases p
    LEFT JOIN suppliers s ON s.id = p.supplier_id
    WHERE p.pharmacy_id = p_pharmacy_id
      AND p.deleted_at IS NULL
      AND p.purchase_status != 'DRAFT'::public.purchase_status_enum
      AND (p_supplier_id IS NULL OR p_supplier_id = '' OR p.supplier_id = p_supplier_id::UUID)
      AND (NULLIF(p_purchase_status, '') IS NULL OR p.purchase_status = p_purchase_status::public.purchase_status_enum)
      AND (NULLIF(p_payment_status, '') IS NULL OR p.payment_status = p_payment_status::public.payment_status_enum)
      AND (NULLIF(p_purchase_type, '') IS NULL
          OR (LOWER(p_purchase_type) = 'credit' AND p.outstanding_amount > 0)
          OR (LOWER(p_purchase_type) = 'cash' AND p.outstanding_amount = 0 AND p.payment_status = 'COMPLETED'::public.payment_status_enum))
      AND (v_start_date IS NULL OR p.purchase_date::DATE >= v_start_date)
      AND (v_end_date IS NULL OR p.purchase_date::DATE <= v_end_date)
      AND (NULLIF(p_payment_method, '') IS NULL OR EXISTS (
          SELECT 1 FROM purchase_payments pp
          WHERE pp.purchase_id = p.id
          AND pp.payment_method = p_payment_method::public.payment_method_enum
      ))
      AND (
          v_search_term IS NULL OR
          p.purchase_number ILIKE v_search_term OR
          s.name ILIKE v_search_term OR
          s.phone ILIKE v_search_term
      );

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Purchase history retrieved',
        'details', json_build_object(
            'purchases', v_purchases,
            'summary', v_summary,
            'pagination', json_build_object(
                'total_count', v_total_count,
                'limit', p_limit,
                'offset', p_offset,
                'has_more', CASE WHEN p_export_all THEN false ELSE (v_total_count > (p_offset + p_limit)) END,
                'current_page', CASE WHEN p_limit > 0 THEN (p_offset / p_limit) + 1 ELSE 1 END,
                'total_pages', CASE WHEN p_limit > 0 THEN CEIL(v_total_count::decimal / p_limit) ELSE 1 END
            ),
            'filters_applied', json_build_object(
                'date_filter', p_date_filter,
                'start_date', p_start_date,
                'end_date', p_end_date,
                'purchase_status', p_purchase_status,
                'payment_status', p_payment_status,
                'payment_method', p_payment_method,
                'purchase_type', p_purchase_type,
                'supplier_id', p_supplier_id,
                'search_query', p_search_query
            )
        )
    );
END;
$$;


ALTER FUNCTION public.get_purchase_list(p_pharmacy_id uuid, p_limit integer, p_offset integer, p_search_query text, p_date_filter text, p_start_date text, p_end_date text, p_purchase_status text, p_payment_status text, p_payment_method text, p_purchase_type text, p_supplier_id text, p_export_all boolean) OWNER TO postgres;

--
-- TOC entry 618 (class 1255 OID 275107)
-- Name: get_purchase_return_details(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_purchase_return_details(p_return_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id      UUID;
    v_return_record        RECORD;
    v_return_data          JSONB;
    v_items_data           JSONB;
    v_purchase_items_data  JSONB;
    v_purchase_data        JSONB;
    v_supplier_data        JSONB;
    v_refund_payments_data JSONB;
    v_credit_adjustment    NUMERIC := 0;
    v_cash_refund          NUMERIC := 0;
BEGIN
    v_current_user_id := auth.uid();
    IF v_current_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'code',    'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint',    'Please log in to continue'
        );
    END IF;

    IF p_return_id IS NULL THEN
        RETURN jsonb_build_object('code', 'INVALID_INPUT', 'message', 'Return ID is required');
    END IF;

    SELECT pr.*,
           p.outstanding_amount AS purchase_outstanding,
           p.pharmacy_id        AS p_pharmacy_id,
           u.id                 AS staff_id,
           u.full_name          AS staff_name,
           u.email              AS staff_email,
           ur.id                AS role_id,
           ur.name              AS role_name,
           ur.slug              AS role_slug
    INTO v_return_record
    FROM purchase_returns pr
    JOIN purchases p ON pr.purchase_id = p.id
    LEFT JOIN users u ON u.id = pr.user_id
    LEFT JOIN user_pharmacies up ON up.user_id = u.id AND up.pharmacy_id = p.pharmacy_id
    LEFT JOIN user_roles ur ON ur.id = up.role_id
    WHERE pr.id = p_return_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'RETURN_NOT_FOUND', 'message', 'Return not found');
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE up.user_id    = v_current_user_id
          AND up.pharmacy_id = v_return_record.p_pharmacy_id
          AND up.is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied');
    END IF;

    -- For COMPLETED returns read persisted values; for PENDING drafts compute dynamically.
    IF v_return_record.refund_status = 'COMPLETED'::payment_status_enum THEN
        v_cash_refund       := v_return_record.cash_refund;
        v_credit_adjustment := v_return_record.credit_adjustment;
    ELSE
        IF v_return_record.purchase_outstanding > 0 THEN
            v_credit_adjustment := LEAST(v_return_record.total_amount, v_return_record.purchase_outstanding);
            v_cash_refund       := GREATEST(0, v_return_record.total_amount - v_credit_adjustment);
        ELSE
            v_credit_adjustment := 0;
            v_cash_refund       := v_return_record.total_amount;
        END IF;
    END IF;

    -- ── return_info ───────────────────────────────────────────────────────────
    v_return_data := jsonb_build_object(
        'id',                v_return_record.id,
        'pharmacy_id',       v_return_record.pharmacy_id,
        'purchase_id',       v_return_record.purchase_id,
        'supplier_id',       v_return_record.supplier_id,
        'return_number',     v_return_record.return_number,
        'return_date',       v_return_record.return_date,
        'subtotal',          v_return_record.subtotal,
        'total_amount',      v_return_record.total_amount,
        'refund_status',     v_return_record.refund_status,
        'refunded_amount',   v_return_record.refunded_amount,
        'return_reason',     v_return_record.return_reason,
        'notes',             v_return_record.notes,
        'created_at',        v_return_record.created_at,
        'updated_at',        v_return_record.updated_at,
        'credit_adjustment', v_credit_adjustment,
        'cash_refund',       v_cash_refund,
        'is_credit_only',    (v_cash_refund = 0 AND v_return_record.total_amount > 0),
        'processed_by_name', v_return_record.staff_name,
        'processed_by', CASE WHEN v_return_record.staff_id IS NOT NULL THEN
            jsonb_build_object(
                'id',        v_return_record.staff_id,
                'full_name', v_return_record.staff_name,
                'email',     v_return_record.staff_email,
                'phone',     NULL,
                'role', CASE WHEN v_return_record.role_id IS NOT NULL THEN
                    jsonb_build_object(
                        'id',   v_return_record.role_id,
                        'name', v_return_record.role_name,
                        'slug', v_return_record.role_slug
                    )
                ELSE NULL END
            )
        ELSE NULL END
    );

    -- ── return_items: rows already included in this draft/completed return ────
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
        'id',               pri.id,
        'return_id',        pri.return_id,
        'purchase_item_id', pri.purchase_item_id,
        'inventory_id',     pri.inventory_id,
        'batch_number',     pri.batch_number,
        'quantity',         pri.quantity,
        'unit_cost',        pri.unit_cost,
        'total_cost',       pri.total_cost,
        'inventory_name',   COALESCE(inv.name, inv.brand, 'Unknown'),
        'inventory_type',   inv.type::text,
        'brand',            inv.brand,
        'strength',         inv.strength,
        'generic_name',     g.name,
        'category',         cat.name,
        'primary_unit',     COALESCE(inv.primary_unit::text, 'PCS'),
        'secondary_unit',   inv.secondary_unit::text,
        'conversion_rate',  COALESCE(inv.conversion_rate, 1),
        'expiry_date',      pi.expiry_date
    )), '[]'::JSONB)
    INTO v_items_data
    FROM purchase_return_items pri
    JOIN inventory inv        ON inv.id = pri.inventory_id
    LEFT JOIN inventory_generics g ON inv.generic_id = g.id
    LEFT JOIN categories cat  ON cat.id = inv.category_id
    LEFT JOIN purchase_items pi ON pi.id = pri.purchase_item_id
    WHERE pri.return_id = p_return_id;

    -- ── purchase_items: all items from the original purchase ──────────────────
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
        'id',                   pi.id,
        'inventory_id',         pi.inventory_id,
        'inventory_name',       COALESCE(inv.name, inv.brand, 'Unknown'),
        'inventory_type',       inv.type::text,
        'batch_number',         pi.batch_number,
        'quantity',             pi.quantity,
        'purchase_price',       pi.purchase_price,
        'total_price',          pi.quantity * pi.purchase_price,
        'brand',                inv.brand,
        'strength',             inv.strength,
        'generic_name',         g2.name,
        'primary_unit',         COALESCE(inv.primary_unit::text, 'PCS'),
        'secondary_unit',       inv.secondary_unit::text,
        'conversion_rate',      COALESCE(inv.conversion_rate, 1),
        -- Stock transparency fields
        'sold_quantity',        GREATEST(0,
            COALESCE(batch_txn.gross_sold, 0) - COALESCE(batch_txn.sale_returned, 0)
        )::INT,
        'adjusted_quantity',    COALESCE(batch_txn.adjusted_qty, 0)::INT,
        'current_stock',        COALESCE(ib.current_quantity, 0)::INT,
        'already_returned',     COALESCE(completed.returned_qty, 0)::INT,
        'available_for_return', GREATEST(0,
            LEAST(
                pi.quantity - COALESCE(completed.returned_qty, 0),
                COALESCE(ib.current_quantity,
                         GREATEST(0, pi.quantity - COALESCE(completed.returned_qty, 0)))
            ) - COALESCE(draft.draft_qty, 0)
        )::INT,
        'is_fully_returned', (
            GREATEST(0, LEAST(
                pi.quantity - COALESCE(completed.returned_qty, 0),
                COALESCE(ib.current_quantity,
                         GREATEST(0, pi.quantity - COALESCE(completed.returned_qty, 0)))
            )) = 0
        )
    ) ORDER BY pi.created_at), '[]'::JSONB)
    INTO v_purchase_items_data
    FROM purchase_items pi
    JOIN inventory inv ON inv.id = pi.inventory_id
    LEFT JOIN inventory_generics g2 ON inv.generic_id = g2.id
    -- Completed returns aggregate
    LEFT JOIN (
        SELECT pri.purchase_item_id, SUM(pri.quantity) AS returned_qty
        FROM purchase_return_items pri
        JOIN purchase_returns pr ON pri.return_id = pr.id
        WHERE pr.purchase_id   = v_return_record.purchase_id
          AND pr.refund_status = 'COMPLETED'::payment_status_enum
        GROUP BY pri.purchase_item_id
    ) completed ON completed.purchase_item_id = pi.id
    -- Current draft quantities
    LEFT JOIN (
        SELECT purchase_item_id, SUM(quantity) AS draft_qty
        FROM purchase_return_items
        WHERE return_id = p_return_id
        GROUP BY purchase_item_id
    ) draft ON draft.purchase_item_id = pi.id
    -- Batch record (for current_quantity)
    LEFT JOIN inventory_batches ib
        ON ib.inventory_id = pi.inventory_id
       AND ib.purchase_id  = v_return_record.purchase_id
       AND ib.pharmacy_id  = v_return_record.p_pharmacy_id
       AND ib.batch_number IS NOT DISTINCT FROM NULLIF(NULLIF(pi.batch_number, ''), 'DEFAULT')
       AND ib.deleted_at IS NULL
    -- Batch-level transaction aggregates: sold, sale_returned, adjusted
    LEFT JOIN LATERAL (
        SELECT
            COALESCE(SUM(CASE
                WHEN st.transaction_type = 'SALE'::transaction_type_enum
                THEN ABS(st.quantity_change) ELSE 0 END), 0) AS gross_sold,
            COALESCE(SUM(CASE
                WHEN st.transaction_type = 'SALE_RETURN'::transaction_type_enum
                THEN ABS(st.quantity_change) ELSE 0 END), 0) AS sale_returned,
            COALESCE(SUM(CASE
                WHEN st.transaction_type IN (
                    'ADJUSTMENT'::transaction_type_enum,
                    'DAMAGE'::transaction_type_enum,
                    'EXPIRED'::transaction_type_enum,
                    'STOCK_COUNT'::transaction_type_enum,
                    'TRANSFER_OUT'::transaction_type_enum
                ) AND st.quantity_change < 0
                THEN ABS(st.quantity_change) ELSE 0 END), 0) AS adjusted_qty
        FROM stock_transactions st
        WHERE st.batch_id = ib.id
          AND st.deleted_at IS NULL
    ) batch_txn ON ib.id IS NOT NULL
    WHERE pi.purchase_id = v_return_record.purchase_id;

    -- ── purchase summary ──────────────────────────────────────────────────────
    SELECT jsonb_build_object(
        'id',                p.id,
        'purchase_number',   p.purchase_number,
        'purchase_date',     p.purchase_date,
        'total_amount',      p.total_amount,
        'paid_amount',       p.paid_amount,
        'outstanding_amount', p.outstanding_amount,
        'payment_status',    p.payment_status,
        'purchase_status',   p.purchase_status
    ) INTO v_purchase_data
    FROM purchases p
    WHERE p.id = v_return_record.purchase_id;

    -- ── supplier ──────────────────────────────────────────────────────────────
    IF v_return_record.supplier_id IS NOT NULL THEN
        SELECT jsonb_build_object(
            'id',    s.id,
            'name',  s.name,
            'phone', s.phone,
            'email', s.email
        ) INTO v_supplier_data
        FROM suppliers s
        WHERE s.id = v_return_record.supplier_id;
    END IF;

    -- ── refund payments ───────────────────────────────────────────────────────
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
        'id',             prp.id,
        'return_id',      prp.return_id,
        'payment_method', prp.payment_method,
        'amount',         prp.amount,
        'mobile_number',  prp.mobile_number,
        'transaction_id', prp.transaction_id,
        'card_number',    prp.card_number,
        'payment_date',   prp.payment_date,
        'notes',          prp.notes,
        'created_at',     prp.created_at,
        'processed_by', CASE WHEN u.id IS NOT NULL THEN
            jsonb_build_object('id', u.id, 'full_name', u.full_name, 'role', ur.name)
        ELSE NULL END
    ) ORDER BY prp.payment_date DESC), '[]'::JSONB)
    INTO v_refund_payments_data
    FROM purchase_return_payments prp
    LEFT JOIN users u ON u.id = prp.user_id
    LEFT JOIN user_pharmacies up2 ON up2.user_id = u.id
        AND up2.pharmacy_id = v_return_record.p_pharmacy_id
    LEFT JOIN user_roles ur ON ur.id = up2.role_id
    WHERE prp.return_id = p_return_id;

    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Return details retrieved successfully',
        'data', jsonb_build_object(
            'return_info',     v_return_data,
            'return_items',    v_items_data,
            'purchase',        v_purchase_data,
            'purchase_items',  v_purchase_items_data,
            'supplier',        v_supplier_data,
            'refund_payments', v_refund_payments_data
        )
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('code', 'INTERNAL_ERROR', 'message', SQLERRM, 'hint', NULL);
END;
$$;


ALTER FUNCTION public.get_purchase_return_details(p_return_id uuid) OWNER TO postgres;

--
-- TOC entry 582 (class 1255 OID 275109)
-- Name: get_sale_details(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_sale_details(p_sale_id uuid DEFAULT NULL::uuid, p_sale_number text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id       UUID;
    v_sale_record   RECORD;
    v_items_data    JSONB;
    v_payments_data JSONB;
    v_returns_data  JSONB;
    v_summary       JSONB;
    v_credit_info   JSONB;
BEGIN
    -- ===================================
    -- 0) AUTHENTICATION  ← BUG-8 FIX: was completely missing
    -- ===================================
    v_user_id := auth.uid();

    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'code',    'UNAUTHORIZED',
            'message', 'User not authenticated',
            'details', NULL
        );
    END IF;

    -- ===================================
    -- 1) RESOLVE SALE NUMBER → SALE ID (if needed)
    -- ===================================
    IF p_sale_number IS NOT NULL AND p_sale_id IS NULL THEN
        SELECT s.id INTO p_sale_id
        FROM   sales s
        WHERE  s.sale_number = p_sale_number
        AND    s.deleted_at  IS NULL
        LIMIT 1;

        IF p_sale_id IS NULL THEN
            RETURN jsonb_build_object(
                'code',    'SALE_NOT_FOUND',
                'message', 'Sale not found for number: ' || p_sale_number,
                'details', NULL
            );
        END IF;
    END IF;

    IF p_sale_id IS NULL THEN
        RETURN jsonb_build_object(
            'code',    'INVALID_INPUT',
            'message', 'Either sale_id or sale_number must be provided',
            'details', NULL
        );
    END IF;

    -- ===================================
    -- 2) FETCH SALE + CREATOR
    -- ===================================
    SELECT
        s.*,
        u.id            AS staff_user_id,
        u.email         AS user_email,
        u.full_name     AS user_full_name,
        u.phone         AS user_phone,
        au.raw_user_meta_data AS user_metadata
    INTO v_sale_record
    FROM   sales s
    LEFT JOIN users      u  ON s.user_id = u.id
    LEFT JOIN auth.users au ON u.id      = au.id
    WHERE  s.id         = p_sale_id
    AND    s.deleted_at IS NULL;

    IF v_sale_record.id IS NULL THEN
        RETURN jsonb_build_object(
            'code',    'SALE_NOT_FOUND',
            'message', 'Sale not found',
            'details', NULL
        );
    END IF;

    -- ── BUG-8 FIX: verify caller belongs to the sale's pharmacy ──────────────
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE  up.user_id    = v_user_id
        AND    up.pharmacy_id = v_sale_record.pharmacy_id
        AND    up.is_active   = true
    ) THEN
        RETURN jsonb_build_object(
            'code',    'PERMISSION_DENIED',
            'message', 'You do not have access to this pharmacy',
            'details', NULL
        );
    END IF;

    -- ===================================
    -- 3) CREDIT INFO (if credit sale)
    -- ===================================
    IF v_sale_record.is_credit_sale THEN
        SELECT jsonb_build_object(
            'credit_id',          cc.id,
            'credit_amount',      cc.credit_amount,
            'paid_amount',        cc.paid_amount,
            'outstanding_amount', cc.outstanding_amount,
            'due_date',           cc.due_date,
            'status',             cc.status,
            'is_overdue',         cc.due_date < NOW() AND cc.status = 'ACTIVE'
        ) INTO v_credit_info
        FROM customer_credits cc
        WHERE cc.sale_id = p_sale_id
        LIMIT 1;
    END IF;

    -- ===================================
    -- 4) SALE ITEMS
    -- ===================================
    SELECT jsonb_build_object(
        'data', COALESCE(jsonb_agg(
            jsonb_build_object(
                'item', jsonb_build_object(
                    'id',                           si.id,
                    'sale_id',                      si.sale_id,
                    'inventory_id',                 si.inventory_id,
                    'batch_id',                     si.batch_id,
                    'quantity',                     si.quantity,
                    'unit_price',                   si.unit_price,
                    'discount_amount',              si.discount_amount,
                    'discount_percentage',          0,
                    'total_price',                  si.total_price,
                    'returned_quantity',            si.returned_quantity,
                    'available_for_return_quantity',si.quantity - si.returned_quantity,
                    'is_fully_returned',            si.returned_quantity >= si.quantity,
                    'batch_number',                 ib.batch_number,
                    'expiry_date',                  ib.expiry_date,
                    'shelf_location',               ib.shelf_location
                ),
                'inventory', jsonb_build_object(
                    'id',              i.id,
                    'type',            i.type::text,
                    'name',            i.name,
                    'brand',           i.brand,
                    'generic_name',    g.name,
                    'strength',        i.strength,
                    'manufacturer',    m.name,
                    'category',        cat.name,
                    'primary_unit',    i.primary_unit,
                    'conversion_rate', i.conversion_rate,
                    'secondary_unit',  i.secondary_unit,
                    'display_name',    CASE
                        WHEN i.type::text = 'MEDICINE'
                        THEN CONCAT_WS(' ', i.brand, g.name, i.strength)
                        ELSE i.name
                    END
                )
            )
        ), '[]'::jsonb),
        'count', (SELECT COUNT(*) FROM sale_items WHERE sale_id = p_sale_id)
    ) INTO v_items_data
    FROM   sale_items si
    JOIN   inventory i         ON si.inventory_id = i.id
    LEFT JOIN inventory_generics g ON i.generic_id = g.id
    LEFT JOIN inventory_manufacturers m ON i.manufacturer_id = m.id
    LEFT JOIN categories cat   ON i.category_id   = cat.id
    LEFT JOIN inventory_batches ib ON si.batch_id = ib.id
    WHERE  si.sale_id = p_sale_id;

    -- ===================================
    -- 5) PAYMENTS (initial + credit top-ups)
    -- ===================================
    SELECT jsonb_build_object(
        'data', COALESCE(jsonb_agg(
            jsonb_build_object(
                'id',             p.id,
                'sale_id',        p.sale_id,
                'payment_method', p.payment_method,
                'amount',         p.amount,
                'payment_date',   p.payment_date,
                'mobile_number',  p.mobile_number,
                'transaction_id', p.transaction_id,
                'card_number',    p.card_number,
                'notes',          p.notes,
                'user_id',        p.user_id,
                'created_at',     p.created_at,
                'payment_source', p.payment_source,
                'processed_by',   CASE WHEN pu.id IS NOT NULL THEN
                    jsonb_build_object(
                        'id',        pu.id,
                        'email',     pu.email,
                        'full_name', pu.full_name,
                        'role',      COALESCE((
                            SELECT ur.name FROM user_pharmacies up2
                            JOIN user_roles ur ON up2.role_id = ur.id
                            WHERE up2.user_id    = pu.id
                            AND   up2.pharmacy_id = v_sale_record.pharmacy_id
                            AND   up2.is_active   = true
                            LIMIT 1
                        ), 'Staff')
                    )
                ELSE NULL END
            )
            ORDER BY p.payment_date ASC
        ), '[]'::jsonb),
        'count', (
            (SELECT COUNT(*) FROM sale_payments WHERE sale_id = p_sale_id)
            + (SELECT COUNT(*) FROM customer_credit_payments ccp
               JOIN customer_credits cc ON ccp.customer_credit_id = cc.id
               WHERE cc.sale_id = p_sale_id
               AND   ccp.transaction_type = 'PAYMENT'::customer_credit_payment_type_enum)
        )
    ) INTO v_payments_data
    FROM (
        -- Initial sale payments (at checkout)
        SELECT
            sp.id,
            sp.sale_id,
            sp.payment_method::text AS payment_method,
            sp.amount,
            sp.payment_date,
            sp.mobile_number,
            sp.transaction_id,
            sp.card_number,
            sp.notes,
            sp.user_id,
            sp.created_at,
            'INITIAL_PAYMENT'::text AS payment_source
        FROM sale_payments sp
        WHERE sp.sale_id = p_sale_id

        UNION ALL

        -- Subsequent credit/due payments
        SELECT
            ccp.id,
            cc.sale_id,
            ccp.payment_method::text,
            ccp.amount,
            ccp.payment_date,
            ccp.mobile_number,
            ccp.transaction_id,
            ccp.card_number,
            ccp.notes,
            ccp.user_id,
            ccp.created_at,
            'CREDIT_PAYMENT'::text
        FROM customer_credit_payments ccp
        JOIN customer_credits cc ON ccp.customer_credit_id = cc.id
        WHERE cc.sale_id = p_sale_id
        AND   ccp.transaction_type = 'PAYMENT'::customer_credit_payment_type_enum
    ) p
    LEFT JOIN users pu ON p.user_id = pu.id;

    -- ===================================
    -- 6) RETURNS
    -- ===================================
    SELECT jsonb_build_object(
        'data', COALESCE(jsonb_agg(
            jsonb_build_object(
                'id',                sr.id,
                'return_number',     sr.return_number,
                'return_date',       sr.return_date,
                'return_status',     sr.return_status,
                'refund_amount',     sr.refund_amount,
                'credit_adjustment', sr.credit_adjustment,
                'items_count',       (SELECT COUNT(*) FROM sale_return_items WHERE return_id = sr.id)
            )
        ), '[]'::jsonb),
        'count', (SELECT COUNT(*) FROM sale_returns WHERE sale_id = p_sale_id)
    ) INTO v_returns_data
    FROM sale_returns sr
    WHERE sr.sale_id = p_sale_id;

    -- ===================================
    -- 7) SUMMARY
    -- ===================================
    SELECT jsonb_build_object(
        'total_items',    (SELECT COUNT(*) FROM sale_items WHERE sale_id = p_sale_id),
        'total_payments', (
            (SELECT COUNT(*) FROM sale_payments WHERE sale_id = p_sale_id)
            + (SELECT COUNT(*) FROM customer_credit_payments ccp
               JOIN customer_credits cc ON ccp.customer_credit_id = cc.id
               WHERE cc.sale_id = p_sale_id
               AND   ccp.transaction_type = 'PAYMENT'::customer_credit_payment_type_enum)
        ),
        'total_returns',  (SELECT COUNT(*) FROM sale_returns WHERE sale_id = p_sale_id),
        'is_completed',   v_sale_record.sale_status::text = 'COMPLETED',
        'is_paid',        v_sale_record.payment_status::text = 'COMPLETED',
        'has_credit',     v_sale_record.is_credit_sale,
        'has_returns',    EXISTS (SELECT 1 FROM sale_returns WHERE sale_id = p_sale_id)
    ) INTO v_summary;

    -- ===================================
    -- 8) BUILD RESPONSE
    -- ===================================
    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Sale details retrieved successfully',
        'details', jsonb_build_object(
            'sale', jsonb_build_object(
                'id',                 v_sale_record.id,
                'pharmacy_id',        v_sale_record.pharmacy_id,
                'customer_id',        v_sale_record.customer_id,
                'user_id',            v_sale_record.user_id,
                'sale_number',        v_sale_record.sale_number,
                'sale_date',          v_sale_record.sale_date,
                'sale_status',        v_sale_record.sale_status,
                'payment_status',     v_sale_record.payment_status,
                'subtotal',           v_sale_record.subtotal,
                'discount_amount',    v_sale_record.discount_amount,
                'discount_percentage', 0,
                'total_amount',       v_sale_record.total_amount,
                'paid_amount',        v_sale_record.paid_amount,
                'outstanding_amount', v_sale_record.outstanding_amount,
                'is_credit_sale',     v_sale_record.is_credit_sale,
                'notes',              v_sale_record.notes,
                'created_at',         v_sale_record.created_at,
                'updated_at',         v_sale_record.updated_at,
                'credit_info',        v_credit_info,
                'created_by', CASE WHEN v_sale_record.user_id IS NOT NULL THEN
                    jsonb_build_object(
                        'id',        v_sale_record.user_id,
                        'email',     v_sale_record.user_email,
                        'full_name', COALESCE(
                            v_sale_record.user_full_name,
                            v_sale_record.user_metadata->>'full_name', ''
                        ),
                        'phone',     COALESCE(
                            v_sale_record.user_phone,
                            v_sale_record.user_metadata->>'phone', ''
                        ),
                        'role',      COALESCE((
                            SELECT ur.name FROM user_pharmacies up2
                            JOIN user_roles ur ON up2.role_id = ur.id
                            WHERE up2.user_id    = v_sale_record.user_id
                            AND   up2.pharmacy_id = v_sale_record.pharmacy_id
                            AND   up2.is_active   = true
                            LIMIT 1
                        ), 'Staff')
                    )
                ELSE NULL END
            ),
            'customer', (
                SELECT jsonb_build_object(
                    'id',      c.id,
                    'name',    c.name,
                    'phone',   c.phone,
                    'email',   c.email,
                    'address', c.address
                ) FROM customers c WHERE c.id = v_sale_record.customer_id
            ),
            'items',    v_items_data,
            'payments', v_payments_data,
            'returns',  v_returns_data,
            'summary',  v_summary
        )
    );
END;
$$;


ALTER FUNCTION public.get_sale_details(p_sale_id uuid, p_sale_number text) OWNER TO postgres;

--
-- TOC entry 1251 (class 1255 OID 271353)
-- Name: get_sale_list(uuid, integer, integer, text, text, timestamp with time zone, timestamp with time zone, text, text, text, text, uuid, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_sale_list(p_pharmacy_id uuid, p_limit integer DEFAULT 50, p_offset integer DEFAULT 0, p_search_query text DEFAULT NULL::text, p_date_filter text DEFAULT 'all'::text, p_start_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_end_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_sale_status text DEFAULT NULL::text, p_payment_status text DEFAULT NULL::text, p_payment_method text DEFAULT NULL::text, p_sale_type text DEFAULT NULL::text, p_customer_id uuid DEFAULT NULL::uuid, p_export_all boolean DEFAULT false) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_total_count     INTEGER;
    v_sales           JSON;
    v_summary         JSON;
    v_pagination      JSON;
    v_filters         JSON;
    v_search_term     TEXT;
BEGIN
    v_current_user_id := auth.uid();

    IF v_current_user_id IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE up.user_id = v_current_user_id AND up.pharmacy_id = p_pharmacy_id AND up.is_active = true
    ) THEN
        RETURN json_build_object('code', 'PERMISSION_DENIED', 'message', 'You do not have access to this pharmacy');
    END IF;

    IF p_search_query IS NOT NULL AND TRIM(p_search_query) != '' THEN
        v_search_term := '%' || TRIM(p_search_query) || '%';
    END IF;

    -- COUNT
    SELECT COUNT(*)
    INTO v_total_count
    FROM sales s
    LEFT JOIN customers c ON s.customer_id = c.id
    WHERE s.pharmacy_id = p_pharmacy_id
    AND s.deleted_at IS NULL
    AND s.sale_status::text != 'DRAFT'
    AND (p_customer_id IS NULL OR s.customer_id = p_customer_id)
    AND (NULLIF(p_sale_status, '') IS NULL OR s.sale_status::text = p_sale_status)
    AND (NULLIF(p_payment_status, '') IS NULL OR s.payment_status::text = p_payment_status)
    AND (
        NULLIF(p_sale_type, '') IS NULL OR
        (p_sale_type = 'CASH' AND NOT s.is_credit_sale) OR
        (p_sale_type = 'CREDIT' AND s.is_credit_sale) OR
        (p_sale_type = 'DUE' AND s.outstanding_amount > 0)
    )
    AND (p_start_date IS NULL OR (s.sale_date AT TIME ZONE 'Asia/Dhaka')::date >= p_start_date::date)
    AND (p_end_date IS NULL OR (s.sale_date AT TIME ZONE 'Asia/Dhaka')::date <= p_end_date::date)
    AND (
        NULLIF(p_payment_method, '') IS NULL OR
        EXISTS (
            SELECT 1 FROM sale_payments sp
            WHERE sp.sale_id = s.id AND sp.payment_method::text = p_payment_method
        )
    )
    AND (
        v_search_term IS NULL OR
        s.sale_number ILIKE v_search_term OR
        c.name ILIKE v_search_term OR
        c.phone ILIKE v_search_term
    );

    -- PAGED ROWS
    SELECT json_agg(sale_data)
    INTO v_sales
    FROM (
        SELECT
            json_build_object(
                'id', s.id,
                'pharmacy_id', s.pharmacy_id,
                'customer_id', s.customer_id,
                'user_id', s.user_id,
                'sale_number', s.sale_number,
                'sale_date', s.sale_date,
                'sale_status', s.sale_status,
                'payment_status', s.payment_status,
                'subtotal', s.subtotal,
                'discount_amount', s.discount_amount,
                'discount_percentage', 0,
                'total_amount', s.total_amount,
                'paid_amount', s.paid_amount,
                'outstanding_amount', s.outstanding_amount,
                'is_credit_sale', s.is_credit_sale,
                'notes', s.notes,
                'created_at', s.created_at,
                'updated_at', s.updated_at,
                'customer', CASE WHEN c.id IS NOT NULL THEN
                    json_build_object('id', c.id, 'name', c.name, 'phone', c.phone, 'email', c.email, 'address', c.address)
                ELSE NULL END,
                'created_by', CASE WHEN u.id IS NOT NULL THEN
                    json_build_object(
                        'id', u.id, 'full_name', u.full_name, 'email', u.email, 'phone', u.phone,
                        'role', COALESCE((
                            SELECT ur.name FROM user_pharmacies up2
                            JOIN user_roles ur ON up2.role_id = ur.id
                            WHERE up2.user_id = u.id AND up2.pharmacy_id = p_pharmacy_id AND up2.is_active = true
                            LIMIT 1
                        ), 'Staff')
                    )
                ELSE NULL END,
                'items_summary', json_build_object(
                    'items_count', (SELECT COUNT(*) FROM sale_items si WHERE si.sale_id = s.id),
                    'total_quantity', (SELECT COALESCE(SUM(quantity), 0) FROM sale_items si WHERE si.sale_id = s.id),
                    'medicine_count', (SELECT COUNT(*) FROM sale_items si JOIN inventory i ON si.inventory_id = i.id WHERE si.sale_id = s.id AND i.type::text = 'MEDICINE'),
                    'product_count', (SELECT COUNT(*) FROM sale_items si JOIN inventory i ON si.inventory_id = i.id WHERE si.sale_id = s.id AND i.type::text != 'MEDICINE')
                ),
                'payment_summary', json_build_object(
                    'is_paid', s.payment_status::text = 'COMPLETED',
                    'is_partial', s.payment_status::text = 'PARTIAL',
                    'is_pending', s.payment_status::text = 'PENDING',
                    'has_credit', s.is_credit_sale,
                    'payments_count', (SELECT COUNT(*) FROM sale_payments WHERE sale_id = s.id)
                ),
                'credit_info', (
                    SELECT json_build_object(
                        'credit_id', cc.id, 'credit_amount', cc.credit_amount, 'paid_amount', cc.paid_amount,
                        'outstanding_amount', cc.outstanding_amount, 'due_date', cc.due_date, 'status', cc.status,
                        'is_overdue', cc.due_date < NOW() AND cc.status::text = 'ACTIVE'
                    )
                    FROM customer_credits cc
                    WHERE cc.sale_id = s.id
                    LIMIT 1
                )
            ) AS sale_data
        FROM sales s
        LEFT JOIN customers c ON c.id = s.customer_id
        LEFT JOIN users u ON u.id = s.user_id
        WHERE s.pharmacy_id = p_pharmacy_id
        AND s.deleted_at IS NULL
        AND s.sale_status::text != 'DRAFT'
        AND (p_customer_id IS NULL OR s.customer_id = p_customer_id)
        AND (NULLIF(p_sale_status, '') IS NULL OR s.sale_status::text = p_sale_status)
        AND (NULLIF(p_payment_status, '') IS NULL OR s.payment_status::text = p_payment_status)
        AND (
            NULLIF(p_sale_type, '') IS NULL OR
            (p_sale_type = 'CASH' AND NOT s.is_credit_sale) OR
            (p_sale_type = 'CREDIT' AND s.is_credit_sale) OR
            (p_sale_type = 'DUE' AND s.outstanding_amount > 0)
        )
        AND (p_start_date IS NULL OR (s.sale_date AT TIME ZONE 'Asia/Dhaka')::date >= p_start_date::date)
        AND (p_end_date IS NULL OR (s.sale_date AT TIME ZONE 'Asia/Dhaka')::date <= p_end_date::date)
        AND (
            NULLIF(p_payment_method, '') IS NULL OR
            EXISTS (
                SELECT 1 FROM sale_payments sp
                WHERE sp.sale_id = s.id AND sp.payment_method::text = p_payment_method
            )
        )
        AND (
            v_search_term IS NULL OR
            s.sale_number ILIKE v_search_term OR
            c.name ILIKE v_search_term OR
            c.phone ILIKE v_search_term
        )
        ORDER BY s.sale_date DESC
        LIMIT CASE WHEN p_export_all THEN NULL ELSE p_limit END
        OFFSET CASE WHEN p_export_all THEN 0 ELSE p_offset END
    ) t;

    -- Aggregate summary
    SELECT json_build_object(
        'total_sales', COUNT(*),
        'total_amount', COALESCE(SUM(s.total_amount), 0),
        'total_paid', COALESCE(SUM(s.paid_amount), 0),
        'total_outstanding', COALESCE(SUM(s.outstanding_amount), 0),
        'total_discount', COALESCE(SUM(s.discount_amount), 0),
        'avg_sale_amount', COALESCE(AVG(s.total_amount), 0),
        'completed_sales', COUNT(*) FILTER (WHERE s.sale_status::text = 'COMPLETED'),
        'cash_sales', COUNT(*) FILTER (WHERE NOT s.is_credit_sale),
        'credit_sales', COUNT(*) FILTER (WHERE s.is_credit_sale),
        'fully_paid', COUNT(*) FILTER (WHERE s.payment_status::text = 'COMPLETED'),
        'partially_paid', COUNT(*) FILTER (WHERE s.payment_status::text = 'PARTIAL'),
        'pending_payment', COUNT(*) FILTER (WHERE s.payment_status::text = 'PENDING')
    ) INTO v_summary
    FROM sales s
    LEFT JOIN customers c ON s.customer_id = c.id
    WHERE s.pharmacy_id = p_pharmacy_id
    AND s.deleted_at IS NULL
    AND s.sale_status::text != 'DRAFT'
    AND (p_customer_id IS NULL OR s.customer_id = p_customer_id)
    AND (NULLIF(p_sale_status, '') IS NULL OR s.sale_status::text = p_sale_status)
    AND (NULLIF(p_payment_status, '') IS NULL OR s.payment_status::text = p_payment_status)
    AND (
        NULLIF(p_sale_type, '') IS NULL OR
        (p_sale_type = 'CASH' AND NOT s.is_credit_sale) OR
        (p_sale_type = 'CREDIT' AND s.is_credit_sale) OR
        (p_sale_type = 'DUE' AND s.outstanding_amount > 0)
    )
    AND (p_start_date IS NULL OR (s.sale_date AT TIME ZONE 'Asia/Dhaka')::date >= p_start_date::date)
    AND (p_end_date IS NULL OR (s.sale_date AT TIME ZONE 'Asia/Dhaka')::date <= p_end_date::date)
    AND (
        NULLIF(p_payment_method, '') IS NULL OR
        EXISTS (
            SELECT 1 FROM sale_payments sp
            WHERE sp.sale_id = s.id AND sp.payment_method::text = p_payment_method
        )
    )
    AND (
        v_search_term IS NULL OR
        s.sale_number ILIKE v_search_term OR
        c.name ILIKE v_search_term OR
        c.phone ILIKE v_search_term
    );

    v_pagination := json_build_object(
        'total_count', v_total_count,
        'limit', p_limit,
        'offset', p_offset,
        'has_more', CASE WHEN p_export_all THEN false ELSE v_total_count > (p_offset + p_limit) END
    );

    v_filters := json_build_object(
        'date_filter', p_date_filter,
        'start_date', p_start_date,
        'end_date', p_end_date,
        'sale_status', p_sale_status,
        'payment_status', p_payment_status,
        'payment_method', p_payment_method,
        'sale_type', p_sale_type,
        'customer_id', p_customer_id,
        'search_query', p_search_query
    );

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Sale history retrieved successfully',
        'hint', NULL,
        'details', json_build_object(
            'sales', COALESCE(v_sales, '[]'::json),
            'summary', v_summary,
            'pagination', v_pagination,
            'filters_applied', v_filters
        )
    );
END;
$$;


ALTER FUNCTION public.get_sale_list(p_pharmacy_id uuid, p_limit integer, p_offset integer, p_search_query text, p_date_filter text, p_start_date timestamp with time zone, p_end_date timestamp with time zone, p_sale_status text, p_payment_status text, p_payment_method text, p_sale_type text, p_customer_id uuid, p_export_all boolean) OWNER TO postgres;

--
-- TOC entry 1459 (class 1255 OID 276759)
-- Name: get_sale_return_details(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_sale_return_details(p_return_id uuid DEFAULT NULL::uuid, p_sale_id uuid DEFAULT NULL::uuid, p_return_number text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$DECLARE
    v_user_id UUID;
    v_returns JSONB;
    v_sale_summary JSONB;
    v_pharmacy_id UUID;
    v_resolved_sale_id UUID;
BEGIN
    -- ===================================
    -- 1) AUTHENTICATION
    -- ===================================
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint', NULL
        );
    END IF;

    -- ===================================
    -- 2) INPUT VALIDATION & RESOLUTION
    -- Resolve return_number to UUID
    -- ===================================

    -- Resolve p_return_number → p_return_id (if provided)
    IF p_return_number IS NOT NULL AND p_return_id IS NULL THEN
        SELECT r.id INTO p_return_id
        FROM sale_returns r
        WHERE r.return_number = p_return_number
          AND r.deleted_at IS NULL
        LIMIT 1;

        IF p_return_id IS NULL THEN
            RETURN jsonb_build_object(
                'code', 'RETURN_NOT_FOUND',
                'message', 'Return not found for number: ' || p_return_number,
                'hint', NULL
            );
        END IF;
    END IF;

    -- At least one identifier must be resolved
    IF p_return_id IS NULL AND p_sale_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Either return_id, sale_id, or return_number must be provided',
            'hint', NULL
        );
    END IF;

    -- ===================================
    -- 3) PHARMACY LOOKUP & PERMISSION
    -- ===================================
    IF p_return_id IS NOT NULL THEN
        SELECT r.pharmacy_id INTO v_pharmacy_id
        FROM sale_returns r
        WHERE r.id = p_return_id
          AND r.deleted_at IS NULL;
    ELSE
        SELECT s.pharmacy_id INTO v_pharmacy_id
        FROM sales s
        WHERE s.id = p_sale_id
          AND s.deleted_at IS NULL;
    END IF;

    IF v_pharmacy_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'RETURN_NOT_FOUND',
            'message', 'Return or sale not found',
            'hint', NULL
        );
    END IF;

    -- Permission check
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies pu
        WHERE pu.user_id = v_user_id
          AND pu.pharmacy_id = v_pharmacy_id
          AND pu.is_active = true
    ) THEN
        RETURN jsonb_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'You do not have permission for this pharmacy',
            'hint', NULL
        );
    END IF;

    -- ===================================
    -- 4) BUILD RETURNS ARRAY
    -- ===================================
    SELECT jsonb_agg(
        jsonb_build_object(
            'returnInfo', jsonb_build_object(
                'returnId',          r.id,
                'returnNumber',      r.return_number,
                'returnDate',        r.return_date,
                'returnStatus',      r.return_status,
                'reason',            r.reason,
                'notes',             r.notes,
                'subtotal',          r.subtotal,
                'discountAmount',    r.discount_amount,
                'totalAmount',       r.refund_amount,
                'refundAmount',      r.refund_amount,
                'creditAdjustment',  r.credit_adjustment,
                'cashRefund',        r.cash_refund,
                'processedAt',       r.processed_at,
                'createdAt',         r.created_at,
                'updatedAt',         r.updated_at
            ),
            'sale', jsonb_build_object(
                'id',                s.id,
                'saleNumber',        s.sale_number,
                'saleDate',          s.sale_date,
                'saleStatus',        s.sale_status,
                'totalAmount',       s.total_amount,
                'paidAmount',        s.paid_amount,
                'outstandingAmount', s.outstanding_amount,
                'paymentStatus',     s.payment_status,
                'isCreditSale',      s.is_credit_sale,
                'discountAmount',    s.discount_amount,
                'returnAdjustment',  COALESCE(s.return_adjustment, 0)
            ),
            'customer', CASE WHEN c.id IS NOT NULL THEN
                jsonb_build_object(
                    'id',      c.id,
                    'name',    c.name,
                    'phone',   c.phone,
                    'address', c.address
                )
            ELSE NULL END,
            'processedBy', CASE WHEN u.id IS NOT NULL THEN
                jsonb_build_object(
                    'id',       u.id,
                    'email',    COALESCE(u.email, au.email, ''),
                    'fullName', COALESCE(u.full_name, au.raw_user_meta_data->>'full_name', ''),
                    'phone',    COALESCE(u.phone, au.raw_user_meta_data->>'phone', ''),
                    'role',     COALESCE((
                        SELECT ur.name
                        FROM user_pharmacies up
                        JOIN user_roles ur ON up.role_id = ur.id
                        WHERE up.user_id = u.id
                          AND up.pharmacy_id = v_pharmacy_id
                          AND up.is_active = true
                        LIMIT 1
                    ), 'Staff')
                )
            ELSE NULL END,

            -- ─── ITEMS SUBQUERY ───
            'items', (
                SELECT COALESCE(jsonb_agg(
                    jsonb_build_object(
                        'id',                   ri.id,
                        'saleItemId',            ri.sale_item_id,
                        'inventoryId',           ri.inventory_id,
                        'inventoryName',         COALESCE(i.name, i.brand),
                        'inventoryType',         i.type::text,
                        'brand',                 i.brand,
                        'genericName', g.name,    -- FIX: was 'generic_name', DTO expects 'genericName'
                        'strength',              i.strength,
                        'manufacturer', m.name,
                        'primaryUnit',           COALESCE(i.primary_unit::text, 'case'),
                        'conversionRate',        COALESCE(i.conversion_rate, 1),
                        'secondaryUnit',         i.secondary_unit,
                        'category',              cat.name,
                        'quantity',              ri.quantity,
                        'unitPrice',             ri.unit_price,
                        'totalPrice',            ri.total_price,
                        'proportionalDiscount',  ri.proportional_discount,
                        'itemDiscount',          ri.item_discount,
                        'netRefund',             ri.net_refund,
                        'batchNumber',           ib.batch_number,
                        'expiryDate',            ib.expiry_date
                    )
                ), '[]'::jsonb)
                FROM sale_return_items ri
                JOIN inventory i ON ri.inventory_id = i.id
                LEFT JOIN inventory_generics g ON i.generic_id = g.id
                LEFT JOIN inventory_manufacturers m ON i.manufacturer_id = m.id
                LEFT JOIN categories cat ON i.category_id = cat.id
                LEFT JOIN inventory_batches ib ON ri.batch_id = ib.id
                WHERE ri.return_id = r.id
                  AND ri.deleted_at IS NULL   -- FIX: exclude soft-deleted items
            ),

            -- ─── PAYMENTS SUBQUERY ───
            'payments', (
                SELECT COALESCE(jsonb_agg(
                    jsonb_build_object(
                        'id',            rp.id,
                        'paymentMethod', rp.payment_method,
                        'amount',        rp.amount,
                        'mobileNumber',  rp.mobile_number,
                        'transactionId', rp.transaction_id,
                        'cardNumber',    rp.card_number,
                        'notes',         rp.notes,
                        'paymentDate',   rp.payment_date,
                        'processedBy',   CASE WHEN pu.id IS NOT NULL THEN
                            jsonb_build_object(
                                'id',       pu.id,
                                'email',    COALESCE(pu.email, pau.email, ''),
                                'fullName', COALESCE(pu.full_name, pau.raw_user_meta_data->>'full_name', ''),
                                'phone',    COALESCE(pu.phone, pau.raw_user_meta_data->>'phone', ''),
                                'role',     COALESCE((
                                    SELECT ur.name
                                    FROM user_pharmacies up
                                    JOIN user_roles ur ON up.role_id = ur.id
                                    WHERE up.user_id = pu.id
                                      AND up.pharmacy_id = v_pharmacy_id
                                      AND up.is_active = true
                                    LIMIT 1
                                ), 'Staff')
                            )
                        ELSE NULL END
                    )
                    ORDER BY rp.payment_date ASC
                ), '[]'::jsonb)
                FROM sale_return_payments rp
                LEFT JOIN users pu ON rp.processed_by = pu.id
                LEFT JOIN auth.users pau ON pu.id = pau.id
                WHERE rp.return_id = r.id
            ),

            -- ─── SUMMARY ───
            'summary', jsonb_build_object(
                'totalItems',          (SELECT COUNT(*) FROM sale_return_items WHERE return_id = r.id AND deleted_at IS NULL),
                'totalQuantity',       (SELECT COALESCE(SUM(quantity), 0) FROM sale_return_items WHERE return_id = r.id AND deleted_at IS NULL),
                'isCompleted',         r.return_status = 'COMPLETED',   -- No ::text cast needed (already TEXT)
                'isDraft',             r.return_status = 'DRAFT',
                'isCancelled',         r.return_status = 'CANCELLED',
                'hasDiscount',         r.discount_amount > 0,
                'hasCreditAdjustment', r.credit_adjustment > 0,
                'isCreditOnly',        r.cash_refund = 0 AND r.credit_adjustment > 0,
                'hasPayments',         EXISTS (SELECT 1 FROM sale_return_payments WHERE return_id = r.id),
                'paymentMethodsUsed',  (
                    SELECT COALESCE(jsonb_agg(DISTINCT payment_method), '[]'::jsonb)
                    FROM sale_return_payments
                    WHERE return_id = r.id
                )
            )
        )
        ORDER BY r.return_date DESC   -- Newest returns first
    ) INTO v_returns
    FROM sale_returns r
    JOIN sales s ON r.sale_id = s.id
    LEFT JOIN customers c ON s.customer_id = c.id AND c.deleted_at IS NULL
    LEFT JOIN users u ON r.processed_by = u.id
    LEFT JOIN auth.users au ON u.id = au.id
    WHERE r.deleted_at IS NULL                                 -- FIX: exclude soft-deleted returns
      AND s.deleted_at IS NULL                                 -- FIX: exclude soft-deleted sales
      AND (p_return_id IS NULL OR r.id = p_return_id)
      AND (p_sale_id IS NULL OR r.sale_id = p_sale_id);

    -- ===================================
    -- 5) SALE RETURN SUMMARY (only for sale_id queries)
    -- ===================================
    IF p_sale_id IS NOT NULL THEN
        SELECT jsonb_build_object(
            'saleId',              p_sale_id,
            'totalReturns',        COUNT(*),
            'completedReturns',    COUNT(*) FILTER (WHERE return_status = 'COMPLETED'),
            'draftReturns',        COUNT(*) FILTER (WHERE return_status = 'DRAFT'),
            'totalRefunded',       COALESCE(SUM(refund_amount) FILTER (WHERE return_status = 'COMPLETED'), 0),
            'totalCashRefunded',   COALESCE(SUM(cash_refund) FILTER (WHERE return_status = 'COMPLETED'), 0),
            'totalCreditAdjusted', COALESCE(SUM(credit_adjustment) FILTER (WHERE return_status = 'COMPLETED'), 0),
            'totalItemsReturned',  (
                SELECT COALESCE(SUM(ri.quantity), 0)
                FROM sale_return_items ri
                JOIN sale_returns r2 ON ri.return_id = r2.id
                WHERE r2.sale_id = p_sale_id
                  AND r2.return_status = 'COMPLETED'
                  AND r2.deleted_at IS NULL
                  AND ri.deleted_at IS NULL
            ),
            'isFullyReturned',     (
                SELECT COALESCE(SUM(si.returned_quantity), 0) >= COALESCE(SUM(si.quantity), 0)
                FROM sale_items si
                WHERE si.sale_id = p_sale_id
            ),
            'canCreateNewReturn',  EXISTS (
                SELECT 1 FROM sale_items si
                WHERE si.sale_id = p_sale_id
                  AND si.quantity > COALESCE(si.returned_quantity, 0)
            )
        ) INTO v_sale_summary
        FROM sale_returns
        WHERE sale_id = p_sale_id
          AND deleted_at IS NULL;   -- FIX: exclude soft-deleted from summary
    END IF;

    -- ===================================
    -- 6) RESPONSE
    -- ===================================
    RETURN jsonb_build_object(
        'code', 'SUCCESS',
        'message', 'Return details retrieved successfully',
        'details', jsonb_build_object(
            'returns',           COALESCE(v_returns, '[]'::jsonb),
            'saleReturnSummary', v_sale_summary
        )
    );
END;$$;


ALTER FUNCTION public.get_sale_return_details(p_return_id uuid, p_sale_id uuid, p_return_number text) OWNER TO postgres;

--
-- TOC entry 1166 (class 1255 OID 269907)
-- Name: get_sale_return_list(uuid, integer, integer, text, text, timestamp with time zone, timestamp with time zone, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_sale_return_list(p_pharmacy_id uuid, p_limit integer DEFAULT 50, p_offset integer DEFAULT 0, p_search_query text DEFAULT NULL::text, p_date_filter text DEFAULT 'all'::text, p_start_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_end_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_return_status text DEFAULT NULL::text, p_customer_id uuid DEFAULT NULL::uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_total_count     INTEGER;
    v_returns         JSON;
    v_summary         JSON;
    v_pagination      JSON;
    v_filters         JSON;
    v_search_term     TEXT;
BEGIN
    v_current_user_id := auth.uid();

    IF v_current_user_id IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated'
        );
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE  up.user_id    = v_current_user_id
        AND    up.pharmacy_id = p_pharmacy_id
        AND    up.is_active   = true
    ) THEN
        RETURN json_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'You do not have access to this pharmacy'
        );
    END IF;

    IF p_search_query IS NOT NULL AND TRIM(p_search_query) != '' THEN
        v_search_term := '%' || TRIM(p_search_query) || '%';
    END IF;

    -- ── COUNT (for pagination) ────────────────────────────────────────────────
    SELECT COUNT(*)
    INTO   v_total_count
    FROM   sale_returns sr
    JOIN   sales s ON sr.sale_id = s.id
    LEFT JOIN customers c ON s.customer_id = c.id
    WHERE  s.pharmacy_id         = p_pharmacy_id
    AND    s.deleted_at          IS NULL
    AND    (p_customer_id       IS NULL OR s.customer_id         = p_customer_id)
    AND    (NULLIF(p_return_status,    '') IS NULL OR sr.return_status::text    = p_return_status)
    AND    (p_start_date IS NULL OR (sr.return_date AT TIME ZONE 'Asia/Dhaka')::date >= p_start_date::date)
    AND    (p_end_date   IS NULL OR (sr.return_date AT TIME ZONE 'Asia/Dhaka')::date <= p_end_date::date)
    AND    (
        v_search_term IS NULL OR
        sr.return_number ILIKE v_search_term OR
        s.sale_number    ILIKE v_search_term OR
        c.name           ILIKE v_search_term OR
        c.phone          ILIKE v_search_term
    );

    -- ── PAGED ROWS ────────────────────────────────────────────────────────────
    SELECT json_agg(return_data)
    INTO   v_returns
    FROM (
        SELECT
            json_build_object(
                'id',                sr.id,
                'sale_id',           sr.sale_id,
                'return_number',     sr.return_number,
                'sale_number',       s.sale_number,
                'return_date',       sr.return_date,
                'return_status',     sr.return_status,
                'refund_amount',     sr.refund_amount,
                'credit_adjustment', sr.credit_adjustment,
                'cash_refund',       COALESCE(sr.refund_amount, 0) - COALESCE(sr.credit_adjustment, 0),
                'reason',            sr.reason,
                'notes',             sr.notes,
                'created_at',        sr.created_at,
                'customer', CASE WHEN c.id IS NOT NULL THEN
                    json_build_object(
                        'id',      c.id,
                        'name',    c.name,
                        'phone',   c.phone,
                        'email',   c.email,
                        'address', c.address
                    )
                ELSE NULL END,
                'items_summary', json_build_object(
                    'items_count',    (SELECT COUNT(*) FROM sale_return_items sri WHERE sri.return_id = sr.id),
                    'total_quantity', (SELECT COALESCE(SUM(quantity), 0) FROM sale_return_items sri WHERE sri.return_id = sr.id)
                ),
                'created_by', CASE WHEN u.id IS NOT NULL THEN
                    json_build_object(
                        'id',        u.id,
                        'full_name', u.full_name,
                        'email',     u.email,
                        'phone',     u.phone
                    )
                ELSE NULL END
            ) AS return_data
        FROM   sale_returns sr
        JOIN   sales s ON sr.sale_id = s.id
        LEFT JOIN customers c ON c.id = s.customer_id
        LEFT JOIN users     u ON u.id = sr.user_id
        WHERE  s.pharmacy_id         = p_pharmacy_id
        AND    s.deleted_at          IS NULL
        AND    (p_customer_id       IS NULL OR s.customer_id         = p_customer_id)
        AND    (NULLIF(p_return_status,    '') IS NULL OR sr.return_status::text    = p_return_status)
        AND    (p_start_date IS NULL OR (sr.return_date AT TIME ZONE 'Asia/Dhaka')::date >= p_start_date::date)
        AND    (p_end_date   IS NULL OR (sr.return_date AT TIME ZONE 'Asia/Dhaka')::date <= p_end_date::date)
        AND    (
            v_search_term IS NULL OR
            sr.return_number ILIKE v_search_term OR
            s.sale_number    ILIKE v_search_term OR
            c.name           ILIKE v_search_term OR
            c.phone          ILIKE v_search_term
        )
        ORDER  BY sr.return_date DESC
        LIMIT  p_limit OFFSET p_offset
    ) t;

    -- ── AGGREGATE SUMMARY ─────────────────────────────────────────────────────
    SELECT json_build_object(
        'total_returns',     COUNT(*),
        'total_refunded',    COALESCE(SUM(sr.refund_amount), 0),
        'total_credit_adj',  COALESCE(SUM(sr.credit_adjustment), 0),
        'total_cash_refund', COALESCE(SUM(sr.refund_amount) - SUM(sr.credit_adjustment), 0),
        'completed_returns', COUNT(*) FILTER (WHERE sr.return_status::text = 'COMPLETED'),
        'draft_returns',     COUNT(*) FILTER (WHERE sr.return_status::text = 'DRAFT'),
        'cancelled_returns', COUNT(*) FILTER (WHERE sr.return_status::text = 'CANCELLED')
    ) INTO v_summary
    FROM   sale_returns sr
    JOIN   sales s ON sr.sale_id = s.id
    LEFT JOIN customers c ON s.customer_id = c.id
    WHERE  s.pharmacy_id         = p_pharmacy_id
    AND    s.deleted_at          IS NULL
    AND    (p_customer_id       IS NULL OR s.customer_id         = p_customer_id)
    AND    (NULLIF(p_return_status,    '') IS NULL OR sr.return_status::text    = p_return_status)
    AND    (p_start_date IS NULL OR (sr.return_date AT TIME ZONE 'Asia/Dhaka')::date >= p_start_date::date)
    AND    (p_end_date   IS NULL OR (sr.return_date AT TIME ZONE 'Asia/Dhaka')::date <= p_end_date::date)
    AND    (
        v_search_term IS NULL OR
        sr.return_number ILIKE v_search_term OR
        s.sale_number    ILIKE v_search_term OR
        c.name           ILIKE v_search_term OR
        c.phone          ILIKE v_search_term
    );

    v_pagination := json_build_object(
        'total_count', v_total_count,
        'limit',       p_limit,
        'offset',      p_offset,
        'has_more',    v_total_count > (p_offset + p_limit)
    );

    v_filters := json_build_object(
        'date_filter',    p_date_filter,
        'start_date',     p_start_date,
        'end_date',       p_end_date,
        'return_status',  p_return_status,
        'customer_id',    p_customer_id,
        'search_query',   p_search_query
    );

    RETURN json_build_object(
        'code',    'SUCCESS',
        'message', 'Sale return history retrieved successfully',
        'hint',    NULL,
        'details', json_build_object(
            'returns',        COALESCE(v_returns, '[]'::json),
            'summary',        v_summary,
            'pagination',     v_pagination,
            'filters_applied',v_filters
        )
    );
END;
$$;


ALTER FUNCTION public.get_sale_return_list(p_pharmacy_id uuid, p_limit integer, p_offset integer, p_search_query text, p_date_filter text, p_start_date timestamp with time zone, p_end_date timestamp with time zone, p_return_status text, p_customer_id uuid) OWNER TO postgres;

--
-- TOC entry 906 (class 1255 OID 275113)
-- Name: get_stock_summaries(uuid, integer, integer, text, text, text, text, text, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_stock_summaries(p_pharmacy_id uuid, p_limit integer DEFAULT 100, p_offset integer DEFAULT 0, p_search_term text DEFAULT NULL::text, p_category text DEFAULT NULL::text, p_type text DEFAULT NULL::text, p_stock_status text DEFAULT NULL::text, p_base_unit text DEFAULT NULL::text, p_export_all boolean DEFAULT false) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id UUID := auth.uid();
    v_total_count INTEGER;
    v_search_normalized TEXT;
    v_items_json JSON;
    v_metadata_categories JSON;
    v_metadata_units JSON;
BEGIN
    IF v_user_id IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'Authentication required');
    END IF;

    IF p_pharmacy_id IS NULL THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Pharmacy ID is required');
    END IF;

    IF NOT user_has_permission(v_user_id, p_pharmacy_id, 'stock.view') THEN
        RETURN json_build_object('code', 'PERMISSION_DENIED', 'message', 'You do not have permission to view stock');
    END IF;

    p_limit := LEAST(GREATEST(COALESCE(p_limit, 100), 1), 200);
    p_offset := GREATEST(COALESCE(p_offset, 0), 0);
    v_search_normalized := NULLIF(TRIM(p_search_term), '');

    IF p_type IS NOT NULL AND UPPER(p_type) NOT IN ('MEDICINE', 'OTHER') THEN
        RETURN json_build_object('code', 'INVALID_TYPE', 'message', 'Invalid type: must be either MEDICINE or OTHER');
    END IF;

    -- Fetch pre-computed metadata
    SELECT m.categories, m.primary_units
    INTO v_metadata_categories, v_metadata_units
    FROM public.mv_pharmacy_stock_metadata m
    WHERE m.pharmacy_id = p_pharmacy_id;

    IF v_metadata_categories IS NULL THEN v_metadata_categories := '[]'::json; END IF;
    IF v_metadata_units IS NULL THEN v_metadata_units := '[]'::json; END IF;

    WITH latest_batches AS (
        SELECT DISTINCT ON (ib.inventory_id)
            ib.inventory_id,
            ib.selling_price AS batch_selling_price,
            ib.purchase_price AS batch_purchase_price
        FROM inventory_batches ib
        WHERE ib.pharmacy_id = p_pharmacy_id
          AND ib.status IN ('ACTIVE', 'NEAR_EXPIRY')
          AND ib.current_quantity > 0
          AND ib.deleted_at IS NULL
        ORDER BY ib.inventory_id, ib.created_at DESC
    ),
    filtered_stock AS (
        SELECT
            ss.inventory_id,
            i.name,
            ig.name AS generic_name,
            i.brand,
            i.category_id,
            COALESCE(c.name, i.category_id::text) as category,
            i.type::text,
            i.strength,
            i.primary_unit::text as primary_unit,
            i.secondary_unit::text as secondary_unit,
            COALESCE(i.conversion_rate, 1) AS conversion_rate,
            COALESCE(ss.total_quantity, 0) AS current_quantity,
            COALESCE(ss.total_batches, 0) AS total_batches,
            COALESCE(ss.active_batches, 0) AS active_batches,
            COALESCE(ss.expired_batches, 0) AS expired_batches,
            ss.nearest_expiry,
            lb.batch_selling_price,
            lb.batch_purchase_price,
            CASE
                WHEN COALESCE(ss.total_quantity, 0) = 0 THEN 'OUT_OF_STOCK'
                WHEN COALESCE(ss.total_quantity, 0) <= COALESCE(i.reorder_level, 10) THEN 'LOW_STOCK'
                WHEN ss.nearest_expiry IS NOT NULL AND ss.nearest_expiry <= CURRENT_DATE + INTERVAL '30 days' THEN 'EXPIRING_SOON'
                WHEN ss.expired_count > 0 THEN 'EXPIRED'
                ELSE 'IN_STOCK'
            END AS stock_status,
            EXTRACT(EPOCH FROM ss.updated_at)::BIGINT AS updated_at
        FROM stock_summary ss
        INNER JOIN inventory i ON ss.inventory_id = i.id
        LEFT JOIN categories c ON i.category_id = c.id
        LEFT JOIN inventory_generics ig ON i.generic_id = ig.id
        LEFT JOIN latest_batches lb ON ss.inventory_id = lb.inventory_id
        WHERE ss.pharmacy_id = p_pharmacy_id
          AND i.is_active = true
          AND i.deleted_at IS NULL
          AND (v_search_normalized IS NULL OR
               COALESCE(i.name, '') ILIKE '%' || v_search_normalized || '%' OR
               COALESCE(ig.name, '') ILIKE '%' || v_search_normalized || '%' OR
               COALESCE(i.brand, '') ILIKE '%' || v_search_normalized || '%' OR
               COALESCE(i.item_code, '') ILIKE '%' || v_search_normalized || '%')
          AND (p_category IS NULL OR c.name = p_category)
          AND (p_type IS NULL OR i.type::text = UPPER(p_type))
          AND (p_base_unit IS NULL OR i.primary_unit::text = p_base_unit)
          AND (p_stock_status IS NULL OR
               (p_stock_status = 'EXPIRED' AND ss.expired_count > 0) OR
               (p_stock_status != 'EXPIRED' AND
                   CASE
                       WHEN COALESCE(ss.total_quantity, 0) = 0 THEN 'OUT_OF_STOCK'
                       WHEN COALESCE(ss.total_quantity, 0) <= COALESCE(i.reorder_level, 10) THEN 'LOW_STOCK'
                       WHEN ss.nearest_expiry IS NOT NULL AND ss.nearest_expiry <= CURRENT_DATE + INTERVAL '30 days' THEN 'EXPIRING_SOON'
                       ELSE 'IN_STOCK'
                   END = p_stock_status)
               )
    )
    SELECT
        count_query.total_count,
        items_query.items_json
    INTO v_total_count, v_items_json
    FROM
        (SELECT COUNT(*) as total_count FROM filtered_stock) count_query,
        (SELECT COALESCE(json_agg(t.*), '[]'::json) as items_json
         FROM (
             SELECT * FROM filtered_stock
             ORDER BY updated_at DESC
             LIMIT CASE WHEN p_export_all THEN NULL ELSE p_limit END
             OFFSET CASE WHEN p_export_all THEN 0 ELSE p_offset END
         ) t) items_query;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Stock summaries retrieved successfully',
        'hint', NULL,
        'details', json_build_object(
            'items', v_items_json,
            'pagination', json_build_object(
                'total_count', v_total_count,
                'limit', p_limit,
                'offset', p_offset,
                'has_more', CASE WHEN p_export_all THEN false ELSE (p_offset + p_limit) < v_total_count END
            ),
            'metadata', json_build_object(
                'categories', v_metadata_categories,
                'types', json_build_array('MEDICINE', 'OTHER'),
                'stock_statuses', json_build_array('OUT_OF_STOCK', 'LOW_STOCK', 'EXPIRING_SOON', 'IN_STOCK'),
                'primary_units', v_metadata_units
            )
        )
    );
EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object(
        'code', 'INTERNAL_ERROR',
        'message', 'Failed to retrieve stock summaries: ' || SQLERRM,
        'details', json_build_object('sqlstate', SQLSTATE)
    );
END;
$$;


ALTER FUNCTION public.get_stock_summaries(p_pharmacy_id uuid, p_limit integer, p_offset integer, p_search_term text, p_category text, p_type text, p_stock_status text, p_base_unit text, p_export_all boolean) OWNER TO postgres;

--
-- TOC entry 493 (class 1255 OID 276777)
-- Name: get_stock_transaction_history(uuid, uuid, uuid, text, text, integer, integer, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_stock_transaction_history(p_pharmacy_id uuid, p_inventory_id uuid, p_batch_id uuid DEFAULT NULL::uuid, p_transaction_type text DEFAULT NULL::text, p_search_query text DEFAULT NULL::text, p_limit integer DEFAULT 50, p_offset integer DEFAULT 0, p_start_date timestamp with time zone DEFAULT NULL::timestamp with time zone, p_end_date timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id UUID;
    v_active_filters jsonb := '[]'::jsonb;
    v_transaction_type_filter text;
    v_search_lower text;
    v_inventory RECORD;
BEGIN
    v_user_id := auth.uid();

    IF v_user_id IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint', 'Please log in'
        );
    END IF;

    IF p_pharmacy_id IS NULL THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Pharmacy ID is required');
    END IF;

    IF p_inventory_id IS NULL THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Inventory ID is required');
    END IF;

    IF NOT user_has_permission(v_user_id, p_pharmacy_id, 'stock.view') THEN
        RETURN json_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied');
    END IF;

    -- Get inventory details with normalized Generic Name
    SELECT
        i.id,
        CASE
            WHEN i.type = 'MEDICINE' THEN CONCAT_WS(' ', i.brand, g.name, i.strength)
            ELSE i.name
        END AS display_name,
        COALESCE(i.primary_unit::text, 'unit') AS primary_unit,
        i.secondary_unit::text,
        COALESCE(i.conversion_rate, 1) AS conversion_rate,
        i.type::text AS inventory_type
    INTO v_inventory
    FROM inventory i
    LEFT JOIN inventory_generics g ON i.generic_id = g.id
    WHERE i.id = p_inventory_id
      AND i.pharmacy_id = p_pharmacy_id;

    IF NOT FOUND THEN
        RETURN json_build_object('code', 'INVENTORY_NOT_FOUND', 'message', 'Inventory not found');
    END IF;

    -- Normalize limits
    p_limit := LEAST(GREATEST(COALESCE(p_limit, 50), 1), 500);
    p_offset := GREATEST(COALESCE(p_offset, 0), 0);

    IF p_search_query IS NOT NULL AND TRIM(p_search_query) != '' THEN
        v_search_lower := LOWER(TRIM(p_search_query));
        v_active_filters := v_active_filters || jsonb_build_object('search', TRIM(p_search_query));
    END IF;

    IF p_batch_id IS NOT NULL THEN
        v_active_filters := v_active_filters || jsonb_build_object('batch_id', p_batch_id::text);
    END IF;

    IF p_transaction_type IS NOT NULL AND TRIM(p_transaction_type) != '' THEN
        v_transaction_type_filter := UPPER(TRIM(p_transaction_type));
        v_active_filters := v_active_filters || jsonb_build_object('transaction_type', v_transaction_type_filter);
    END IF;

    RETURN (
        WITH combined_history AS (
            -- STOCK TRANSACTIONS (quantity changes)
            SELECT
                st.id,
                st.inventory_id,
                st.batch_id,
                COALESCE(b.batch_number, 'N/A') AS batch_number,
                'transaction'::text AS change_category,
                st.transaction_type::text AS change_type,
                NULL::text AS field_name,
                st.quantity_before::text AS old_value,
                st.quantity_after::text AS new_value,
                st.quantity_change,
                st.quantity_before,
                st.quantity_after,
                COALESCE(st.unit_price, 0.0) AS unit_price,
                COALESCE(st.total_amount, 0.0) AS total_amount,
                st.reference_id,
                COALESCE(st.reference_number, '') AS reference_number,
                st.user_id,
                COALESCE(usr.full_name, 'System') AS user_name,
                COALESCE(upr.role_name, 'unknown') AS user_role,
                COALESCE(st.notes, '') AS notes,
                st.created_at,
                pur.purchase_number
            FROM stock_transactions st
            LEFT JOIN inventory_batches b ON st.batch_id = b.id
            LEFT JOIN purchases pur ON b.purchase_id = pur.id
            LEFT JOIN users usr ON st.user_id = usr.id
            LEFT JOIN LATERAL (
                SELECT ur.name AS role_name
                FROM user_pharmacies up
                JOIN user_roles ur ON ur.id = up.role_id
                WHERE up.user_id = st.user_id
                  AND up.pharmacy_id = p_pharmacy_id
                  AND up.is_active = true
                LIMIT 1
            ) upr ON true
            WHERE st.inventory_id = p_inventory_id
              AND st.deleted_at IS NULL
              AND (p_batch_id IS NULL OR st.batch_id = p_batch_id)
              AND (v_transaction_type_filter IS NULL OR st.transaction_type::text = v_transaction_type_filter)
              AND (p_start_date IS NULL OR st.created_at >= p_start_date)
              AND (p_end_date IS NULL OR st.created_at <= p_end_date)
              AND (
                  v_search_lower IS NULL
                  OR LOWER(COALESCE(st.notes, '')) LIKE '%' || v_search_lower || '%'
                  OR LOWER(COALESCE(usr.full_name, '')) LIKE '%' || v_search_lower || '%'
                  OR LOWER(st.transaction_type::TEXT) LIKE '%' || v_search_lower || '%'
              )

            UNION ALL

            -- BATCH AUDIT LOG (property changes)
            SELECT
                bal.id,
                bal.inventory_id,
                bal.batch_id,
                COALESCE(b.batch_number, 'N/A') AS batch_number,
                'audit'::text AS change_category,
                bal.change_type,
                bal.field_name,
                bal.old_value,
                bal.new_value,
                NULL::integer AS quantity_change,
                NULL::integer AS quantity_before,
                NULL::integer AS quantity_after,
                0.0 AS unit_price,
                0.0 AS total_amount,
                NULL::uuid AS reference_id,
                '' AS reference_number,
                bal.user_id,
                COALESCE(usr.full_name, 'System') AS user_name,
                COALESCE(upr.role_name, 'unknown') AS user_role,
                COALESCE(bal.notes, '') AS notes,
                bal.created_at,
                pur.purchase_number
            FROM batch_audit_log bal
            LEFT JOIN inventory_batches b ON bal.batch_id = b.id
            LEFT JOIN purchases pur ON b.purchase_id = pur.id
            LEFT JOIN users usr ON bal.user_id = usr.id
            LEFT JOIN LATERAL (
                SELECT ur.name AS role_name
                FROM user_pharmacies up
                JOIN user_roles ur ON ur.id = up.role_id
                WHERE up.user_id = bal.user_id
                  AND up.pharmacy_id = p_pharmacy_id
                  AND up.is_active = true
                LIMIT 1
            ) upr ON true
            WHERE bal.inventory_id = p_inventory_id
              AND (p_batch_id IS NULL OR bal.batch_id = p_batch_id)
              AND (v_transaction_type_filter IS NULL OR v_transaction_type_filter = 'ADJUSTMENT' OR bal.change_type ILIKE '%' || v_transaction_type_filter || '%')
              AND (p_start_date IS NULL OR bal.created_at >= p_start_date)
              AND (p_end_date IS NULL OR bal.created_at <= p_end_date)
              AND (
                  v_search_lower IS NULL
                  OR LOWER(COALESCE(bal.notes, '')) LIKE '%' || v_search_lower || '%'
                  OR LOWER(COALESCE(usr.full_name, '')) LIKE '%' || v_search_lower || '%'
                  OR LOWER(bal.change_type) LIKE '%' || v_search_lower || '%'
                  OR LOWER(bal.field_name) LIKE '%' || v_search_lower || '%'
              )
        ),
        windowed AS (
            SELECT
                *,
                COUNT(*) OVER() AS total_count
            FROM combined_history
            ORDER BY created_at DESC
            LIMIT p_limit OFFSET p_offset
        )
        SELECT json_build_object(
            'code', 'SUCCESS',
            'message', format('%s record(s) found', COALESCE((SELECT total_count FROM windowed LIMIT 1), 0)),
            'details', json_build_object(
                'total_count', COALESCE((SELECT total_count FROM windowed LIMIT 1), 0),
                'limit', p_limit,
                'offset', p_offset,
                'page', CASE WHEN p_limit > 0 THEN (p_offset / p_limit) + 1 ELSE 1 END,
                'has_more', COALESCE((SELECT total_count FROM windowed LIMIT 1), 0) > (p_offset + p_limit),
                'returned_count', (SELECT COUNT(*) FROM windowed),
                'active_filters', v_active_filters,
                'inventory_name', v_inventory.display_name,
                'primary_unit', v_inventory.primary_unit,
                'secondary_unit', v_inventory.secondary_unit,
                'conversion_rate', v_inventory.conversion_rate,
                'inventory_type', v_inventory.inventory_type,
                'transactions', COALESCE(
                    (SELECT json_agg(
                        json_build_object(
                            'id', w.id,
                            'inventory_id', w.inventory_id,
                            'batch_id', w.batch_id,
                            'batch_number', w.batch_number,
                            'purchase_number', w.purchase_number,
                            'change_category', w.change_category,
                            'change_type', w.change_type,
                            'field_name', w.field_name,
                            'old_value', w.old_value,
                            'new_value', w.new_value,
                            'quantity_change', w.quantity_change,
                            'quantity_before', w.quantity_before,
                            'quantity_after', w.quantity_after,
                            'unit_price', w.unit_price,
                            'total_amount', w.total_amount,
                            'reference_id', w.reference_id,
                            'reference_number', w.reference_number,
                            'user_id', w.user_id,
                            'user_name', w.user_name,
                            'user_role', w.user_role,
                            'notes', w.notes,
                            'created_at', w.created_at,
                            'primary_unit', v_inventory.primary_unit,
                            'secondary_unit', v_inventory.secondary_unit,
                            'conversion_rate', v_inventory.conversion_rate,
                            'inventory_type', v_inventory.inventory_type
                        ) ORDER BY w.created_at DESC
                    ) FROM windowed w),
                    '[]'::json
                )
            )
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        RETURN json_build_object(
            'code', 'INTERNAL_ERROR',
            'message', 'Failed to retrieve stock history',
            'details', json_build_object('sqlstate', SQLSTATE, 'error', SQLERRM)
        );
END;
$$;


ALTER FUNCTION public.get_stock_transaction_history(p_pharmacy_id uuid, p_inventory_id uuid, p_batch_id uuid, p_transaction_type text, p_search_query text, p_limit integer, p_offset integer, p_start_date timestamp with time zone, p_end_date timestamp with time zone) OWNER TO postgres;

--
-- TOC entry 1201 (class 1255 OID 237747)
-- Name: get_supplier_details(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_supplier_details(p_supplier_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$DECLARE
    v_result JSONB;
BEGIN
    SELECT json_build_object(
        'id', s.id,
        'pharmacy_id', s.pharmacy_id,
        'name', s.name,
        'type', s.supplier_type,
        'contact_person', s.contact_person,
        'phone', s.phone,
        'email', s.email,
        'address', s.address,
        'notes', s.notes,
        'is_active', s.is_active,
        'created_at', s.created_at,
        'stats', json_build_object(
            'total_purchases', COALESCE(stats.total_purchases, 0),
            'total_purchase_amount', COALESCE(stats.total_amount, 0),
            'total_paid', COALESCE(stats.total_paid, 0),
            'total_due', COALESCE(stats.total_due, 0),
            'last_purchase_date', stats.last_purchase_date
        )
    ) INTO v_result
    FROM public.suppliers s
    LEFT JOIN (
        SELECT
            supplier_id,
            COUNT(*) as total_purchases,
            SUM(total_amount) as total_amount,
            SUM(paid_amount) as total_paid,
            SUM(total_amount - paid_amount) as total_due,
            MAX(purchase_date) as last_purchase_date
        FROM public.purchases
        WHERE purchase_status != 'CANCELLED'
        GROUP BY supplier_id
    ) stats ON stats.supplier_id = s.id
    WHERE s.id = p_supplier_id
      AND s.deleted_at IS NULL;

    IF v_result IS NULL THEN
        RETURN json_build_object(
            'code', '404',
            'message', 'Supplier not found',
            'details', null
        );
    END IF;

    RETURN json_build_object(
        'code', '200',
        'message', 'Success',
        'details', v_result
    );
END;$$;


ALTER FUNCTION public.get_supplier_details(p_supplier_id uuid) OWNER TO postgres;

--
-- TOC entry 1269 (class 1255 OID 169027)
-- Name: get_user_pharmacies(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_user_pharmacies(p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    result jsonb;
BEGIN
    -- Fetch active pharmacies for the user
    SELECT COALESCE(
        jsonb_agg(
            jsonb_build_object(
                'id', p.id,
                'name', p.name,
                'address', p.address,
                'city', p.city,
                'district', p.district,
                'phone', p.phone,
                'email', p.email,
                'is_active', p.is_active,
                'verified', p.verified,
                'is_primary', up.is_primary,
                'role', ur.slug,
                'role_name', ur.name,
                'created_at', p.created_at
            ) ORDER BY up.is_primary DESC, p.created_at DESC
        ),
        '[]'::jsonb
    )
    INTO result
    FROM user_pharmacies up
    JOIN pharmacies p ON p.id = up.pharmacy_id
    JOIN user_roles ur ON ur.id = up.role_id
    WHERE up.user_id = p_user_id
      AND up.is_active = true
      AND p.deleted_at IS NULL
      AND p.is_active = true;

    -- Wrap response in base API structure
    RETURN jsonb_build_object(
        'code', 'SUCCESS',
        'message', 'User pharmacies fetched successfully',
        'hint', null,
        'details', result
    );

EXCEPTION
    WHEN OTHERS THEN
        -- Catch any errors and return in standard API format
        RETURN jsonb_build_object(
            'code', 'FAILED',
            'message', 'Failed to fetch user pharmacies',
            'hint', SQLERRM,
            'details', '[]'::jsonb
        );
END;
$$;


ALTER FUNCTION public.get_user_pharmacies(p_user_id uuid) OWNER TO postgres;

--
-- TOC entry 1163 (class 1255 OID 169053)
-- Name: get_user_profile_with_pharmacies(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_user_profile_with_pharmacies(p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$DECLARE
    response JSONB;
BEGIN
    WITH user_data AS (
        SELECT
            u.id,
            u.full_name,
            u.phone,
            u.email,
            u.avatar_url,
            u.is_active,
            u.created_at,
            u.updated_at,

            (
                CASE 
                    WHEN NULLIF(TRIM(u.full_name), '') IS NULL
                      OR NULLIF(TRIM(u.phone), '') IS NULL
                    THEN false
                    ELSE true
                END
            ) AS profile_complete

        FROM users u
        WHERE u.id = p_user_id
          AND u.deleted_at IS NULL
    ),

    pharmacy_data AS (
        SELECT jsonb_agg(
            jsonb_build_object(
                'id', p.id,
                'name', p.name,
                'verified', p.verified,
                'is_active', p.is_active,
                'address', p.address,
                'city', p.city,
                'district', p.district,
                'phone', p.phone,
                'email', p.email,
                'role', ur.slug,
                'created_by', p.created_by
            )
            ORDER BY p.created_at DESC
        ) AS pharmacies
        FROM user_pharmacies up
        JOIN pharmacies p ON p.id = up.pharmacy_id AND p.deleted_at IS NULL
        JOIN user_roles ur ON ur.id = up.role_id
        WHERE up.user_id = p_user_id
          AND up.is_active = true
    )

    SELECT jsonb_build_object(
        'code', 'SUCCESS',
        'message', 'User data loaded successfully',
        'hint', NULL,
        'details', jsonb_build_object(
            'user', (SELECT row_to_json(user_data.*) FROM user_data),
            'pharmacies', (SELECT pharmacies FROM pharmacy_data)
        )
    )
    INTO response;

    RETURN response;
END;$$;


ALTER FUNCTION public.get_user_profile_with_pharmacies(p_user_id uuid) OWNER TO postgres;

--
-- TOC entry 1450 (class 1255 OID 88168)
-- Name: global_inventory_add_data_from_python(text, text, text, text, text, text, text, text, smallint); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.global_inventory_add_data_from_python(p_category text, p_name text, p_brand text, p_generic_name text, p_strength text, p_base_unit text, p_manufacturer text, p_item_code text, p_unit_per_strip smallint DEFAULT 1) RETURNS json
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_exists integer := 0;
  v_result json;
  v_new_id uuid;
  v_generic_id uuid;
  v_manufacturer_id uuid;
BEGIN
  -- Check for duplicates
  SELECT COUNT(*) INTO v_exists
  FROM inventory_global
  WHERE type = 'MEDICINE'
    AND LOWER(TRIM(brand)) = LOWER(TRIM(p_brand))
    AND LOWER(TRIM(strength)) = LOWER(TRIM(COALESCE(p_strength, '')));

  IF v_exists > 0 THEN
    v_result := json_build_object(
      'success', false,
      'message', 'Medicine already exists in inventory',
      'duplicate', true
    );
  ELSE
    v_new_id := gen_random_uuid();

    -- Upsert generic
    IF p_generic_name IS NOT NULL AND TRIM(p_generic_name) != '' AND TRIM(p_generic_name) != 'N/A' THEN
      INSERT INTO public.inventory_generics (name)
      VALUES (TRIM(p_generic_name))
      ON CONFLICT (LOWER(TRIM(name))) DO UPDATE SET name = EXCLUDED.name
      RETURNING id INTO v_generic_id;
    END IF;

    -- Upsert manufacturer
    IF p_manufacturer IS NOT NULL AND TRIM(p_manufacturer) != '' AND TRIM(p_manufacturer) != 'N/A' THEN
      INSERT INTO public.inventory_manufacturers (name)
      VALUES (TRIM(p_manufacturer))
      ON CONFLICT (LOWER(TRIM(name))) DO UPDATE SET name = EXCLUDED.name
      RETURNING id INTO v_manufacturer_id;
    END IF;

    INSERT INTO inventory_global (
      id,
      type,
      category,
      name,
      brand,
      generic_id,
      strength,
      primary_unit,
      manufacturer_id,
      item_code,
      conversion_rate,
      created_at,
      updated_at
    ) VALUES (
      v_new_id,
      'MEDICINE',
      TRIM(p_category),
      NULL,
      CASE WHEN p_brand IS NOT NULL AND TRIM(p_brand) != '' AND TRIM(p_brand) != 'N/A'
           THEN TRIM(p_brand) ELSE NULL END,
      v_generic_id,
      TRIM(p_strength),
      p_base_unit,
      v_manufacturer_id,
      TRIM(p_item_code),
      CASE WHEN p_unit_per_strip IS NOT NULL AND p_unit_per_strip > 0
           THEN p_unit_per_strip ELSE 1 END,
      NOW(),
      NOW()
    );

    v_result := json_build_object(
      'success', true,
      'message', 'Medicine added to inventory',
      'id', v_new_id
    );
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION public.global_inventory_add_data_from_python(p_category text, p_name text, p_brand text, p_generic_name text, p_strength text, p_base_unit text, p_manufacturer text, p_item_code text, p_unit_per_strip smallint) OWNER TO postgres;

--
-- TOC entry 928 (class 1255 OID 276610)
-- Name: global_inventory_add_data_from_python(text, uuid, text, text, text, text, text, text, text, integer, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.global_inventory_add_data_from_python(p_type text, p_category_id uuid, p_brand text, p_generic_name text, p_strength text, p_manufacturer_name text, p_name text, p_primary_unit text, p_secondary_unit text, p_conversion_rate integer, p_item_code text, p_medex_url text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_generic_id UUID;
    v_manufacturer_id UUID;
    v_enum_primary_unit public.unit_enum;
    v_enum_secondary_unit public.unit_enum;
    v_new_id UUID;
BEGIN
    IF p_generic_name IS NOT NULL THEN v_generic_id := public.create_generic(p_generic_name); END IF;
    IF p_manufacturer_name IS NOT NULL THEN v_manufacturer_id := public.create_manufacturer(p_manufacturer_name); END IF;
    
    v_enum_primary_unit := COALESCE(public.text_to_unit_enum(p_primary_unit), 'piece'::public.unit_enum);
    v_enum_secondary_unit := public.text_to_unit_enum(p_secondary_unit);

    INSERT INTO public.inventory_global (
        type, category_id, brand, generic_id, strength, manufacturer_id, name,
        primary_unit, secondary_unit, conversion_rate, item_code, medex_url, entry_status
    )
    VALUES (
        CAST(p_type AS public.inventory_type_enum), p_category_id, p_brand, v_generic_id, p_strength, v_manufacturer_id, p_name,
        v_enum_primary_unit, v_enum_secondary_unit, COALESCE(p_conversion_rate, 1), COALESCE(p_item_code, ''), p_medex_url, 'AI_L1'
    )
    ON CONFLICT (brand, generic_id, manufacturer_id, strength) DO NOTHING
    RETURNING id INTO v_new_id;

    RETURN json_build_object('code', 'SUCCESS', 'id', v_new_id);
EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object('code', 'INTERNAL_ERROR', 'message', SQLERRM);
END;
$$;


ALTER FUNCTION public.global_inventory_add_data_from_python(p_type text, p_category_id uuid, p_brand text, p_generic_name text, p_strength text, p_manufacturer_name text, p_name text, p_primary_unit text, p_secondary_unit text, p_conversion_rate integer, p_item_code text, p_medex_url text) OWNER TO postgres;

--
-- TOC entry 994 (class 1255 OID 271063)
-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.handle_new_user() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    INSERT INTO public.users (id, full_name, email, phone, is_active, created_at, updated_at)
    VALUES (
        NEW.id,
        COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.raw_user_meta_data->>'display_name', ''),
        NEW.email,
        NEW.raw_user_meta_data->>'phone',
        TRUE,
        NOW(),
        NOW()
    )
    ON CONFLICT (id) DO UPDATE
    SET
        email = EXCLUDED.email,
        full_name = CASE 
            WHEN public.users.full_name = '' OR public.users.full_name IS NULL THEN EXCLUDED.full_name 
            ELSE public.users.full_name 
        END,
        phone = CASE 
            WHEN public.users.phone = '' OR public.users.phone IS NULL THEN EXCLUDED.phone 
            ELSE public.users.phone 
        END,
        updated_at = NOW();
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.handle_new_user() OWNER TO postgres;

--
-- TOC entry 1344 (class 1255 OID 265044)
-- Name: log_batch_changes(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.log_batch_changes() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_inv_name TEXT;
    v_inv_type TEXT;
    v_message TEXT;
    v_changes JSONB := '{}'::jsonb;
    v_has_changes BOOLEAN := FALSE;
    v_today DATE := (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE;
BEGIN
    -- Detect individual field changes
    IF OLD.status IS DISTINCT FROM NEW.status THEN
        v_changes := v_changes || jsonb_build_object('old_status', OLD.status, 'new_status', NEW.status);
        v_message := 'Status: ' || NEW.status;
        v_has_changes := TRUE;
    END IF;

    IF OLD.expiry_date IS DISTINCT FROM NEW.expiry_date THEN
        v_changes := v_changes || jsonb_build_object('old_expiry', OLD.expiry_date, 'new_expiry', NEW.expiry_date);
        v_message := COALESCE(v_message || ', ', '') || 'Expiry: ' || COALESCE(NEW.expiry_date::TEXT, 'N/A')
            || CASE WHEN NEW.expiry_date IS NOT NULL AND NEW.expiry_date < v_today THEN ' (Expired)' ELSE '' END;
        v_has_changes := TRUE;
    END IF;

    IF OLD.selling_price IS DISTINCT FROM NEW.selling_price THEN
        v_changes := v_changes || jsonb_build_object('old_price', OLD.selling_price, 'new_price', NEW.selling_price);
        v_message := COALESCE(v_message || ', ', '') || 'Price: ' || COALESCE(NEW.selling_price::TEXT, '0');
        v_has_changes := TRUE;
    END IF;

    IF OLD.purchase_price IS DISTINCT FROM NEW.purchase_price THEN
        v_changes := v_changes || jsonb_build_object('old_cost', OLD.purchase_price, 'new_cost', NEW.purchase_price);
        v_has_changes := TRUE;
    END IF;

    -- Only log if something actually changed
    IF NOT v_has_changes THEN
        RETURN NEW;
    END IF;

    -- Get inventory display name (only needed columns, not SELECT *)
    SELECT
        CASE WHEN i.type = 'MEDICINE'
            THEN COALESCE(i.brand, 'Unknown') || ' ' || COALESCE(i.strength, '')
            ELSE COALESCE(i.name, 'Unknown')
        END,
        i.type::TEXT
    INTO v_inv_name, v_inv_type
    FROM inventory i
    WHERE i.id = NEW.inventory_id;

    -- Fallback if inventory not found
    IF v_inv_name IS NULL THEN
        v_inv_name := 'Item #' || LEFT(NEW.inventory_id::TEXT, 8);
    END IF;

    -- Append batch number
    IF NEW.batch_number IS NOT NULL THEN
        v_inv_name := v_inv_name || ' (' || NEW.batch_number || ')';
    END IF;

    v_message := 'Batch Audit: ' || v_inv_name || ' -> ' || COALESCE(v_message, 'Details updated');

    INSERT INTO public.activity_logs (pharmacy_id, entity_id, activity_type, message, metadata, created_at)
    VALUES (
        NEW.pharmacy_id,
        NEW.id,
        'AUDIT',
        v_message,
        jsonb_build_object(
            'inventory_id', NEW.inventory_id,
            'inventory_name', v_inv_name,
            'batch_number', NEW.batch_number,
            'changes', v_changes
        ),
        NOW() AT TIME ZONE 'Asia/Dhaka'
    );

    RETURN NEW;
END;
$$;


ALTER FUNCTION public.log_batch_changes() OWNER TO postgres;

