--

CREATE FUNCTION public.log_purchase_activity() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_supplier_name TEXT;
    v_message TEXT;
BEGIN
    -- Only log on transition to COMPLETED
    IF NOT (
        (TG_OP = 'INSERT' AND NEW.purchase_status = 'COMPLETED') OR
        (TG_OP = 'UPDATE' AND NEW.purchase_status = 'COMPLETED' AND OLD.purchase_status IS DISTINCT FROM 'COMPLETED')
    ) THEN
        RETURN NEW;
    END IF;

    -- Fetch supplier name (single safe query, no exception block needed)
    SELECT COALESCE(s.name, 'Supplier')
    INTO v_supplier_name
    FROM suppliers s
    WHERE s.id = NEW.supplier_id;

    v_supplier_name := COALESCE(v_supplier_name, 'Supplier');

    v_message := 'Purchase #' || COALESCE(NEW.purchase_number, 'N/A') ||
                 ': ৳' || COALESCE(NEW.total_amount::TEXT, '0') ||
                 ' - ' || v_supplier_name;

    INSERT INTO public.activity_logs (pharmacy_id, entity_id, activity_type, message, metadata, created_at)
    VALUES (
        NEW.pharmacy_id,
        NEW.id,
        'PURCHASE',
        v_message,
        jsonb_build_object(
            'amount', COALESCE(NEW.total_amount, 0),
            'purchase_number', COALESCE(NEW.purchase_number, ''),
            'invoice_number', COALESCE(NEW.invoice_number, ''),
            'supplier_id', NEW.supplier_id,
            'supplier_name', v_supplier_name
        ),
        COALESCE(NEW.purchase_date, NOW())
    );

    RETURN NEW;
END;
$$;


