CREATE FUNCTION public.log_purchase_return_activity() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_purchase_number TEXT;
    v_supplier_name TEXT;
    v_message TEXT;
BEGIN
    -- Only log on transition to COMPLETED
    IF NOT (
        (TG_OP = 'INSERT' AND NEW.refund_status = 'COMPLETED') OR
        (TG_OP = 'UPDATE' AND NEW.refund_status = 'COMPLETED' AND OLD.refund_status IS DISTINCT FROM 'COMPLETED')
    ) THEN
        RETURN NEW;
    END IF;

    -- Fetch purchase number and supplier name in one query
    SELECT
        COALESCE(p.purchase_number, 'Unknown Purchase'),
        COALESCE(s.name, 'Supplier')
    INTO v_purchase_number, v_supplier_name
    FROM purchases p
    LEFT JOIN suppliers s ON s.id = COALESCE(NEW.supplier_id, p.supplier_id)
    WHERE p.id = NEW.purchase_id;

    v_purchase_number := COALESCE(v_purchase_number, 'Unknown Purchase');
    v_supplier_name := COALESCE(v_supplier_name, 'Supplier');

    v_message := 'Purchase Return #' || COALESCE(NEW.return_number, 'N/A') ||
                 ' (Purchase #' || v_purchase_number || ')' ||
                 ': ৳' || COALESCE(NEW.total_amount::TEXT, '0') ||
                 ' - ' || v_supplier_name;

    INSERT INTO public.activity_logs (pharmacy_id, entity_id, activity_type, message, metadata, created_at)
    VALUES (
        NEW.pharmacy_id,
        NEW.id,
        'PURCHASE_RETURN',
        v_message,
        jsonb_build_object(
            'amount', COALESCE(NEW.total_amount, 0),
            'return_number', COALESCE(NEW.return_number, ''),
            'purchase_id', NEW.purchase_id,
            'purchase_number', v_purchase_number,
            'supplier_id', NEW.supplier_id,
            'supplier_name', v_supplier_name
        ),
        COALESCE(NEW.return_date, NOW())
    );

    RETURN NEW;
END;
$$;


