--

CREATE FUNCTION public.log_sale_activity() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_item_count INTEGER;
    v_staff_name TEXT;
    v_message TEXT;
BEGIN
    -- Only log on transition to COMPLETED
    IF NOT (
        (TG_OP = 'INSERT' AND NEW.sale_status = 'COMPLETED') OR
        (TG_OP = 'UPDATE' AND NEW.sale_status = 'COMPLETED' AND OLD.sale_status IS DISTINCT FROM 'COMPLETED')
    ) THEN
        RETURN NEW;
    END IF;

    -- Single query: fetch item count and staff name together
    SELECT
        COALESCE(si.cnt, 0),
        COALESCE(u.full_name, 'Staff')
    INTO v_item_count, v_staff_name
    FROM (SELECT 1) AS dummy
    LEFT JOIN (
        SELECT COUNT(*) AS cnt FROM sale_items WHERE sale_id = NEW.id
    ) si ON true
    LEFT JOIN users u ON u.id = NEW.user_id;

    v_message := 'Sale #' || COALESCE(NEW.sale_number, 'N/A') ||
                 ': ৳' || COALESCE(NEW.total_amount::TEXT, '0') ||
                 ' - ' || v_staff_name ||
                 ' (' || v_item_count || ' items)';

    INSERT INTO public.activity_logs (pharmacy_id, entity_id, activity_type, message, metadata, created_at)
    VALUES (
        NEW.pharmacy_id,
        NEW.id,
        'SALE',
        v_message,
        jsonb_build_object(
            'amount', COALESCE(NEW.total_amount, 0),
            'sale_number', COALESCE(NEW.sale_number, ''),
            'customer_id', NEW.customer_id,
            'item_count', v_item_count,
            'staff_name', v_staff_name
        ),
        COALESCE(NEW.sale_date, NOW())
    );

    RETURN NEW;
END;
$$;


