--
-- TOC entry 971 (class 1255 OID 255290)
-- Name: log_stock_activity(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.log_stock_activity() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_inv_name TEXT;
    v_inv_type TEXT;
    v_conversion_rate INTEGER;
    v_primary_unit TEXT;
    v_secondary_unit TEXT;
    v_message TEXT;
    v_qty_text TEXT;
    v_qty_change INTEGER;
    v_abs_qty INTEGER;
    v_primary_qty INTEGER;
    v_secondary_qty INTEGER;
    v_sign TEXT;
BEGIN
    -- Only log relevant transaction types (not PURCHASE or SALE which have their own logs)
    IF NEW.transaction_type::TEXT NOT IN ('ADJUSTMENT', 'DAMAGE', 'EXPIRED', 'LOST', 'SALE_RETURN', 'PURCHASE_RETURN') THEN
        RETURN NEW;
    END IF;

    -- Fetch only needed inventory columns (NOT SELECT *)
    SELECT
        CASE WHEN i.type = 'MEDICINE'
            THEN COALESCE(i.brand, i.name, 'Unknown') || ' ' || COALESCE(i.strength, '')
            ELSE COALESCE(i.name, 'Unknown')
        END,
        i.type::TEXT,
        COALESCE(i.conversion_rate, 1),
        COALESCE(i.primary_unit, 'Units'),
        COALESCE(i.secondary_unit, 'Pcs')
    INTO v_inv_name, v_inv_type, v_conversion_rate, v_primary_unit, v_secondary_unit
    FROM inventory i
    WHERE i.id = NEW.inventory_id;

    -- Fallback if inventory not found (deleted)
    IF v_inv_name IS NULL THEN
        v_inv_name := 'Item #' || LEFT(NEW.inventory_id::TEXT, 8);
        v_conversion_rate := 1;
        v_primary_unit := 'Units';
        v_secondary_unit := 'Pcs';
    END IF;

    -- Format quantity with unit breakdown
    v_qty_change := COALESCE(NEW.quantity_change, 0);
    v_abs_qty := ABS(v_qty_change);
    v_sign := CASE WHEN v_qty_change >= 0 THEN '+' ELSE '-' END;

    IF v_conversion_rate > 1 AND v_abs_qty > 0 THEN
        v_primary_qty := v_abs_qty / v_conversion_rate;
        v_secondary_qty := v_abs_qty % v_conversion_rate;

        v_qty_text := v_sign;
        IF v_primary_qty > 0 THEN
            v_qty_text := v_qty_text || v_primary_qty || ' ' || v_primary_unit;
        END IF;
        IF v_secondary_qty > 0 THEN
            IF v_primary_qty > 0 THEN v_qty_text := v_qty_text || ' '; END IF;
            v_qty_text := v_qty_text || v_secondary_qty || ' ' || v_secondary_unit;
        END IF;
    ELSE
        v_qty_text := v_sign || v_abs_qty || ' ' || v_primary_unit;
    END IF;

    -- Edge case: zero change
    IF v_abs_qty = 0 THEN
        v_qty_text := '0 ' || v_primary_unit;
    END IF;

    v_message := 'Stock: ' || v_inv_name || ' ' || v_qty_text ||
                 ' (' || REPLACE(INITCAP(NEW.transaction_type::TEXT), '_', ' ') || ')';

    INSERT INTO public.activity_logs (pharmacy_id, entity_id, activity_type, message, metadata, created_at)
    VALUES (
        NEW.pharmacy_id,
        NEW.id,
        'ADJUSTMENT',
        v_message,
        jsonb_build_object(
            'inventory_id', NEW.inventory_id,
            'inventory_name', v_inv_name,
            'inventory_type', v_inv_type,
            'quantity_change', v_qty_change,
            'quantity_formatted', v_qty_text,
            'batch_id', NEW.batch_id,
            'transaction_type', NEW.transaction_type,
            'reason', NEW.notes
        ),
        COALESCE(NEW.created_at, NOW() AT TIME ZONE 'Asia/Dhaka')
    );

    RETURN NEW;
END;
$$;


