--
-- TOC entry 1023 (class 1255 OID 235345)
-- Name: open_sale_draft(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.open_sale_draft(p_pharmacy_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
    v_user_id      UUID;
    v_sale_id      UUID;
    v_sale_number  TEXT;
    v_draft        RECORD;   -- BUG-10 FIX: holds existing draft's real values
BEGIN
    v_user_id := auth.uid();

    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated'
        );
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies pu
        WHERE  pu.user_id    = v_user_id
        AND    pu.pharmacy_id = p_pharmacy_id
        AND    pu.is_active   = true
    ) THEN
        RETURN jsonb_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'Permission denied'
        );
    END IF;

    -- ── BUG-10 FIX: load all columns of the existing draft ───────────────────
    --   Previous code only selected id, then returned hardcoded 0,0,0 for
    --   subtotal / discount_amount / total_amount. The Kotlin Sale domain
    --   object is populated from this response, so the cart showed empty
    --   totals even when items were already in the draft.
    SELECT *
    INTO   v_draft
    FROM   sales
    WHERE  pharmacy_id  = p_pharmacy_id
    AND    user_id      = v_user_id
    AND    sale_status  = 'DRAFT'
    AND    deleted_at   IS NULL
    ORDER  BY created_at DESC
    LIMIT  1;

    IF v_draft IS NOT NULL THEN
        RETURN jsonb_build_object(
            'code',    'SUCCESS',
            'message', 'Existing draft found',
            'details', jsonb_build_object(
                'sale_id',        v_draft.id,
                'sale_number',    v_draft.sale_number,
                'customer_id',    v_draft.customer_id,
                -- Real persisted values (previously hardcoded to 0)
                'subtotal',       ROUND(COALESCE(v_draft.subtotal, 0), 2),
                'discount_amount',ROUND(COALESCE(v_draft.discount_amount, 0), 2),
                'total_amount',   ROUND(COALESCE(v_draft.total_amount, 0), 2),
                'items_count',    (SELECT COUNT(*) FROM sale_items WHERE sale_id = v_draft.id),
                'is_new',         false,
                'created_at',     v_draft.created_at,
                'updated_at',     v_draft.updated_at
            )
        );
    END IF;

    -- ── Create a new draft ────────────────────────────────────────────────────
    SELECT 'SAL-' || LPAD(
        (COALESCE(MAX(CAST(SUBSTRING(sale_number FROM 5) AS INT)), 0) + 1)::TEXT,
        8, '0'
    )
    INTO   v_sale_number
    FROM   sales
    WHERE  pharmacy_id  = p_pharmacy_id
    AND    sale_number ~ '^SAL-[0-9]{8}$';

    v_sale_id := gen_random_uuid();

    INSERT INTO sales (
        id, pharmacy_id, user_id, sale_number,
        sale_status, payment_status,
        subtotal, discount_amount, total_amount,
        paid_amount, outstanding_amount,
        is_credit_sale,
        created_at, updated_at
    ) VALUES (
        v_sale_id, p_pharmacy_id, v_user_id, v_sale_number,
        'DRAFT', 'PENDING',
        0, 0, 0,
        0, 0,
        false,
        NOW(), NOW()
    );

    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Sale created',
        'details', jsonb_build_object(
            'sale_id',         v_sale_id,
            'sale_number',     v_sale_number,
            'customer_id',     NULL,
            'subtotal',        0,
            'discount_amount', 0,
            'total_amount',    0,
            'items_count',     0,
            'is_new',          true,
            'created_at',      NOW(),
            'updated_at',      NOW()
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'code',    'INTERNAL_ERROR',
            'message', SQLERRM
        );
END;
$_$;


