-- TOC entry 863 (class 1255 OID 269886)
-- Name: pay_customer_due(uuid, text, numeric, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pay_customer_due(p_sale_id uuid, p_payment_method text, p_amount numeric, p_mobile_number text DEFAULT NULL::text, p_transaction_id text DEFAULT NULL::text, p_card_number text DEFAULT NULL::text, p_notes text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
    -- Delegate to the canonical implementation using named arguments.
    -- p_credit_id is intentionally omitted (defaults to NULL) so the
    -- implementation resolves the credit record via p_sale_id.
    RETURN public.settle_customer_outstanding(
        p_payment_method := p_payment_method,
        p_amount         := p_amount,
        p_sale_id        := p_sale_id,
        p_mobile_number  := p_mobile_number,
        p_transaction_id := p_transaction_id,
        p_card_number    := p_card_number,
        p_notes          := p_notes
    );
END;
$$;


