--
-- TOC entry 965 (class 1255 OID 275117)
-- Name: remove_purchase_item(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.remove_purchase_item(p_purchase_id uuid, p_item_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_purchase        RECORD;
    v_item            RECORD;
    v_inventory       RECORD;
    v_new_subtotal    NUMERIC(12,2);
    v_new_total       NUMERIC(12,2);
    v_new_outstanding NUMERIC(12,2);
    v_items_count     INTEGER;
BEGIN
    v_current_user_id := auth.uid();

    IF v_current_user_id IS NULL THEN
        RETURN json_build_object(
            'code',    'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint',    'Please log in to continue',
            'details', NULL
        );
    END IF;

    IF p_purchase_id IS NULL THEN
        RETURN json_build_object(
            'code',    'INVALID_INPUT',
            'message', 'Purchase ID is required',
            'hint',    'Provide a valid purchase ID',
            'details', NULL
        );
    END IF;

    IF p_item_id IS NULL THEN
        RETURN json_build_object(
            'code',    'INVALID_INPUT',
            'message', 'Item ID is required',
            'hint',    'Provide a valid item ID',
            'details', NULL
        );
    END IF;

    SELECT
        p.id, p.pharmacy_id, p.user_id, p.purchase_number,
        p.purchase_status, p.discount_amount, p.paid_amount
    INTO v_purchase
    FROM purchases p
    WHERE p.id = p_purchase_id
      AND p.deleted_at IS NULL
    FOR UPDATE NOWAIT;

    IF NOT FOUND THEN
        RETURN json_build_object(
            'code',    'PURCHASE_NOT_FOUND',
            'message', 'Purchase not found',
            'hint',    'Verify purchase ID is correct',
            'details', NULL
        );
    END IF;

    IF v_purchase.purchase_status != 'DRAFT' THEN
        RETURN json_build_object(
            'code',    'INVALID_STATUS',
            'message', 'Can only modify draft purchases',
            'hint',    'Purchase status: ' || v_purchase.purchase_status,
            'details', json_build_object(
                'current_status',  v_purchase.purchase_status,
                'purchase_number', v_purchase.purchase_number
            )
        );
    END IF;

    IF NOT user_has_permission(v_current_user_id, v_purchase.pharmacy_id, 'purchase.create') THEN
        RETURN json_build_object(
            'code',    'PERMISSION_DENIED',
            'message', 'You do not have permission to modify purchases',
            'hint',    'Contact your administrator',
            'details', NULL
        );
    END IF;

    SELECT
        pi.id, pi.inventory_id, pi.batch_number, pi.expiry_date,
        pi.quantity, pi.purchase_price, pi.selling_price, pi.total_price
    INTO v_item
    FROM purchase_items pi
    WHERE pi.id = p_item_id
      AND pi.purchase_id = p_purchase_id;

    IF NOT FOUND THEN
        RETURN json_build_object(
            'code',    'ITEM_NOT_FOUND',
            'message', 'Item not found in this purchase',
            'hint',    'Verify item ID is correct',
            'details', NULL
        );
    END IF;

    SELECT
        i.type,
        i.name,
        i.brand,
        g.name AS generic_name,
        i.primary_unit,
        CASE WHEN i.type = 'MEDICINE' THEN i.brand ELSE i.name END AS display_name
    INTO v_inventory
    FROM inventory i
    LEFT JOIN inventory_generics g ON i.generic_id = g.id
    WHERE i.id = v_item.inventory_id;

    DELETE FROM purchase_items WHERE id = p_item_id;

    SELECT COALESCE(SUM(total_price), 0)
    INTO v_new_subtotal
    FROM purchase_items
    WHERE purchase_id = p_purchase_id;

    v_new_total       := GREATEST(v_new_subtotal - COALESCE(v_purchase.discount_amount, 0), 0);
    -- [BUG-PR-4] Guard against negative outstanding when paid_amount > new_total.
    v_new_outstanding := GREATEST(0, v_new_total - COALESCE(v_purchase.paid_amount, 0));

    SELECT COUNT(*) INTO v_items_count
    FROM purchase_items
    WHERE purchase_id = p_purchase_id;

    UPDATE purchases
    SET subtotal          = v_new_subtotal,
        total_amount      = v_new_total,
        outstanding_amount = v_new_outstanding,
        updated_at        = NOW() AT TIME ZONE 'Asia/Dhaka'
    WHERE id = p_purchase_id;

    RETURN json_build_object(
        'code',    'SUCCESS',
        'message', 'Item removed successfully',
        'hint',    NULL,
        'details', json_build_object(
            'removed_item', json_build_object(
                'item_id',        v_item.id,
                'inventory_type', v_inventory.type,
                'inventory_name', v_inventory.display_name,
                'batch_number',   v_item.batch_number,
                'expiry_date',    v_item.expiry_date,
                'quantity',       v_item.quantity,
                'primary_unit',   v_inventory.primary_unit,
                'purchase_price', v_item.purchase_price,
                'selling_price',  v_item.selling_price,
                'total_price',    v_item.total_price
            ),
            'purchase_totals', json_build_object(
                'subtotal',          v_new_subtotal,
                'discount_amount',   COALESCE(v_purchase.discount_amount, 0),
                'total_amount',      v_new_total,
                'outstanding_amount', v_new_outstanding,
                'items_count',       v_items_count
            )
        )
    );

EXCEPTION
    WHEN lock_not_available THEN
        RETURN json_build_object(
            'code',    'SYSTEM_BUSY',
            'message', 'Purchase is being modified by another request',
            'hint',    'Please try again in a moment',
            'details', NULL
        );
    WHEN foreign_key_violation THEN
        RETURN json_build_object(
            'code',    'CONSTRAINT_VIOLATION',
            'message', 'Cannot remove item due to foreign key constraint',
            'hint',    'Item may be referenced elsewhere',
            'details', json_build_object('sqlstate', SQLSTATE, 'error', SQLERRM)
        );
    WHEN OTHERS THEN
        RETURN json_build_object(
            'code',    'INTERNAL_ERROR',
            'message', 'Failed to remove item',
            'hint',    'Contact system administrator',
            'details', json_build_object(
                'sqlstate',    SQLSTATE,
                'error',       SQLERRM,
                'purchase_id', p_purchase_id,
                'item_id',     p_item_id
            )
        );
END;
$$;


ALTER FUNCTION public.remove_purchase_item(p_purchase_id uuid, p_item_id uuid) OWNER TO postgres;

--
-- TOC entry 841 (class 1255 OID 231622)
-- Name: remove_purchase_return_item(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.remove_purchase_return_item(p_return_item_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id     UUID;
    v_return_id   UUID;
    v_return      RECORD;
    v_subtotal    DECIMAL;
    v_credit_adj  DECIMAL;
    v_cash_refund DECIMAL;
    v_now         TIMESTAMP WITH TIME ZONE;
BEGIN
    v_now     := NOW() AT TIME ZONE 'Asia/Dhaka';
    v_user_id := auth.uid();

    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    -- Step 1: resolve the parent return_id.
    SELECT return_id INTO v_return_id
    FROM purchase_return_items
    WHERE id = p_return_item_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'NOT_FOUND', 'message', 'Item not found');
    END IF;

    -- Step 2: lock the parent return with NOWAIT so concurrent calls
    --   (discard_purchase_return, add_or_update_purchase_return_item, finalize_purchase_return)
    --   get SYSTEM_BUSY instead of racing past the permission / status guards.
    BEGIN
        SELECT pr.*, p.pharmacy_id       AS purchase_pharmacy_id,
                     p.outstanding_amount AS purchase_outstanding
        INTO STRICT v_return
        FROM purchase_returns pr
        JOIN purchases p ON pr.purchase_id = p.id
        WHERE pr.id = v_return_id
        FOR UPDATE OF pr NOWAIT;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN jsonb_build_object('code', 'NOT_FOUND', 'message', 'Draft not found');
        WHEN lock_not_available THEN
            RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'Return is being modified, please try again');
    END;

    IF v_return.refund_status != 'PENDING'::payment_status_enum THEN
        RETURN jsonb_build_object('code', 'INVALID_STATUS', 'message', 'Cannot modify a completed return');
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies
        WHERE user_id    = v_user_id
          AND pharmacy_id = v_return.purchase_pharmacy_id
          AND is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied');
    END IF;

    DELETE FROM purchase_return_items WHERE id = p_return_item_id;

    SELECT COALESCE(SUM(total_cost), 0)
    INTO v_subtotal
    FROM purchase_return_items
    WHERE return_id = v_return_id;

    IF v_return.purchase_outstanding > 0 THEN
        v_credit_adj  := LEAST(v_subtotal, v_return.purchase_outstanding);
        v_cash_refund := GREATEST(0, v_subtotal - v_credit_adj);
    ELSE
        v_credit_adj  := 0;
        v_cash_refund := v_subtotal;
    END IF;

    UPDATE purchase_returns
    SET subtotal     = v_subtotal,
        total_amount = v_subtotal,
        updated_at   = v_now
    WHERE id = v_return_id;

    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Item removed',
        'details', jsonb_build_object(
            'return_id',         v_return_id,
            'subtotal',          v_subtotal,
            'total_amount',      v_subtotal,
            'credit_adjustment', v_credit_adj,
            'cash_refund',       v_cash_refund,
            'is_credit_only',    (v_cash_refund = 0 AND v_subtotal > 0)
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'ERROR', 'message', SQLERRM);
END;
$$;


ALTER FUNCTION public.remove_purchase_return_item(p_return_item_id uuid) OWNER TO postgres;

--
-- TOC entry 811 (class 1255 OID 226283)
-- Name: remove_return_item(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.remove_return_item(p_return_item_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id         UUID;
    v_return_item     RECORD;
    v_remaining_items INT;
BEGIN
    -- ── 1. AUTH ────────────────────────────────────────────────────────────
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED',
            'message', 'User not authenticated', 'hint', NULL);
    END IF;

    -- ── 2. FETCH ITEM + RETURN INFO ────────────────────────────────────────
    SELECT ri.*, r.id AS return_id, r.return_status, r.pharmacy_id, r.sale_id
    INTO v_return_item
    FROM sale_return_items ri
    JOIN sale_returns r ON ri.return_id = r.id
    WHERE ri.id          = p_return_item_id
      AND ri.deleted_at  IS NULL;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('code', 'ITEM_NOT_FOUND',
            'message', 'Return item not found', 'hint', NULL);
    END IF;

    -- ── 3. STATUS CHECK ────────────────────────────────────────────────────
    IF v_return_item.return_status != 'DRAFT' THEN
        RETURN jsonb_build_object(
            'code',    'INVALID_STATUS',
            'message', 'Only draft returns can be modified',
            'hint',    'This return has status: ' || v_return_item.return_status
        );
    END IF;

    -- ── 4. LOCK RETURN (fail-fast instead of blocking) ─────────────────────
    -- BUG-NEW-7 FIX: serialize concurrent remove calls on the same return.
    BEGIN
        PERFORM 1 FROM sale_returns WHERE id = v_return_item.return_id FOR UPDATE NOWAIT;
    EXCEPTION
        WHEN lock_not_available THEN
            RETURN jsonb_build_object('code', 'SYSTEM_BUSY',
                'message', 'Another operation is in progress, please retry', 'hint', NULL);
    END;

    -- ── 5. PERMISSION ──────────────────────────────────────────────────────
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies pu
        WHERE pu.user_id    = v_user_id
          AND pu.pharmacy_id = v_return_item.pharmacy_id
          AND pu.is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED',
            'message', 'You do not have permission for this pharmacy', 'hint', NULL);
    END IF;

    -- ── 6. DELETE ITEM ─────────────────────────────────────────────────────
    DELETE FROM sale_return_items WHERE id = p_return_item_id;

    -- ── 7. COUNT REMAINING (exclude soft-deleted) ──────────────────────────
    SELECT COUNT(*) INTO v_remaining_items
    FROM sale_return_items
    WHERE return_id  = v_return_item.return_id
      AND deleted_at IS NULL;

    IF v_remaining_items = 0 THEN
        -- Draft is empty — delete the header too
        DELETE FROM sale_returns WHERE id = v_return_item.return_id;

        -- BUG-NEW-6 FIX: use a distinct code so Kotlin branches by code, not text.
        RETURN jsonb_build_object(
            'code',    'SUCCESS_EMPTY',
            'message', 'Last item removed; draft return has been deleted.',
            'hint',    NULL
        );
    ELSE
        PERFORM recalculate_return_totals(v_return_item.return_id);

        RETURN jsonb_build_object(
            'code',    'SUCCESS',
            'message', 'Return item removed successfully',
            'hint',    NULL
        );
    END IF;

EXCEPTION
    WHEN SQLSTATE '55P03' THEN
        RETURN jsonb_build_object('code', 'SYSTEM_BUSY',
            'message', 'System is busy, please try again',
            'hint',    'Another operation is in progress');
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'INTERNAL_ERROR',
            'message', 'Failed to remove return item: ' || SQLERRM, 'hint', NULL);
END;
$$;


ALTER FUNCTION public.remove_return_item(p_return_item_id uuid) OWNER TO postgres;

--
-- TOC entry 999 (class 1255 OID 247253)
-- Name: remove_sale_item(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.remove_sale_item(p_sale_id uuid, p_item_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id         UUID;
    v_sale            RECORD;
    v_item            RECORD;
    v_new_subtotal    NUMERIC(12,2);
    v_new_item_discounts NUMERIC(12,2);
    v_new_total       NUMERIC(12,2);
    v_items_count     INT;
BEGIN
    v_user_id := auth.uid();

    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated'
        );
    END IF;

    -- Lock the sale row to prevent concurrent modifications
    SELECT s.*, p.id AS pharmacy_id
    INTO   v_sale
    FROM   sales s
    JOIN   pharmacies p ON s.pharmacy_id = p.id
    WHERE  s.id           = p_sale_id
    AND    s.deleted_at   IS NULL
    FOR UPDATE OF s NOWAIT;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'code', 'SALE_NOT_FOUND',
            'message', 'Sale not found'
        );
    END IF;

    IF v_sale.sale_status::text != 'DRAFT' THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_STATUS',
            'message', 'Cannot modify a sale that is not in DRAFT status'
        );
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies pu
        WHERE  pu.user_id    = v_user_id
        AND    pu.pharmacy_id = v_sale.pharmacy_id
        AND    pu.is_active   = true
    ) THEN
        RETURN jsonb_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'Permission denied'
        );
    END IF;

    SELECT *
    INTO   v_item
    FROM   sale_items
    WHERE  id      = p_item_id
    AND    sale_id = p_sale_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'code', 'ITEM_NOT_FOUND',
            'message', 'Item not found in this sale'
        );
    END IF;

    DELETE FROM sale_items WHERE id = v_item.id;

    -- ── BUG-6 FIX: include item-level discounts in the total formula ──────────
    --   gross_subtotal   = SUM(quantity × unit_price)        ← no discounts
    --   item_discounts   = SUM(discount_amount per item)
    --   total_amount     = gross_subtotal − item_discounts − sale_discount
    --   This must match the formula used by add_or_update_sale_item (BUG-4 fix).
    SELECT
        COALESCE(SUM(si.quantity * si.unit_price), 0),
        COALESCE(SUM(si.discount_amount), 0),
        COUNT(*)
    INTO v_new_subtotal, v_new_item_discounts, v_items_count
    FROM sale_items si
    WHERE si.sale_id = p_sale_id;

    v_new_total := ROUND(
        v_new_subtotal
        - v_new_item_discounts
        - COALESCE(v_sale.discount_amount, 0),
    2);

    -- Ensure total never goes negative (e.g. item discount > remaining subtotal)
    v_new_total := GREATEST(v_new_total, 0);

    UPDATE sales
    SET subtotal           = v_new_subtotal,
        total_amount       = v_new_total,
        outstanding_amount = ROUND(v_new_total - COALESCE(paid_amount, 0), 2),
        updated_at         = NOW()
    WHERE id = p_sale_id;

    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Item removed',
        'details', jsonb_build_object(
            'removed_item', jsonb_build_object(
                'item_id',      v_item.id,
                'inventory_id', v_item.inventory_id,
                'quantity',     v_item.quantity
            ),
            'sale_totals', jsonb_build_object(
                'subtotal',        v_new_subtotal,
                'item_discounts',  v_new_item_discounts,
                'discount_amount', COALESCE(v_sale.discount_amount, 0),
                'total_amount',    v_new_total,
                'items_count',     v_items_count
            )
        )
    );

EXCEPTION
    WHEN SQLSTATE '55P03' THEN          -- lock_not_available (NOWAIT)
        RETURN jsonb_build_object(
            'code',    'SYSTEM_BUSY',
            'message', 'System is busy, please try again',
            'hint',    'Another operation is in progress'
        );
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'code',    'INTERNAL_ERROR',
            'message', SQLERRM,
            'hint',    'Contact support'
        );
END;
$$;


ALTER FUNCTION public.remove_sale_item(p_sale_id uuid, p_item_id uuid) OWNER TO postgres;

--
-- TOC entry 1004 (class 1255 OID 97280)
-- Name: save_customer(uuid, text, uuid, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.save_customer(p_pharmacy_id uuid, p_name text, p_id uuid DEFAULT NULL::uuid, p_phone text DEFAULT NULL::text, p_email text DEFAULT NULL::text, p_address text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_color_label text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_customer_id uuid;
    v_is_new boolean := false;
BEGIN
    IF p_pharmacy_id IS NULL THEN
        RETURN json_build_object(
            'code', 'ERROR',
            'message', 'Pharmacy ID cannot be null',
            'hint', null,
            'details', null
        );
    END IF;

    IF p_name IS NULL OR trim(p_name) = '' THEN
        RETURN json_build_object(
            'code', 'ERROR',
            'message', 'Customer name cannot be empty',
            'hint', null,
            'details', null
        );
    END IF;

    -- Duplicate phone check
    IF p_phone IS NOT NULL AND trim(p_phone) <> '' THEN
        IF EXISTS (
            SELECT 1 FROM customers
            WHERE pharmacy_id = p_pharmacy_id
            AND phone = trim(p_phone)
            AND deleted_at IS NULL
            AND (p_id IS NULL OR id <> p_id)
        ) THEN
            RETURN json_build_object(
                'code', 'ERROR',
                'message', 'Phone number already exists',
                'hint', 'Use a different phone number',
                'details', null
            );
        END IF;
    END IF;

    -- Duplicate email check
    IF p_email IS NOT NULL AND trim(p_email) <> '' THEN
        IF EXISTS (
            SELECT 1 FROM customers
            WHERE pharmacy_id = p_pharmacy_id
            AND email = trim(p_email)
            AND deleted_at IS NULL
            AND (p_id IS NULL OR id <> p_id)
        ) THEN
            RETURN json_build_object(
                'code', 'ERROR',
                'message', 'Email already exists',
                'hint', 'Use a different email',
                'details', null
            );
        END IF;
    END IF;

    IF p_id IS NOT NULL THEN
        UPDATE customers
        SET
            name = trim(p_name),
            phone = NULLIF(trim(p_phone), ''),
            email = NULLIF(trim(p_email), ''),
            address = NULLIF(trim(p_address), ''),
            notes = NULLIF(trim(p_notes), ''),
            color_label = p_color_label,
            updated_at = now()
        WHERE id = p_id
        AND pharmacy_id = p_pharmacy_id
        AND deleted_at IS NULL
        RETURNING id INTO v_customer_id;

        IF v_customer_id IS NULL THEN
            RETURN json_build_object(
                'code', 'ERROR',
                'message', 'Customer not found',
                'hint', null,
                'details', null
            );
        END IF;

    ELSE
        INSERT INTO customers (
            pharmacy_id, name, phone, email, address, notes, color_label
        )
        VALUES (
            p_pharmacy_id,
            trim(p_name),
            NULLIF(trim(p_phone), ''),
            NULLIF(trim(p_email), ''),
            NULLIF(trim(p_address), ''),
            NULLIF(trim(p_notes), ''),
            p_color_label
        )
        RETURNING id INTO v_customer_id;

        v_is_new := true;
    END IF;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', CASE
            WHEN v_is_new THEN 'Customer created successfully'
            ELSE 'Customer updated successfully'
        END,
        'hint', null,
        'details', json_build_object(
            'customer_id', v_customer_id,
            'is_new', v_is_new,
            'pharmacy_id', p_pharmacy_id
        )
    );

EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object(
        'code', 'ERROR',
        'message', SQLERRM,
        'hint', 'Unexpected database error',
        'details', null
    );
END;
$$;


ALTER FUNCTION public.save_customer(p_pharmacy_id uuid, p_name text, p_id uuid, p_phone text, p_email text, p_address text, p_notes text, p_color_label text) OWNER TO postgres;

--
-- TOC entry 875 (class 1255 OID 276767)
-- Name: save_inventory_item(uuid, uuid, public.inventory_type_enum, uuid, text, text, integer, text, text, uuid, text, uuid, integer, text, text, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.save_inventory_item(p_pharmacy_id uuid, p_category_id uuid, p_type public.inventory_type_enum DEFAULT 'MEDICINE'::public.inventory_type_enum, p_id uuid DEFAULT NULL::uuid, p_primary_unit text DEFAULT NULL::text, p_secondary_unit text DEFAULT NULL::text, p_conversion_rate integer DEFAULT 1, p_name text DEFAULT NULL::text, p_brand text DEFAULT NULL::text, p_generic_id uuid DEFAULT NULL::uuid, p_strength text DEFAULT NULL::text, p_manufacturer_id uuid DEFAULT NULL::uuid, p_reorder_level integer DEFAULT 10, p_item_code text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_is_active boolean DEFAULT true) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_is_update BOOLEAN;
    v_required_permission TEXT;
    v_new_id UUID;
    v_category_exists BOOLEAN;
    v_category_type TEXT;
    v_expected_category_type TEXT;
    v_trimmed_name TEXT;
    v_trimmed_brand TEXT;
    v_trimmed_strength TEXT;
    v_trimmed_primary_unit TEXT;
    v_trimmed_secondary_unit TEXT;
    v_safe_conversion_rate INTEGER;
    v_enum_primary_unit public.unit_enum;
    v_enum_secondary_unit public.unit_enum;
BEGIN
    -- STEP 1: Authentication Check
    v_current_user_id := auth.uid();
    IF v_current_user_id IS NULL THEN RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated'); END IF;

    -- STEP 2: Required Parameter Validation
    IF p_pharmacy_id IS NULL THEN RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Pharmacy ID is required'); END IF;
    IF p_category_id IS NULL THEN RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Category is required'); END IF;

    -- STEP 3: Category Validation
    SELECT EXISTS(SELECT 1 FROM public.categories WHERE id = p_category_id AND is_active = true), (SELECT type FROM public.categories WHERE id = p_category_id)
    INTO v_category_exists, v_category_type;
    IF NOT v_category_exists THEN RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Invalid category selected'); END IF;

    v_expected_category_type := CASE WHEN p_type = 'MEDICINE' THEN 'medicine' WHEN p_type = 'OTHER' THEN 'other' ELSE 'unknown' END;
    IF v_category_type != v_expected_category_type THEN RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Category type mismatch'); END IF;

    -- STEP 4: Permission Check
    v_is_update := p_id IS NOT NULL;
    v_required_permission := CASE WHEN v_is_update THEN 'inventory.update' ELSE 'inventory.create' END;
    IF NOT user_has_permission(v_current_user_id, p_pharmacy_id, v_required_permission) THEN RETURN json_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied'); END IF;

    -- STEP 5: Trim and Sanitize Inputs
    v_trimmed_name := NULLIF(TRIM(COALESCE(p_name, '')), '');
    v_trimmed_brand := NULLIF(TRIM(COALESCE(p_brand, '')), '');
    v_trimmed_strength := NULLIF(TRIM(COALESCE(p_strength, '')), '');

    -- Optional Secondary Unit and Normalization
    v_trimmed_primary_unit := LOWER(NULLIF(TRIM(COALESCE(p_primary_unit, '')), ''));
    v_trimmed_secondary_unit := LOWER(NULLIF(TRIM(COALESCE(p_secondary_unit, '')), ''));

    IF v_trimmed_primary_unit IS NULL THEN
        RETURN json_build_object('code', 'INVALID_INPUT', 'message', 'Primary unit is required');
    END IF;

    v_safe_conversion_rate := GREATEST(1, COALESCE(p_conversion_rate, 1));
    IF v_trimmed_secondary_unit IS NOT NULL AND v_trimmed_primary_unit = v_trimmed_secondary_unit THEN v_safe_conversion_rate := 1; END IF;
    IF v_trimmed_secondary_unit IS NULL THEN v_safe_conversion_rate := 1; END IF;

    -- Cast to enum
    v_enum_primary_unit := public.text_to_unit_enum(v_trimmed_primary_unit);
    v_enum_secondary_unit := public.text_to_unit_enum(v_trimmed_secondary_unit);

    -- STEP 6: Execute Insert or Update
    IF v_is_update THEN
        UPDATE public.inventory
        SET
            type = p_type,
            category_id = p_category_id,
            name = v_trimmed_name,
            brand = v_trimmed_brand,
            generic_id = p_generic_id,
            strength = v_trimmed_strength,
            manufacturer_id = p_manufacturer_id,
            primary_unit = v_enum_primary_unit,
            secondary_unit = v_enum_secondary_unit,
            conversion_rate = v_safe_conversion_rate,
            reorder_level = p_reorder_level,
            item_code = NULLIF(TRIM(COALESCE(p_item_code, '')), ''),
            description = NULLIF(TRIM(COALESCE(p_description, '')), ''),
            is_active = p_is_active,
            updated_at = NOW()
        WHERE id = p_id AND pharmacy_id = p_pharmacy_id;

        IF NOT FOUND THEN RETURN json_build_object('code', 'NOT_FOUND', 'message', 'Inventory item not found'); END IF;
        v_new_id := p_id;
    ELSE
        INSERT INTO public.inventory (
            pharmacy_id, type, category_id, name, brand, generic_id,
            strength, manufacturer_id, primary_unit, secondary_unit,
            conversion_rate, reorder_level, item_code, description, is_active
        ) VALUES (
            p_pharmacy_id, p_type, p_category_id, v_trimmed_name, v_trimmed_brand, p_generic_id,
            v_trimmed_strength, p_manufacturer_id, v_enum_primary_unit, v_enum_secondary_unit,
            v_safe_conversion_rate, p_reorder_level, NULLIF(TRIM(COALESCE(p_item_code, '')), ''), NULLIF(TRIM(COALESCE(p_description, '')), ''), p_is_active
        ) RETURNING id INTO v_new_id;
    END IF;

    RETURN json_build_object('code', 'SUCCESS', 'message', 'Inventory item saved successfully', 'details', json_build_object('id', v_new_id));
EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object('code', 'INTERNAL_ERROR', 'message', SQLERRM);
END;
$$;


ALTER FUNCTION public.save_inventory_item(p_pharmacy_id uuid, p_category_id uuid, p_type public.inventory_type_enum, p_id uuid, p_primary_unit text, p_secondary_unit text, p_conversion_rate integer, p_name text, p_brand text, p_generic_id uuid, p_strength text, p_manufacturer_id uuid, p_reorder_level integer, p_item_code text, p_description text, p_is_active boolean) OWNER TO postgres;

--
-- TOC entry 619 (class 1255 OID 271107)
-- Name: save_pharmacy_profile(uuid, text, text, text, text, text, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.save_pharmacy_profile(p_user_id uuid, p_name text, p_email text, p_phone text, p_address text, p_city text, p_district text, p_pharmacy_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_pharmacy_id UUID;
    v_owner_role_id UUID;
    v_has_other_pharmacies BOOLEAN;
    v_user_record RECORD;
    v_pharmacy_info JSONB;
    v_is_update BOOLEAN;
    v_has_permission BOOLEAN;
    -- Validated inputs
    v_name text;
    v_email text;
    v_phone text;
BEGIN
    -- Input Validation & Trimming
    v_name := TRIM(p_name);
    v_email := TRIM(p_email);
    v_phone := TRIM(p_phone);
    v_is_update := p_pharmacy_id IS NOT NULL;

    IF v_name IS NULL OR v_name = '' THEN
        RETURN jsonb_build_object(
            'code', 'VALIDATION_ERROR',
            'message', 'Pharmacy name is required',
            'details', NULL
        );
    END IF;

    IF v_is_update THEN
        -- Permission check for updates
        SELECT user_has_permission(
            p_user_id,
            p_pharmacy_id,
            'pharmacy_settings.update'
        ) INTO v_has_permission;

        IF NOT v_has_permission THEN
            RETURN jsonb_build_object(
                'code', 'PERMISSION_DENIED',
                'message', 'You do not have permission to update this pharmacy',
                'hint', 'pharmacy_settings.update permission required',
                'details', NULL
            );
        END IF;

        UPDATE pharmacies
        SET 
            name = v_name,
            phone = v_phone,
            email = v_email,
            address = TRIM(p_address),
            city = TRIM(p_city),
            district = TRIM(p_district),
            updated_by = p_user_id,
            updated_at = CURRENT_TIMESTAMP
        WHERE id = p_pharmacy_id
        RETURNING id INTO v_pharmacy_id;

        IF v_pharmacy_id IS NULL THEN
            RETURN jsonb_build_object(
                'code', 'PHARMACY_NOT_FOUND',
                'message', 'Pharmacy does not exist',
                'hint', 'Verify pharmacy ID is correct',
                'details', NULL
            );
        END IF;
    ELSE
        -- Check for other pharmacies for primary status logic
        SELECT EXISTS(
            SELECT 1 FROM user_pharmacies WHERE user_id = p_user_id
        ) INTO v_has_other_pharmacies;

        -- Get or create Owner role
        SELECT id INTO v_owner_role_id
        FROM user_roles
        WHERE slug = 'owner' AND is_system = TRUE
        LIMIT 1;

        IF v_owner_role_id IS NULL THEN
            -- Ensure owner role exists (fallback)
            INSERT INTO user_roles (name, slug, description, permissions, is_system, created_at, updated_at)
            VALUES ('Owner', 'owner', 'Primary owner', '["*"]'::jsonb, TRUE, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
            RETURNING id INTO v_owner_role_id;
        END IF;

        -- Create pharmacy record
        INSERT INTO pharmacies (
            name, phone, address, city, district, email,
            is_active, created_by, updated_by, created_at, updated_at
        )
        VALUES (
            v_name, v_phone, TRIM(p_address), TRIM(p_city), TRIM(p_district), v_email,
            TRUE, p_user_id, p_user_id, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
        )
        RETURNING id INTO v_pharmacy_id;

        -- Link user to pharmacy (Note: user_pharmacies does not have created_by/updated_by columns)
        INSERT INTO user_pharmacies (
            user_id, pharmacy_id, role_id, is_primary, is_active,
            metadata, created_at, updated_at
        )
        VALUES (
            p_user_id, v_pharmacy_id, v_owner_role_id, NOT v_has_other_pharmacies,
            TRUE,
            jsonb_build_object('registration_source', 'self_registration', 'registered_at', CURRENT_TIMESTAMP),
            CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
        );
    END IF;

    -- Standardized Return (v_user_record and v_pharmacy_info)
    SELECT u.id, u.email, u.phone, u.full_name, u.avatar_url, u.is_active, u.created_at, u.updated_at,
           (u.full_name IS NOT NULL AND u.full_name != '') as profile_complete
    INTO v_user_record FROM users u WHERE u.id = p_user_id;

    SELECT jsonb_build_object(
        'id', p.id, 'name', p.name, 'phone', p.phone, 'email', p.email,
        'address', p.address, 'city', p.city, 'district', p.district,
        'verified', COALESCE(p.verified, FALSE), 'is_active', p.is_active,
        'role', (SELECT ur.slug FROM user_pharmacies up JOIN user_roles ur ON up.role_id = ur.id WHERE up.pharmacy_id = p.id AND up.user_id = p_user_id LIMIT 1),
        'created_by', COALESCE(p.created_by::TEXT, '')
    ) INTO v_pharmacy_info FROM pharmacies p WHERE p.id = v_pharmacy_id;

    RETURN jsonb_build_object(
        'code', 'SUCCESS',
        'message', CASE WHEN v_is_update THEN 'Pharmacy updated' ELSE 'Pharmacy registered' END,
        'details', jsonb_build_object(
            'user', jsonb_build_object(
                'id', v_user_record.id, 'email', v_user_record.email, 'phone', COALESCE(v_user_record.phone, ''),
                'full_name', COALESCE(v_user_record.full_name, ''), 'avatar_url', v_user_record.avatar_url,
                'is_active', v_user_record.is_active, 'profile_complete', v_user_record.profile_complete,
                'created_at', v_user_record.created_at, 'updated_at', v_user_record.updated_at
            ),
            'pharmacies', jsonb_build_array(v_pharmacy_info),
            'operation', CASE WHEN v_is_update THEN 'update' ELSE 'create' END
        )
    );

EXCEPTION 
    WHEN unique_violation THEN
        RETURN jsonb_build_object('code', 'DUPLICATE_ENTRY', 'message', 'Pharmacy or link already exists');
    WHEN foreign_key_violation THEN
        RETURN jsonb_build_object('code', 'FOREIGN_KEY_ERROR', 'message', 'User does not exist');
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'INTERNAL_ERROR', 'message', SQLERRM);
END;
$$;


ALTER FUNCTION public.save_pharmacy_profile(p_user_id uuid, p_name text, p_email text, p_phone text, p_address text, p_city text, p_district text, p_pharmacy_id uuid) OWNER TO postgres;

--
-- TOC entry 813 (class 1255 OID 237746)
-- Name: save_supplier(uuid, text, text, text, text, text, text, text, boolean, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.save_supplier(p_pharmacy_id uuid, p_name text, p_type text, p_contact_person text DEFAULT NULL::text, p_phone text DEFAULT NULL::text, p_email text DEFAULT NULL::text, p_address text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_is_active boolean DEFAULT true, p_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$DECLARE
    v_supplier_id UUID;
    v_result JSONB;
BEGIN
    -- Validation
    IF p_name IS NULL OR trim(p_name) = '' THEN
         RETURN json_build_object(
            'code', '400',
            'message', 'Supplier name is required',
            'hint', 'Provide a valid name',
            'details', null
        );
    END IF;

    -- Upsert logic
    IF p_id IS NOT NULL THEN
        UPDATE public.suppliers
        SET
            name = p_name,
            supplier_type = p_type::public.supplier_type_enum,
            contact_person = p_contact_person,
            phone = p_phone,
            email = p_email,
            address = p_address,
            notes = p_notes,
            is_active = p_is_active,
            updated_at = NOW()
        WHERE id = p_id AND pharmacy_id = p_pharmacy_id
        RETURNING id INTO v_supplier_id;

        IF v_supplier_id IS NULL THEN
            RETURN json_build_object(
                'code', '404',
                'message', 'Supplier not found',
                'hint', 'Check the supplier ID',
                'details', null
            );
        END IF;
    ELSE
        INSERT INTO public.suppliers (
            pharmacy_id, name, supplier_type, contact_person, phone, email, address, notes, is_active
        ) VALUES (
            p_pharmacy_id, p_name, p_type::public.supplier_type_enum, p_contact_person, p_phone, p_email, p_address, p_notes, p_is_active
        )
        RETURNING id INTO v_supplier_id;
    END IF;

    -- Fetch details to return (including history for consistency)
    SELECT json_build_object(
        'id', s.id,
        'pharmacy_id', s.pharmacy_id,
        'name', s.name,
        'type', s.supplier_type,
        'contact_person', s.contact_person,
        'phone', s.phone,
        'email', s.email,
        'address', s.address,
        'notes', s.notes,
        'is_active', s.is_active,
        'created_at', s.created_at,
        'stats', json_build_object(
            'total_purchases', COALESCE(stats.total_purchases, 0),
            'total_purchase_amount', COALESCE(stats.total_amount, 0),
            'total_paid', COALESCE(stats.total_paid, 0),
            'total_due', COALESCE(stats.total_due, 0),
            'last_purchase_date', stats.last_purchase_date
        )
    ) INTO v_result
    FROM public.suppliers s
    LEFT JOIN (
        SELECT
            supplier_id,
            COUNT(*) as total_purchases,
            SUM(total_amount) as total_amount,
            SUM(paid_amount) as total_paid,
            SUM(total_amount - paid_amount) as total_due,
            MAX(purchase_date) as last_purchase_date
        FROM public.purchases
        WHERE purchase_status != 'CANCELLED'
        GROUP BY supplier_id
    ) stats ON stats.supplier_id = s.id
    WHERE s.id = v_supplier_id;

    RETURN json_build_object(
        'code', '200',
        'message', 'Supplier saved successfully',
        'details', v_result
    );
EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object(
        'code', '500',
        'message', SQLERRM,
        'details', null
    );
END;$$;


ALTER FUNCTION public.save_supplier(p_pharmacy_id uuid, p_name text, p_type text, p_contact_person text, p_phone text, p_email text, p_address text, p_notes text, p_is_active boolean, p_id uuid) OWNER TO postgres;

--
-- TOC entry 1388 (class 1255 OID 156298)
-- Name: search_customers(uuid, text, boolean, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_customers(p_pharmacy_id uuid, p_search text DEFAULT NULL::text, p_has_credit boolean DEFAULT NULL::boolean, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_customers json;
    v_active_filters jsonb := '[]'::jsonb;
    v_total_count integer := 0;
BEGIN
    v_current_user_id := auth.uid();

    IF v_current_user_id IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint', 'Please log in',
            'details', NULL
        );
    END IF;

    IF p_pharmacy_id IS NULL THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Pharmacy ID is required',
            'hint', 'Provide a valid pharmacy ID',
            'details', NULL
        );
    END IF;

    IF NOT user_has_permission(v_current_user_id, p_pharmacy_id, 'customers.view') THEN
        RETURN json_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'You do not have permission to view customers',
            'hint', 'Contact your administrator for access',
            'details', NULL
        );
    END IF;

    IF NOT EXISTS (SELECT 1 FROM pharmacies WHERE id = p_pharmacy_id) THEN
        RETURN json_build_object(
            'code', 'PHARMACY_NOT_FOUND',
            'message', 'Pharmacy not found',
            'hint', 'Check the pharmacy ID',
            'details', json_build_object('pharmacy_id', p_pharmacy_id)
        );
    END IF;

    IF p_limit IS NULL OR p_limit <= 0 THEN
        p_limit := 20;
    END IF;

    IF p_limit > 100 THEN
        RETURN json_build_object(
            'code', 'INVALID_LIMIT',
            'message', 'Limit exceeds maximum allowed',
            'hint', 'Maximum limit is 100 records per request',
            'details', json_build_object('requested_limit', p_limit, 'max_limit', 100)
        );
    END IF;

    IF p_offset IS NULL OR p_offset < 0 THEN
        p_offset := 0;
    END IF;

    IF p_search IS NOT NULL AND TRIM(p_search) != '' THEN
        v_active_filters := v_active_filters || jsonb_build_object('search', TRIM(p_search));
    END IF;
    
    IF p_has_credit IS NOT NULL THEN
        v_active_filters := v_active_filters || jsonb_build_object('has_credit', p_has_credit);
    END IF;

    WITH credit_agg AS (
        SELECT 
            customer_id,
            COUNT(*) AS total_credits,
            COUNT(*) FILTER (
                WHERE outstanding_amount > 0 
                AND status IN ('ACTIVE', 'OVERDUE')
            ) AS active_credits,
            COUNT(*) FILTER (
                WHERE outstanding_amount > 0 
                AND paid_amount = 0
                AND status IN ('ACTIVE', 'OVERDUE')
            ) AS outstanding_count,
            COUNT(*) FILTER (
                WHERE outstanding_amount > 0 
                AND paid_amount > 0 
                AND paid_amount < credit_amount
                AND status IN ('ACTIVE', 'OVERDUE')
            ) AS partial_count,
            COUNT(*) FILTER (
                WHERE status = 'PAID' 
                OR (outstanding_amount = 0 AND paid_amount = credit_amount)
            ) AS paid_count,
            COALESCE(SUM(credit_amount), 0) AS total_credit_amount,
            COALESCE(SUM(paid_amount), 0) AS total_paid_amount,
            COALESCE(
                SUM(outstanding_amount) FILTER (
                    WHERE status NOT IN ('PAID', 'CANCELLED')
                ), 0
            ) AS total_outstanding,
            MIN(due_date) FILTER (
                WHERE outstanding_amount > 0 
                AND due_date IS NOT NULL
                AND status IN ('ACTIVE', 'OVERDUE')
            ) AS earliest_due_date,
            COALESCE(
                SUM(outstanding_amount) FILTER (
                    WHERE status NOT IN ('PAID', 'CANCELLED')
                ), 0
            ) > 0 AS has_outstanding
        FROM customer_credits
        WHERE pharmacy_id = p_pharmacy_id
          AND status != 'CANCELLED'
        GROUP BY customer_id
    ),
    filtered_customers AS (
        SELECT 
            c.id,
            c.pharmacy_id,
            c.name,
            c.phone,
            c.email,
            c.address,
            c.notes,
            c.color_label,
            c.created_at,
            c.updated_at,
            COALESCE(cc.has_outstanding, FALSE) AS has_outstanding,
            COALESCE(cc.total_outstanding, 0) AS total_outstanding,
            COALESCE(cc.total_credit_amount, 0) AS total_credit_amount,
            COALESCE(cc.total_paid_amount, 0) AS total_paid_amount,
            COALESCE(cc.total_credits, 0) AS total_credits,
            COALESCE(cc.active_credits, 0) AS active_credits,
            COALESCE(cc.outstanding_count, 0) AS outstanding_count,
            COALESCE(cc.partial_count, 0) AS partial_count,
            COALESCE(cc.paid_count, 0) AS paid_count,
            cc.earliest_due_date,
            CASE 
                WHEN cc.total_credit_amount > 0 
                THEN ROUND((cc.total_paid_amount / cc.total_credit_amount) * 100, 2)
                ELSE 0
            END AS payment_percentage
        FROM customers c
        LEFT JOIN credit_agg cc ON cc.customer_id = c.id
        WHERE c.pharmacy_id = p_pharmacy_id
          AND c.deleted_at IS NULL
          AND (
              p_search IS NULL 
              OR TRIM(p_search) = ''
              OR c.name ILIKE '%' || TRIM(p_search) || '%'
              OR c.phone ILIKE '%' || TRIM(p_search) || '%'
              OR COALESCE(c.email, '') ILIKE '%' || TRIM(p_search) || '%'
          )
          AND (p_has_credit IS NULL OR COALESCE(cc.has_outstanding, FALSE) = p_has_credit)
        ORDER BY 
            CASE WHEN COALESCE(cc.has_outstanding, FALSE) = TRUE THEN 0 ELSE 1 END,
            c.updated_at DESC, 
            c.created_at DESC
        LIMIT p_limit OFFSET p_offset
    )
    SELECT 
        (SELECT COUNT(*) 
         FROM customers c2 
         LEFT JOIN credit_agg cc2 ON cc2.customer_id = c2.id
         WHERE c2.pharmacy_id = p_pharmacy_id
           AND c2.deleted_at IS NULL
           AND (
               p_search IS NULL 
               OR TRIM(p_search) = ''
               OR c2.name ILIKE '%' || TRIM(p_search) || '%'
               OR c2.phone ILIKE '%' || TRIM(p_search) || '%'
               OR COALESCE(c2.email, '') ILIKE '%' || TRIM(p_search) || '%'
           )
           AND (p_has_credit IS NULL OR COALESCE(cc2.has_outstanding, FALSE) = p_has_credit)
        ) AS total_count,
        json_build_object(
            'data', COALESCE(json_agg(
                json_build_object(
                    'id', fc.id,
                    'pharmacy_id', fc.pharmacy_id,
                    'name', fc.name,
                    'phone', fc.phone,
                    'email', fc.email,
                    'address', fc.address,
                    'notes', fc.notes,
                    'color_label', fc.color_label,
                    'created_at', fc.created_at,
                    'updated_at', fc.updated_at,
                    'credit_summary', json_build_object(
                        'has_outstanding', fc.has_outstanding,
                        'total_outstanding', ROUND(fc.total_outstanding, 2),
                        'total_credit_amount', ROUND(fc.total_credit_amount, 2),
                        'total_paid_amount', ROUND(fc.total_paid_amount, 2),
                        'payment_percentage', fc.payment_percentage,
                        'total_credits', fc.total_credits,
                        'active_credits', fc.active_credits,
                        'status_breakdown', json_build_object(
                            'outstanding', fc.outstanding_count,
                            'partial', fc.partial_count,
                            'paid', fc.paid_count
                        ),
                        'earliest_due_date', fc.earliest_due_date
                    )
                ) ORDER BY 
                    CASE WHEN fc.has_outstanding = TRUE THEN 0 ELSE 1 END,
                    fc.updated_at DESC
            ) FILTER (WHERE fc.id IS NOT NULL), '[]'::json)
        ) AS result
    INTO v_total_count, v_customers
    FROM filtered_customers fc;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', format('Found %s customer(s)', COALESCE(v_total_count, 0)),
        'hint', NULL,
        'details', json_build_object(
            'total_count', COALESCE(v_total_count, 0),
            'limit', p_limit,
            'offset', p_offset,
            'has_more', COALESCE(v_total_count, 0) > (p_offset + p_limit),
            'returned_count', LEAST(p_limit, COALESCE(v_total_count, 0) - p_offset),
            'active_filters', v_active_filters,
            'customers', (v_customers->>'data')::json
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        RETURN json_build_object(
            'code', 'ERROR',
            'message', 'Failed to search customers',
            'hint', SQLERRM,
            'details', json_build_object(
                'sqlstate', SQLSTATE,
                'error', SQLERRM,
                'pharmacy_id', p_pharmacy_id
            )
        );
END;
$$;


