--
-- TOC entry 725 (class 1255 OID 254076)
-- Name: search_global_medicine_catalogue(text, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_global_medicine_catalogue(p_query text, p_type text DEFAULT NULL::text, p_limit integer DEFAULT 10) RETURNS json
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_user_id uuid;
    v_search_normalized text;
    v_type_filter public.inventory_type_enum;
    v_search_words text[];
    v_word_count INT;
BEGIN
    -- Auth check
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'Authentication required'
        );
    END IF;

    -- Normalize search query and split into words
    v_search_normalized := LOWER(TRIM(COALESCE(p_query, '')));
    v_search_words := string_to_array(v_search_normalized, ' ');
    v_word_count := array_length(v_search_words, 1);

    -- Empty query check
    IF LENGTH(v_search_normalized) < 2 THEN
        RETURN json_build_object(
            'code', 'SUCCESS',
            'message', 'Query too short',
            'details', json_build_object('items', '[]'::JSON)
        );
    END IF;

    -- Parse type filter (case-insensitive)
    IF p_type IS NOT NULL AND TRIM(p_type) != '' THEN
        BEGIN
            v_type_filter := UPPER(TRIM(p_type))::public.inventory_type_enum;
        EXCEPTION WHEN OTHERS THEN
            v_type_filter := NULL;
        END;
    END IF;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', 'Suggestions retrieved',
        'details', json_build_object(
            'items', COALESCE((
                SELECT json_agg(item ORDER BY relevance DESC, display_name ASC)
                FROM (
                    SELECT DISTINCT ON (ig.id)
                        ig.id,
                        ig.type::TEXT AS type,
                        ig.category AS category_name,
                        (SELECT c.id::TEXT FROM public.categories c
                         WHERE LOWER(c.slug) = LOWER(ig.category)
                         OR LOWER(c.name) = LOWER(ig.category)
                         LIMIT 1) AS category_id,
                        ig.brand,
                        ig.generic_id::TEXT AS generic_id,
                        g.name AS generic_name,
                        ig.strength,
                        ig.manufacturer_id::TEXT AS manufacturer_id,
                        m.name AS manufacturer,
                        ig.name,
                        ig.primary_unit,
                        ig.secondary_unit,
                        ig.conversion_rate,
                        ig.item_code,

                        CASE
                            WHEN ig.type = 'MEDICINE' THEN ig.brand
                            ELSE ig.name
                        END AS display_name,

                        -- Relevance Scoring
                        CASE
                            -- Exact brand/name match (highest priority)
                            WHEN ig.type = 'MEDICINE' AND LOWER(ig.brand) = v_search_normalized THEN 100
                            WHEN ig.type = 'OTHER' AND LOWER(ig.name) = v_search_normalized THEN 100

                            -- Brand/name starts with precise query
                            WHEN ig.type = 'MEDICINE' AND LOWER(ig.brand) LIKE v_search_normalized || '%' THEN 90
                            WHEN ig.type = 'OTHER' AND LOWER(ig.name) LIKE v_search_normalized || '%' THEN 90

                            -- Generic name starts with precise query
                            WHEN ig.type = 'MEDICINE' AND LOWER(g.name) LIKE v_search_normalized || '%' THEN 80

                            -- Multi-word matching
                            WHEN v_word_count > 1 AND (
                                (ig.type = 'MEDICINE' AND LOWER(ig.brand) LIKE '%' || v_search_words[1] || '%' AND LOWER(ig.brand) LIKE '%' || v_search_words[2] || '%')
                                OR
                                (ig.type = 'OTHER' AND LOWER(ig.name) LIKE '%' || v_search_words[1] || '%' AND LOWER(ig.name) LIKE '%' || v_search_words[2] || '%')
                            ) THEN 75

                            -- Item code match
                            WHEN LOWER(ig.item_code) LIKE v_search_normalized || '%' THEN 75

                            -- Contains precise single word match
                            WHEN ig.type = 'MEDICINE' AND LOWER(ig.brand) LIKE '%' || v_search_normalized || '%' THEN 60
                            WHEN ig.type = 'OTHER' AND LOWER(ig.name) LIKE '%' || v_search_normalized || '%' THEN 60

                            -- Generic name contains query
                            WHEN ig.type = 'MEDICINE' AND LOWER(g.name) LIKE '%' || v_search_normalized || '%' THEN 50

                            -- Manufacturer match
                            WHEN LOWER(m.name) LIKE '%' || v_search_normalized || '%' THEN 30
                            ELSE 10
                        END AS relevance
                    FROM public.inventory_global ig
                    LEFT JOIN public.inventory_generics g ON ig.generic_id = g.id
                    LEFT JOIN public.inventory_manufacturers m ON ig.manufacturer_id = m.id
                    WHERE
                        (v_type_filter IS NULL OR ig.type = v_type_filter)
                        AND (
                            -- Precise match
                            (ig.type = 'MEDICINE' AND ig.brand ILIKE '%' || v_search_normalized || '%')
                            OR (ig.type = 'OTHER' AND ig.name ILIKE '%' || v_search_normalized || '%')
                            OR (ig.type = 'MEDICINE' AND g.name ILIKE '%' || v_search_normalized || '%')
                            OR ig.item_code ILIKE v_search_normalized || '%'
                            OR m.name ILIKE '%' || v_search_normalized || '%'
                            -- Word split matching
                            OR (v_word_count > 1 AND (
                                (ig.type = 'MEDICINE' AND ig.brand ILIKE '%' || v_search_words[1] || '%' AND ig.brand ILIKE '%' || v_search_words[2] || '%')
                                OR
                                (ig.type = 'OTHER' AND ig.name ILIKE '%' || v_search_words[1] || '%' AND ig.name ILIKE '%' || v_search_words[2] || '%')
                            ))
                        )
                    ORDER BY ig.id, relevance DESC
                    LIMIT p_limit
                ) item
            ), '[]'::JSON)
        )
    );
END;$$;


