--
-- TOC entry 1226 (class 1255 OID 242088)
-- Name: search_inventory_items(uuid, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_inventory_items(p_pharmacy_id uuid, p_query text, p_limit integer DEFAULT 10) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_items             JSON;
    v_search_normalized TEXT;
    v_search_pattern    TEXT;
    v_search_prefix     TEXT;
BEGIN
    IF auth.uid() IS NULL THEN
        RETURN json_build_object('code', 'UNAUTHORIZED', 'message', 'Authentication required');
    END IF;

    IF p_pharmacy_id IS NULL THEN
        RETURN json_build_object('code', 'BAD_REQUEST', 'message', 'Pharmacy ID is required');
    END IF;

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE  up.user_id    = auth.uid()
        AND    up.pharmacy_id = p_pharmacy_id
        AND    up.is_active   = true
    ) THEN
        RETURN json_build_object('code', 'PERMISSION_DENIED', 'message', 'You do not have access to this pharmacy');
    END IF;

    v_search_normalized := LOWER(TRIM(COALESCE(p_query, '')));

    IF v_search_normalized = '' OR LENGTH(v_search_normalized) < 2 THEN
        RETURN json_build_object(
            'code', 'SUCCESS',
            'message', 'Query too short or empty',
            'details', json_build_object('items', '[]'::json)
        );
    END IF;

    v_search_pattern := '%' || v_search_normalized || '%';
    v_search_prefix  :=        v_search_normalized || '%';

    SELECT json_agg(t)
    INTO   v_items
    FROM (
        SELECT
            i.id,
            i.type,
            i.category_id,
            COALESCE(cat.name, 'Uncategorized')  AS category_name,
            i.name,
            i.brand,
            i.generic_id,
            ig.name AS generic_name,
            i.strength,
            i.manufacturer_id,
            im.name AS manufacturer,
            i.item_code,
            i.primary_unit,
            i.secondary_unit,
            i.conversion_rate,
            i.reorder_level,
            i.pharmacy_id,

            COALESCE(fefo_batch.selling_price, 0.0)  AS selling_price,
            fefo_batch.shelf_location                AS shelf_location,

            COALESCE((
                SELECT SUM(ib.current_quantity)
                FROM   inventory_batches ib
                WHERE  ib.inventory_id = i.id
                AND    ib.deleted_at   IS NULL
                AND    ib.status       IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY')
                AND    (ib.expiry_date IS NULL OR ib.expiry_date > CURRENT_DATE)
            ), 0)                                    AS stock_quantity,

            -- Relevance score
            CASE
                WHEN i.item_code = v_search_normalized                           THEN 100
                WHEN LOWER(COALESCE(i.brand, ''))        = v_search_normalized   THEN 95
                WHEN LOWER(COALESCE(i.name, ''))         = v_search_normalized   THEN 95
                WHEN LOWER(COALESCE(ig.name, ''))        = v_search_normalized   THEN 90

                WHEN LOWER(COALESCE(i.brand, ''))        LIKE v_search_prefix    THEN 88
                WHEN LOWER(COALESCE(i.name, ''))         LIKE v_search_prefix    THEN 88
                WHEN i.item_code                         LIKE v_search_prefix    THEN 85
                WHEN LOWER(COALESCE(ig.name, ''))        LIKE v_search_prefix    THEN 80
                WHEN LOWER(COALESCE(i.strength, ''))     LIKE v_search_prefix    THEN 75

                WHEN LOWER(COALESCE(i.brand, ''))        LIKE v_search_pattern   THEN 60
                WHEN LOWER(COALESCE(i.name, ''))         LIKE v_search_pattern   THEN 60
                WHEN LOWER(COALESCE(ig.name, ''))        LIKE v_search_pattern   THEN 50
                WHEN i.item_code                         LIKE v_search_pattern   THEN 40
                WHEN LOWER(COALESCE(i.strength, ''))     LIKE v_search_pattern   THEN 35
                WHEN LOWER(COALESCE(im.name, ''))        LIKE v_search_pattern   THEN 30

                ELSE 10
            END AS relevance

        FROM   inventory i
        LEFT JOIN categories cat ON i.category_id = cat.id
        LEFT JOIN inventory_generics ig ON i.generic_id = ig.id
        LEFT JOIN inventory_manufacturers im ON i.manufacturer_id = im.id

        LEFT JOIN LATERAL (
            SELECT ib.selling_price, ib.shelf_location
            FROM   inventory_batches ib
            WHERE  ib.inventory_id = i.id
            AND    ib.deleted_at   IS NULL
            AND    ib.status       IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY')
            AND    (ib.expiry_date IS NULL OR ib.expiry_date > CURRENT_DATE)
            ORDER  BY ib.expiry_date ASC NULLS LAST, ib.created_at ASC
            LIMIT  1
        ) fefo_batch ON true

        WHERE  i.pharmacy_id = p_pharmacy_id
        AND    i.deleted_at  IS NULL
        AND    i.is_active   = true
        AND    (
            i.name         ILIKE v_search_pattern OR
            i.brand        ILIKE v_search_pattern OR
            ig.name        ILIKE v_search_pattern OR
            i.item_code    ILIKE v_search_pattern OR
            i.strength     ILIKE v_search_pattern OR
            im.name        ILIKE v_search_pattern
        )
        ORDER  BY relevance DESC,
                  CASE WHEN COALESCE((
                      SELECT SUM(ib2.current_quantity)
                      FROM inventory_batches ib2
                      WHERE ib2.inventory_id = i.id
                      AND ib2.deleted_at IS NULL
                      AND ib2.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY')
                      AND (ib2.expiry_date IS NULL OR ib2.expiry_date > CURRENT_DATE)
                  ), 0) > 0 THEN 0 ELSE 1 END ASC,
                  COALESCE(i.brand, i.name) ASC
        LIMIT  p_limit
    ) t;

    RETURN json_build_object(
        'code',    'SUCCESS',
        'message', 'Autocomplete results retrieved successfully',
        'details', json_build_object(
            'items', COALESCE(v_items, '[]'::json)
        )
    );
END;
$$;


