--
-- TOC entry 1227 (class 1255 OID 237748)
-- Name: search_suppliers(uuid, text, boolean, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_suppliers(p_pharmacy_id uuid, p_search text DEFAULT NULL::text, p_has_due boolean DEFAULT NULL::boolean, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_data JSONB;
    v_total_count INT;
BEGIN
    -- Calculate total count
    SELECT COUNT(*)
    INTO v_total_count
    FROM public.suppliers s
    LEFT JOIN (
         SELECT
            supplier_id,
            SUM(total_amount - paid_amount) as total_due
         FROM public.purchases
         WHERE purchase_status != 'CANCELLED'
         GROUP BY supplier_id
    ) due_stats ON due_stats.supplier_id = s.id
    WHERE s.pharmacy_id = p_pharmacy_id
    AND s.deleted_at IS NULL
    AND (p_search IS NULL OR s.name ILIKE '%' || p_search || '%' OR s.phone ILIKE '%' || p_search || '%')
    AND (p_has_due IS NULL OR (p_has_due = TRUE AND COALESCE(due_stats.total_due, 0) > 0) OR (p_has_due = FALSE AND COALESCE(due_stats.total_due, 0) = 0));

    -- Fetch data using CTE to filtering, sorting and pagination
    WITH filtered_suppliers AS (
        SELECT
            s.id, s.pharmacy_id, s.name, s.supplier_type, s.contact_person, s.phone, s.email, s.address, s.notes, s.is_active, s.created_at,
            stats.total_purchases, stats.total_amount, stats.total_paid, stats.total_due, stats.last_purchase_date
        FROM public.suppliers s
        LEFT JOIN (
            SELECT
                supplier_id,
                COUNT(*) as total_purchases,
                SUM(total_amount) as total_amount,
                SUM(paid_amount) as total_paid,
                SUM(total_amount - paid_amount) as total_due,
                MAX(purchase_date) as last_purchase_date
            FROM public.purchases
            WHERE purchase_status != 'CANCELLED'
            GROUP BY supplier_id
        ) stats ON stats.supplier_id = s.id
        WHERE s.pharmacy_id = p_pharmacy_id
        AND s.deleted_at IS NULL
        AND (p_search IS NULL OR s.name ILIKE '%' || p_search || '%' OR s.phone ILIKE '%' || p_search || '%')
        AND (p_has_due IS NULL OR (p_has_due = TRUE AND COALESCE(stats.total_due, 0) > 0) OR (p_has_due = FALSE AND COALESCE(stats.total_due, 0) = 0))
        ORDER BY s.is_active DESC, s.name ASC
        LIMIT p_limit OFFSET p_offset
    )
    SELECT jsonb_agg(
        jsonb_build_object(
            'id', fs.id,
            'name', fs.name,
            'type', fs.supplier_type,
            'contact_person', fs.contact_person,
            'phone', fs.phone,
            'email', fs.email,
            'address', fs.address,
            'notes', fs.notes,
            'is_active', fs.is_active,
            'total_purchases', COALESCE(fs.total_purchases, 0),
            'total_purchase_amount', COALESCE(fs.total_amount, 0),
            'total_paid', COALESCE(fs.total_paid, 0),
            'total_due', COALESCE(fs.total_due, 0),
            'last_purchase_date', fs.last_purchase_date
        )
    ) INTO v_data
    FROM filtered_suppliers fs;

    RETURN json_build_object(
        'code', '200',
        'message', 'Success',
        'details', json_build_object(
            'suppliers', COALESCE(v_data, '[]'::jsonb),
            'total_count', v_total_count
        )
    );
END;
$$;


