--
-- TOC entry 634 (class 1255 OID 259218)
-- Name: settle_customer_outstanding(text, numeric, uuid, uuid, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.settle_customer_outstanding(p_payment_method text, p_amount numeric, p_credit_id uuid DEFAULT NULL::uuid, p_sale_id uuid DEFAULT NULL::uuid, p_mobile_number text DEFAULT NULL::text, p_transaction_id text DEFAULT NULL::text, p_card_number text DEFAULT NULL::text, p_notes text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_current_user_id UUID;
    v_credit          RECORD;
    v_payment_method  payment_method_enum;
    v_applied_amount  NUMERIC(12,2);
    v_new_paid_amount NUMERIC(12,2);
    v_new_outstanding NUMERIC(12,2);
    v_new_status      TEXT;
    v_payment_status  payment_status_enum;
BEGIN
    -- ===================================
    -- AUTHENTICATION
    -- ===================================
    v_current_user_id := auth.uid();

    IF v_current_user_id IS NULL THEN
        RETURN json_build_object(
            'code',    'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint',    'Please log in to continue',
            'details', NULL
        );
    END IF;

    -- ===================================
    -- INPUT VALIDATION
    -- ===================================
    IF p_credit_id IS NULL AND p_sale_id IS NULL THEN
        RETURN json_build_object(
            'code',    'INVALID_INPUT',
            'message', 'Either credit ID or sale ID is required',
            'hint',    'Provide p_credit_id or p_sale_id',
            'details', NULL
        );
    END IF;

    IF p_payment_method IS NULL OR TRIM(p_payment_method) = '' THEN
        RETURN json_build_object(
            'code',    'INVALID_INPUT',
            'message', 'Payment method is required',
            'hint',    'Specify payment method (CASH, CARD, BKASH, etc.)',
            'details', NULL
        );
    END IF;

    IF p_amount IS NULL OR p_amount <= 0 THEN
        RETURN json_build_object(
            'code',    'INVALID_INPUT',
            'message', 'Payment amount must be greater than zero',
            'hint',    'Enter a valid payment amount',
            'details', json_build_object('amount', p_amount)
        );
    END IF;

    -- Validate and cast payment method enum
    BEGIN
        v_payment_method := UPPER(TRIM(p_payment_method))::payment_method_enum;
    EXCEPTION
        WHEN invalid_text_representation THEN
            RETURN json_build_object(
                'code',    'INVALID_PAYMENT_METHOD',
                'message', format('Invalid payment method: %s', p_payment_method),
                'hint',    'Valid methods: CASH, CARD, BKASH, NAGAD, ROCKET, BANK_TRANSFER, CHECK',
                'details', NULL
            );
    END;

    -- Mobile money requires mobile_number + transaction_id
    IF v_payment_method IN ('BKASH', 'NAGAD', 'ROCKET') THEN
        IF p_mobile_number IS NULL OR TRIM(p_mobile_number) = '' OR
           p_transaction_id IS NULL OR TRIM(p_transaction_id) = '' THEN
            RETURN json_build_object(
                'code',    'PAYMENT_DETAILS_REQUIRED',
                'message', format('Mobile number and transaction ID required for %s', v_payment_method),
                'hint',    'Provide complete payment details',
                'details', NULL
            );
        END IF;
    END IF;

    -- Card requires card_number + transaction_id
    IF v_payment_method = 'CARD' THEN
        IF p_card_number IS NULL OR TRIM(p_card_number) = '' OR
           p_transaction_id IS NULL OR TRIM(p_transaction_id) = '' THEN
            RETURN json_build_object(
                'code',    'PAYMENT_DETAILS_REQUIRED',
                'message', 'Card number and transaction ID required for card payment',
                'hint',    'Provide complete card payment details',
                'details', NULL
            );
        END IF;
    END IF;

    -- ===================================
    -- FIND & LOCK CREDIT RECORD
    -- ===================================
    IF p_credit_id IS NOT NULL THEN
        SELECT
            cc.id,
            cc.customer_id,
            cc.sale_id,
            cc.pharmacy_id,
            cc.credit_amount,
            cc.paid_amount,
            cc.outstanding_amount,
            cc.status,
            c.name      AS customer_name,
            s.sale_number
        INTO v_credit
        FROM   customer_credits cc
        JOIN   customers c ON c.id = cc.customer_id
        JOIN   sales     s ON s.id = cc.sale_id
        WHERE  cc.id = p_credit_id
        FOR UPDATE OF cc NOWAIT;

        IF NOT FOUND THEN
            RETURN json_build_object(
                'code',    'CREDIT_NOT_FOUND',
                'message', 'Customer credit not found',
                'hint',    'Verify credit ID is correct',
                'details', json_build_object('credit_id', p_credit_id)
            );
        END IF;
    ELSE
        SELECT
            cc.id,
            cc.customer_id,
            cc.sale_id,
            cc.pharmacy_id,
            cc.credit_amount,
            cc.paid_amount,
            cc.outstanding_amount,
            cc.status,
            c.name      AS customer_name,
            s.sale_number
        INTO v_credit
        FROM   customer_credits cc
        JOIN   customers c ON c.id = cc.customer_id
        JOIN   sales     s ON s.id = cc.sale_id
        WHERE  cc.sale_id = p_sale_id
        ORDER  BY cc.created_at DESC
        LIMIT  1
        FOR UPDATE OF cc NOWAIT;

        IF NOT FOUND THEN
            RETURN json_build_object(
                'code',    'CREDIT_NOT_FOUND',
                'message', 'No credit record found for this sale',
                'hint',    'This sale may not have an outstanding credit',
                'details', json_build_object('sale_id', p_sale_id)
            );
        END IF;
    END IF;

    -- ===================================
    -- BUG-12 FIX: PHARMACY MEMBERSHIP CHECK
    -- Now that we have v_credit.pharmacy_id, verify the caller belongs to it.
    -- Without this, any authenticated user who knows a sale_id can pay off
    -- credits belonging to a pharmacy they have no access to.
    -- ===================================
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE  up.user_id    = v_current_user_id
        AND    up.pharmacy_id = v_credit.pharmacy_id
        AND    up.is_active   = true
    ) THEN
        RETURN json_build_object(
            'code',    'PERMISSION_DENIED',
            'message', 'You do not have access to this pharmacy',
            'hint',    'Contact your administrator if you believe this is an error',
            'details', NULL
        );
    END IF;

    -- ===================================
    -- VERIFY CREDIT STATUS
    -- ===================================
    IF v_credit.status NOT IN ('ACTIVE', 'OVERDUE') THEN
        RETURN json_build_object(
            'code',    'INVALID_CREDIT_STATUS',
            'message', 'Can only pay active or overdue credits',
            'hint',    'Credit status: ' || v_credit.status,
            'details', json_build_object('current_status', v_credit.status)
        );
    END IF;

    -- ===================================
    -- CALCULATE PAYMENT (OVERPAYMENT SAFE)
    -- Cap applied amount at the outstanding — user can tender more but we
    -- only apply what is owed.
    -- ===================================
    v_applied_amount := LEAST(p_amount, v_credit.outstanding_amount);

    IF v_applied_amount <= 0 THEN
        RETURN json_build_object(
            'code',    'ALREADY_PAID',
            'message', 'Credit is already fully paid',
            'hint',    'Outstanding amount is 0',
            'details', NULL
        );
    END IF;

    v_new_paid_amount := v_credit.paid_amount + v_applied_amount;
    v_new_outstanding := v_credit.outstanding_amount - v_applied_amount;

    IF v_new_outstanding = 0 THEN
        v_new_status    := 'PAID';
        v_payment_status := 'COMPLETED'::payment_status_enum;
    ELSE
        v_new_status    := v_credit.status;   -- keep ACTIVE / OVERDUE
        v_payment_status := 'PARTIAL'::payment_status_enum;
    END IF;

    -- ===================================
    -- 1) INSERT customer_credit_payments
    -- ===================================
    INSERT INTO customer_credit_payments (
        customer_credit_id,
        payment_method,
        amount,
        mobile_number,
        transaction_id,
        card_number,
        notes,
        user_id,
        payment_date,
        created_at,
        transaction_type
    ) VALUES (
        v_credit.id,
        v_payment_method,
        v_applied_amount,
        NULLIF(TRIM(p_mobile_number),  ''),
        NULLIF(TRIM(p_transaction_id), ''),
        NULLIF(TRIM(p_card_number),    ''),
        COALESCE(
            NULLIF(TRIM(p_notes), ''),
            'Payment for Sale #' || v_credit.sale_number
        ),
        v_current_user_id,
        NOW() AT TIME ZONE 'Asia/Dhaka',
        NOW() AT TIME ZONE 'Asia/Dhaka',
        'PAYMENT'::customer_credit_payment_type_enum
    );

    -- ===================================
    -- 2) UPDATE customer_credits
    -- ===================================
    UPDATE customer_credits
    SET paid_amount        = v_new_paid_amount,
        outstanding_amount = v_new_outstanding,
        status             = v_new_status,
        updated_at         = NOW() AT TIME ZONE 'Asia/Dhaka'
    WHERE id = v_credit.id;

    -- ===================================
    -- 3) UPDATE sales
    -- ===================================
    UPDATE sales
    SET paid_amount        = paid_amount        + v_applied_amount,
        outstanding_amount = outstanding_amount - v_applied_amount,
        payment_status     = v_payment_status,
        updated_at         = NOW() AT TIME ZONE 'Asia/Dhaka'
    WHERE id = v_credit.sale_id;

    -- ===================================
    -- 4) INSERT activity_logs
    -- ===================================
    INSERT INTO activity_logs (
        pharmacy_id,
        entity_id,
        activity_type,
        message,
        metadata,
        created_at
    ) VALUES (
        v_credit.pharmacy_id,
        v_credit.sale_id,
        'PAYMENT',
        format('Payment of ৳%s received for Sale #%s', v_applied_amount, v_credit.sale_number),
        jsonb_build_object(
            'tendered_amount', p_amount,
            'applied_amount',  v_applied_amount,
            'method',          v_payment_method::TEXT,
            'sale_number',     v_credit.sale_number,
            'user_id',         v_current_user_id
        ),
        NOW() AT TIME ZONE 'Asia/Dhaka'
    );

    -- ===================================
    -- RETURN SUCCESS
    -- ===================================
    RETURN json_build_object(
        'code',    'SUCCESS',
        'message', CASE
            WHEN v_new_outstanding = 0
            THEN 'Payment received. Credit fully paid!'
            ELSE format('Payment received. Outstanding: ৳%s', v_new_outstanding)
        END,
        'hint',    NULL,
        'details', json_build_object(
            'credit_id',          v_credit.id,
            'sale_id',            v_credit.sale_id,
            'sale_number',        v_credit.sale_number,
            'customer_name',      v_credit.customer_name,
            'payment_amount',     v_applied_amount,
            'payment_method',     v_payment_method::TEXT,
            'credit_amount',      v_credit.credit_amount,
            'paid_amount',        v_new_paid_amount,
            'outstanding_amount', v_new_outstanding,
            'credit_status',      v_new_status,
            'payment_status',     v_payment_status::TEXT,
            'is_fully_paid',      (v_new_outstanding = 0),
            'payment_date',       NOW() AT TIME ZONE 'Asia/Dhaka'
        )
    );

EXCEPTION
    WHEN SQLSTATE '55P03' THEN          -- lock_not_available (NOWAIT)
        RETURN json_build_object(
            'code',    'SYSTEM_BUSY',
            'message', 'Another payment is being processed, please retry',
            'hint',    'Try again in a moment',
            'details', NULL
        );
    WHEN OTHERS THEN
        RETURN json_build_object(
            'code',    'INTERNAL_ERROR',
            'message', 'Failed to process payment',
            'hint',    'Contact system administrator',
            'details', json_build_object(
                'sqlstate', SQLSTATE,
                'error',    SQLERRM,
                'credit_id', p_credit_id,
                'sale_id',   p_sale_id
            )
        );
END;
$$;


ALTER FUNCTION public.settle_customer_outstanding(p_payment_method text, p_amount numeric, p_credit_id uuid, p_sale_id uuid, p_mobile_number text, p_transaction_id text, p_card_number text, p_notes text) OWNER TO postgres;

--
-- TOC entry 1127 (class 1255 OID 259263)
-- Name: settle_supplier_outstanding(uuid, uuid, numeric, text, uuid, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.settle_supplier_outstanding(p_purchase_id uuid, p_pharmacy_id uuid, p_amount numeric, p_payment_method text, p_user_id uuid, p_mobile_number text DEFAULT NULL::text, p_transaction_id text DEFAULT NULL::text, p_card_number text DEFAULT NULL::text, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$DECLARE
    v_current_user_id UUID;
    v_purchase RECORD;
    v_new_outstanding NUMERIC(12,2);
    v_new_paid NUMERIC(12,2);
    v_payment_id UUID;
    v_now TIMESTAMP WITH TIME ZONE;
BEGIN
    v_now := NOW() AT TIME ZONE 'Asia/Dhaka';

    -- ===================================
    -- 1) AUTHENTICATION
    -- ===================================
    v_current_user_id := auth.uid();
    IF v_current_user_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'User not authenticated',
            'hint', 'Please log in to continue',
            'details', NULL
        );
    END IF;

    -- ===================================
    -- 2) INPUT VALIDATION
    -- ===================================
    IF p_purchase_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Purchase ID is required',
            'hint', NULL,
            'details', NULL
        );
    END IF;

    IF p_pharmacy_id IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Pharmacy ID is required',
            'hint', NULL,
            'details', NULL
        );
    END IF;

    IF p_amount IS NULL OR p_amount <= 0 THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_AMOUNT',
            'message', 'Amount must be greater than zero',
            'hint', NULL,
            'details', NULL
        );
    END IF;

    -- Cap amount to 2 decimal places
    p_amount := ROUND(p_amount, 2);

    IF p_payment_method IS NULL OR UPPER(TRIM(p_payment_method)) NOT IN ('CASH', 'BKASH', 'NAGAD', 'ROCKET', 'CARD', 'BANK_TRANSFER', 'CHEQUE') THEN
        RETURN jsonb_build_object(
            'code', 'INVALID_PAYMENT_METHOD',
            'message', 'Invalid payment method',
            'hint', 'Valid methods: CASH, BKASH, NAGAD, ROCKET, CARD, BANK_TRANSFER, CHEQUE',
            'details', NULL
        );
    END IF;

    -- ===================================
    -- 3) LOCK AND VERIFY PURCHASE
    -- ===================================
    BEGIN
        SELECT id, pharmacy_id, outstanding_amount, paid_amount, total_amount,
               purchase_status, payment_status, supplier_id, purchase_number
        INTO STRICT v_purchase
        FROM purchases
        WHERE id = p_purchase_id
          AND pharmacy_id = p_pharmacy_id
          AND deleted_at IS NULL
        FOR UPDATE NOWAIT;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN jsonb_build_object(
                'code', 'PURCHASE_NOT_FOUND',
                'message', 'Purchase not found or does not belong to this pharmacy',
                'hint', NULL,
                'details', NULL
            );
        WHEN lock_not_available THEN
            RETURN jsonb_build_object(
                'code', 'SYSTEM_BUSY',
                'message', 'Purchase is being modified by another user',
                'hint', 'Please try again in a moment',
                'details', NULL
            );
    END;

    -- ===================================
    -- 4) PERMISSION CHECK
    -- ===================================
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies up
        WHERE up.user_id = v_current_user_id
          AND up.pharmacy_id = p_pharmacy_id
          AND up.is_active = true
    ) THEN
        RETURN jsonb_build_object(
            'code', 'PERMISSION_DENIED',
            'message', 'You do not have permission to make payments',
            'hint', 'Contact your administrator',
            'details', NULL
        );
    END IF;

    -- ===================================
    -- 5) VALIDATE AMOUNT
    -- ===================================
    IF v_purchase.outstanding_amount <= 0 THEN
        RETURN jsonb_build_object(
            'code', 'NO_OUTSTANDING',
            'message', 'No outstanding amount on this purchase',
            'hint', NULL,
            'details', jsonb_build_object('outstanding_amount', v_purchase.outstanding_amount)
        );
    END IF;

    IF p_amount > v_purchase.outstanding_amount THEN
        RETURN jsonb_build_object(
            'code', 'AMOUNT_EXCEEDS_DUE',
            'message', 'Amount exceeds outstanding due',
            'hint', 'Maximum payable: ' || v_purchase.outstanding_amount,
            'details', jsonb_build_object('outstanding_amount', v_purchase.outstanding_amount)
        );
    END IF;

    -- ===================================
    -- 6) CALCULATE NEW VALUES
    -- ===================================
    v_new_paid := ROUND(v_purchase.paid_amount + p_amount, 2);
    v_new_outstanding := GREATEST(0, ROUND(v_purchase.outstanding_amount - p_amount, 2));

    -- ===================================
    -- 7) RECORD PAYMENT (with user_id for traceability)
    -- ===================================
    INSERT INTO purchase_payments (
        purchase_id, payment_method, amount,
        mobile_number, transaction_id, card_number, notes,
        payment_date, created_at, updated_at
    ) VALUES (
        p_purchase_id,
        UPPER(TRIM(p_payment_method))::payment_method_enum,
        p_amount,
        NULLIF(TRIM(p_mobile_number), ''),
        NULLIF(TRIM(p_transaction_id), ''),
        NULLIF(TRIM(p_card_number), ''),
        NULLIF(TRIM(p_notes), ''),
        v_now, v_now, v_now
    ) RETURNING id INTO v_payment_id;

    -- ===================================
    -- 8) UPDATE PURCHASE
    -- ===================================
    UPDATE purchases
    SET paid_amount = v_new_paid,
        outstanding_amount = v_new_outstanding,
        payment_status = CASE
            WHEN v_new_outstanding <= 0 THEN 'COMPLETED'::payment_status_enum
            ELSE 'PARTIAL'::payment_status_enum
        END,
        updated_at = v_now
    WHERE id = p_purchase_id;

    -- ===================================
    -- 9) UPDATE SUPPLIER CREDITS
    -- ===================================
    IF v_purchase.supplier_id IS NOT NULL THEN
        UPDATE supplier_credits
        SET paid_amount = ROUND(paid_amount + p_amount, 2),
            outstanding_amount = GREATEST(0, ROUND(outstanding_amount - p_amount, 2)),
            status = CASE
                WHEN GREATEST(0, ROUND(outstanding_amount - p_amount, 2)) <= 0 THEN 'PAID'
                ELSE status
            END,
            updated_at = v_now
        WHERE purchase_id = p_purchase_id
          AND supplier_id = v_purchase.supplier_id;

        -- Also record in supplier_credit_payments
        INSERT INTO supplier_credit_payments (
            supplier_credit_id, payment_method, amount,
            mobile_number, transaction_id, card_number, notes,
            user_id, payment_date, created_at, transaction_type
        )
        SELECT
            sc.id,
            UPPER(TRIM(p_payment_method))::payment_method_enum,
            p_amount,
            NULLIF(TRIM(p_mobile_number), ''),
            NULLIF(TRIM(p_transaction_id), ''),
            NULLIF(TRIM(p_card_number), ''),
            COALESCE(NULLIF(TRIM(p_notes), ''),
                format('Payment for purchase %s', v_purchase.purchase_number)),
            v_current_user_id,
            v_now, v_now,
            'PAYMENT'::supplier_credit_payment_type_enum
        FROM supplier_credits sc
        WHERE sc.purchase_id = p_purchase_id
          AND sc.supplier_id = v_purchase.supplier_id
        LIMIT 1;
    END IF;

    -- ===================================
    -- 10) LOG ACTIVITY
    -- ===================================
    INSERT INTO activity_logs (
        pharmacy_id, entity_id, activity_type, message, metadata, created_at
    ) VALUES (
        p_pharmacy_id, p_purchase_id, 'PURCHASE',
        'Payment of ' || p_amount || ' recorded for purchase #' || v_purchase.purchase_number,
        jsonb_build_object(
            'action', 'PAYMENT',
            'amount', p_amount,
            'payment_method', UPPER(TRIM(p_payment_method)),
            'new_outstanding', v_new_outstanding,
            'paid_by', v_current_user_id
        ),
        v_now
    );

    -- ===================================
    -- 11) RETURN SUCCESS
    -- ===================================
    RETURN jsonb_build_object(
        'code', 'SUCCESS',
        'message', 'Payment recorded successfully',
        'hint', NULL,
        'details', jsonb_build_object(
            'payment_id', v_payment_id,
            'amount_paid', p_amount,
            'new_outstanding', v_new_outstanding
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'code', 'INTERNAL_ERROR',
            'message', SQLERRM,
            'hint', NULL,
            'details', jsonb_build_object('sqlstate', SQLSTATE)
        );
END;$$;


ALTER FUNCTION public.settle_supplier_outstanding(p_purchase_id uuid, p_pharmacy_id uuid, p_amount numeric, p_payment_method text, p_user_id uuid, p_mobile_number text, p_transaction_id text, p_card_number text, p_notes text) OWNER TO postgres;

--
-- TOC entry 1033 (class 1255 OID 258065)
-- Name: setup_user_profile(uuid, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.setup_user_profile(p_user_id uuid, p_full_name text, p_phone text, p_email text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user RECORD;
    v_full_name text := NULLIF(TRIM(p_full_name), '');
    v_phone text := NULLIF(TRIM(p_phone), '');
BEGIN
    -- Validation
    IF v_full_name IS NULL THEN
        RETURN jsonb_build_object(
            'code', 'VALIDATION_ERROR',
            'message', 'Full name is required',
            'details', NULL
        );
    END IF;

    -- Ensure user exists (in case trigger was delayed or failed)
    -- This makes the signup flow bulletproof
    INSERT INTO public.users (id, full_name, email, phone, is_active)
    VALUES (p_user_id, v_full_name, p_email, v_phone, TRUE)
    ON CONFLICT (id) DO UPDATE
    SET 
        full_name = v_full_name,
        phone = COALESCE(v_phone, public.users.phone),
        email = COALESCE(p_email, public.users.email),
        updated_at = NOW(),
        updated_by = p_user_id
    RETURNING * INTO v_user;

    RETURN jsonb_build_object(
        'code', 'SUCCESS',
        'message', 'Profile setup complete',
        'details', jsonb_build_object(
            'id', v_user.id,
            'email', v_user.email,
            'phone', COALESCE(v_user.phone, ''),
            'full_name', v_user.full_name,
            'avatar_url', v_user.avatar_url,
            'is_active', v_user.is_active,
            'profile_complete', TRUE,
            'created_at', v_user.created_at,
            'updated_at', v_user.updated_at
        )
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'code', 'INTERNAL_ERROR',
        'message', SQLERRM,
        'details', NULL
    );
END;
$$;


ALTER FUNCTION public.setup_user_profile(p_user_id uuid, p_full_name text, p_phone text, p_email text) OWNER TO postgres;

--
-- TOC entry 1208 (class 1255 OID 246111)
-- Name: start_full_sale_return(uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.start_full_sale_return(p_sale_id uuid, p_selected_item_ids uuid[] DEFAULT NULL::uuid[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id              UUID;
    v_sale                 RECORD;
    v_return_id            UUID;
    v_return_number        TEXT;
    v_pharmacy_id          UUID;
    v_item                 RECORD;
    v_item_subtotal        DECIMAL;
    v_discount_calc        RECORD;
    v_items_count          INT     := 0;
    v_subtotal             DECIMAL := 0;
    v_discount_amount      DECIMAL := 0;
    v_refund_amount        DECIMAL := 0;
    v_credit_adjustment    DECIMAL;
    v_cash_refund          DECIMAL;
    v_is_credit_only       BOOLEAN;
    v_customer_name        TEXT    := 'Walk-in Customer';
    v_invoice_discount     DECIMAL;
    v_existing_draft       UUID;
    v_prev_cash_refunded   DECIMAL;
    v_prev_credit_adjusted DECIMAL;
BEGIN
    -- ── 1. AUTHENTICATION ──────────────────────────────────────────────────
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated', 'hint', NULL);
    END IF;

    -- ── 2. LOCK SALE ───────────────────────────────────────────────────────
    BEGIN
        SELECT s.*, c.name AS customer_name
        INTO STRICT v_sale
        FROM sales s
        LEFT JOIN customers c ON s.customer_id = c.id
        WHERE s.id = p_sale_id
          AND s.deleted_at IS NULL
        FOR UPDATE OF s NOWAIT;
    EXCEPTION
        WHEN NO_DATA_FOUND    THEN
            RETURN jsonb_build_object('code', 'SALE_NOT_FOUND', 'message', 'Sale not found', 'hint', NULL);
        WHEN lock_not_available THEN
            RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'Sale is being modified, please retry', 'hint', NULL);
    END;

    v_pharmacy_id := v_sale.pharmacy_id;

    -- ── 3. STATUS CHECK ────────────────────────────────────────────────────
    IF v_sale.sale_status NOT IN ('COMPLETED', 'PARTIALLY_RETURNED') THEN
        RETURN jsonb_build_object(
            'code',    'INVALID_STATUS',
            'message', 'Only completed sales can be returned',
            'hint',    'Sale status is ' || v_sale.sale_status::TEXT
        );
    END IF;

    -- ── 4. PHARMACY MEMBERSHIP ─────────────────────────────────────────────
    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies pu
        WHERE pu.user_id    = v_user_id
          AND pu.pharmacy_id = v_pharmacy_id
          AND pu.is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED', 'message', 'You do not have permission for this pharmacy', 'hint', NULL);
    END IF;

    -- ── 5. RETURNABLE ITEMS CHECK ──────────────────────────────────────────
    IF NOT EXISTS (
        SELECT 1 FROM sale_items si
        WHERE si.sale_id  = p_sale_id
          AND si.quantity  > COALESCE(si.returned_quantity, 0)
          AND (p_selected_item_ids IS NULL OR si.id = ANY(p_selected_item_ids))
    ) THEN
        RETURN jsonb_build_object(
            'code',    'NO_RETURNABLE_ITEMS',
            'message', 'No items available for return',
            'hint',    'All items have already been returned'
        );
    END IF;

    -- ── 6. BUG-SR-2 FIX: Delete existing DRAFT for this user+sale (idempotency) ─
    SELECT id INTO v_existing_draft
    FROM sale_returns
    WHERE sale_id      = p_sale_id
      AND user_id      = v_user_id
      AND return_status = 'DRAFT'
      AND deleted_at   IS NULL
    LIMIT 1;

    IF v_existing_draft IS NOT NULL THEN
        -- BUG-NEW-3 FIX: acquire NOWAIT lock so we fail-fast instead of hanging
        -- if add_or_update_return_item holds an open lock on the draft row.
        BEGIN
            PERFORM 1 FROM sale_returns WHERE id = v_existing_draft FOR UPDATE NOWAIT;
        EXCEPTION
            WHEN lock_not_available THEN
                RETURN jsonb_build_object(
                    'code',    'SYSTEM_BUSY',
                    'message', 'Another operation is in progress, please retry',
                    'hint',    NULL
                );
        END;
        DELETE FROM sale_return_items WHERE return_id = v_existing_draft;
        DELETE FROM sale_returns       WHERE id        = v_existing_draft;
    END IF;

    IF v_sale.customer_name IS NOT NULL THEN
        v_customer_name := v_sale.customer_name;
    END IF;

    -- ── 7. RETURN NUMBER (daily sequence) ──────────────────────────────────
    v_return_number := 'RET-' || TO_CHAR(NOW() AT TIME ZONE 'Asia/Dhaka', 'YYYYMMDD') || '-' ||
                       LPAD((
                           SELECT COUNT(*) + 1
                           FROM sale_returns
                           WHERE pharmacy_id = v_pharmacy_id
                             AND DATE(created_at AT TIME ZONE 'Asia/Dhaka')
                                 = (NOW() AT TIME ZONE 'Asia/Dhaka')::DATE
                       )::TEXT, 4, '0');

    -- ── 8. INSERT DRAFT HEADER ─────────────────────────────────────────────
    INSERT INTO sale_returns (
        id, pharmacy_id, sale_id, user_id, return_number, return_date,
        return_status, subtotal, discount_amount, refund_amount,
        credit_adjustment, cash_refund, created_at, updated_at
    ) VALUES (
        gen_random_uuid(), v_pharmacy_id, p_sale_id, v_user_id,
        v_return_number,
        NOW() AT TIME ZONE 'Asia/Dhaka',
        'DRAFT', 0, 0, 0, 0, 0,
        NOW() AT TIME ZONE 'Asia/Dhaka',
        NOW() AT TIME ZONE 'Asia/Dhaka'
    ) RETURNING id INTO v_return_id;

    -- ── 9. BUG-SR-1 FIX: Extract invoice-only discount (excludes per-item discounts) ─
    v_invoice_discount := calculate_sale_invoice_discount(p_sale_id, v_sale.discount_amount);

    -- ── 10. INSERT RETURN ITEMS WITH CORRECT DISCOUNT SPLIT ────────────────
    FOR v_item IN
        SELECT
            si.id                                                  AS sale_item_id,
            si.inventory_id,
            si.batch_id,
            si.quantity - COALESCE(si.returned_quantity, 0)        AS available_qty,
            si.quantity                                             AS total_qty,
            si.unit_price,
            COALESCE(si.discount_amount, 0)                        AS item_discount
        FROM sale_items si
        WHERE si.sale_id  = p_sale_id
          AND si.quantity  > COALESCE(si.returned_quantity, 0)
          AND (p_selected_item_ids IS NULL OR si.id = ANY(p_selected_item_ids))
    LOOP
        -- BUG-NEW-2 FIX: ROUND subtotal before passing into discount calc so that
        -- accumulated totals stay in sync with the ROUND()ed values stored per item.
        v_item_subtotal := ROUND(v_item.available_qty * v_item.unit_price, 2);

        -- Use the same discount helper as add_or_update_return_item (BUG-SR-1 fix)
        SELECT *
        INTO v_discount_calc
        FROM calculate_total_discount_share(
            v_item.available_qty,
            v_item.total_qty,
            v_item.item_discount,
            v_item_subtotal,
            v_sale.subtotal,
            v_invoice_discount
        );

        INSERT INTO sale_return_items (
            id, return_id, sale_item_id, inventory_id, batch_id,
            quantity, unit_price, total_price,
            proportional_discount, item_discount, net_refund,
            created_at
        ) VALUES (
            gen_random_uuid(), v_return_id, v_item.sale_item_id,
            v_item.inventory_id, v_item.batch_id,
            v_item.available_qty, v_item.unit_price,
            v_item_subtotal,
            ROUND(v_discount_calc.proportional_portion, 2),
            ROUND(v_discount_calc.item_portion, 2),
            ROUND(v_item_subtotal - v_discount_calc.total_discount, 2),
            NOW() AT TIME ZONE 'Asia/Dhaka'
        );

        -- BUG-NEW-2 FIX: accumulate already-rounded values so draft header totals
        -- match SUM(stored net_refund), preventing spurious PAYMENT_MISMATCH.
        v_items_count     := v_items_count + 1;
        v_subtotal        := v_subtotal        + v_item_subtotal;
        v_discount_amount := v_discount_amount + ROUND(v_discount_calc.total_discount, 2);
        v_refund_amount   := v_refund_amount   + ROUND(v_item_subtotal - v_discount_calc.total_discount, 2);
    END LOOP;

    -- ── 11. REFUND SPLIT (cash vs credit), accounting for previous returns ─
    SELECT
        COALESCE(SUM(cash_refund), 0),
        COALESCE(SUM(credit_adjustment), 0)
    INTO v_prev_cash_refunded, v_prev_credit_adjusted
    FROM sale_returns
    WHERE sale_id      = p_sale_id
      AND return_status = 'COMPLETED';

    SELECT credit_adjustment, cash_refund, is_credit_only
    INTO   v_credit_adjustment, v_cash_refund, v_is_credit_only
    FROM calculate_refund_breakdown(
        v_sale.total_amount,
        v_sale.paid_amount,
        v_sale.outstanding_amount,
        ROUND(v_refund_amount, 2),
        v_prev_cash_refunded,
        v_prev_credit_adjusted
    );

    -- ── 12. STAMP TOTALS ON THE DRAFT ─────────────────────────────────────
    UPDATE sale_returns
    SET subtotal          = ROUND(v_subtotal, 2),
        discount_amount   = ROUND(v_discount_amount, 2),
        refund_amount     = ROUND(v_refund_amount, 2),
        credit_adjustment = v_credit_adjustment,
        cash_refund       = v_cash_refund,
        updated_at        = NOW() AT TIME ZONE 'Asia/Dhaka'
    WHERE id = v_return_id;

    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Return initialized successfully',
        'details', jsonb_build_object(
            'return_id',        v_return_id,
            'return_number',    v_return_number,
            'sale_id',          p_sale_id,
            'sale_number',      v_sale.sale_number,
            'customer_name',    v_customer_name,
            'items_count',      v_items_count,
            'subtotal',         ROUND(v_subtotal, 2),
            'discount_amount',  ROUND(v_discount_amount, 2),
            'refund_amount',    ROUND(v_refund_amount, 2),
            'credit_adjustment', v_credit_adjustment,
            'cash_refund',      v_cash_refund,
            'created_at',       NOW() AT TIME ZONE 'Asia/Dhaka'
        )
    );

EXCEPTION
    WHEN SQLSTATE '55P03' THEN
        RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'System is busy, please try again', 'hint', 'Another operation is in progress');
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'INTERNAL_ERROR', 'message', 'Failed to initialize return: ' || SQLERRM, 'hint', NULL);
END;
$$;


ALTER FUNCTION public.start_full_sale_return(p_sale_id uuid, p_selected_item_ids uuid[]) OWNER TO postgres;

--
-- TOC entry 825 (class 1255 OID 231618)
-- Name: start_purchase_return(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.start_purchase_return(p_purchase_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_purchase          RECORD;
    v_pharmacy_id       UUID;
    v_user_id           UUID;
    v_return_id         UUID;
    v_return_number     TEXT;
    v_existing_draft    UUID;
    v_items_count       INT     := 0;
    v_subtotal          DECIMAL := 0;
    v_credit_adjustment DECIMAL := 0;
    v_cash_refund       DECIMAL := 0;
    v_supplier_name     TEXT    := 'No Supplier';
    v_now               TIMESTAMP WITH TIME ZONE;
    v_total_purchased   INT     := 0;
    v_total_returned    INT     := 0;
BEGIN
    v_now := NOW() AT TIME ZONE 'Asia/Dhaka';

    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
        RETURN jsonb_build_object('code', 'UNAUTHORIZED', 'message', 'User not authenticated');
    END IF;

    BEGIN
        SELECT p.*, s.name AS supplier_name
        INTO STRICT v_purchase
        FROM purchases p
        LEFT JOIN suppliers s ON p.supplier_id = s.id
        WHERE p.id = p_purchase_id AND p.deleted_at IS NULL
        FOR UPDATE OF p NOWAIT;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN jsonb_build_object('code', 'PURCHASE_NOT_FOUND', 'message', 'Purchase not found');
        WHEN lock_not_available THEN
            RETURN jsonb_build_object('code', 'SYSTEM_BUSY', 'message', 'Purchase is being modified, please try again');
    END;

    v_pharmacy_id   := v_purchase.pharmacy_id;
    v_supplier_name := COALESCE(v_purchase.supplier_name, 'Cash Purchase');

    IF NOT EXISTS (
        SELECT 1 FROM user_pharmacies
        WHERE user_id    = v_user_id
          AND pharmacy_id = v_pharmacy_id
          AND is_active   = true
    ) THEN
        RETURN jsonb_build_object('code', 'PERMISSION_DENIED', 'message', 'Permission denied');
    END IF;

    IF v_purchase.purchase_status NOT IN ('COMPLETED', 'RETURNED', 'PARTIALLY_RETURNED') THEN
        RETURN jsonb_build_object('code', 'INVALID_STATUS', 'message', 'Purchase must be completed to return');
    END IF;

    -- Find any existing PENDING draft for this user.
    SELECT id INTO v_existing_draft
    FROM purchase_returns
    WHERE purchase_id   = p_purchase_id
      AND refund_status = 'PENDING'::payment_status_enum
      AND user_id       = v_user_id;

    -- Lock existing draft with NOWAIT before deleting to avoid silent blocking.
    IF v_existing_draft IS NOT NULL THEN
        BEGIN
            PERFORM 1 FROM purchase_returns
            WHERE id = v_existing_draft
            FOR UPDATE NOWAIT;
        EXCEPTION
            WHEN lock_not_available THEN
                RETURN jsonb_build_object(
                    'code',    'SYSTEM_BUSY',
                    'message', 'Another operation is in progress on this return, please retry'
                );
        END;
        DELETE FROM purchase_return_items WHERE return_id = v_existing_draft;
        DELETE FROM purchase_returns       WHERE id       = v_existing_draft;
    END IF;

    -- Count items and compute subtotal using batch-stock-aware qty.
    SELECT
        COUNT(*),
        COALESCE(SUM(
            GREATEST(0, LEAST(
                pi.quantity - COALESCE(ar.returned_qty, 0),
                COALESCE(ib.current_quantity,
                         GREATEST(0, pi.quantity - COALESCE(ar.returned_qty, 0)))
            )) * pi.purchase_price
        ), 0)
    INTO v_items_count, v_subtotal
    FROM purchase_items pi
    LEFT JOIN (
        SELECT pri.purchase_item_id, SUM(pri.quantity) AS returned_qty
        FROM purchase_return_items pri
        JOIN purchase_returns pr ON pri.return_id = pr.id
        WHERE pr.purchase_id   = p_purchase_id
          AND pr.refund_status = 'COMPLETED'::payment_status_enum
        GROUP BY pri.purchase_item_id
    ) ar ON ar.purchase_item_id = pi.id
    LEFT JOIN inventory_batches ib
        ON ib.inventory_id = pi.inventory_id
       AND ib.purchase_id  = p_purchase_id
       AND ib.pharmacy_id  = v_pharmacy_id
       AND ib.batch_number IS NOT DISTINCT FROM NULLIF(NULLIF(pi.batch_number, ''), 'DEFAULT')
       AND ib.deleted_at IS NULL
    WHERE pi.purchase_id = p_purchase_id
      AND GREATEST(0, LEAST(
              pi.quantity - COALESCE(ar.returned_qty, 0),
              COALESCE(ib.current_quantity,
                       GREATEST(0, pi.quantity - COALESCE(ar.returned_qty, 0)))
          )) > 0;

    IF v_items_count = 0 THEN
        -- Determine WHY no items are available:
        -- Compare total purchased quantity vs total returned quantity
        SELECT
            COALESCE(SUM(pi.quantity), 0),
            COALESCE(SUM(ar.returned_qty), 0)
        INTO v_total_purchased, v_total_returned
        FROM purchase_items pi
        LEFT JOIN (
            SELECT pri.purchase_item_id, SUM(pri.quantity) AS returned_qty
            FROM purchase_return_items pri
            JOIN purchase_returns pr ON pri.return_id = pr.id
            WHERE pr.purchase_id   = p_purchase_id
              AND pr.refund_status = 'COMPLETED'::payment_status_enum
            GROUP BY pri.purchase_item_id
        ) ar ON ar.purchase_item_id = pi.id
        WHERE pi.purchase_id = p_purchase_id;

        IF v_total_returned >= v_total_purchased AND v_total_returned > 0 THEN
            -- Everything was actually returned to supplier
            RETURN jsonb_build_object(
                'code',    'NO_ITEMS',
                'message', 'All items from this purchase have already been returned to the supplier.',
                'reason',  'FULLY_RETURNED'
            );
        ELSE
            -- Stock depleted by sales, adjustments, etc.
            RETURN jsonb_build_object(
                'code',    'NO_ITEMS',
                'message', 'No items available for return. All stock from this purchase has been sold or adjusted.',
                'reason',  'NO_STOCK'
            );
        END IF;
    END IF;

    v_return_id     := gen_random_uuid();
    v_return_number := 'PR-' || TO_CHAR(v_now, 'YYYYMMDD') || '-' ||
                       UPPER(SPLIT_PART(v_return_id::TEXT, '-', 1));

    INSERT INTO purchase_returns (
        id, pharmacy_id, purchase_id, supplier_id, return_number,
        return_date, subtotal, total_amount, refund_status, refunded_amount,
        user_id, return_reason, notes, created_at, updated_at
    ) VALUES (
        v_return_id, v_pharmacy_id, p_purchase_id, v_purchase.supplier_id, v_return_number,
        v_now, 0, 0, 'PENDING'::payment_status_enum, 0,
        v_user_id, 'OTHER', NULL, v_now, v_now
    );

    -- Pre-fill draft items with batch-stock-aware quantities.
    INSERT INTO purchase_return_items (
        id, return_id, purchase_item_id, inventory_id, batch_number,
        quantity, unit_cost, total_cost, created_at
    )
    SELECT
        gen_random_uuid(),
        v_return_id,
        pi.id,
        pi.inventory_id,
        COALESCE(pi.batch_number, ''),
        GREATEST(0, LEAST(
            pi.quantity - COALESCE(ar.returned_qty, 0),
            COALESCE(ib.current_quantity,
                     GREATEST(0, pi.quantity - COALESCE(ar.returned_qty, 0)))
        )),
        pi.purchase_price,
        GREATEST(0, LEAST(
            pi.quantity - COALESCE(ar.returned_qty, 0),
            COALESCE(ib.current_quantity,
                     GREATEST(0, pi.quantity - COALESCE(ar.returned_qty, 0)))
        )) * pi.purchase_price,
        v_now
    FROM purchase_items pi
    LEFT JOIN (
        SELECT pri.purchase_item_id, SUM(pri.quantity) AS returned_qty
        FROM purchase_return_items pri
        JOIN purchase_returns pr ON pri.return_id = pr.id
        WHERE pr.purchase_id   = p_purchase_id
          AND pr.refund_status = 'COMPLETED'::payment_status_enum
        GROUP BY pri.purchase_item_id
    ) ar ON ar.purchase_item_id = pi.id
    LEFT JOIN inventory_batches ib
        ON ib.inventory_id = pi.inventory_id
       AND ib.purchase_id  = p_purchase_id
       AND ib.pharmacy_id  = v_pharmacy_id
       AND ib.batch_number IS NOT DISTINCT FROM NULLIF(NULLIF(pi.batch_number, ''), 'DEFAULT')
       AND ib.deleted_at IS NULL
    WHERE pi.purchase_id = p_purchase_id
      AND GREATEST(0, LEAST(
              pi.quantity - COALESCE(ar.returned_qty, 0),
              COALESCE(ib.current_quantity,
                       GREATEST(0, pi.quantity - COALESCE(ar.returned_qty, 0)))
          )) > 0;

    IF v_purchase.outstanding_amount > 0 THEN
        v_credit_adjustment := LEAST(v_subtotal, v_purchase.outstanding_amount);
        v_cash_refund       := GREATEST(0, v_subtotal - v_credit_adjustment);
    ELSE
        v_credit_adjustment := 0;
        v_cash_refund       := v_subtotal;
    END IF;

    UPDATE purchase_returns
    SET subtotal     = v_subtotal,
        total_amount = v_subtotal,
        updated_at   = v_now
    WHERE id = v_return_id;

    RETURN jsonb_build_object(
        'code',    'SUCCESS',
        'message', 'Return initialized with all items',
        'details', jsonb_build_object(
            'return_id',         v_return_id,
            'return_number',     v_return_number,
            'purchase_id',       p_purchase_id,
            'purchase_number',   v_purchase.purchase_number,
            'supplier_id',       v_purchase.supplier_id,
            'supplier_name',     v_supplier_name,
            'has_supplier',      v_purchase.supplier_id IS NOT NULL,
            'items_count',       v_items_count,
            'subtotal',          v_subtotal,
            'total_amount',      v_subtotal,
            'credit_adjustment', v_credit_adjustment,
            'cash_refund',       v_cash_refund,
            'is_credit_only',    (v_cash_refund = 0 AND v_subtotal > 0),
            'created_at',        v_now
        )
    );

EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object('code', 'INTERNAL_ERROR', 'message', 'Failed: ' || SQLERRM);
END;
$$;


ALTER FUNCTION public.start_purchase_return(p_purchase_id uuid) OWNER TO postgres;

--
-- TOC entry 643 (class 1255 OID 276577)
-- Name: text_to_unit_enum(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.text_to_unit_enum(val text) RETURNS public.unit_enum
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    cleaned text;
BEGIN
    cleaned := LOWER(NULLIF(TRIM(val), ''));
    IF cleaned IS NULL THEN
        RETURN NULL::public.unit_enum;
    END IF;
    
    -- Try direct cast, catch exception to return 'other' if not in enum list
    BEGIN
        RETURN cleaned::public.unit_enum;
    EXCEPTION WHEN invalid_text_representation THEN
        RETURN 'other'::public.unit_enum;
    END;
END;
$$;


ALTER FUNCTION public.text_to_unit_enum(val text) OWNER TO postgres;

--
-- TOC entry 978 (class 1255 OID 131803)
-- Name: trigger_update_stock_summary(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.trigger_update_stock_summary() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_inventory_id UUID;
BEGIN
    -- Determine which inventory was affected
    IF TG_OP = 'DELETE' THEN
        v_inventory_id := OLD.inventory_id;
    ELSE
        v_inventory_id := NEW.inventory_id;
    END IF;

    -- Guard: skip if inventory_id is NULL
    IF v_inventory_id IS NULL THEN
        IF TG_OP = 'DELETE' THEN RETURN OLD; END IF;
        RETURN NEW;
    END IF;

    -- Update the stock summary for the affected inventory
    PERFORM update_stock_summary(v_inventory_id);

    -- Handle inventory_id change (rare: batch reassignment)
    IF TG_OP = 'UPDATE' AND OLD.inventory_id IS DISTINCT FROM NEW.inventory_id THEN
        PERFORM update_stock_summary(OLD.inventory_id);
    END IF;

    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    END IF;
    RETURN NEW;

EXCEPTION WHEN OTHERS THEN
    -- Non-blocking: log warning but never abort the parent transaction
    RAISE WARNING 'trigger_update_stock_summary failed for inventory %: % [%]',
        v_inventory_id, SQLERRM, SQLSTATE;
    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.trigger_update_stock_summary() OWNER TO postgres;

--
-- TOC entry 7278 (class 0 OID 0)
-- Dependencies: 978
-- Name: FUNCTION trigger_update_stock_summary(); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.trigger_update_stock_summary() IS 'AFTER trigger on inventory_batches: Refreshes stock_summary for the affected inventory.
Non-blocking: logs WARNING on failure without aborting the transaction.
Handles DELETE, INSERT, UPDATE, and inventory_id reassignment.';


--
-- TOC entry 469 (class 1255 OID 261548)
-- Name: update_stock_summary(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_stock_summary(p_inventory_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_pharmacy_id UUID;
    v_reorder_level INTEGER;
    v_result RECORD;
BEGIN
    IF p_inventory_id IS NULL THEN
        RETURN;
    END IF;

    -- Get inventory metadata
    SELECT pharmacy_id, COALESCE(reorder_level, 0)
    INTO v_pharmacy_id, v_reorder_level
    FROM inventory
    WHERE id = p_inventory_id AND deleted_at IS NULL;

    IF NOT FOUND THEN
        -- Inventory was deleted; clean up orphan summary
        DELETE FROM stock_summary WHERE inventory_id = p_inventory_id;
        RETURN;
    END IF;

    -- Single combined query: batch metrics + transaction timestamps
    SELECT
        -- Batch metrics (only sellable statuses with stock)
        COALESCE(SUM(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY') AND b.current_quantity > 0
            THEN b.current_quantity ELSE 0 END), 0)::INTEGER AS total_quantity,
        COUNT(*)::INTEGER AS total_batches,
        COUNT(*) FILTER (WHERE b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY'))::INTEGER AS active_batches,
        COUNT(*) FILTER (WHERE b.status = 'EXPIRED')::INTEGER AS expired_batches,

        -- Valuation
        COALESCE(SUM(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY') AND b.current_quantity > 0
            THEN b.current_quantity * b.purchase_price ELSE 0 END), 0) AS total_purchase_value,
        COALESCE(SUM(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY') AND b.current_quantity > 0
            THEN b.current_quantity * b.selling_price ELSE 0 END), 0) AS total_selling_value,

        -- Weighted average prices
        CASE WHEN SUM(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY') AND b.current_quantity > 0
                THEN b.current_quantity ELSE 0 END) > 0
            THEN ROUND(
                SUM(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY') AND b.current_quantity > 0
                    THEN b.current_quantity * b.purchase_price ELSE 0 END) /
                NULLIF(SUM(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY') AND b.current_quantity > 0
                    THEN b.current_quantity ELSE 0 END), 0), 2)
            ELSE 0 END AS avg_purchase_price,
        CASE WHEN SUM(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY') AND b.current_quantity > 0
                THEN b.current_quantity ELSE 0 END) > 0
            THEN ROUND(
                SUM(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY') AND b.current_quantity > 0
                    THEN b.current_quantity * b.selling_price ELSE 0 END) /
                NULLIF(SUM(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY') AND b.current_quantity > 0
                    THEN b.current_quantity ELSE 0 END), 0), 2)
            ELSE 0 END AS avg_selling_price,

        -- Expiry tracking
        MIN(CASE WHEN b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY')
                  AND b.expiry_date > CURRENT_DATE AND b.current_quantity > 0
            THEN b.expiry_date END) AS nearest_expiry,
        COUNT(*) FILTER (WHERE b.status IN ('ACTIVE', 'LOW_STOCK', 'NEAR_EXPIRY')
            AND b.expiry_date > CURRENT_DATE
            AND b.expiry_date <= CURRENT_DATE + INTERVAL '30 days'
            AND b.current_quantity > 0)::INTEGER AS expiring_soon_count,
        COUNT(*) FILTER (WHERE b.expiry_date <= CURRENT_DATE
            AND b.current_quantity > 0)::INTEGER AS expired_count,

        -- Transaction timestamps (from subquery)
        t.last_purchase_at,
        t.last_sale_at,
        t.last_transaction_at
    INTO v_result
    FROM inventory_batches b
    LEFT JOIN LATERAL (
        SELECT
            MAX(CASE WHEN st.transaction_type = 'PURCHASE' THEN st.created_at END) AS last_purchase_at,
            MAX(CASE WHEN st.transaction_type = 'SALE' THEN st.created_at END) AS last_sale_at,
            MAX(st.created_at) AS last_transaction_at
        FROM stock_transactions st
        WHERE st.inventory_id = p_inventory_id AND st.deleted_at IS NULL
    ) t ON true
    WHERE b.inventory_id = p_inventory_id AND b.deleted_at IS NULL
    GROUP BY t.last_purchase_at, t.last_sale_at, t.last_transaction_at;

    -- Handle case where no batches exist
    IF NOT FOUND THEN
        -- Insert/update with zero values
        INSERT INTO stock_summary (
            pharmacy_id, inventory_id, total_quantity, total_batches,
            active_batches, expired_batches, total_purchase_value, total_selling_value,
            avg_purchase_price, avg_selling_price, nearest_expiry,
            expiring_soon_count, expired_count, reorder_level, is_below_reorder,
            last_transaction_at, last_purchase_at, last_sale_at,
            created_at, updated_at
        ) VALUES (
            v_pharmacy_id, p_inventory_id, 0, 0, 0, 0, 0, 0, 0, 0, NULL, 0, 0,
            v_reorder_level, true, NULL, NULL, NULL,
            NOW() AT TIME ZONE 'Asia/Dhaka', NOW() AT TIME ZONE 'Asia/Dhaka'
        )
        ON CONFLICT (inventory_id) DO UPDATE SET
            total_quantity = 0, total_batches = 0, active_batches = 0,
            expired_batches = 0, total_purchase_value = 0, total_selling_value = 0,
            avg_purchase_price = 0, avg_selling_price = 0, nearest_expiry = NULL,
            expiring_soon_count = 0, expired_count = 0,
            reorder_level = v_reorder_level, is_below_reorder = true,
            updated_at = NOW() AT TIME ZONE 'Asia/Dhaka';
        RETURN;
    END IF;

    -- UPSERT the stock summary
    INSERT INTO stock_summary (
        pharmacy_id, inventory_id, total_quantity, total_batches,
        active_batches, expired_batches, total_purchase_value, total_selling_value,
        avg_purchase_price, avg_selling_price, nearest_expiry,
        expiring_soon_count, expired_count, reorder_level, is_below_reorder,
        last_transaction_at, last_purchase_at, last_sale_at,
        created_at, updated_at
    ) VALUES (
        v_pharmacy_id, p_inventory_id,
        v_result.total_quantity,
        v_result.total_batches,
        v_result.active_batches,
        v_result.expired_batches,
        v_result.total_purchase_value,
        v_result.total_selling_value,
        v_result.avg_purchase_price,
        v_result.avg_selling_price,
        v_result.nearest_expiry,
        v_result.expiring_soon_count,
        v_result.expired_count,
        v_reorder_level,
        v_result.total_quantity < v_reorder_level,
        v_result.last_transaction_at,
        v_result.last_purchase_at,
        v_result.last_sale_at,
        NOW() AT TIME ZONE 'Asia/Dhaka',
        NOW() AT TIME ZONE 'Asia/Dhaka'
    )
    ON CONFLICT (inventory_id) DO UPDATE SET
        total_quantity = EXCLUDED.total_quantity,
        total_batches = EXCLUDED.total_batches,
        active_batches = EXCLUDED.active_batches,
        expired_batches = EXCLUDED.expired_batches,
        total_purchase_value = EXCLUDED.total_purchase_value,
        total_selling_value = EXCLUDED.total_selling_value,
        avg_purchase_price = EXCLUDED.avg_purchase_price,
        avg_selling_price = EXCLUDED.avg_selling_price,
        nearest_expiry = EXCLUDED.nearest_expiry,
        expiring_soon_count = EXCLUDED.expiring_soon_count,
        expired_count = EXCLUDED.expired_count,
        reorder_level = EXCLUDED.reorder_level,
        is_below_reorder = EXCLUDED.is_below_reorder,
        last_transaction_at = EXCLUDED.last_transaction_at,
        last_purchase_at = EXCLUDED.last_purchase_at,
        last_sale_at = EXCLUDED.last_sale_at,
        updated_at = EXCLUDED.updated_at;
END;
$$;


