Uses UPSERT (ON CONFLICT) for idempotency. SECURITY DEFINER for trigger compatibility.';


--
-- TOC entry 495 (class 1255 OID 194869)
-- Name: update_stock_transaction(uuid, uuid, text, integer, numeric, numeric, uuid, text, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_stock_transaction(p_inventory_id uuid, p_batch_id uuid, p_transaction_type text, p_quantity_change integer, p_unit_price numeric DEFAULT NULL::numeric, p_total_amount numeric DEFAULT NULL::numeric, p_reference_id uuid DEFAULT NULL::uuid, p_reference_number text DEFAULT NULL::text, p_user_id uuid DEFAULT NULL::uuid, p_notes text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_transaction_id UUID;
    v_transaction_type transaction_type_enum;
    v_batch RECORD;
    v_inventory RECORD;
    v_quantity_before INTEGER;
    v_quantity_after INTEGER;
    v_final_user_id UUID;
BEGIN
    -- INPUT VALIDATION
    IF p_inventory_id IS NULL THEN
        RAISE EXCEPTION 'Inventory ID is required';
    END IF;

    IF p_batch_id IS NULL THEN
        RAISE EXCEPTION 'Batch ID is required';
    END IF;

    IF p_transaction_type IS NULL OR TRIM(p_transaction_type) = '' THEN
        RAISE EXCEPTION 'Transaction type is required';
    END IF;

    IF p_quantity_change IS NULL OR p_quantity_change = 0 THEN
        RAISE EXCEPTION 'Quantity change must be non-zero (got: %)', p_quantity_change;
    END IF;

    -- Validate and convert transaction type
    BEGIN
        v_transaction_type := UPPER(TRIM(p_transaction_type))::transaction_type_enum;
    EXCEPTION
        WHEN invalid_text_representation THEN
            RAISE EXCEPTION 'Invalid transaction type: "%". Valid types: PURCHASE, SALE, SALE_RETURN, ADJUSTMENT, DAMAGE, EXPIRED, TRANSFER_IN, TRANSFER_OUT, STOCK_COUNT',
                p_transaction_type;
    END;

    -- Get current user if not provided
    v_final_user_id := COALESCE(p_user_id, auth.uid());

    IF v_final_user_id IS NULL THEN
        RAISE EXCEPTION 'User ID is required (not authenticated)';
    END IF;

    -- VERIFY BATCH
    SELECT
        ib.id,
        ib.pharmacy_id,
        ib.inventory_id,
        ib.current_quantity,
        ib.batch_number,
        ib.expiry_date,
        ib.status
    INTO v_batch
    FROM inventory_batches ib
    WHERE ib.id = p_batch_id
    AND ib.deleted_at IS NULL;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Batch not found: %', p_batch_id;
    END IF;

    -- Verify batch belongs to inventory
    IF v_batch.inventory_id != p_inventory_id THEN
        RAISE EXCEPTION 'Batch % does not belong to inventory %', p_batch_id, p_inventory_id;
    END IF;

    -- VERIFY INVENTORY (FIXED: use primary_unit instead of base_unit)
    SELECT
        i.id,
        i.pharmacy_id,
        i.type,
        i.name,
        i.brand,
        i.primary_unit
    INTO v_inventory
    FROM inventory i
    WHERE i.id = p_inventory_id
    AND i.deleted_at IS NULL;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Inventory item not found: %', p_inventory_id;
    END IF;

    -- Verify pharmacy consistency
    IF v_batch.pharmacy_id != v_inventory.pharmacy_id THEN
        RAISE EXCEPTION 'Batch and inventory belong to different pharmacies';
    END IF;

    -- VALIDATE QUANTITY CHANGE
    v_quantity_before := v_batch.current_quantity;
    v_quantity_after := v_quantity_before + p_quantity_change;

    -- Prevent negative stock
    IF v_quantity_after < 0 THEN
        RAISE EXCEPTION 'Transaction would result in negative stock. Current: %, Change: %, Result: %',
            v_quantity_before, p_quantity_change, v_quantity_after;
    END IF;

    -- Warning for sales from expired batches (allow but log)
    IF v_transaction_type = 'SALE' AND v_batch.expiry_date IS NOT NULL AND v_batch.expiry_date <= CURRENT_DATE THEN
        RAISE WARNING 'Selling from expired batch: % (Expired: %)', v_batch.batch_number, v_batch.expiry_date;
    END IF;

    -- VALIDATE PRICING
    IF p_unit_price IS NOT NULL AND p_unit_price < 0 THEN
        RAISE EXCEPTION 'Unit price cannot be negative: %', p_unit_price;
    END IF;

    IF p_total_amount IS NOT NULL AND p_total_amount < 0 THEN
        RAISE EXCEPTION 'Total amount cannot be negative: %', p_total_amount;
    END IF;

    -- CREATE TRANSACTION RECORD
    INSERT INTO stock_transactions (
        pharmacy_id,
        inventory_id,
        batch_id,
        transaction_type,
        quantity_change,
        quantity_before,
        quantity_after,
        unit_price,
        total_amount,
        reference_id,
        reference_number,
        user_id,
        notes,
        created_at
    ) VALUES (
        v_inventory.pharmacy_id,
        p_inventory_id,
        p_batch_id,
        v_transaction_type,
        p_quantity_change,
        v_quantity_before,
        v_quantity_after,
        p_unit_price,
        p_total_amount,
        p_reference_id,
        p_reference_number,
        v_final_user_id,
        CASE
            WHEN p_notes IS NOT NULL AND TRIM(p_notes) != '' THEN TRIM(p_notes)
            ELSE format('%s transaction for %s',
                v_transaction_type::TEXT,
                COALESCE(v_inventory.brand, v_inventory.name)
            )
        END,
        NOW() AT TIME ZONE 'Asia/Dhaka'
    )
    RETURNING id INTO v_transaction_id;

    RETURN v_transaction_id;

EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to create stock transaction: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
END;
$$;


