--
-- TOC entry 1302 (class 1255 OID 165368)
-- Name: upsert_customer(uuid, text, uuid, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.upsert_customer(p_pharmacy_id uuid, p_name text, p_id uuid DEFAULT NULL::uuid, p_phone text DEFAULT NULL::text, p_email text DEFAULT NULL::text, p_address text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_color_label text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $_$
DECLARE
    v_current_user_id UUID;
    v_customer_id UUID;
    v_is_new BOOLEAN := false;
    v_permission TEXT;
    v_cleaned_phone TEXT;
    v_cleaned_email TEXT;
BEGIN
    v_current_user_id := auth.uid();

    IF v_current_user_id IS NULL THEN
        RETURN json_build_object(
            'code', 'UNAUTHORIZED',
            'message', 'Authentication required',
            'hint', 'User must be logged in',
            'details', NULL
        );
    END IF;

    IF p_pharmacy_id IS NULL THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Pharmacy ID is required',
            'hint', 'Provide a valid pharmacy ID',
            'details', NULL
        );
    END IF;

    v_permission := CASE WHEN p_id IS NULL THEN 'customers.create' ELSE 'customers.update' END;

    IF NOT user_has_permission(v_current_user_id, p_pharmacy_id, v_permission) THEN
        RETURN json_build_object(
            'code', 'PERMISSION_DENIED',
            'message', format('You do not have permission to %s customers', 
                CASE WHEN p_id IS NULL THEN 'create' ELSE 'update' END),
            'hint', 'Contact your administrator for access',
            'details', NULL
        );
    END IF;

    IF p_name IS NULL OR TRIM(p_name) = '' THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Customer name is required',
            'hint', 'Provide a valid customer name',
            'details', NULL
        );
    END IF;

    IF LENGTH(TRIM(p_name)) < 2 THEN
        RETURN json_build_object(
            'code', 'INVALID_INPUT',
            'message', 'Customer name must be at least 2 characters',
            'hint', 'Provide a longer customer name',
            'details', NULL
        );
    END IF;

    v_cleaned_phone := NULLIF(TRIM(p_phone), '');
    v_cleaned_email := NULLIF(TRIM(p_email), '');

    IF v_cleaned_phone IS NOT NULL THEN
        IF LENGTH(v_cleaned_phone) < 10 THEN
            RETURN json_build_object(
                'code', 'INVALID_PHONE',
                'message', 'Phone number must be at least 10 digits',
                'hint', 'Provide a valid phone number',
                'details', NULL
            );
        END IF;

        IF EXISTS (
            SELECT 1 FROM customers
            WHERE phone = v_cleaned_phone
              AND pharmacy_id = p_pharmacy_id
              AND deleted_at IS NULL
              AND (p_id IS NULL OR id != p_id)
        ) THEN
            RETURN json_build_object(
                'code', 'DUPLICATE_PHONE',
                'message', 'Phone number already exists',
                'hint', 'This phone number is already registered with another customer',
                'details', json_build_object('phone', v_cleaned_phone)
            );
        END IF;
    END IF;

    IF v_cleaned_email IS NOT NULL THEN
        IF NOT v_cleaned_email ~ '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$' THEN
            RETURN json_build_object(
                'code', 'INVALID_EMAIL',
                'message', 'Invalid email format',
                'hint', 'Provide a valid email address',
                'details', NULL
            );
        END IF;

        IF EXISTS (
            SELECT 1 FROM customers
            WHERE email = v_cleaned_email
              AND pharmacy_id = p_pharmacy_id
              AND deleted_at IS NULL
              AND (p_id IS NULL OR id != p_id)
        ) THEN
            RETURN json_build_object(
                'code', 'DUPLICATE_EMAIL',
                'message', 'Email already exists',
                'hint', 'This email is already registered with another customer',
                'details', json_build_object('email', v_cleaned_email)
            );
        END IF;
    END IF;

    IF p_id IS NOT NULL THEN
        UPDATE customers 
        SET 
            name = TRIM(p_name),
            phone = v_cleaned_phone,
            email = v_cleaned_email,
            address = NULLIF(TRIM(p_address), ''),
            notes = NULLIF(TRIM(p_notes), ''),
            color_label = p_color_label
        WHERE id = p_id 
          AND pharmacy_id = p_pharmacy_id 
          AND deleted_at IS NULL;
        
        IF FOUND THEN
            v_customer_id := p_id;
            v_is_new := false;
        ELSE
            RETURN json_build_object(
                'code', 'CUSTOMER_NOT_FOUND',
                'message', 'Customer not found or does not belong to your pharmacy',
                'hint', 'Check the customer ID and try again',
                'details', json_build_object('customer_id', p_id)
            );
        END IF;
    ELSE
        INSERT INTO customers (
            pharmacy_id,
            name,
            phone,
            email,
            address,
            notes,
            color_label
        ) VALUES (
            p_pharmacy_id, 
            TRIM(p_name), 
            v_cleaned_phone,
            v_cleaned_email,
            NULLIF(TRIM(p_address), ''),
            NULLIF(TRIM(p_notes), ''),
            p_color_label
        ) RETURNING id INTO v_customer_id;
        
        v_is_new := true;
    END IF;

    RETURN json_build_object(
        'code', 'SUCCESS',
        'message', CASE 
            WHEN v_is_new THEN 'Customer created successfully'
            ELSE 'Customer updated successfully'
        END,
        'hint', NULL,
        'details', json_build_object(
            'customer_id', v_customer_id,
            'is_new', v_is_new,
            'pharmacy_id', p_pharmacy_id
        )
    );
    
EXCEPTION
    WHEN unique_violation THEN
        RETURN json_build_object(
            'code', 'DUPLICATE_ENTRY',
            'message', 'Duplicate customer entry',
            'hint', 'A customer with these details already exists',
            'details', json_build_object('error', SQLERRM)
        );
    WHEN foreign_key_violation THEN
        RETURN json_build_object(
            'code', 'INVALID_REFERENCE',
            'message', 'Invalid pharmacy reference',
            'hint', 'The specified pharmacy does not exist',
            'details', json_build_object('pharmacy_id', p_pharmacy_id)
        );
    WHEN OTHERS THEN
        RETURN json_build_object(
            'code', 'ERROR',
            'message', 'Failed to save customer',
            'hint', SQLERRM,
            'details', json_build_object(
                'sqlstate', SQLSTATE,
                'error', SQLERRM
            )
        );
END;
$_$;


