--
-- TOC entry 1041 (class 1255 OID 171604)
-- Name: user_has_permission(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.user_has_permission(p_user_id uuid, p_pharmacy_id uuid, p_permission text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_has_permission BOOLEAN;
BEGIN
    SELECT EXISTS(
        SELECT 1 
        FROM user_pharmacies up
        JOIN user_roles ur ON up.role_id = ur.id
        WHERE up.user_id = p_user_id 
            AND up.pharmacy_id = p_pharmacy_id
            AND up.is_active = TRUE
            AND ur.permissions ? p_permission
    ) INTO v_has_permission;

    RETURN v_has_permission;
END;
$$;


