--
-- TOC entry 459 (class 1259 OID 276743)
-- Name: mv_pharmacy_stock_metadata; Type: MATERIALIZED VIEW; Schema: public; Owner: postgres
--

CREATE MATERIALIZED VIEW public.mv_pharmacy_stock_metadata AS
 SELECT i.pharmacy_id,
    COALESCE(to_json(array_agg(DISTINCT c.name ORDER BY c.name) FILTER (WHERE (c.name IS NOT NULL))), '[]'::json) AS categories,
    COALESCE(to_json(array_agg(DISTINCT i.primary_unit ORDER BY i.primary_unit) FILTER (WHERE (i.primary_unit IS NOT NULL))), '[]'::json) AS primary_units
   FROM (public.inventory i
     LEFT JOIN public.categories c ON ((i.category_id = c.id)))
  WHERE ((i.deleted_at IS NULL) AND (i.is_active = true))
  GROUP BY i.pharmacy_id
  WITH NO DATA;


ALTER MATERIALIZED VIEW public.mv_pharmacy_stock_metadata OWNER TO postgres;

