-- TOC entry 442 (class 1259 OID 226595)
-- Name: v_sale_items_with_return_info; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.v_sale_items_with_return_info AS
 SELECT id,
    sale_id,
    inventory_id,
    batch_id,
    quantity,
    total_price,
    created_at,
    updated_at,
    unit_price,
    discount_amount,
    returned_quantity,
    (quantity - COALESCE(returned_quantity, 0)) AS available_for_return,
        CASE
            WHEN (COALESCE(returned_quantity, 0) >= quantity) THEN true
            ELSE false
        END AS is_fully_returned
   FROM public.sale_items si;


